#[derive(Clone, Copy, Debug)]
pub(crate) struct CachedAdversarialEmbeddingSignals {
    tick: u64,
    signals: Option<SoccerAdversarialEmbeddingSignals>,
}

/// Per-player Beta-Bernoulli posterior over how readily a player presses / steps
/// toward the ball (a proxy for their pass-lane interception propensity).
/// `mean()` = alpha / (alpha + beta). Updated online with soft Bernoulli evidence and
/// an exponential forget toward the neutral prior, so it tracks the last ~tau seconds
/// of behaviour; pure arithmetic (no RNG) => deterministic / parity-safe. See the
/// `OPPONENT_PRESS_*` constants and [`SoccerMatch::update_opponent_press_beliefs`].
#[derive(Clone, Copy, Debug)]
pub(crate) struct OpponentPressBelief {
    alpha: f64,
    beta: f64,
}

impl Default for OpponentPressBelief {
    fn default() -> Self {
        OpponentPressBelief {
            alpha: OPPONENT_PRESS_PRIOR_ALPHA,
            beta: OPPONENT_PRESS_PRIOR_BETA,
        }
    }
}

impl OpponentPressBelief {
    /// Posterior mean tendency theta-hat in (0,1). Falls back to the neutral prior mean if the
    /// concentration is ever non-finite or non-positive (it cannot be in normal operation, but
    /// the guard keeps a single bad sample from propagating NaN into pass selection).
    pub(crate) fn mean(&self) -> f64 {
        let total = self.alpha + self.beta;
        let mean = self.alpha / total;
        if total > 0.0 && mean.is_finite() {
            mean
        } else {
            OPPONENT_PRESS_NEUTRAL_TENDENCY
        }
    }

    /// One filter step: exponential forget toward the prior (so the belief tracks the
    /// last ~tau seconds), then, when an observation is available this tick, fold soft
    /// Bernoulli evidence `e` in [0,1] ("how strongly is this player stepping toward the
    /// ball right now?") as a conjugate Beta update. Non-finite evidence is dropped (treated as
    /// "no observation") and the concentration is capped so the counts stay finite even when the
    /// forget factor is 1.0 (dt == 0).
    pub(crate) fn step(&mut self, forget: f64, observation: Option<f64>) {
        let forget = forget.clamp(0.0, 1.0);
        self.alpha =
            OPPONENT_PRESS_PRIOR_ALPHA + forget * (self.alpha - OPPONENT_PRESS_PRIOR_ALPHA);
        self.beta = OPPONENT_PRESS_PRIOR_BETA + forget * (self.beta - OPPONENT_PRESS_PRIOR_BETA);
        if let Some(e) = observation {
            if e.is_finite() {
                let e = e.clamp(0.0, 1.0);
                self.alpha += OPPONENT_PRESS_OBSERVATION_WEIGHT * e;
                self.beta += OPPONENT_PRESS_OBSERVATION_WEIGHT * (1.0 - e);
            }
        }
        // Cap the concentration (mean-preserving) so alpha+beta cannot grow without bound when
        // there is no effective decay (forget == 1.0 at dt == 0).
        let total = self.alpha + self.beta;
        if total > OPPONENT_PRESS_MAX_CONCENTRATION && total.is_finite() {
            let scale = OPPONENT_PRESS_MAX_CONCENTRATION / total;
            self.alpha *= scale;
            self.beta *= scale;
        }
    }
}

/// One windowed wasted-energy sample: a transition where the player was "moving a lot"
/// (locomotion cost above [`WASTED_ENERGY_MIN_JOULES_PER_TICK`]), held until its 10s
/// lookahead closes. If no ball interaction lands in that window the transition is re-trained
/// with a small negative reward scaled by `joules`; otherwise it is dropped. See
/// [`SoccerMatch::finalize_wasted_energy_window`].
#[derive(Clone)]
pub(crate) struct WastedEnergySample {
    pub(crate) transition: SoccerLearningTransition,
    pub(crate) joules: f64,
}

pub struct SoccerMatch {
    pub config: MatchConfig,
    pub tick: u64,
    pub clock_seconds: f64,
    pub players: Vec<PlayerAgent>,
    pub officials: Vec<OfficialAgent>,
    pub ball: BallAgent,
    pub shared_positions: SharedPlayerPositions,
    pub score_home: u32,
    pub score_away: u32,
    pub stats: MatchStats,
    pub events: Vec<MatchEvent>,
    pub learning_transitions: Vec<SoccerLearningTransition>,
    pub tactical_summary: SoccerTacticalLearningSummary,
    pub learned_policy: Option<SoccerQPolicy>,
    pub team_policies: Option<SoccerTeamQPolicies>,
    /// HOME-team value/critic learner — and, when `away_neural_learner` is `None`,
    /// the *shared* learner for both teams (the historical single-net behavior).
    pub(crate) neural_learner: Option<SoccerNeuralLearner>,
    /// Optional dedicated AWAY-team value/critic learner. `None` (default) means
    /// the away team shares `neural_learner`, preserving the original shared-net
    /// dynamics exactly. `Some` enables true **per-team neural brains** — each
    /// team trains its own critic — which is what the tournament's bi-learning and
    /// frozen-opponent modes require so two distinct brains can be compared.
    pub(crate) away_neural_learner: Option<SoccerNeuralLearner>,
    /// Per-team training freeze. A frozen team's learner still serves predictions
    /// (so its brain plays) but receives no gradient updates — the frozen-opponent
    /// evaluation pattern. Only meaningful alongside a dedicated per-team learner.
    pub(crate) home_neural_frozen: bool,
    pub(crate) away_neural_frozen: bool,
    /// Per-team tactical genome (formation / press / pass / keeper style …). Both
    /// default to the neutral genome, which reproduces the original genome-agnostic
    /// behavior exactly; the tournament installs each side's evolved genome via
    /// [`SoccerMatch::set_team_tactical_genome`] so engine consumers can bias play
    /// by team. Each consumer reads it opt-in (see `genome_for`).
    pub(crate) home_genome: SoccerTeamGenome,
    pub(crate) away_genome: SoccerTeamGenome,
    /// Clock (seconds) when the defending keeper's current in-hands handling
    /// episode began, or `None` when no keeper is handling. Drives the no-steal
    /// protection and the release time limit (`GK_HANDLING_HOLD_LIMIT_SECONDS`).
    pub(crate) gk_handling_since_clock: Option<f64>,
    /// Ticks remaining in the post-goal celebration hold (0 = not celebrating).
    /// While >0, play is frozen with the ball in the net; on reaching 0 the kickoff
    /// is set up for `goal_celebration_kickoff_team` (the conceding side).
    pub(crate) goal_celebration_remaining_ticks: u32,
    pub(crate) goal_celebration_kickoff_team: Option<Team>,
    /// How the trained value head couples into live action selection. `Off` by
    /// default, so play is unchanged unless a run opts in via `with_neural_blend`.
    pub(crate) neural_blend: SoccerNeuralBlendConfig,
    /// The neural **actor set** `π(family|s, role, assigned-position)`, trained by
    /// advantage policy-gradient from the critic (the value head). Present only when
    /// the run opts into actor-critic (`neural_blend.actor_critic` + neural learning enabled).
    pub(crate) policy_head: Option<SoccerPolicyHead>,
    /// Independent pass/dribble/shot specialist actors over the shared actor features. Present
    /// only when the actor is active AND `DD_SOCCER_ENABLE_SKILL_POLICY_HEADS` is set; their
    /// log-probabilities refine technical action selection on top of the joint actor.
    pub(crate) skill_policy_heads: Option<SoccerSkillPolicyHeads>,
    /// Dedicated goalkeeper actor over the keeper action vocabulary, biasing the keeper's
    /// come-for-the-ball decision. Present only when the actor is active AND
    /// `DD_SOCCER_ENABLE_KEEPER_POLICY_HEAD` is set.
    pub(crate) keeper_policy_head: Option<SoccerKeeperPolicyHead>,
    /// Specialist-curriculum training-round counter: increments each actor training pass and drives
    /// [`soccer_specialist_curriculum_focus`] (pass → dribble → shot → GK → joint). Only consulted
    /// when `DD_SOCCER_ENABLE_SPECIALIST_CURRICULUM` is set.
    pub(crate) specialist_curriculum_round: usize,
    /// The learned **world model** `P̂(s'|s,a)` over the feature space, trained on
    /// consecutive transitions. Present only when `neural_blend.world_model` is on.
    pub(crate) world_model: Option<SoccerWorldModel>,
    pub human_inputs: SharedHumanInputs,
    /// Latched human movement per controller slot. Human input arrives intermittently
    /// (key events, one frame per /api/step) but the sim ticks many times between
    /// frames, so without latching an assigned player flickers back to the AI on the
    /// gap ticks. The latched axis is replayed every tick until a fresh input or a
    /// release (axis ~0) clears it. Commands (pass/shoot) are never latched.
    pub(crate) latched_human_inputs: HashMap<usize, HumanInputDrainResult>,
    /// Direct human-control directive `(player_id, unit-direction, pace tier)` staged
    /// for the player whose intent is being applied this tick, so a controlled player
    /// is driven responsively (tiered speed, hard brake on release) rather than through
    /// the AI movement model. Runtime-only; consumed in `apply_player_intent`.
    pub(crate) pending_human_control: Option<(usize, Vec2, u8)>,
    pub central_brain: CentralBrain,
    pub active_set_play: Option<SoccerSetPlayCall>,
    pub(crate) rng: SeededRandom,
    pub(crate) pending_pass: Option<PendingPass>,
    /// One-shot guard: set true for the duration of an `apply_restart` when the aerial-pass
    /// out-of-bounds penalty has already claimed the event (a qualifying long loft sailed out),
    /// so the generic [`Self::record_out_of_bounds_turnover_penalty`] defers instead of
    /// double-charging the same passer. Always cleared after the restart. Only ever true when
    /// `DD_SOCCER_ENABLE_AERIAL_PASS_OOB_DISCIPLINE` is on ⇒ baseline byte-identical.
    pub(crate) suppress_generic_oob_turnover: bool,
    pub(crate) pending_shot: Option<PendingShot>,
    pub(crate) pending_rebound: Option<PendingRebound>,
    /// Latched "live cross" window for the situational flank crash-the-box play: set when an
    /// aerial cross is released into the box under the recognizer, consumed to credit a headed
    /// finish (and the box-crash arrivals) back to the move. Runtime-only; `None` unless
    /// `DD_SOCCER_ENABLE_FLANK_CRASH_BOX` is on. See [`crash_box`].
    pub(crate) flank_crash_box_cross: Option<crash_box::FlankCrashBoxCross>,
    /// `(shooter, tick)` stamped when a shot is taken with the ball aerial in the heading band,
    /// so a goal on the same tick can be recognised as a headed finish. Runtime-only.
    pub(crate) pending_aerial_finish: Option<(usize, u64)>,
    pub(crate) coach_set_play_hints: HashMap<Team, SoccerSetPlayVectorHint>,
    pub(crate) reward_events: Vec<SoccerRewardEvent>,
    pub(crate) episode_learning_transitions: Vec<SoccerLearningTransition>,
    /// Per-tick whole-field configuration captures (ball carrier only) for the
    /// retrieval corpus. Populated only when `config.retrieval.capture_enabled`
    /// and joined with the retained transition stream by `(tick, player_id)` to
    /// attach the decision + n-step outcome in [`SoccerMatch::config_moments`].
    /// Empty (zero cost) when capture is off.
    pub(crate) episode_config_captures: Vec<SoccerConfigCapture>,
    /// Per-team retrieval action prior (action label → bounded favourability in
    /// `[-1, 1]`), set by the retrieval consumer from neighbours of the current
    /// configuration. Folded into the tabular action ranking, scaled by
    /// `config.retrieval.prior_weight`, only when `decision_prior_enabled`. Empty
    /// ⇒ no effect (byte-identical play). See [`SoccerMatch::set_retrieval_action_prior`].
    pub(crate) retrieval_action_prior: HashMap<Team, HashMap<String, f64>>,
    pub(crate) full_game_learning_applied: bool,
    pub(crate) full_game_learning_replay_transitions: usize,
    pub(crate) possession_chain: VecDeque<usize>,
    pub(crate) possession_chain_previous_touch_team: Option<Team>,
    pub(crate) completed_pass_chain: VecDeque<CompletedPassChainEntry>,
    /// Running tally of the CURRENT consecutive-completed-pass chain, finalised into
    /// [`MatchStats`] (chain count, total gained yards, chains ending in net loss) when the
    /// chain ends (turnover / dead ball / match end). Not serialised — it is transient match
    /// bookkeeping for the learning-progress metrics.
    pub(crate) pass_chain_meter: PassChainMeter,
    pub(crate) home_mpc_latent_objective: SoccerMpcLatentObjective,
    pub(crate) away_mpc_latent_objective: SoccerMpcLatentObjective,
    pub(crate) possession_progress_tracker: Option<PossessionProgressTracker>,
    /// The most recent player to touch the ball — a simple "who last touched it"
    /// reference used to enforce the no-double-touch rule on restarts.
    pub(crate) last_touch_player: Option<usize>,
    /// Stuck-ball watchdog: how long the ball has sat near `ball_stuck_anchor`
    /// without meaningfully moving (whether loose in a cluster or held by a player
    /// sitting on it). When it exceeds the limit the nearest player hoofs it clear.
    pub(crate) ball_stationary_ticks: u32,
    pub(crate) ball_stuck_anchor: Vec2,
    /// On a restart, the taker who may not touch the ball twice in a row; cleared
    /// once any other player touches it. (Held-restart already forces them to
    /// pass, so this is the explicit tracking/backstop.)
    pub(crate) restart_double_touch_guard: Option<usize>,
    /// Law 16 outcome enforcement: while a goal kick is in progress the ball must LEAVE
    /// the taking team's own penalty area before any teammate touches it. Holds
    /// `(taking_team, retake_spot)`; cleared the instant the ball exits the box (the kick
    /// is then legally in play). If a teammate brings the ball under control while it is
    /// still inside the box, the goal kick is retaken. Backs up the decision-level guard
    /// (which already steers the AI keeper to an out-of-box outlet) so the rule also holds
    /// for human takers, deflections, and mishit short kicks.
    pub(crate) goal_kick_must_clear_box: Option<(Team, Vec2)>,
    pub(crate) recent_learning_history: VecDeque<SoccerLearningTransition>,
    pub(crate) deferred_reward_transitions: Vec<SoccerLearningTransition>,
    /// Rolling window of pass-outcome training samples (config embedding + pass features captured
    /// at launch, labelled completed/intercepted at resolution). The substrate for learned pass
    /// completion; drained by the cluster learner to Postgres + [`SoccerPassCompletionHead`].
    pub(crate) pass_outcome_samples: Vec<SoccerPassOutcomeSample>,
    /// The learned pass-completion model, when present (trained from `pass_outcome_samples`).
    /// Set by the learner (carried + trained across games, seeded from the Postgres corpus) so
    /// the pass-quality assessor consumes it live; `None` ⇒ analytic completion estimate
    /// (parity). Shared into each [`WorldSnapshot`] via an `Arc` clone, mirroring
    /// [`Self::line_depth_head`].
    pub(crate) pass_completion_head: Option<std::sync::Arc<SoccerPassCompletionHead>>,
    /// The trained back-four line-depth head, when present. Set by the learner
    /// (carried + trained across games) so the line decision consumes it live; `None`
    /// ⇒ analytic seed. Shared into each [`WorldSnapshot`] via an `Arc` clone.
    pub(crate) line_depth_head: Option<std::sync::Arc<BackFourLineHead>>,
    /// Rolling RL training corpus for the line-depth heads (Gap 5): a state + the gap
    /// the line used + the windowed territorial reward. Collected only while a
    /// line-depth model is enabled (`collect_line_depth_rl_samples`); drained by the
    /// cluster learner. Empty + untouched in the default (gated-off) process.
    pub(crate) line_depth_samples: Vec<LineDepthSample>,
    /// Open line-depth decisions awaiting their windowed reward.
    pub(crate) pending_line_depth: Vec<PendingLineDepthDecision>,
    /// The trained loose-ball commit head (which player attacks a loose ball), when
    /// present. Carried + trained across games by the learner; `None` ⇒ analytic
    /// seed. Shared into each [`WorldSnapshot`] via an `Arc` clone.
    pub(crate) loose_ball_commit_head: Option<std::sync::Arc<LooseBallCommitHead>>,
    /// The trained attacking-spacing target head, when present. Carried + trained
    /// across games by the learner; `None` ⇒ analytic 5-8yd seed. Shared into each
    /// [`WorldSnapshot`] via an `Arc` clone so the off-ball ranker and LP floor read
    /// the same learned band.
    pub(crate) attack_spacing_head: Option<std::sync::Arc<AttackSpacingHead>>,
    /// Rolling RL corpus for the loose-ball commit head: per-candidate state + the
    /// commit action taken + the windowed possession/territorial reward. Collected
    /// only while the commit model is enabled; empty + untouched in the default process.
    pub(crate) loose_ball_commit_samples: Vec<LooseBallCommitSample>,
    /// Open loose-ball commit decisions awaiting their windowed reward.
    pub(crate) pending_loose_ball_commit: Vec<PendingLooseBallCommitDecision>,
    /// The trained receive-approach head (how far a receiver steps toward/away from an
    /// incoming ball), when present. Carried + trained across games by the learner;
    /// `None` ⇒ analytic seed. Shared into each [`WorldSnapshot`] via an `Arc` clone.
    pub(crate) receive_approach_head: Option<std::sync::Arc<ReceiveApproachHead>>,
    /// Rolling RL corpus for the receive-approach head: per-receiver state + the signed
    /// approach action taken + the windowed possession/territorial reward. Collected only
    /// while the model is enabled; empty + untouched in the default process.
    pub(crate) receive_approach_samples: Vec<ReceiveApproachSample>,
    /// Open receive-approach decisions awaiting their windowed reward.
    pub(crate) pending_receive_approach: Vec<PendingReceiveApproachDecision>,
    /// The trained long-pass run head (which attacker should break forward so a deep carrier
    /// can pick them out), when present. Carried + trained across games by the learner; `None`
    /// ⇒ the analytic `backfield_long_pass_run_invite_for` seed. Shared into each
    /// [`WorldSnapshot`] via an `Arc` clone.
    pub(crate) long_pass_run_head: Option<std::sync::Arc<LongPassRunHead>>,
    /// Rolling RL corpus for the long-pass run head: per-runner state + the run action taken +
    /// the windowed territorial reward. Collected only while the model is enabled
    /// (`collect_long_pass_run_rl_samples`); empty + untouched in the default process.
    pub(crate) long_pass_run_samples: Vec<LongPassRunSample>,
    /// Open long-pass run decisions awaiting their windowed reward.
    pub(crate) pending_long_pass_run: Vec<PendingLongPassRunDecision>,
    /// The trained aerial-reception control head (how high to attack a dropping lofted
    /// ball), when present. Carried + trained across games by the learner; `None` ⇒ the
    /// analytic seed. Shared into each [`WorldSnapshot`] via an `Arc` clone.
    pub(crate) aerial_reception_head: Option<std::sync::Arc<AerialReceptionControlHead>>,
    /// Rolling RL corpus for the aerial-reception head: the descent/contest context + the
    /// attack-height blend used + whether the ball was cleanly controlled. Collected only
    /// while the model is enabled; empty + untouched in the default process.
    pub(crate) aerial_reception_samples: Vec<AerialReceptionSample>,
    /// Open aerial receptions awaiting their control outcome.
    pub(crate) pending_aerial_reception: Vec<PendingAerialReception>,
    /// The trained shot-trigger value head (when to pull the trigger on a shot), when
    /// present. Carried + trained across games by the learner; `None` ⇒ the analytic
    /// seed. Shared into each [`WorldSnapshot`] via an `Arc` clone so the shot decision
    /// reads the same learned value.
    pub(crate) shot_trigger_head: Option<std::sync::Arc<ShotTriggerHead>>,
    /// Rolling RL corpus for the shot-trigger head: the shot-decision state + whether a
    /// shot was taken + the windowed reward. Collected only while the model is enabled
    /// (`collect_shot_trigger_rl_samples`); empty + untouched in the default process.
    pub(crate) shot_trigger_samples: Vec<ShotTriggerSample>,
    /// Open shot decisions awaiting their windowed reward.
    pub(crate) pending_shot_trigger: Vec<PendingShotTriggerDecision>,
    /// Tick at which the ball most recently became loose AND went uncontested (no
    /// player challenging it). `None` whenever the ball is held / contested. Drives
    /// the "no loose ball sits uncontested for >¼s" urgency override; carried into
    /// each [`WorldSnapshot`] so the retriever decision can read it.
    pub(crate) loose_ball_uncontested_since_tick: Option<u64>,
    /// Rolling RL training corpus for the learnable attacking-spacing target: a
    /// team-level context + the spacing held + the windowed territorial reward.
    /// Collected only while the spacing model is enabled
    /// (`collect_attack_spacing_rl_samples`); drained by the cluster learner. Empty +
    /// untouched in the default (gated-off) process.
    pub(crate) attack_spacing_samples: Vec<AttackSpacingSample>,
    /// Open attacking-spacing decisions awaiting their windowed reward.
    pub(crate) pending_attack_spacing: Vec<PendingAttackSpacingDecision>,
    /// Rolling ~5s window of recent learning transitions, evicted by tick-age. Maintained
    /// only while the turnover-window penalty is enabled, so a dispossession/interception
    /// can retroactively penalize the losing team's last-5s actions (`penalize_turnover_window`).
    pub(crate) turnover_penalty_history: VecDeque<SoccerLearningTransition>,
    /// De-dupes the windowed penalty when multiple turnover signals fire on one tick.
    pub(crate) last_turnover_penalty_tick: Option<u64>,
    /// Rolling ~10s window of recent "moving a lot" transitions awaiting their wasted-energy
    /// verdict, evicted by tick-age. Maintained only while the wasted-energy penalty is enabled.
    /// Each sample whose 10s lookahead closes with no ball touch is re-queued into
    /// `deferred_reward_transitions` with a tiny negative reward (`finalize_wasted_energy_window`).
    pub(crate) wasted_energy_history: VecDeque<WastedEnergySample>,
    /// Per-player tick of the most recent ball interaction (touch or holding it). A windowed
    /// energy sample at tick `t` is "wasted" iff this is `< t` when the 10s window closes.
    /// Maintained only while the wasted-energy penalty is enabled.
    pub(crate) player_last_ball_interaction_tick: HashMap<usize, u64>,
    /// Per-team (`[Home, Away]`, indexed by `team_index`) tick of the most recent genuine
    /// positive outcome — a won ball, shot, goal, beaten defender, or 2+ forward-pass
    /// sequence. The sustained-effort variant treats a windowed sprint as "paid off" when this
    /// is `>= ` the sample tick. Maintained only while that variant is enabled.
    pub(crate) team_last_positive_outcome_tick: [Option<u64>; 2],
    pub(crate) defensive_delay_clocks: HashMap<usize, f64>,
    pub(crate) defensive_beat_clocks: HashMap<usize, f64>,
    pub(crate) offside_clocks: HashMap<usize, f64>,
    /// Seconds each same-team field pair has continuously been within its
    /// minimum-spacing band (keyed by sorted `(id, id)`). Drives the "too close
    /// for too long → one of you move" notices. Ticked every match step in
    /// [`Self::update_teammate_spacing_proximity`].
    pub(crate) teammate_proximity_seconds: HashMap<(usize, usize), f64>,
    /// Spacing notices produced from `teammate_proximity_seconds` this tick;
    /// copied by value into every [`WorldSnapshot`] for the next tick's decisions.
    pub(crate) teammate_spacing_notices: Vec<TeammateSpacingNotice>,
    /// Territory-spacing clocks: continuous seconds each field player has spent inside
    /// the tight (`near`) and wider (`far`/minimum) teammate radius of its nearest
    /// teammate. Reset to zero the moment the pair separates. See the
    /// `TEAMMATE_SPACING_*` constants and [`Self::update_teammate_spacing_separation`].
    pub(crate) teammate_spacing_near_clocks: HashMap<usize, f64>,
    pub(crate) teammate_spacing_far_clocks: HashMap<usize, f64>,
    /// Players currently told to move because a spacing clock passed its grace window:
    /// `yielder id -> the teammate whose territory it must vacate`. Only the
    /// worse-positioned member of a too-close pair is entered here (the better-placed
    /// one holds its ground); both are "aware" via their running clocks.
    pub(crate) teammate_spacing_yield: HashMap<usize, usize>,
    pub(crate) defensive_clear_hold_trackers: HashMap<Team, DefensiveClearAndHoldTracker>,
    pub(crate) adversarial_moment_memory: VecDeque<SoccerMomentWindow>,
    pub(crate) adversarial_moment_index_cache: std::cell::RefCell<Option<SoccerMomentVectorIndex>>,
    pub(crate) adversarial_embedding_signal_cache:
        std::cell::RefCell<Option<CachedAdversarialEmbeddingSignals>>,
    pub(crate) retrieved_action_prior_cache: std::cell::RefCell<SoccerRetrievedActionPriorCache>,
    pub(crate) last_agent_schedule: Vec<AgentScheduleEntry>,
    pub(crate) controller_yield_stats: ControllerYieldStats,
    pub(crate) step_timing_stats: SoccerStepTimingStats,
    /// Most recent change of possession won via a tackle/steal. Used to break
    /// the 1v1 duel livelock: the player who just lost the ball cannot
    /// immediately re-win it from the new holder for a short grace window.
    pub(crate) recent_dispossession: Option<RecentDispossession>,
    /// The team that most recently held *controlled* possession (an actual ball
    /// holder), retained across loose-ball ticks. When controlled possession
    /// next lands with the *other* team without an intervening dead ball, that's
    /// an open-play turnover by this team and its recent actions are penalized.
    /// Cleared on every restart so a post-dead-ball touch (kickoff, throw-in,
    /// goal kick) is never mistaken for a turnover.
    pub(crate) last_controlled_possession_team: Option<Team>,
    /// Manual coaching position hints (drag-and-drop on the live UI), keyed by
    /// player id. Each steers the player to a dropped spot for a short window;
    /// see [`CoachPositionHint`] and [`Self::active_coach_hint_target`].
    pub(crate) coach_position_hints: HashMap<usize, CoachPositionHint>,
    /// Ring buffer of recent possession flips (steals), used by the ping-pong
    /// livelock detector to spot a ball cycling among a confined cluster of
    /// players and break it by squirting it loose to an uninvolved third man.
    pub(crate) possession_swaps: VecDeque<PossessionSwap>,
    /// Debug-only per-player ring buffers of each player's most recent DISTINCT
    /// MDP/POMDP decisions (appended only when the chosen action changes), for ALL
    /// 22 players — on-ball AND off-ball — captured only while
    /// `decision_trace_capture_enabled`. Powers the live UI's "Pause & Analyze"
    /// dump so a human can see exactly which state/options/action produced bad
    /// play, including why off-ball players (e.g. a striker) did or didn't attack.
    /// Each ring holds only the last `SOCCER_DECISION_TRACE_WINDOW_SECONDS` of a
    /// player's DISTINCT decisions, so it is negligible memory and zero work when
    /// capture is off. Player decisions only — the team brain is not captured
    /// here. Never serialized into the per-tick state frame.
    pub(crate) decision_trace_capture_enabled: bool,
    pub(crate) decision_trace_by_player: BTreeMap<usize, VecDeque<LiveDecisionTraceEntry>>,
    /// Tier-2 per-player Model Predictive Control controllers, created lazily for
    /// the active subset (ball carrier + players contesting near the ball) and
    /// retained across ticks so each controller's receding-horizon warm start
    /// persists (successive solves then converge in a handful of iterations).
    /// Empty and never touched unless `config.mpc.tier2_player_enabled`. Pure
    /// runtime state — never serialized into a frame.
    pub(crate) mpc_player_controllers:
        HashMap<usize, crate::des::general::mpc_point_mass::PlanarPointMassMpc>,
    /// Running tally of MDP↔MPC decision divergence and how reconciliation
    /// resolved it. Only updated while `config.mpc.reconcile_enabled`; otherwise
    /// stays at its zero default. Runtime telemetry — never serialized.
    pub(crate) mpc_reconcile_stats: SoccerMpcReconcileStats,
    /// Per-player Bayesian press belief (Beta-Bernoulli posterior over how readily each
    /// player steps into pass lanes), advanced each tick by
    /// [`Self::update_opponent_press_beliefs`] while `opponent_belief_enabled`. Empty (and
    /// never updated) when the feature is off, so pass-lane risk is byte-identical to the
    /// analytic-only path. Pure runtime state — never serialized.
    pub(crate) opponent_press_belief: HashMap<usize, OpponentPressBelief>,
    /// Per-player cross-tick decision/action carryover. This is the explicit continuity layer
    /// between successive [`Self::run_time_step`] calls: every POMDP observation can read the
    /// player's previous MDP state, belief summary, chosen action, action target, and MPC
    /// reconciliation summary without depending on transient `WorldSnapshot` instances.
    pub(crate) player_tick_carryover: HashMap<usize, SoccerPlayerTickCarryover>,
}

/// A just-completed dispossession, retained only long enough to suppress an
/// immediate reverse steal (the ping-pong that traps the ball between two
/// players in a 1v1).
#[derive(Clone, Copy, Debug)]
pub(crate) struct RecentDispossession {
    pub(crate) tick: u64,
    pub(crate) winner: usize,
    pub(crate) loser: usize,
    /// How long (ticks) the loser is blocked from winning it straight back. Starts
    /// at POSSESSION_REGAIN_GRACE_TICKS and escalates when the ball has been
    /// ping-ponging in this zone (a shielding winner holds it more securely).
    pub(crate) grace_ticks: u64,
}

/// A manual coaching hint placed by dragging a player on the live UI: "be here."
/// If the player's team had controlled possession at drop time it is a *receive*
/// hint (where to get open for a pass); otherwise it is a positioning hint (where
/// to stand on defense/offense). Applied as a movement override for a short
/// window so the dragged player goes to the spot without permanently fighting the
/// formation system.
#[derive(Clone, Copy, Debug)]
pub(crate) struct CoachPositionHint {
    pub(crate) target: Vec2,
    /// True when the hint means "get open here to receive a pass" (the player's
    /// team was on the ball when dropped); false for a plain positioning hint.
    pub(crate) receive: bool,
    /// The team that held controlled possession at drop time. A receive hint is
    /// dropped once this team no longer has the ball (you can't receive a pass
    /// your team isn't making).
    pub(crate) possession_team: Option<Team>,
    pub(crate) set_tick: u64,
}

/// One possession flip (a completed defensive dispossession), logged for the
/// ping-pong livelock detector: who won it from whom, when, and where.
#[derive(Clone, Copy)]
pub(crate) struct PossessionSwap {
    tick: u64,
    winner: usize,
    loser: usize,
    position: Vec2,
}

