    pub fn with_neural_network_snapshot(
        mut self,
        snapshot: SoccerNeuralNetworkSnapshot,
    ) -> Result<Self, String> {
        self.set_neural_network_snapshot(snapshot)?;
        Ok(self)
    }

    pub fn set_neural_network_snapshot(
        &mut self,
        snapshot: SoccerNeuralNetworkSnapshot,
    ) -> Result<(), String> {
        if !self.config.neural_learning.enabled {
            self.neural_learner = None;
            return Ok(());
        }
        let network = build_soccer_neural_network_from_snapshot(&snapshot)?;
        self.neural_learner = Some(SoccerNeuralLearner::from_pretrained_snapshot(
            &self.config,
            network,
            &snapshot,
        ));
        self.policy_head = if let Some(policy_head) = snapshot.policy_head.as_deref() {
            Some(soccer_policy_head_from_snapshot(
                policy_head,
                self.config.seed,
            )?)
        } else if self.neural_blend.actor_critic {
            Some(SoccerPolicyHead::new(self.config.seed))
        } else {
            None
        };
        Ok(())
    }

    /// Resolve the value/critic learner serving a given team. The away team falls
    /// back to the shared `neural_learner` when it has no dedicated learner, so
    /// single-net runs behave exactly as before.
    fn neural_learner_for(&self, team: Team) -> Option<&SoccerNeuralLearner> {
        match team {
            Team::Home => self.neural_learner.as_ref(),
            Team::Away => self
                .away_neural_learner
                .as_ref()
                .or(self.neural_learner.as_ref()),
        }
    }

    /// Mutable counterpart to [`neural_learner_for`]. Away resolves to its
    /// dedicated learner when present, else the shared `neural_learner`.
    fn neural_learner_for_mut(&mut self, team: Team) -> Option<&mut SoccerNeuralLearner> {
        match team {
            Team::Home => self.neural_learner.as_mut(),
            Team::Away => {
                if self.away_neural_learner.is_some() {
                    self.away_neural_learner.as_mut()
                } else {
                    self.neural_learner.as_mut()
                }
            }
        }
    }

    fn neural_team_frozen(&self, team: Team) -> bool {
        match team {
            Team::Home => self.home_neural_frozen,
            Team::Away => self.away_neural_frozen,
        }
    }

    /// Drop every neural brain (both teams) and clear freeze flags — used when
    /// learning is toggled off or the backend changes at runtime.
    fn clear_all_neural_learners(&mut self) {
        self.neural_learner = None;
        self.away_neural_learner = None;
        self.home_neural_frozen = false;
        self.away_neural_frozen = false;
    }

    /// True when this match runs distinct per-team neural brains (the away team
    /// has its own learner) rather than one shared net.
    pub fn has_per_team_neural_learners(&self) -> bool {
        self.away_neural_learner.is_some()
    }

    /// Latest trained value/critic snapshot for the shared/home learner. This is
    /// the small (KB-scale) artifact that is the *real* converging learner — the
    /// tabular Q-table is a weak, fast-bloating prior. Persisted to a sidecar so
    /// warm-start restores the net even when the tabular policy file exceeds the
    /// autoload byte cap.
    pub fn neural_network_snapshot(&self) -> Option<SoccerNeuralNetworkSnapshot> {
        self.neural_network_snapshot_for(Team::Home)
    }

    /// Latest trained value/critic snapshot for a specific team's brain. Used by
    /// the tournament to extract each competitor's learned net after a match.
    pub fn neural_network_snapshot_for(&self, team: Team) -> Option<SoccerNeuralNetworkSnapshot> {
        self.neural_learner_for(team).and_then(|learner| {
            learner.last_network_snapshot.clone().map(|mut snapshot| {
                // Stamp the learner's live training progress so a net loaded for inference (or
                // resumed for training) is recognised as already-warm by the decision-time value
                // blend, keeping serve consistent with train.
                snapshot.training_steps = learner.training_steps();
                snapshot.average_loss = learner.average_loss();
                if let Some(policy_head) = &self.policy_head {
                    snapshot.policy_head = Some(Box::new(soccer_policy_head_snapshot(policy_head)));
                }
                snapshot
            })
        })
    }

    /// Gradient steps a team's brain has taken — per-team learning progress for
    /// tournament telemetry. A frozen team stays at its inherited step count.
    pub fn neural_training_steps_for(&self, team: Team) -> usize {
        self.neural_learner_for(team)
            .map_or(0, |learner| learner.stats.training_steps)
    }

    /// Install a dedicated per-team neural brain from a snapshot, optionally
    /// frozen (served for predictions but never trained). Installing the away
    /// team's brain switches the match into per-team mode. A `None` snapshot
    /// starts that team from a fresh (untrained) net so it can learn from scratch.
    /// Install a team's evolved tactical genome. Defaults to the neutral genome
    /// (original behavior); the tournament calls this per side so engine consumers
    /// can read team-specific style (the genome rides along on `WorldSnapshot`).
    pub fn set_team_tactical_genome(&mut self, team: Team, mut genome: SoccerTeamGenome) {
        genome.sanitize();
        match team {
            Team::Home => self.home_genome = genome,
            Team::Away => self.away_genome = genome,
        }
        // Optionally let the (now-installed) genome's per-player grid anchors drive
        // each player's field-position affinity — see the gate's doc comment. Off by
        // default ⇒ home positions stay the hard-coded formation (byte-identical).
        if dd_soccer_enable_genome_anchor_home_positions() {
            self.apply_genome_anchor_home_positions(team);
        }
    }

    /// Re-anchor `team`'s players' home positions from the (sanitized, 11-slot) genome
    /// anchors on the 12×24 grid, so the grid is the single source of each player's
    /// field-position affinity — especially WIDTH, since `lane` is x and the existing
    /// role lane band keys off `home_position.x`.
    ///
    /// Two passes give a 1:1 anchor↔player mapping for ANY formation (Fix D):
    /// 1. Within each role, match same-role players to anchors left→right by lane,
    ///    preserving the natural layout (leftmost defender ↔ leftmost defender anchor).
    /// 2. Reconcile a genome whose role split differs from the spawned lineup (e.g. an
    ///    F433 genome — 3 mid / 3 fwd — against a 4-4-2 lineup): each still-unfilled
    ///    anchor takes the NEAREST unassigned outfield player and re-roles it to that
    ///    anchor's role. The keeper is always 1:1 and never reassigned. The result's
    ///    role counts therefore equal the genome's, and every anchor maps to a player.
    ///
    /// Runs at match setup (before kickoff), so it snaps current position + history to
    /// the new home too, keeping the opening shape consistent with the anchors.
    fn apply_genome_anchor_home_positions(&mut self, team: Team) {
        use crate::des::general::soccer_genome::GenomeRole;
        use std::cmp::Ordering::Equal;
        let width = self.config.field_width_yards;
        let length = self.config.field_length_yards;
        let anchors = match team {
            Team::Home => self.home_genome.anchors.clone(),
            Team::Away => self.away_genome.anchors.clone(),
        };
        let role_of = |role: GenomeRole| match role {
            GenomeRole::Goalkeeper => PlayerRole::Goalkeeper,
            GenomeRole::Defender => PlayerRole::Defender,
            GenomeRole::Midfielder => PlayerRole::Midfielder,
            GenomeRole::Forward => PlayerRole::Forward,
        };
        // Resolve each anchor to its (role, target home position) once.
        let targets: Vec<(PlayerRole, Vec2)> = anchors
            .iter()
            .map(|a| {
                (
                    role_of(a.role),
                    genome_anchor_home_position(a.lane, a.row, team, width, length),
                )
            })
            .collect();

        let mut assigned = vec![false; self.players.len()];
        let mut leftover_targets: Vec<(PlayerRole, Vec2)> = Vec::new();

        // Pass 1: same-role match, left→right by lane (target) / current home x (player).
        for role in [
            PlayerRole::Goalkeeper,
            PlayerRole::Defender,
            PlayerRole::Midfielder,
            PlayerRole::Forward,
        ] {
            let mut role_targets: Vec<Vec2> = targets
                .iter()
                .filter(|(r, _)| *r == role)
                .map(|(_, p)| *p)
                .collect();
            role_targets.sort_by(|a, b| a.x.partial_cmp(&b.x).unwrap_or(Equal));
            let mut role_players: Vec<usize> = self
                .players
                .iter()
                .enumerate()
                .filter(|(_, p)| p.team == team && p.role == role)
                .map(|(i, _)| i)
                .collect();
            role_players.sort_by(|&a, &b| {
                self.players[a]
                    .home_position
                    .x
                    .partial_cmp(&self.players[b].home_position.x)
                    .unwrap_or(Equal)
            });
            let shared = role_targets.len().min(role_players.len());
            for k in 0..shared {
                let pi = role_players[k];
                self.snap_player_home(pi, role_targets[k]);
                assigned[pi] = true;
            }
            for &target in role_targets.iter().skip(shared) {
                leftover_targets.push((role, target));
            }
        }

        // Pass 2: reconcile formation-shape differences (Fix D) — give each unfilled
        // anchor the nearest unassigned outfield player and re-role it.
        for (target_role, target_pos) in leftover_targets {
            let pick = self
                .players
                .iter()
                .enumerate()
                .filter(|(i, p)| {
                    !assigned[*i] && p.team == team && p.role != PlayerRole::Goalkeeper
                })
                .min_by(|(_, a), (_, b)| {
                    a.home_position
                        .distance(target_pos)
                        .partial_cmp(&b.home_position.distance(target_pos))
                        .unwrap_or(Equal)
                })
                .map(|(i, _)| i);
            if let Some(pi) = pick {
                self.players[pi].role = target_role;
                self.snap_player_home(pi, target_pos);
                assigned[pi] = true;
            }
        }
    }

    /// Snap a player to a new home: the affinity anchor plus the current position and
    /// history (so a setup-time re-anchor starts the player on its new home).
    fn snap_player_home(&mut self, player_index: usize, home: Vec2) {
        let player = &mut self.players[player_index];
        player.home_position = home;
        player.position = home;
        player.position_history = VecDeque::from([home]);
    }

    pub fn set_team_neural_brain(
        &mut self,
        team: Team,
        snapshot: Option<SoccerNeuralNetworkSnapshot>,
        frozen: bool,
    ) -> Result<(), String> {
        if !self.config.neural_learning.enabled {
            // Neural inference disabled for this match: nothing to install.
            match team {
                Team::Home => self.neural_learner = None,
                Team::Away => self.away_neural_learner = None,
            }
            return Ok(());
        }
        let learner = match snapshot {
            Some(snapshot) => {
                let network = build_soccer_neural_network_from_snapshot(&snapshot)?;
                SoccerNeuralLearner::from_pretrained_snapshot(&self.config, network, &snapshot)
            }
            None if self.config.learning_enabled => SoccerNeuralLearner::new(&self.config),
            None => {
                match team {
                    Team::Home => self.neural_learner = None,
                    Team::Away => self.away_neural_learner = None,
                }
                return Ok(());
            }
        };
        match team {
            Team::Home => {
                self.neural_learner = Some(learner);
                self.home_neural_frozen = frozen;
            }
            Team::Away => {
                self.away_neural_learner = Some(learner);
                self.away_neural_frozen = frozen;
            }
        }
        Ok(())
    }

