    fn sanitized_adversarial_moment_memory_limit(&self) -> usize {
        self.config
            .adversarial_embedding_memory_limit
            .min(MAX_ADVERSARIAL_MOMENT_MEMORY_LIMIT)
    }

    pub fn adversarial_moment_memory_len(&self) -> usize {
        self.adversarial_moment_memory.len()
    }

    pub fn remember_adversarial_moment_window(&mut self, window: SoccerMomentWindow) {
        if !self.config.adversarial_embedding_exploitation_enabled {
            return;
        }
        let limit = self.sanitized_adversarial_moment_memory_limit();
        let moment_id = window.summary.id.trim();
        if limit == 0 || window.feature_vector.is_empty() {
            return;
        }
        if moment_id.is_empty() {
            return;
        }
        if window.embedder_version != SOCCER_MOMENT_EMBEDDER_VERSION
            || !soccer_moment_feature_vector_is_valid(&window.feature_vector)
        {
            return;
        }
        self.adversarial_moment_memory
            .retain(|existing| existing.summary.id.trim() != moment_id);
        self.adversarial_moment_memory.push_back(window);
        while self.adversarial_moment_memory.len() > limit {
            self.adversarial_moment_memory.pop_front();
        }
        *self.adversarial_moment_index_cache.get_mut() = None;
        *self.adversarial_embedding_signal_cache.get_mut() = None;
        self.retrieved_action_prior_cache.get_mut().clear();
    }

    fn remember_adversarial_moment_records(&mut self, records: &[SoccerMomentStorageRecord]) {
        for record in records {
            self.remember_adversarial_moment_window(record.window.clone());
        }
    }

    fn adversarial_embedding_exploitation_active(&self) -> bool {
        // Exploiting a retrieved moment corpus to bias decisions is a DECISION-time
        // feature, gated by its own flag — it is independent of online TRAINING
        // (`learning_enabled`), so a live game running a frozen snapshot still uses it.
        self.config.adversarial_embedding_exploitation_enabled
            && self.sanitized_adversarial_moment_memory_limit() > 0
            && !self.adversarial_moment_memory.is_empty()
    }

    fn learned_policy_inference_enabled(&self) -> bool {
        self.config.learning_enabled
            || self.team_policies.is_some()
            || self.learned_policy.is_some()
    }

    fn neural_blend_readiness_for_learner(&self, learner: &SoccerNeuralLearner) -> f64 {
        let readiness = self
            .neural_blend
            .readiness(learner.training_steps(), learner.average_loss());
        if readiness > 0.0 {
            return readiness;
        }
        if !self.config.learning_enabled && learner.has_prediction_network() {
            1.0
        } else {
            0.0
        }
    }

    fn neural_blend_lambda_for_learner(&self, learner: &SoccerNeuralLearner) -> f64 {
        if !self.neural_blend.lambda.is_finite() || self.neural_blend.lambda <= 0.0 {
            return 0.0;
        }
        self.neural_blend.lambda * self.neural_blend_readiness_for_learner(learner)
    }

    fn with_adversarial_moment_index<R>(
        &self,
        f: impl FnOnce(&SoccerMomentVectorIndex) -> R,
    ) -> Option<R> {
        if !self.adversarial_embedding_exploitation_active() {
            *self.adversarial_moment_index_cache.borrow_mut() = None;
            return None;
        }
        let mut cache = self.adversarial_moment_index_cache.borrow_mut();
        if cache.is_none() {
            *cache = Some(SoccerMomentVectorIndex::from_window_iter(
                self.adversarial_moment_memory.iter(),
            ));
        }
        let index = cache.as_ref()?;
        if index.status().entries == 0 {
            return None;
        }
        Some(f(index))
    }

    fn adversarial_embedding_signals(&self) -> Option<SoccerAdversarialEmbeddingSignals> {
        if !self.adversarial_embedding_exploitation_active() {
            *self.adversarial_embedding_signal_cache.borrow_mut() = None;
            return None;
        }

        if let Some(cached) = *self.adversarial_embedding_signal_cache.borrow() {
            if self.tick.saturating_sub(cached.tick) < ADVERSARIAL_EMBEDDING_SIGNAL_REFRESH_TICKS {
                return cached.signals;
            }
        }

        let computed = self
            .with_adversarial_moment_index(|index| {
                let frame = tracking_frame_from_match(self);
                let mut signals = SoccerAdversarialEmbeddingSignals::default();
                for perspective_team in [Team::Home, Team::Away] {
                    let feature_vector = soccer_moment_feature_vector(
                        std::slice::from_ref(&frame),
                        perspective_team,
                        &self.config,
                    );
                    if feature_vector.is_empty() {
                        continue;
                    }
                    let bucket = soccer_moment_bucket_key(
                        "current_shape",
                        perspective_team,
                        &frame,
                        &self.config,
                    );
                    let response = index.search(&SoccerMomentIndexSearchRequest {
                        bucket,
                        feature_vector,
                        limit: ADVERSARIAL_EMBEDDING_SEARCH_LIMIT,
                        max_candidates: ADVERSARIAL_EMBEDDING_MAX_CANDIDATES
                            .min(self.adversarial_moment_memory.len().max(1)),
                        bucket_radius: ADVERSARIAL_EMBEDDING_BUCKET_RADIUS,
                        same_label_only: false,
                    });
                    for hit in response.results {
                        if hit.score < ADVERSARIAL_EMBEDDING_MIN_SCORE {
                            continue;
                        }
                        let score = ((hit.score - ADVERSARIAL_EMBEDDING_MIN_SCORE)
                            / (1.0 - ADVERSARIAL_EMBEDDING_MIN_SCORE))
                            .clamp(0.0, 1.0) as f64;
                        let contribution =
                            score * soccer_moment_adversarial_label_weight(&hit.summary.label);
                        if contribution <= 1e-9 {
                            continue;
                        }

                        let attack_signal = signals.signal_for_mut(perspective_team);
                        attack_signal.attack_score =
                            (attack_signal.attack_score + contribution).clamp(0.0, 1.0);
                        attack_signal.hits = attack_signal.hits.saturating_add(1);

                        let defense_signal = signals.signal_for_mut(perspective_team.other());
                        defense_signal.defense_score =
                            (defense_signal.defense_score + contribution).clamp(0.0, 1.0);
                        defense_signal.hits = defense_signal.hits.saturating_add(1);
                    }
                }

                if signals.home.hits == 0 && signals.away.hits == 0 {
                    None
                } else {
                    Some(signals)
                }
            })
            .flatten();

        *self.adversarial_embedding_signal_cache.borrow_mut() =
            Some(CachedAdversarialEmbeddingSignals {
                tick: self.tick,
                signals: computed,
            });
        computed
    }

    fn compute_retrieved_action_priors_for_team(&self, team: Team) -> Option<HashMap<String, f64>> {
        self.with_adversarial_moment_index(|index| {
            let frame = tracking_frame_from_match(self);
            let feature_vector =
                soccer_moment_feature_vector(std::slice::from_ref(&frame), team, &self.config);
            if feature_vector.is_empty() {
                return None;
            }
            let bucket = soccer_moment_bucket_key("current_shape", team, &frame, &self.config);
            let response = index.search(&SoccerMomentIndexSearchRequest {
                bucket,
                feature_vector,
                limit: ADVERSARIAL_EMBEDDING_ACTION_PRIOR_SEARCH_LIMIT,
                max_candidates: ADVERSARIAL_EMBEDDING_ACTION_PRIOR_MAX_CANDIDATES
                    .min(self.adversarial_moment_memory.len().max(1)),
                bucket_radius: ADVERSARIAL_EMBEDDING_BUCKET_RADIUS,
                same_label_only: false,
            });
            let mut weighted: HashMap<String, (f64, f64)> = HashMap::new();
            for hit in response.results {
                if hit.score < ADVERSARIAL_EMBEDDING_MIN_SCORE {
                    continue;
                }
                let similarity = ((hit.score - ADVERSARIAL_EMBEDDING_MIN_SCORE)
                    / (1.0 - ADVERSARIAL_EMBEDDING_MIN_SCORE))
                    .clamp(0.0, 1.0) as f64;
                if similarity <= 1e-9 {
                    continue;
                }
                let Some(window) = self
                    .adversarial_moment_memory
                    .iter()
                    .find(|window| window.summary.id == hit.summary.id)
                else {
                    continue;
                };
                for marker in &window.actions {
                    let action = normalize_soccer_action_label(&marker.action).to_string();
                    if action.is_empty() {
                        continue;
                    }
                    if !marker.reward.is_finite() {
                        continue;
                    }
                    let outcome =
                        (marker.reward / SOCCER_MOMENT_REPLAY_SHOT_REWARD).clamp(-1.0, 1.0);
                    let entry = weighted.entry(action).or_insert((0.0, 0.0));
                    entry.0 += similarity * outcome;
                    entry.1 += similarity;
                }
            }

            let priors = weighted
                .into_iter()
                .filter_map(|(action, (sum, weight))| {
                    (weight > 1e-9)
                        .then_some((action, (sum / weight) * SOCCER_RETRIEVAL_ACTION_PRIOR_SCALE))
                })
                .collect::<HashMap<_, _>>();
            (!priors.is_empty()).then_some(priors)
        })
        .flatten()
    }

    fn retrieved_action_priors_for_team(&self, team: Team) -> Option<HashMap<String, f64>> {
        if !self.adversarial_embedding_exploitation_active() {
            self.retrieved_action_prior_cache.borrow_mut().clear();
            return None;
        }

        let tick = self.tick;
        if let Some(priors) = {
            let mut cache = self.retrieved_action_prior_cache.borrow_mut();
            cache.reset_for_tick(tick);
            cache.slot(team).get()
        } {
            return priors;
        }

        let priors = self.compute_retrieved_action_priors_for_team(team);
        {
            let mut cache = self.retrieved_action_prior_cache.borrow_mut();
            cache.reset_for_tick(tick);
            cache.slot_mut(team).store(priors.clone());
        }
        priors
    }

    /// NN → LP coupling. Scores each team's most-recent transition with the
    /// gradient-trained critic and squashes the value into an attack/defense
    /// contribution. A positive critic value for a team's latest action-in-
    /// state means that team is well placed: it nudges *that* team's attack
    /// embedding up and the opponent's defense embedding up. The contribution
    /// is capped at [`SOCCER_NEURAL_LP_SIGNAL_CAP`] so a half-trained or noisy
    /// net can only ever apply a small, bounded bias to the whole-field LP.
    pub(crate) fn neural_lp_embedding_signals(&self) -> Option<SoccerAdversarialEmbeddingSignals> {
        if !self.config.neural_learning.enabled || !self.config.neural_learning.lp_coupling_enabled
        {
            return None;
        }
        let target_scale = self.config.neural_learning.sanitized_target_scale();
        let mut signals = SoccerAdversarialEmbeddingSignals::default();
        let mut any = false;
        for team in [Team::Home, Team::Away] {
            // Each team is scored by its own brain (away falls back to the shared
            // net in single-net runs).
            let Some(learner) = self.neural_learner_for(team) else {
                continue;
            };
            let Some(transition) = self
                .episode_learning_transitions
                .iter()
                .rev()
                .find(|transition| transition.team == team)
            else {
                continue;
            };
            let features = soccer_neural_transition_features(transition);
            let Some(value) = learner.predict_value(&features) else {
                continue;
            };
            // Squash into (-1, 1) about the critic's natural target scale, then
            // keep only the positive (favourable) half and cap it.
            let squashed = (value / target_scale).tanh();
            let favourable = squashed.max(0.0) * SOCCER_NEURAL_LP_SIGNAL_CAP;
            if favourable <= 1e-9 {
                continue;
            }
            let attack = signals.signal_for_mut(team);
            attack.attack_score = (attack.attack_score + favourable).clamp(0.0, 1.0);
            attack.hits = attack.hits.saturating_add(1);
            let defense = signals.signal_for_mut(team.other());
            defense.defense_score = (defense.defense_score + favourable).clamp(0.0, 1.0);
            defense.hits = defense.hits.saturating_add(1);
            any = true;
        }
        any.then_some(signals)
    }

    pub fn set_coach_set_play_hint(&mut self, mut hint: SoccerSetPlayVectorHint) {
        if !hint.score.is_finite() {
            return;
        }
        let Some(restart) = canonical_set_play_restart_label(&hint.restart) else {
            return;
        };
        hint.restart = restart.to_string();
        self.coach_set_play_hints.insert(hint.team, hint);
    }

    pub fn clear_coach_set_play_hint(&mut self, team: Team) {
        self.coach_set_play_hints.remove(&team);
    }

    pub fn stage_set_play_restart(
        &mut self,
        restart: SoccerSetPlayRestartKind,
        team: Team,
        spot: Vec2,
    ) {
        let (field_width, field_length) = sane_pitch_dimensions(
            self.config.field_width_yards,
            self.config.field_length_yards,
        );
        let center = Vec2::new(field_width * 0.5, field_length * 0.5);
        let spot = finite_pitch_point(spot, field_width, field_length, center);
        if let Some(kind) = restart.ball_restart_kind() {
            self.apply_restart_with_label(kind, team, spot, restart.as_label());
            return;
        }

        let kickoff = self
            .players
            .iter()
            .filter(|player| player.team == team)
            .min_by(|a, b| {
                a.position
                    .distance(center)
                    .partial_cmp(&b.position.distance(center))
                    .unwrap_or(std::cmp::Ordering::Equal)
            })
            .map(|player| player.id);
        self.arrange_kickoff_shape(team, kickoff, center);
        self.activate_set_play_for_restart(restart.as_label(), None, team, center, kickoff);
        self.ball.position = center;
        self.ball.velocity = Vec2::zero();
        self.ball.acceleration = Vec2::zero();
        self.ball.jerk = Vec2::zero();
        self.ball.curl_acceleration = Vec2::zero();
        self.ball.altitude_yards = 0.0;
        self.ball.holder = kickoff;
        self.ball.last_touch_team = Some(team);
        self.finish_possession_progress_chain(false);
        self.possession_chain.clear();
        self.possession_chain_previous_touch_team = None;
        self.completed_pass_chain.clear();
        if let Some(holder_id) = kickoff {
            self.mark_ball_received(holder_id);
            self.record_possession_touch(holder_id);
            // The kickoff taker may not touch the ball twice in a row: they must
            // play it to a teammate (held-restart release) before touching again.
            // Set AFTER record_possession_touch, which would otherwise clear it.
            self.restart_double_touch_guard = Some(holder_id);
        }
        self.ball.record_decision(self.tick, "kickoff", None);
        self.pending_pass = None;
        self.pending_shot = None;
        self.shared_positions.sync_from_players_and_ball(
            &self.players,
            &self.officials,
            &self.ball,
            self.tick,
            self.clock_seconds,
        );
        let taker = kickoff
            .and_then(|id| self.players.iter().find(|player| player.id == id))
            .map(|player| player.name.as_str())
            .unwrap_or("Kickoff");
        self.events.push(MatchEvent {
            tick: self.tick,
            clock_seconds: self.clock_seconds,
            kind: "kickoff".to_string(),
            team: Some(team),
            player_id: kickoff,
            description: format!("{taker} kickoff for {}", team.label()),
            ..MatchEvent::default()
        });
    }

    pub fn summary(&self) -> MatchSummary {
        // Include the still-open consecutive-pass chain (if any) so the final sequence of the
        // match is counted, without mutating live state — `summary` is a read-only view.
        let mut stats = self.stats.clone();
        stats.fold_pass_chain(&self.pass_chain_meter);
        MatchSummary {
            score_home: self.score_home,
            score_away: self.score_away,
            ticks: self.tick,
            simulated_seconds: self.clock_seconds,
            stats,
        }
    }

    pub fn match_clock(&self) -> SoccerMatchClock {
        let total_ticks = self.config.total_ticks();
        let total_seconds = self.config.effective_duration_seconds().max(0.0);
        let elapsed_seconds = self
            .clock_seconds
            .clamp(0.0, total_seconds.max(self.clock_seconds));
        let remaining_ticks = total_ticks.saturating_sub(self.tick);
        let remaining_seconds = (total_seconds - elapsed_seconds).max(0.0);
        let progress = if total_ticks > 0 {
            (self.tick as f64 / total_ticks as f64).clamp(0.0, 1.0)
        } else if total_seconds > 0.0 {
            (elapsed_seconds / total_seconds).clamp(0.0, 1.0)
        } else {
            1.0
        };
        SoccerMatchClock {
            tick: self.tick,
            total_ticks,
            dt_seconds: self.config.dt_seconds,
            elapsed_seconds,
            total_seconds,
            remaining_ticks,
            remaining_seconds,
            progress,
            done: self.is_done(),
        }
    }

    pub fn drain_neural_learning(&mut self, max_wait: Duration) {
        if let Some(learner) = &mut self.neural_learner {
            learner.drain_results_until_idle(max_wait);
        }
        if let Some(learner) = &mut self.away_neural_learner {
            learner.drain_results_until_idle(max_wait);
        }
    }

    pub fn learning_snapshot(&self) -> SoccerLearningSnapshot {
        self.learning_snapshot_with_neural_network(true)
    }

    pub fn learning_stats_snapshot(&self) -> SoccerLearningSnapshot {
        self.learning_snapshot_with_neural_network(false)
    }

    fn learning_snapshot_with_neural_network(
        &self,
        include_neural_network: bool,
    ) -> SoccerLearningSnapshot {
        let (
            shared_policy_entries,
            shared_policy_visits,
            shared_policy_target_entries,
            shared_policy_target_visits,
        ) = self
            .learned_policy
            .as_ref()
            .map(|policy| {
                (
                    policy.q_values.len(),
                    policy.visit_count(),
                    policy.target_values.len(),
                    policy.target_visit_count(),
                )
            })
            .unwrap_or((0, 0, 0, 0));
        let (
            home_policy_entries,
            home_policy_visits,
            home_policy_target_entries,
            home_policy_target_visits,
            away_policy_entries,
            away_policy_visits,
            away_policy_target_entries,
            away_policy_target_visits,
        ) = self
            .team_policies
            .as_ref()
            .map(|policies| {
                (
                    policies.home.q_values.len(),
                    policies.home.visit_count(),
                    policies.home.target_values.len(),
                    policies.home.target_visit_count(),
                    policies.away.q_values.len(),
                    policies.away.visit_count(),
                    policies.away.target_values.len(),
                    policies.away.target_visit_count(),
                )
            })
            .unwrap_or((0, 0, 0, 0, 0, 0, 0, 0));
        let neural_stats = self.neural_learner.as_ref().map(|learner| &learner.stats);

        SoccerLearningSnapshot {
            total_transitions: self.learning_transitions.len(),
            learning_enabled: self.config.learning_enabled,
            learning_logging_enabled: self.config.learning_logging_enabled,
            learning_interval_ticks: self.config.learning_interval_ticks.max(1),
            policy_train_max_transitions_per_tick: self
                .config
                .policy_train_max_transitions_per_tick
                .max(1),
            deferred_reward_transitions: self.deferred_reward_transitions.len(),
            full_game_learning_enabled: self.config.full_game_learning_enabled,
            full_game_learning_applied: self.full_game_learning_applied,
            full_game_learning_episode_transitions: self.episode_learning_transitions.len(),
            full_game_learning_replay_transitions: self.full_game_learning_replay_transitions,
            shared_policy_enabled: self.learned_policy.is_some(),
            shared_policy_entries,
            shared_policy_visits,
            shared_policy_target_entries,
            shared_policy_target_visits,
            team_policies_enabled: self.team_policies.is_some(),
            adversarial_learning_enabled: self.config.learning_enabled
                && self.team_policies.is_some(),
            adversarial_embedding_exploitation_enabled: self.config.learning_enabled
                && self.config.adversarial_embedding_exploitation_enabled,
            adversarial_embedding_memory_size: self.adversarial_moment_memory.len(),
            home_policy_entries,
            home_policy_visits,
            home_policy_target_entries,
            home_policy_target_visits,
            away_policy_entries,
            away_policy_visits,
            away_policy_target_entries,
            away_policy_target_visits,
            neural_learning_enabled: self.config.learning_enabled
                && self.config.neural_learning.enabled,
            neural_learning_backend: self.config.neural_learning.backend.as_str().to_string(),
            neural_learning_training_steps: neural_stats
                .map(|stats| stats.training_steps)
                .unwrap_or(0),
            neural_learning_samples: neural_stats.map(|stats| stats.samples).unwrap_or(0),
            neural_learning_pending_batches: neural_stats
                .map(|stats| stats.pending_batches)
                .unwrap_or(0),
            neural_learning_dropped_batches: neural_stats
                .map(|stats| stats.dropped_batches)
                .unwrap_or(0),
            neural_learning_replay_samples: neural_stats
                .map(|stats| stats.replay_samples)
                .unwrap_or(0),
            neural_learning_replay_capacity: neural_stats
                .map(|stats| stats.replay_capacity)
                .unwrap_or(0),
            neural_learning_parameter_count: neural_stats
                .map(|stats| stats.parameter_count)
                .unwrap_or(0),
            marl_learning_enabled: self.config.learning_enabled
                && self.config.neural_learning.marl_enabled(),
            marl_algorithm: self
                .config
                .neural_learning
                .marl_algorithm
                .as_str()
                .to_string(),
            marl_team_reward_weight: self
                .config
                .neural_learning
                .sanitized_marl_team_reward_weight(),
            marl_intermediate_reward_weight: self
                .config
                .neural_learning
                .sanitized_marl_intermediate_reward_weight(),
            mappo_enabled: self.config.learning_enabled
                && self.config.neural_learning.mappo_enabled()
                && self.neural_blend.actor_critic,
            mappo_clip_epsilon: self.config.neural_learning.sanitized_mappo_clip_epsilon(),
            mappo_team_reward_share: self
                .config
                .neural_learning
                .sanitized_mappo_team_reward_share(),
            neural_learning_target_clip: self.config.neural_learning.sanitized_target_clip(),
            neural_learning_snapshot_every_batches: self
                .config
                .neural_learning
                .sanitized_snapshot_every_batches(),
            neural_learning_last_loss: neural_stats.and_then(|stats| stats.last_loss),
            neural_learning_average_loss: neural_stats.and_then(|stats| stats.average_loss()),
            neural_network: if include_neural_network {
                self.neural_learner
                    .as_ref()
                    .and_then(|learner| learner.last_network_snapshot.clone())
            } else {
                None
            },
        }
    }

    pub fn team_policy_artifact(&self) -> SoccerTeamPolicyArtifact {
        let (
            home_options,
            away_options,
            home_entries,
            home_target_entries,
            home_action_probabilities,
            away_entries,
            away_target_entries,
            away_action_probabilities,
        ) = if let Some(policies) = &self.team_policies {
            (
                Some(policies.home.options.clone()),
                Some(policies.away.options.clone()),
                policies.home.entries(),
                policies.home.target_entries(),
                policies.home.action_probability_summaries(
                    SOCCER_POLICY_PROBABILITY_STATE_LIMIT,
                    SOCCER_POLICY_PROBABILITY_ACTION_LIMIT,
                ),
                policies.away.entries(),
                policies.away.target_entries(),
                policies.away.action_probability_summaries(
                    SOCCER_POLICY_PROBABILITY_STATE_LIMIT,
                    SOCCER_POLICY_PROBABILITY_ACTION_LIMIT,
                ),
            )
        } else {
            (
                None,
                None,
                Vec::new(),
                Vec::new(),
                Vec::new(),
                Vec::new(),
                Vec::new(),
                Vec::new(),
            )
        };

        SoccerTeamPolicyArtifact {
            config: self.config.clone(),
            summary: self.summary(),
            learning: self.learning_snapshot(),
            tactical_summary: self.tactical_summary.clone(),
            adversarial: self.team_policies.is_some(),
            home_options,
            away_options,
            home_entries,
            home_target_entries,
            home_action_probabilities,
            away_entries,
            away_target_entries,
            away_action_probabilities,
            events: self.events.clone(),
        }
    }

    pub fn team_policy_probability_summary(&self) -> SoccerPolicyProbabilitySummaryStatus {
        let Some(policies) = &self.team_policies else {
            return SoccerPolicyProbabilitySummaryStatus::default();
        };
        let home = policies.home.action_probability_summaries(
            SOCCER_POLICY_PROBABILITY_STATE_LIMIT,
            SOCCER_POLICY_PROBABILITY_ACTION_LIMIT,
        );
        let away = policies.away.action_probability_summaries(
            SOCCER_POLICY_PROBABILITY_STATE_LIMIT,
            SOCCER_POLICY_PROBABILITY_ACTION_LIMIT,
        );
        SoccerPolicyProbabilitySummaryStatus {
            home_states: home.len(),
            home_actions: home.iter().map(|summary| summary.actions.len()).sum(),
            away_states: away.len(),
            away_actions: away.iter().map(|summary| summary.actions.len()).sum(),
            home_top_action: home.first().and_then(|summary| summary.best_action.clone()),
            away_top_action: away.first().and_then(|summary| summary.best_action.clone()),
        }
    }

    pub fn team_policy_artifact_for_disk_request(
        &self,
        request: Option<&SoccerTeamPolicyDiskRequest>,
    ) -> SoccerTeamPolicyArtifact {
        let mut artifact = self.team_policy_artifact();
        let Some(request) = request.filter(|request| request.has_prune_limits()) else {
            return artifact;
        };
        let Some(mut policies) = self.team_policies.clone() else {
            return artifact;
        };

        policies.prune(
            request.max_action_entries_per_team,
            request.max_target_entries_per_team,
            request.min_visits,
        );

        artifact.home_options = Some(policies.home.options.clone());
        artifact.away_options = Some(policies.away.options.clone());
        artifact.home_entries = policies.home.entries();
        artifact.home_target_entries = policies.home.target_entries();
        artifact.home_action_probabilities = policies.home.action_probability_summaries(
            SOCCER_POLICY_PROBABILITY_STATE_LIMIT,
            SOCCER_POLICY_PROBABILITY_ACTION_LIMIT,
        );
        artifact.away_entries = policies.away.entries();
        artifact.away_target_entries = policies.away.target_entries();
        artifact.away_action_probabilities = policies.away.action_probability_summaries(
            SOCCER_POLICY_PROBABILITY_STATE_LIMIT,
            SOCCER_POLICY_PROBABILITY_ACTION_LIMIT,
        );
        artifact.learning.home_policy_entries = artifact.home_entries.len();
        artifact.learning.home_policy_visits = policies.home.visit_count();
        artifact.learning.home_policy_target_entries = artifact.home_target_entries.len();
        artifact.learning.home_policy_target_visits = policies.home.target_visit_count();
        artifact.learning.away_policy_entries = artifact.away_entries.len();
        artifact.learning.away_policy_visits = policies.away.visit_count();
        artifact.learning.away_policy_target_entries = artifact.away_target_entries.len();
        artifact.learning.away_policy_target_visits = policies.away.target_visit_count();
        artifact
    }

    pub fn import_team_policy_artifact(
        &mut self,
        artifact: SoccerTeamPolicyArtifact,
    ) -> Result<SoccerTeamPolicyImportResponse, String> {
        let policies = SoccerTeamQPolicies::from_artifact(&artifact)?;
        let imported_home_entries = policies.home.q_values.len();
        let imported_away_entries = policies.away.q_values.len();
        let imported_home_target_entries = policies.home.target_values.len();
        let imported_away_target_entries = policies.away.target_values.len();
        self.team_policies = Some(policies);
        Ok(SoccerTeamPolicyImportResponse {
            learning: self.learning_snapshot(),
            policy_probability: self.team_policy_probability_summary(),
            imported_home_entries,
            imported_away_entries,
            imported_home_target_entries,
            imported_away_target_entries,
        })
    }

    pub fn save_team_policy_artifact_to_path(
        &self,
        path: impl AsRef<Path>,
    ) -> Result<SoccerTeamPolicyDiskResponse, String> {
        self.save_team_policy_artifact_to_path_for_request(path, None)
    }

    pub fn save_team_policy_artifact_to_path_for_request(
        &self,
        path: impl AsRef<Path>,
        request: Option<&SoccerTeamPolicyDiskRequest>,
    ) -> Result<SoccerTeamPolicyDiskResponse, String> {
        let path = path.as_ref();
        let artifact = self.team_policy_artifact_for_disk_request(request);
        write_soccer_team_policy_artifact(path, &artifact)?;
        let policy_probability = team_policy_artifact_probability_summary(&artifact);
        Ok(SoccerTeamPolicyDiskResponse {
            path: path.display().to_string(),
            history_path: policy_history_disk_path(path).display().to_string(),
            learning: artifact.learning,
            policy_probability,
            home_policy_entries: artifact.home_entries.len(),
            away_policy_entries: artifact.away_entries.len(),
            home_policy_target_entries: artifact.home_target_entries.len(),
            away_policy_target_entries: artifact.away_target_entries.len(),
        })
    }

    pub fn load_team_policy_artifact_from_path(
        &mut self,
        path: impl AsRef<Path>,
    ) -> Result<SoccerTeamPolicyDiskResponse, String> {
        let path = path.as_ref();
        let artifact = read_soccer_team_policy_artifact(path)?;
        let imported = self.import_team_policy_artifact(artifact)?;
        let learning = imported.learning;
        Ok(SoccerTeamPolicyDiskResponse {
            path: path.display().to_string(),
            history_path: policy_history_disk_path(path).display().to_string(),
            policy_probability: imported.policy_probability,
            home_policy_entries: learning.home_policy_entries,
            away_policy_entries: learning.away_policy_entries,
            home_policy_target_entries: learning.home_policy_target_entries,
            away_policy_target_entries: learning.away_policy_target_entries,
            learning,
        })
    }

    pub fn import_self_play_training_artifact(
        &mut self,
        artifact: SoccerSelfPlayTrainingArtifact,
    ) -> Result<SoccerTeamPolicyImportResponse, String> {
        let policies = SoccerTeamQPolicies::from_self_play_artifact(&artifact)?;
        let imported_home_entries = policies.home.q_values.len();
        let imported_away_entries = policies.away.q_values.len();
        let imported_home_target_entries = policies.home.target_values.len();
        let imported_away_target_entries = policies.away.target_values.len();
        self.team_policies = Some(policies);
        Ok(SoccerTeamPolicyImportResponse {
            learning: self.learning_snapshot(),
            policy_probability: self.team_policy_probability_summary(),
            imported_home_entries,
            imported_away_entries,
            imported_home_target_entries,
            imported_away_target_entries,
        })
    }

    pub fn import_tracking_for_team_policy(
        &mut self,
        request: SoccerTrackingImportRequest,
    ) -> Result<SoccerTrackingImportResponse, String> {
        let source = if request.source.trim().is_empty() {
            "live-upload".to_string()
        } else {
            request.source.clone()
        };
        let format = tracking_import_format(&request);
        let tracking = match format.as_str() {
            "json" => soccer_tracking_dataset_from_json(&request.content),
            "jsonl" => {
                soccer_tracking_dataset_from_jsonl(&request.content, self.config.clone(), &source)
            }
            "csv" => {
                soccer_tracking_dataset_from_csv(&request.content, self.config.clone(), &source)
            }
            other => Err(format!("unsupported tracking import format {other}")),
        }?;
        let physics_smoke = soccer_tracking_physics_smoke_report(&tracking);
        if physics_smoke.violation_count > 0 && !request.allow_physics_warnings {
            let (
                imported_home_entries,
                imported_away_entries,
                imported_home_target_entries,
                imported_away_target_entries,
            ) = self
                .team_policies
                .as_ref()
                .map(|policies| {
                    (
                        policies.home.q_values.len(),
                        policies.away.q_values.len(),
                        policies.home.target_values.len(),
                        policies.away.target_values.len(),
                    )
                })
                .unwrap_or((0, 0, 0, 0));
            return Ok(SoccerTrackingImportResponse {
                learning: self.learning_stats_snapshot(),
                policy_probability: self.team_policy_probability_summary(),
                tracking_tactical_summary: SoccerTacticalLearningSummary::default(),
                source: tracking.source.clone(),
                format,
                frames: tracking.frames.len(),
                imported_transitions: 0,
                imported_home_entries,
                imported_away_entries,
                imported_home_target_entries,
                imported_away_target_entries,
                imported_neural_samples: 0,
                physics_smoke,
                training_skipped: true,
                physics_rejected: true,
                rejection_reason: Some(
                    "tracking physics warnings blocked policy training".to_string(),
                ),
            });
        }
        let dataset = tracking.to_learning_dataset()?;
        let tracking_tactical_summary =
            SoccerTacticalLearningSummary::from_transitions(&dataset.transitions);
        let (
            imported_home_entries,
            imported_away_entries,
            imported_home_target_entries,
            imported_away_target_entries,
        ) = {
            let policies = self
                .team_policies
                .get_or_insert_with(|| SoccerTeamQPolicies::new(SoccerQPolicyOptions::default()));
            policies.train_adversarial(&dataset.transitions);
            (
                policies.home.q_values.len(),
                policies.away.q_values.len(),
                policies.home.target_values.len(),
                policies.away.target_values.len(),
            )
        };
        let imported_neural_samples =
            if self.config.learning_enabled && self.config.neural_learning.enabled {
                let neural_samples = self.neural_training_samples_for(&dataset.transitions);
                let imported_neural_samples = neural_samples.len();
                self.train_neural_value_model(neural_samples);
                imported_neural_samples
            } else {
                0
            };
        let learning = self.learning_stats_snapshot();

        Ok(SoccerTrackingImportResponse {
            learning,
            policy_probability: self.team_policy_probability_summary(),
            tracking_tactical_summary,
            source: tracking.source.clone(),
            format,
            frames: tracking.frames.len(),
            imported_transitions: dataset.transitions.len(),
            imported_home_entries,
            imported_away_entries,
            imported_home_target_entries,
            imported_away_target_entries,
            imported_neural_samples,
            physics_smoke,
            training_skipped: false,
            physics_rejected: false,
            rejection_reason: None,
        })
    }

    pub fn import_moment_replay_records_for_team_policy(
        &mut self,
        source: String,
        raw_jsonl: &str,
        request: &SoccerMomentReplayImportRequest,
    ) -> Result<SoccerMomentReplayImportResponse, String> {
        let mut records = soccer_moment_records_from_jsonl(raw_jsonl)?;
        if request.limit > 0 && records.len() > request.limit {
            records = records.split_off(records.len() - request.limit);
        }
        let reward_scale = request
            .reward_scale
            .filter(|scale| scale.is_finite())
            .unwrap_or(1.0)
            .max(0.0);
        let replay_passes = request.passes.max(1);
        let dataset =
            soccer_moment_records_to_learning_dataset(&records, self.config.clone(), reward_scale)?;
        self.remember_adversarial_moment_records(&records);
        let policies = self
            .team_policies
            .get_or_insert_with(|| SoccerTeamQPolicies::new(SoccerQPolicyOptions::default()));
        for _ in 0..replay_passes {
            policies.train_adversarial(&dataset.transitions);
        }
        let imported_home_entries = policies.home.q_values.len();
        let imported_away_entries = policies.away.q_values.len();
        let imported_home_target_entries = policies.home.target_values.len();
        let imported_away_target_entries = policies.away.target_values.len();
        let learning = self.learning_stats_snapshot();

        Ok(SoccerMomentReplayImportResponse {
            learning,
            policy_probability: self.team_policy_probability_summary(),
            source,
            records: records.len(),
            imported_transitions: dataset.transitions.len(),
            replay_passes,
            reward_scale,
            imported_home_entries,
            imported_away_entries,
            imported_home_target_entries,
            imported_away_target_entries,
        })
    }

    pub fn is_done(&self) -> bool {
        self.tick >= self.config.total_ticks()
    }

    pub fn start_new_period(&mut self, period_number: usize, kickoff_team: Team) {
        let recovery_seconds = self.config.period_break_recovery_seconds.max(0.0);
        if recovery_seconds > 0.0 {
            for player in &mut self.players {
                let recovery =
                    MovementGait::Stand.fatigue_delta(player.skills.stamina, recovery_seconds);
                player.add_fatigue(recovery);
            }
        }
        self.events.push(MatchEvent {
            tick: self.tick,
            clock_seconds: self.clock_seconds,
            kind: "period-break".to_string(),
            team: None,
            player_id: None,
            description: format!("period {} complete", period_number.saturating_sub(1)),
            ..MatchEvent::default()
        });
        self.reset_after_goal(kickoff_team);
        self.events.push(MatchEvent {
            tick: self.tick,
            clock_seconds: self.clock_seconds,
            kind: "period-start".to_string(),
            team: Some(kickoff_team),
            player_id: self.ball.holder,
            description: format!(
                "period {period_number} kickoff for {}",
                kickoff_team.label()
            ),
            ..MatchEvent::default()
        });
    }

    pub fn controller_assignments(&self) -> Vec<ControllerAssignment> {
        let mut assignments = self
            .players
            .iter()
            .filter_map(|p| {
                p.controller_slot
                    .map(|controller_slot| ControllerAssignment {
                        controller_slot,
                        player_id: p.id,
                        player_name: p.name.clone(),
                        team: p.team,
                    })
            })
            .collect::<Vec<_>>();
        assignments.sort_by_key(|a| a.controller_slot);
        assignments
    }

    fn assigned_player_for_controller_slot(&self, controller_slot: usize) -> Option<usize> {
        self.players
            .iter()
            .find(|player| player.controller_slot == Some(controller_slot))
            .map(|player| player.id)
    }

    pub fn assign_controller_slot(
        &mut self,
        controller_slot: usize,
        player_id: Option<usize>,
    ) -> Result<bool, String> {
        let slot_count = self.config.human_slots();
        if controller_slot >= slot_count {
            let range = if slot_count == 0 {
                "no configured slots".to_string()
            } else {
                format!("configured slots 0..{}", slot_count - 1)
            };
            return Err(format!(
                "controller slot {controller_slot} is outside {range}"
            ));
        }

        let (target_idx, previous_target_slot) = if let Some(player_id) = player_id {
            let target_idx = self
                .players
                .iter()
                .position(|p| p.id == player_id)
                .ok_or_else(|| format!("player {player_id} does not exist"))?;
            (Some(target_idx), self.players[target_idx].controller_slot)
        } else {
            (None, None)
        };

        let current_slot_player = self.assigned_player_for_controller_slot(controller_slot);
        let changed = current_slot_player != player_id
            || previous_target_slot.is_some_and(|slot| slot != controller_slot);
        if !changed {
            return Ok(false);
        }

        for player in &mut self.players {
            if player.controller_slot == Some(controller_slot) {
                player.controller_slot = None;
            }
        }

        if let Some(target_idx) = target_idx {
            self.players[target_idx].controller_slot = Some(controller_slot);
        }
        self.human_inputs.clear_slot(controller_slot);
        self.latched_human_inputs.remove(&controller_slot);
        if let Some(previous_slot) = previous_target_slot.filter(|slot| *slot != controller_slot) {
            self.human_inputs.clear_slot(previous_slot);
            self.latched_human_inputs.remove(&previous_slot);
        }

        Ok(true)
    }

    pub fn clear_controller_assignments(&mut self) {
        for player in &mut self.players {
            player.controller_slot = None;
        }
        for controller_slot in 0..self.config.human_slots() {
            self.human_inputs.clear_slot(controller_slot);
        }
        self.latched_human_inputs.clear();
    }

    pub fn update_ball_surface(&mut self, request: SoccerBallSurfaceRequest) -> Result<(), String> {
        validate_ball_surface(
            request.ball_drag_per_tick,
            request.ball_air_resistance,
            request.ball_grass_resistance_yps2,
            request.ball_stop_speed_yps,
        )?;
        self.config.ball_drag_per_tick = request.ball_drag_per_tick;
        self.config.ball_air_resistance = request.ball_air_resistance;
        self.config.ball_grass_resistance_yps2 = request.ball_grass_resistance_yps2;
        self.config.ball_stop_speed_yps = request.ball_stop_speed_yps;
        Ok(())
    }

    pub fn update_learning_runtime(
        &mut self,
        request: SoccerLearningRuntimeRequest,
    ) -> Result<SoccerLearningRuntimeResponse, String> {
        if let Some(enabled) = request.learning_enabled {
            if self.config.learning_enabled != enabled {
                self.retrieved_action_prior_cache.get_mut().clear();
            }
            self.config.learning_enabled = enabled;
            if !enabled {
                self.config.neural_learning.enabled = false;
                self.clear_all_neural_learners();
            }
        }
        if let Some(enabled) = request.learning_logging_enabled {
            self.config.learning_logging_enabled = enabled;
        }
        if let Some(interval) = request.learning_interval_ticks {
            if interval == 0 {
                return Err("learningIntervalTicks must be at least 1".to_string());
            }
            self.config.learning_interval_ticks = interval;
        }
        if let Some(max_transitions) = request.policy_train_max_transitions_per_tick {
            if max_transitions == 0 {
                return Err("policyTrainMaxTransitionsPerTick must be at least 1".to_string());
            }
            self.config.policy_train_max_transitions_per_tick = max_transitions;
        }
        if let Some(enabled) = request.neural_learning_enabled {
            self.config.neural_learning.enabled = enabled && self.config.learning_enabled;
            if !self.config.neural_learning.enabled {
                self.clear_all_neural_learners();
            }
        }
        if let Some(backend) = request.neural_learning_backend {
            if self.config.neural_learning.backend != backend {
                self.config.neural_learning.backend = backend;
                self.clear_all_neural_learners();
            }
        }
        Ok(SoccerLearningRuntimeResponse {
            config: self.config.clone(),
            learning: self.learning_stats_snapshot(),
        })
    }

    pub(crate) fn learned_action_for_player(
        &self,
        snapshot: &WorldSnapshot,
        player_id: usize,
    ) -> Option<SoccerLearnedPlan> {
        let mdp_state = snapshot.mdp_state_for_player(player_id);
        let observation = snapshot.observation_for(player_id);
        self.learned_action_for_player_with_context(snapshot, player_id, &mdp_state, &observation)
            .map(|decision| decision.plan)
    }

    fn policy_rank_selection_draw(
        &self,
        snapshot: &WorldSnapshot,
        player_id: usize,
        salt: u64,
    ) -> f64 {
        soccer_policy_rank_draw(self.config.seed, snapshot.tick, player_id, salt)
    }

    fn weighted_ranked_action_choice(
        ranked: &[SoccerLearnedActionTrace],
        draw: f64,
    ) -> Option<SoccerPolicyActionChoice> {
        let candidate_count = ranked
            .iter()
            .filter(|action| action.legal)
            .take(POLICY_SELECTION_TOP_RANK_LIMIT)
            .count();
        if candidate_count == 0 {
            return None;
        }
        let selected_rank = soccer_policy_weighted_rank_index(candidate_count, draw);
        ranked
            .iter()
            .filter(|action| action.legal)
            .nth(selected_rank)
            .map(|action| SoccerPolicyActionChoice {
                label: action.label.clone(),
                behavior_probability: soccer_policy_rank_probability(
                    candidate_count,
                    selected_rank,
                ),
            })
    }

    fn weighted_scored_candidate_choice(
        candidates: &[SoccerNeuralMctsCandidate],
        draw: f64,
    ) -> Option<SoccerPolicyActionChoice> {
        let candidate_count = candidates.len().min(POLICY_SELECTION_TOP_RANK_LIMIT);
        if candidate_count == 0 {
            return None;
        }
        let selected_rank = soccer_policy_weighted_rank_index(candidate_count, draw);
        candidates
            .get(selected_rank)
            .map(|candidate| SoccerPolicyActionChoice {
                label: candidate.label.clone(),
                behavior_probability: soccer_policy_rank_probability(
                    candidate_count,
                    selected_rank,
                ),
            })
    }

    fn apply_retrieval_prior_to_policy_actions(
        ranked: &mut [SoccerLearnedActionTrace],
        retrieval_prior: Option<(&std::collections::HashMap<String, f64>, f64)>,
    ) {
        if let Some((prior, weight)) =
            retrieval_prior.filter(|(p, w)| !p.is_empty() && w.is_finite() && *w != 0.0)
        {
            for candidate in ranked.iter_mut().filter(|candidate| candidate.legal) {
                candidate.value += weight
                    * prior
                        .get(normalize_soccer_action_label(&candidate.label))
                        .copied()
                        .unwrap_or(0.0);
            }
            ranked.sort_by(|a, b| {
                b.legal
                    .cmp(&a.legal)
                    .then_with(|| b.value.total_cmp(&a.value))
                    .then_with(|| b.visits.cmp(&a.visits))
                    .then_with(|| a.label.cmp(&b.label))
            });
        }
    }

    fn weighted_policy_action_probability_for_player(
        &self,
        policy: &SoccerQPolicy,
        snapshot: &WorldSnapshot,
        player_id: usize,
        mdp_state: &SoccerMdpState,
        observation: &SoccerPomdpObservation,
        retrieval_prior: Option<(&std::collections::HashMap<String, f64>, f64)>,
        action_label: &str,
    ) -> f64 {
        let Some((_, mut ranked)) = policy.ranked_action_values_for_snapshot(
            snapshot,
            player_id,
            SOCCER_RETRIEVAL_PRIOR_RERANK_LIMIT.max(POLICY_SELECTION_TOP_RANK_LIMIT),
        ) else {
            return policy
                .best_action_for_state_observation_with_prior(
                    snapshot,
                    player_id,
                    mdp_state,
                    observation,
                    retrieval_prior,
                )
                .filter(|label| {
                    normalize_soccer_action_label(label)
                        == normalize_soccer_action_label(action_label)
                })
                .map(|_| 1.0)
                .unwrap_or(0.0);
        };
        Self::apply_retrieval_prior_to_policy_actions(&mut ranked, retrieval_prior);
        let probability = soccer_policy_rank_probability_for_label(&ranked, action_label);
        if probability > 0.0 {
            return probability;
        }
        policy
            .best_action_for_state_observation_with_prior(
                snapshot,
                player_id,
                mdp_state,
                observation,
                retrieval_prior,
            )
            .filter(|label| {
                normalize_soccer_action_label(label) == normalize_soccer_action_label(action_label)
            })
            .map(|_| 1.0)
            .unwrap_or(0.0)
    }

    fn weighted_policy_action_for_player(
        &self,
        policy: &SoccerQPolicy,
        snapshot: &WorldSnapshot,
        player_id: usize,
        mdp_state: &SoccerMdpState,
        observation: &SoccerPomdpObservation,
        retrieval_prior: Option<(&std::collections::HashMap<String, f64>, f64)>,
        salt: u64,
    ) -> Option<SoccerPolicyActionChoice> {
        let draw = self.policy_rank_selection_draw(snapshot, player_id, salt);
        let (_, mut ranked) = policy.ranked_action_values_for_snapshot(
            snapshot,
            player_id,
            SOCCER_RETRIEVAL_PRIOR_RERANK_LIMIT.max(POLICY_SELECTION_TOP_RANK_LIMIT),
        )?;
        Self::apply_retrieval_prior_to_policy_actions(&mut ranked, retrieval_prior);
        Self::weighted_ranked_action_choice(&ranked, draw).or_else(|| {
            policy
                .best_action_for_state_observation_with_prior(
                    snapshot,
                    player_id,
                    mdp_state,
                    observation,
                    retrieval_prior,
                )
                .map(|label| SoccerPolicyActionChoice {
                    label,
                    behavior_probability: 1.0,
                })
        })
    }

    fn learned_action_for_player_with_context(
        &self,
        snapshot: &WorldSnapshot,
        player_id: usize,
        mdp_state: &SoccerMdpState,
        observation: &SoccerPomdpObservation,
    ) -> Option<SoccerLearnedDecisionPlan> {
        let player = snapshot.players.iter().find(|p| p.id == player_id)?;
        // Retrieval action prior for this player's team (empty/None unless the
        // consumer installed one and `decision_prior_enabled`). `Option<(&map, w)>`
        // is `Copy`, so the same prior is shared by both decision branches below.
        let retrieval_prior = if self.config.retrieval.decision_prior_enabled {
            self.retrieval_action_prior
                .get(&player.team)
                .filter(|map| !map.is_empty())
                .map(|map| (map, self.config.retrieval.prior_weight))
        } else {
            None
        };
        if let Some(team_policies) = &self.team_policies {
            let policy = team_policies.policy(player.team);
            if let Some(choice) = self
                .neural_blended_action(
                    policy,
                    snapshot,
                    player_id,
                    mdp_state,
                    observation,
                    player.team,
                    player.role,
                    SOCCER_POLICY_RANK_SALT_TEAM_NEURAL,
                )
                .or_else(|| {
                    self.exploration_action_for_player(
                        policy,
                        snapshot,
                        player_id,
                        mdp_state,
                        observation,
                        retrieval_prior,
                    )
                })
                .or_else(|| {
                    self.weighted_policy_action_for_player(
                        policy,
                        snapshot,
                        player_id,
                        mdp_state,
                        observation,
                        retrieval_prior,
                        SOCCER_POLICY_RANK_SALT_TEAM_TABULAR,
                    )
                })
            {
                return Some(SoccerLearnedDecisionPlan {
                    plan: Self::mpc_reconciled_learned_plan_for_policy(
                        policy,
                        snapshot,
                        player_id,
                        choice.label,
                    ),
                    behavior_probability: choice.behavior_probability,
                });
            }
        }
        let learned_policy = self.learned_policy.as_ref()?;
        self.neural_blended_action(
            learned_policy,
            snapshot,
            player_id,
            mdp_state,
            observation,
            player.team,
            player.role,
            SOCCER_POLICY_RANK_SALT_SHARED_NEURAL,
        )
        .or_else(|| {
            self.exploration_action_for_player(
                learned_policy,
                snapshot,
                player_id,
                mdp_state,
                observation,
                retrieval_prior,
            )
        })
        .or_else(|| {
            self.weighted_policy_action_for_player(
                learned_policy,
                snapshot,
                player_id,
                mdp_state,
                observation,
                retrieval_prior,
                SOCCER_POLICY_RANK_SALT_SHARED_TABULAR,
            )
        })
        .map(|choice| SoccerLearnedDecisionPlan {
            plan: Self::mpc_reconciled_learned_plan_for_policy(
                learned_policy,
                snapshot,
                player_id,
                choice.label,
            ),
            behavior_probability: choice.behavior_probability,
        })
    }

    fn stamp_learned_policy_behavior_probability(
        player: &mut PlayerAgent,
        behavior_probability: f64,
    ) {
        let Some(decision) = player.last_decision.as_mut() else {
            return;
        };
        stamp_learned_policy_behavior_probability_on_decision(decision, behavior_probability);
    }

    /// Build a feature-only decision-time transition: the player's real
    /// state/observation/team/role, with neutral defaults for the post-action
    /// fields the value-head feature builder reads (those sit at the same
    /// fallbacks the training path uses when a field is absent). `action` is left
    /// empty for the caller to set per candidate; `belief` and `next_*` are not
    /// read by the feature builder and carry placeholders.
    fn neural_decision_transition(
        &self,
        snapshot: &WorldSnapshot,
        player_id: usize,
        team: Team,
        role: PlayerRole,
        mdp_state: &SoccerMdpState,
        observation: &SoccerPomdpObservation,
    ) -> SoccerLearningTransition {
        SoccerLearningTransition {
            tick: snapshot.tick,
            player_id,
            team,
            role,
            state: mdp_state.clone(),
            observation: observation.clone(),
            belief: BeliefState {
                possession_confidence: 0.0,
                pressure: 0.0,
                pass_lane_open: 0.0,
                shot_quality: 0.0,
            },
            action: String::new(),
            action_target: None,
            decision_context: soccer_decision_context_for(
                player_id, team, "", None, snapshot, snapshot,
            ),
            tactical_trace: SoccerTacticalLearningTrace::default(),
            reward: 0.0,
            next_state: mdp_state.clone(),
            next_observation: observation.clone(),
            done: false,
        }
    }

    fn neural_mcts_action_from_candidates(
        blend: SoccerNeuralBlendConfig,
        candidates: &[SoccerNeuralMctsCandidate],
        draw: f64,
    ) -> Option<SoccerPolicyActionChoice> {
        if !blend.mcts_enabled {
            return None;
        }
        let candidate_count = blend.sanitized_mcts_candidates().min(candidates.len());
        if candidate_count < 2 {
            return None;
        }
        let simulations = blend.sanitized_mcts_simulations();
        let exploration = blend.sanitized_mcts_exploration();
        let candidates = &candidates[..candidate_count];
        let min_score = candidates
            .iter()
            .map(|candidate| candidate.score)
            .fold(f64::INFINITY, f64::min);
        let max_score = candidates
            .iter()
            .map(|candidate| candidate.score)
            .fold(f64::NEG_INFINITY, f64::max);
        if !min_score.is_finite() || !max_score.is_finite() {
            return None;
        }
        let score_span = (max_score - min_score).abs();
        let mut raw_priors = Vec::with_capacity(candidate_count);
        let mut prior_sum = 0.0;
        for (index, candidate) in candidates.iter().enumerate() {
            let rank_floor = 0.05 / (index as f64 + 1.0);
            let candidate_prior = if candidate.prior.is_finite() {
                candidate.prior.max(0.0)
            } else {
                0.0
            };
            let raw = candidate_prior + rank_floor;
            raw_priors.push(raw);
            prior_sum += raw;
        }
        let uniform_prior = 1.0 / candidate_count as f64;
        let mut nodes = candidates
            .iter()
            .zip(raw_priors.iter())
            .map(|(candidate, raw_prior)| {
                let value_estimate = if score_span > 1e-9 {
                    (((candidate.score - min_score) / score_span) * 2.0 - 1.0).clamp(-1.0, 1.0)
                } else {
                    0.0
                };
                SoccerNeuralMctsNode {
                    label: candidate.label.clone(),
                    raw_score: candidate.score,
                    value_estimate,
                    prior: if prior_sum > 1e-9 {
                        raw_prior / prior_sum
                    } else {
                        uniform_prior
                    },
                    q_visits: candidate.q_visits,
                    search_visits: 0,
                    total_value: 0.0,
                }
            })
            .collect::<Vec<_>>();

        for _ in 0..simulations {
            let total_visits = nodes
                .iter()
                .map(|node| f64::from(node.search_visits))
                .sum::<f64>()
                .max(1.0);
            let sqrt_total = total_visits.sqrt();
            let mut best_index = 0usize;
            let mut best_puct = f64::NEG_INFINITY;
            for (index, node) in nodes.iter().enumerate() {
                let exploit = node.mean_value();
                let explore =
                    exploration * node.prior * sqrt_total / (1.0 + f64::from(node.search_visits));
                let puct = exploit + explore;
                let replace = puct
                    .total_cmp(&best_puct)
                    .then_with(|| node.raw_score.total_cmp(&nodes[best_index].raw_score))
                    .then_with(|| nodes[best_index].q_visits.cmp(&node.q_visits))
                    .is_gt();
                if replace {
                    best_index = index;
                    best_puct = puct;
                }
            }
            let rollout_value = nodes[best_index].value_estimate;
            nodes[best_index].total_value += rollout_value;
            nodes[best_index].search_visits = nodes[best_index].search_visits.saturating_add(1);
        }

        nodes.sort_by(|a, b| {
            b.search_visits
                .cmp(&a.search_visits)
                .then_with(|| b.mean_value().total_cmp(&a.mean_value()))
                .then_with(|| b.raw_score.total_cmp(&a.raw_score))
                .then_with(|| a.q_visits.cmp(&b.q_visits))
                .then_with(|| a.label.cmp(&b.label))
        });
        let candidate_count = nodes.len().min(POLICY_SELECTION_TOP_RANK_LIMIT);
        if candidate_count == 0 {
            return None;
        }
        let selected_rank = soccer_policy_weighted_rank_index(candidate_count, draw);
        nodes
            .get(selected_rank)
            .map(|node| SoccerPolicyActionChoice {
                label: node.label.clone(),
                behavior_probability: soccer_policy_rank_probability(
                    candidate_count,
                    selected_rank,
                ),
            })
    }

    fn neural_mcts_model_rollout_value(
        &self,
        learner: Option<&SoccerNeuralLearner>,
        transition: &SoccerLearningTransition,
        target_scale: f64,
        depth: usize,
        gamma: f64,
    ) -> f64 {
        if depth <= 1 {
            return 0.0;
        }
        let Some(world_model) = self.world_model.as_ref() else {
            return 0.0;
        };
        let Some(learner) = learner else {
            return 0.0;
        };
        let mut features = soccer_neural_transition_features(transition);
        let mut discount = gamma.clamp(0.0, 0.999);
        let mut value = 0.0;
        // Bound each rolled-out critic value to the critic's training-target range. The
        // world model is fed its own prediction recursively, so an early/diverging model
        // can drive the features off-distribution and make the critic extrapolate to a huge
        // value that would dominate `model_bonus` and corrupt selection. Outputs already in
        // range are untouched; this only trims pathological extrapolation.
        let value_clip = self.config.neural_learning.sanitized_target_clip();
        for _ in 1..depth {
            let Some(predicted) = world_model.predict_next(&features) else {
                break;
            };
            let Some(predicted_value) = learner.predict_value(&predicted) else {
                break;
            };
            let predicted_value = predicted_value.clamp(-value_clip, value_clip);
            value += discount * predicted_value * target_scale;
            features = predicted;
            discount *= gamma.clamp(0.0, 0.999);
        }
        value
    }

    /// Re-rank legal tabular candidates with the trained value head per
    /// `neural_blend`, then supplement from the fixed neural action vocabulary
    /// when a warmed critic exists. That lets the 22+ball kinematic critic
    /// de-alias sparse Q buckets without letting an untrained net into play.
    fn neural_blended_action(
        &self,
        policy: &SoccerQPolicy,
        snapshot: &WorldSnapshot,
        player_id: usize,
        mdp_state: &SoccerMdpState,
        observation: &SoccerPomdpObservation,
        team: Team,
        role: PlayerRole,
        rank_salt: u64,
    ) -> Option<SoccerPolicyActionChoice> {
        let blend = self.neural_blend;
        let value_active = blend.mode != SoccerNeuralBlendMode::Off;
        let actor_requested = blend.actor_critic && self.policy_head.is_some();
        let retrieval_priors = self.retrieved_action_priors_for_team(team);
        let retrieval_active = retrieval_priors
            .as_ref()
            .is_some_and(|priors| !priors.is_empty());
        if !value_active && !actor_requested && !retrieval_active {
            return None;
        }
        // Decisions are scored by the deciding player's own team brain. Retrieval
        // can still rerank tabular candidates before the neural learner is warm.
        let learner = if value_active || actor_requested {
            self.neural_learner_for(team)
                .filter(|learner| learner.has_prediction_network())
        } else {
            None
        };
        let actor_active = actor_requested && learner.is_some();
        // Value-blend weight (ramped); 0 when the value blend is off or still cold.
        let lambda = if value_active {
            learner
                .map(|learner| self.neural_blend_lambda_for_learner(learner))
                .unwrap_or(0.0)
        } else {
            0.0
        };
        if lambda <= 0.0 && !actor_active && !retrieval_active {
            // Value head not ready and no actor/retrieval prior: let tabular decide.
            return None;
        }
        let (_state, ranked) = policy.ranked_action_values_for_snapshot(
            snapshot,
            player_id,
            blend.candidates.max(2),
        )?;
        let mut legal: Vec<SoccerLearnedActionTrace> =
            ranked.into_iter().filter(|action| action.legal).collect();

        // The value head trains on `(reward + γ·max_next) / target_scale`; undo the
        // scale so neural value lands in the same Q units as the tabular values.
        let target_scale = self.config.neural_learning.sanitized_target_scale();
        let best_tabular = legal
            .iter()
            .map(|action| action.value)
            .fold(f64::NEG_INFINITY, f64::max);

        let mut base = self.neural_decision_transition(
            snapshot,
            player_id,
            team,
            role,
            mdp_state,
            observation,
        );

        // Actor: π(family|s). Computed once from state features (null action), then
        // added as a log-probability bonus to each candidate's family. The action
        // dims are constant across candidates, so this is a pure function of state.
        let (policy_log_probs, skill_log_probs): (Option<Vec<f64>>, Option<SoccerSkillLogProbs>) =
            if actor_active {
                base.action = String::new();
                let state_features = self.policy_state_features(&base);
                let joint = self
                    .policy_head
                    .as_ref()
                    .and_then(|head| head.action_distribution(&state_features))
                    .map(|dist| dist.iter().map(|&p| p.max(1e-8).ln()).collect());
                // Specialist skill log-probs (pass/dribble/shot) over the same shared features.
                let skill = if dd_soccer_enable_skill_policy_heads() {
                    self.skill_policy_heads
                        .as_ref()
                        .map(|heads| heads.log_probs(&state_features))
                } else {
                    None
                };
                (joint, skill)
            } else {
                (None, None)
            };

        // Tactical look-ahead (AlphaZero/MuZero-style planning): when a run opts in via
        // `DD_SOCCER_LOOKAHEAD_DEPTH >= 1` AND a trained world model is present, the value blend
        // scores each candidate by rolling the world model one step forward (`predict_next`) and
        // evaluating the predicted state with the critic (folded into the `neural_q` closure
        // below), rather than scoring the current state-action directly. Depth 0 — the default, and
        // forced when no world model exists — reproduces the direct depth-0 critic value
        // byte-for-byte, so play is unchanged unless a run opts in.
        let lookahead_depth = if self.world_model.is_some() {
            dd_soccer_lookahead_depth()
        } else {
            0
        };
        let policy_bonus = |label: &str| -> f64 {
            let action_index = soccer_policy_action_index(label);
            let mut bonus = match (&policy_log_probs, action_index) {
                (Some(log_probs), Some(index)) => log_probs
                    .get(index)
                    .map(|&log_p| SOCCER_POLICY_DECISION_WEIGHT * log_p)
                    .unwrap_or(0.0),
                _ => 0.0,
            };
            // Specialist head refinement: add the pass/dribble/shot head's own log-prob for
            // technical families, below the joint weight so it tunes rather than overrides.
            if let (Some(skill), Some(index)) = (&skill_log_probs, action_index) {
                if let Some(skill_log_p) = skill.log_prob_for_action_index(index) {
                    bonus += SOCCER_SKILL_POLICY_DECISION_WEIGHT * skill_log_p;
                }
            }
            bonus
        };
        let retrieval_bonus = |label: &str| -> f64 {
            retrieval_priors
                .as_ref()
                .and_then(|priors| priors.get(normalize_soccer_action_label(label)))
                .copied()
                .unwrap_or(0.0)
        };
        if learner.is_some() {
            for &label in SOCCER_POLICY_ACTIONS {
                let normalized = normalize_soccer_action_label(label);
                if legal
                    .iter()
                    .any(|candidate| normalize_soccer_action_label(&candidate.label) == normalized)
                {
                    continue;
                }
                if !learned_action_label_is_legal(normalized, snapshot, player_id) {
                    continue;
                }
                legal.push(SoccerLearnedActionTrace {
                    label: normalized.to_string(),
                    value: 0.0,
                    visits: 0,
                    probability: 0.0,
                    legal: true,
                    level: PitchGridLevel::WholePitch,
                });
            }
        }
        if legal.is_empty() {
            return None;
        }
        if legal.len() < 2 && learner.is_none() {
            // Nothing to re-rank — let the tabular greedy path decide.
            return None;
        }

        let gamma = soccer_q_sanitized_gamma(policy.options.gamma);
        let mcts_depth = if blend.mcts_enabled {
            blend.sanitized_mcts_depth()
        } else {
            1
        };
        let mcts_model_weight = if blend.mcts_enabled {
            blend.sanitized_mcts_model_weight()
        } else {
            0.0
        };
        let neural_q = |label: &str| -> Option<f64> {
            let learner = learner?;
            // Look-ahead-aware critic value: depth 0 is the direct critic (byte-identical to the
            // pre-look-ahead path, since `model_based_lookahead_value` at depth 0 == predict_value
            // of the same features); depth >= 1 rolls the world model one step forward first.
            self.model_based_lookahead_value(&base, label, learner, lookahead_depth)
                .map(|v| v * target_scale)
        };
        let mut scored_candidates = Vec::with_capacity(legal.len());
        for candidate in legal.iter() {
            let mut transition = base.clone();
            transition.action = candidate.label.clone();
            let neural_value = neural_q(&candidate.label);
            // Value contribution (0-weighted when the value blend is off/cold).
            let value_score = match blend.mode {
                SoccerNeuralBlendMode::Off => candidate.value,
                SoccerNeuralBlendMode::Additive => {
                    candidate.value + lambda * neural_value.unwrap_or(0.0)
                }
                SoccerNeuralBlendMode::TieBreak => {
                    if best_tabular - candidate.value > blend.tie_epsilon {
                        // Outside the tie window — not a candidate for re-ranking.
                        continue;
                    }
                    candidate.value + lambda * neural_value.unwrap_or(0.0)
                }
                SoccerNeuralBlendMode::ConfidenceGated => {
                    if candidate.visits < blend.min_confidence_visits {
                        // Tabular is blind here — blend toward the net's estimate.
                        let weight = lambda.min(1.0);
                        let nv = neural_value.unwrap_or(candidate.value);
                        (1.0 - weight) * candidate.value + weight * nv
                    } else {
                        candidate.value
                    }
                }
            };
            // Actor bias: nudge toward the family the learned policy prefers.
            let actor_bonus = policy_bonus(&candidate.label);
            let retrieved_bonus = retrieval_bonus(&candidate.label);
            let model_bonus = mcts_model_weight
                * self.neural_mcts_model_rollout_value(
                    learner,
                    &transition,
                    target_scale,
                    mcts_depth,
                    gamma,
                );
            let score = value_score + actor_bonus + retrieved_bonus + model_bonus;
            if !score.is_finite() {
                continue;
            }
            let actor_prior = policy_log_probs
                .as_ref()
                .and_then(|log_probs| {
                    soccer_policy_action_index(&candidate.label).and_then(|i| log_probs.get(i))
                })
                .map(|log_p| log_p.exp())
                .unwrap_or(0.0);
            scored_candidates.push(SoccerNeuralMctsCandidate {
                label: candidate.label.clone(),
                score,
                prior: actor_prior + retrieved_bonus.max(0.0),
                q_visits: candidate.visits,
            });
        }
        scored_candidates.sort_by(|a, b| {
            b.score
                .total_cmp(&a.score)
                .then_with(|| a.q_visits.cmp(&b.q_visits))
                .then_with(|| a.label.cmp(&b.label))
        });
        let rank_draw = self.policy_rank_selection_draw(snapshot, player_id, rank_salt);
        if let Some(mcts_label) =
            Self::neural_mcts_action_from_candidates(blend, &scored_candidates, rank_draw)
        {
            return Some(mcts_label);
        }
        Self::weighted_scored_candidate_choice(&scored_candidates, rank_draw)
    }

    /// Per-team value-head forward-intent for this tick: for each outfield player,
    /// how much more value the net assigns to advancing (`dribble`) than to
    /// holding shape (`hold`), averaged per team and squashed into opposing
    /// attack/defense pulls in [0, 1]. This is how the gradient-learned value
    /// governs *whole-field* configuration — it feeds the formation LP's
    /// forward-pull coefficient, complementing the per-player action blend.
    /// Returns all-zero (LP untouched) unless the blend is opted in and the value
    /// head has warmed up.
    fn neural_formation_intent(&self, snapshot: &WorldSnapshot) -> SoccerNeuralFormationIntent {
        let mut intent = SoccerNeuralFormationIntent::default();
        if self.neural_blend.mode == SoccerNeuralBlendMode::Off {
            return intent;
        }
        let target_scale = self.config.neural_learning.sanitized_target_scale();
        for team in [Team::Home, Team::Away] {
            // Each team's forward-intent comes from its own brain (away falls back
            // to the shared net in single-net runs), so per-team brains pull the
            // whole-field LP shape independently.
            let Some(learner) = self.neural_learner_for(team) else {
                continue;
            };
            if !learner.has_prediction_network() {
                continue;
            }
            let readiness = self.neural_blend_readiness_for_learner(learner);
            if readiness <= 0.0 {
                continue;
            }
            let mut advantage_sum = 0.0;
            let mut count = 0u32;
            for player in snapshot.players.iter().filter(|player| player.team == team) {
                let mdp_state = snapshot.mdp_state_for_player(player.id);
                let observation = snapshot.observation_for(player.id);
                let mut base = self.neural_decision_transition(
                    snapshot,
                    player.id,
                    team,
                    player.role,
                    &mdp_state,
                    &observation,
                );
                base.action = "dribble".to_string();
                let forward = learner.predict_value(&soccer_neural_transition_features(&base));
                base.action = "hold".to_string();
                let hold = learner.predict_value(&soccer_neural_transition_features(&base));
                if let (Some(forward), Some(hold)) = (forward, hold) {
                    advantage_sum += (forward - hold) * target_scale;
                    count += 1;
                }
            }
            if count == 0 {
                continue;
            }
            let advantage = (advantage_sum / count as f64) * readiness;
            // Signed advantage → opposing attack/defense pulls in [0, 1].
            let squashed = (advantage * SOCCER_NEURAL_FORMATION_INTENT_SCALE).tanh();
            let (attack, defense) = if squashed >= 0.0 {
                (squashed, 0.0)
            } else {
                (0.0, -squashed)
            };
            match team {
                Team::Home => {
                    intent.home_attack = attack;
                    intent.home_defense = defense;
                }
                Team::Away => {
                    intent.away_attack = attack;
                    intent.away_defense = defense;
                }
            }
        }
        intent
    }

    /// Opt-in exploration for the decision path. When a learning run explicitly enables ε,
    /// an independent deterministic gate occasionally samples among high-ranked legal policy
    /// actions, nudging toward lower-visit candidates inside the plausible top-k set.
    ///
    /// Gating, by design:
    /// - Only active while `learning_enabled` is true. Realtime/4-controller
    ///   play, live-learning-toggled-off, and after-the-fact playback all run
    ///   with learning disabled, so they never explore (selection stays greedy
    ///   and reproducible there).
    /// - ε defaults to 0 (`SoccerQPolicyOptions::exploration_epsilon`), so even
    ///   during a learning run nothing changes unless the run opts in. When enabled,
    ///   both the ε gate and rank draw are deterministic and separately salted,
    ///   keeping replays stable without biasing the rank distribution.
    fn exploration_action_for_player(
        &self,
        policy: &SoccerQPolicy,
        snapshot: &WorldSnapshot,
        player_id: usize,
        mdp_state: &SoccerMdpState,
        observation: &SoccerPomdpObservation,
        retrieval_prior: Option<(&std::collections::HashMap<String, f64>, f64)>,
    ) -> Option<SoccerPolicyActionChoice> {
        if !self.config.learning_enabled {
            return None;
        }
        let epsilon = soccer_q_sanitized_epsilon(policy.options.exploration_epsilon);
        if epsilon <= 0.0 {
            return None;
        }
        let gate_draw = self.policy_rank_selection_draw(
            snapshot,
            player_id,
            SOCCER_POLICY_EPSILON_SALT_EXPLORATION,
        );
        if !soccer_policy_epsilon_gate_allows(epsilon, gate_draw) {
            return None;
        }
        let (_state, ranked) = policy.ranked_action_values_for_snapshot(
            snapshot,
            player_id,
            SOCCER_Q_EXPLORATION_CANDIDATES,
        )?;
        let draw = self.policy_rank_selection_draw(
            snapshot,
            player_id,
            SOCCER_POLICY_RANK_SALT_EXPLORATION,
        );
        let mut choice = soccer_policy_uncertainty_weighted_ranked_action_choice(&ranked, draw)?;
        let fallback_probability = self.weighted_policy_action_probability_for_player(
            policy,
            snapshot,
            player_id,
            mdp_state,
            observation,
            retrieval_prior,
            &choice.label,
        );
        choice.behavior_probability = soccer_policy_mixed_behavior_probability(
            epsilon,
            choice.behavior_probability,
            fallback_probability,
        );
        Some(choice)
    }

    fn learned_policy_trace_for_player(
        &self,
        snapshot: &WorldSnapshot,
        player_id: usize,
    ) -> Option<SoccerLearnedPolicyTrace> {
        let player = snapshot.players.iter().find(|p| p.id == player_id)?;
        if let Some(team_policies) = &self.team_policies {
            let policy = team_policies.policy(player.team);
            if let Some(trace) =
                Self::learned_policy_trace_from_policy(policy, "team", snapshot, player_id)
            {
                return Some(trace);
            }
        }
        self.learned_policy.as_ref().and_then(|policy| {
            Self::learned_policy_trace_from_policy(policy, "shared", snapshot, player_id)
        })
    }

    fn learned_policy_trace_from_policy(
        policy: &SoccerQPolicy,
        source: &str,
        snapshot: &WorldSnapshot,
        player_id: usize,
    ) -> Option<SoccerLearnedPolicyTrace> {
        let (state, action_values) =
            policy.ranked_action_values_for_snapshot(snapshot, player_id, 6)?;
        let best_action = action_values
            .iter()
            .find(|action| action.legal)
            .map(|action| action.label.clone());
        let learned_plan = best_action.as_ref().map(|action| {
            Self::learned_plan_for_policy(policy, snapshot, player_id, action.clone())
        });
        let target_player = learned_plan.as_ref().and_then(|plan| plan.target_player);
        let target_value = target_player.and_then(|target| {
            let position = snapshot.player_position(target)?;
            let action = best_action.as_deref()?;
            Some(policy.target_preference_for_snapshot(snapshot, player_id, action, position))
        });
        Some(SoccerLearnedPolicyTrace {
            source: source.to_string(),
            state,
            best_action,
            target_player,
            target_value,
            action_values,
        })
    }

    fn learned_plan_for_policy(
        policy: &SoccerQPolicy,
        snapshot: &WorldSnapshot,
        player_id: usize,
        action: String,
    ) -> SoccerLearnedPlan {
        let normalized_action = normalize_soccer_action_label(&action).to_string();
        let is_pass = pass_like_action_flight(&normalized_action).is_some();
        let mut plan = SoccerLearnedPlan {
            action,
            target_player: None,
            target_point: None,
            mpc_replan: None,
        };
        if is_pass {
            let candidates = if matches!(
                normalized_action.as_str(),
                "aerial-pass" | "flank-high-cross"
            ) {
                snapshot.ranked_visible_aerial_pass_targets(player_id, 11)
            } else {
                let mut candidates = snapshot.ranked_visible_pass_targets(player_id, 11);
                if candidates.is_empty() {
                    if let Some(target) = snapshot.best_pass_target(player_id) {
                        candidates.push(target);
                    }
                }
                candidates
            };
            let flight = pass_like_action_flight(&normalized_action).unwrap_or(PassFlight::Floor);
            plan.target_player = policy.best_pass_target_player_for_snapshot(
                snapshot,
                player_id,
                &normalized_action,
                flight,
                &candidates,
            );
            plan.target_point = plan
                .target_player
                .and_then(|target| snapshot.player_position(target));
        } else if matches!(normalized_action.as_str(), "clearance" | "route-one") {
            if let Some(player) = snapshot
                .players
                .iter()
                .find(|player| player.id == player_id)
            {
                plan.target_point = if normalized_action == "route-one" {
                    snapshot.route_one_target_for(player_id).or_else(|| {
                        Some(route_one_target_for_actor(
                            player.team,
                            snapshot.player_snapshot_position(player),
                            snapshot.field_width,
                            snapshot.field_length,
                            player.role,
                        ))
                    })
                } else {
                    snapshot
                        .pressure_clearance_target_for(player_id)
                        .or_else(|| {
                            Some(clearance_target_for_player(
                                player.team,
                                snapshot.player_snapshot_position(player),
                                snapshot.field_width,
                                snapshot.field_length,
                            ))
                        })
                };
            }
        } else if matches!(
            normalized_action.as_str(),
            "keeper-mpc-floor-pass" | "keeper-mpc-aerial-pass" | "keeper-mpc-clearance"
        ) {
            if let Some(keeper_plan) = snapshot.goalkeeper_mpc_play_out_plan(player_id, None) {
                let matches_requested = match normalized_action.as_str() {
                    "keeper-mpc-floor-pass" => {
                        keeper_plan.target_player.is_some()
                            && keeper_plan.flight == PassFlight::Floor
                    }
                    "keeper-mpc-aerial-pass" => {
                        keeper_plan.target_player.is_some()
                            && keeper_plan.flight != PassFlight::Floor
                    }
                    "keeper-mpc-clearance" => keeper_plan.target_player.is_none(),
                    _ => false,
                };
                if matches_requested {
                    plan.target_player = keeper_plan.target_player;
                    plan.target_point = Some(keeper_plan.target);
                }
            }
        }
        plan
    }

    fn mpc_reconciled_learned_plan_for_policy(
        policy: &SoccerQPolicy,
        snapshot: &WorldSnapshot,
        player_id: usize,
        action: String,
    ) -> SoccerLearnedPlan {
        let plan = Self::learned_plan_for_policy(policy, snapshot, player_id, action);
        if !Self::learned_plan_needs_mpc_replan(snapshot, player_id, &plan) {
            return plan;
        }
        let original_action = normalize_soccer_action_label(&plan.action).to_string();
        let rejected_execution_probability =
            Self::learned_plan_mpc_execution_probability(snapshot, player_id, &plan)
                .unwrap_or(0.0)
                .clamp(0.0, 1.0);
        let Some((_, ranked)) = policy.ranked_action_values_for_snapshot(
            snapshot,
            player_id,
            LEARNED_MPC_REPLAN_CANDIDATES,
        ) else {
            return plan;
        };
        let mut candidate_count = 0usize;
        for candidate in ranked.iter().filter(|candidate| candidate.legal) {
            if normalize_soccer_action_label(&candidate.label) == original_action {
                continue;
            }
            candidate_count += 1;
            let mut candidate_plan =
                Self::learned_plan_for_policy(policy, snapshot, player_id, candidate.label.clone());
            if !Self::learned_plan_needs_mpc_replan(snapshot, player_id, &candidate_plan) {
                candidate_plan.mpc_replan = Some(SoccerLearnedMpcReplanTrace {
                    original_action: original_action.clone(),
                    replacement_action: normalize_soccer_action_label(&candidate_plan.action)
                        .to_string(),
                    rejected_execution_probability,
                    candidate_count,
                });
                return candidate_plan;
            }
        }
        plan
    }

    fn learned_plan_needs_mpc_replan(
        snapshot: &WorldSnapshot,
        player_id: usize,
        plan: &SoccerLearnedPlan,
    ) -> bool {
        let label = normalize_soccer_action_label(&plan.action);
        let threshold = if pass_like_action_flight(label).is_some() {
            Some(LEARNED_MPC_PASS_IMPOSSIBLE_PROBABILITY)
        } else if is_dribble_action_label(label) {
            Some(LEARNED_MPC_DRIBBLE_IMPOSSIBLE_PROBABILITY)
        } else if matches!(label, "shoot" | "first-time-shot" | "first-time-header") {
            Some(LEARNED_MPC_SHOT_IMPOSSIBLE_PROBABILITY)
        } else {
            None
        };
        let Some(threshold) = threshold else {
            return false;
        };
        Self::learned_plan_mpc_execution_probability(snapshot, player_id, plan)
            .is_some_and(|probability| probability < threshold)
    }

    fn learned_plan_mpc_execution_probability(
        snapshot: &WorldSnapshot,
        player_id: usize,
        plan: &SoccerLearnedPlan,
    ) -> Option<f64> {
        let label = normalize_soccer_action_label(&plan.action);
        if matches!(
            label,
            "keeper-mpc-floor-pass" | "keeper-mpc-aerial-pass" | "keeper-mpc-clearance"
        ) {
            return Some(Self::learned_keeper_mpc_execution_probability(
                snapshot, player_id, plan, label,
            ));
        }
        if let Some(flight) = pass_like_action_flight(label) {
            return Some(Self::learned_pass_mpc_execution_probability(
                snapshot, player_id, plan, flight,
            ));
        }
        if let Some(kind) = dribble_move_kind_for_action_label(label) {
            return Some(Self::learned_dribble_mpc_execution_probability(
                snapshot, player_id, kind,
            ));
        }
        if matches!(label, "shoot" | "first-time-shot" | "first-time-header") {
            return Some(Self::learned_shot_mpc_execution_probability(
                snapshot, player_id, label,
            ));
        }
        if matches!(label, "clearance" | "route-one") {
            return Some(Self::learned_clearance_mpc_execution_probability(
                snapshot, player_id, plan, label,
            ));
        }
        if learned_policy_action_has_mpc_definition(label) {
            return Some(Self::learned_movement_mpc_execution_probability(
                snapshot, player_id, plan, label,
            ));
        }
        None
    }

    fn learned_keeper_mpc_execution_probability(
        snapshot: &WorldSnapshot,
        player_id: usize,
        plan: &SoccerLearnedPlan,
        label: &str,
    ) -> f64 {
        let preferred_target = plan.target_player;
        let Some(keeper_plan) = snapshot.goalkeeper_mpc_play_out_plan(player_id, preferred_target)
        else {
            return 0.0;
        };
        let matches_requested = match label {
            "keeper-mpc-floor-pass" => {
                keeper_plan.target_player.is_some() && keeper_plan.flight == PassFlight::Floor
            }
            "keeper-mpc-aerial-pass" => {
                keeper_plan.target_player.is_some() && keeper_plan.flight != PassFlight::Floor
            }
            "keeper-mpc-clearance" => keeper_plan.target_player.is_none(),
            _ => false,
        };
        if !matches_requested {
            return 0.0;
        }
        if keeper_plan.target_player.is_some() {
            let keeper_pass_plan = SoccerLearnedPlan {
                action: if keeper_plan.flight == PassFlight::Floor {
                    "pass".to_string()
                } else {
                    "aerial-pass".to_string()
                },
                target_player: keeper_plan.target_player,
                target_point: Some(keeper_plan.target),
                mpc_replan: None,
            };
            return Self::learned_pass_mpc_execution_probability(
                snapshot,
                player_id,
                &keeper_pass_plan,
                keeper_plan.flight,
            );
        }
        let keeper_clearance_plan = SoccerLearnedPlan {
            action: "clearance".to_string(),
            target_player: None,
            target_point: Some(keeper_plan.target),
            mpc_replan: None,
        };
        Self::learned_clearance_mpc_execution_probability(
            snapshot,
            player_id,
            &keeper_clearance_plan,
            "clearance",
        )
    }

    fn learned_pass_mpc_execution_probability(
        snapshot: &WorldSnapshot,
        player_id: usize,
        plan: &SoccerLearnedPlan,
        flight: PassFlight,
    ) -> f64 {
        let Some(passer) = snapshot
            .players
            .iter()
            .find(|player| player.id == player_id)
        else {
            return 0.0;
        };
        let Some(target_id) = plan.target_player else {
            return 0.0;
        };
        let Some(target) = snapshot
            .players
            .iter()
            .find(|player| player.id == target_id)
        else {
            return 0.0;
        };
        if target.team != passer.team {
            return 0.0;
        }
        let passer_position = snapshot
            .player_position(player_id)
            .unwrap_or(passer.position);
        let target_position = plan
            .target_point
            .or_else(|| snapshot.player_position(target_id))
            .unwrap_or(target.position);
        pass_target_quality_for_snapshot(
            snapshot,
            passer,
            passer_position,
            target,
            target_position,
            flight,
        )
        .mpc_receipt_probability
        .clamp(0.0, 1.0)
    }

    fn learned_dribble_mpc_execution_probability(
        snapshot: &WorldSnapshot,
        player_id: usize,
        kind: DribbleMoveKind,
    ) -> f64 {
        let Some(player) = snapshot
            .players
            .iter()
            .find(|player| player.id == player_id)
        else {
            return 0.0;
        };
        let position = snapshot
            .player_position(player_id)
            .unwrap_or(player.position);
        let velocity = snapshot
            .player_velocity(player_id)
            .unwrap_or(player.velocity);
        let touch = snapshot.deterministic_dribble_touch_decision_for(player_id, kind);
        let target =
            snapshot.dribble_move_target_for_touch(player_id, player.home_position, kind, touch);
        dribble_mpc_control_estimate_for_snapshot(
            snapshot,
            player.id,
            player.team,
            player.role,
            &player.skills,
            player.fatigue,
            position,
            velocity,
            target,
            touch.distance_yards,
        )
        .control_probability
        .clamp(0.0, 1.0)
    }

    fn learned_shot_mpc_execution_probability(
        snapshot: &WorldSnapshot,
        player_id: usize,
        label: &str,
    ) -> f64 {
        let Some(player) = snapshot
            .players
            .iter()
            .find(|player| player.id == player_id)
        else {
            return 0.0;
        };
        let position = snapshot
            .player_position(player_id)
            .unwrap_or(player.position);
        let velocity = snapshot
            .player_velocity(player_id)
            .unwrap_or(player.velocity);
        let first_time = matches!(label, "first-time-shot" | "first-time-header");
        let finish_skill = if label == "first-time-header" {
            aerial_duel_skill_from_snapshot(player)
        } else {
            (ability01(
                player
                    .skills
                    .right_foot_shot_power
                    .max(player.skills.left_foot_shot_power),
            ) * 0.62
                + ability01(player.skills.shooting) * 0.26
                + ability01(player.skills.first_touch) * 0.12)
                .clamp(0.0, 1.0)
        };
        let power = if first_time {
            shot_power_for_finish_skill(finish_skill)
        } else {
            shot_power_for_skill(ability01(player.skills.shooting))
        };
        let shot_speed = shot_speed_yps_from_power(power, &player.skills);
        let nearest_opponent_distance = snapshot
            .players
            .iter()
            .filter(|opponent| opponent.team == player.team.other())
            .map(|opponent| {
                snapshot
                    .player_position(opponent.id)
                    .unwrap_or(opponent.position)
                    .distance(position)
            })
            .fold(f64::INFINITY, f64::min);
        shot_mpc_accuracy_estimate_for_snapshot(
            snapshot,
            player.id,
            player.team,
            &player.skills,
            player.fatigue,
            position,
            velocity,
            shot_speed,
            first_time,
            pressure_from_nearest_distance(nearest_opponent_distance),
        )
        .accuracy_probability
        .clamp(0.0, 1.0)
    }

    fn learned_clearance_mpc_execution_probability(
        snapshot: &WorldSnapshot,
        player_id: usize,
        plan: &SoccerLearnedPlan,
        label: &str,
    ) -> f64 {
        let Some(player) = snapshot
            .players
            .iter()
            .find(|player| player.id == player_id)
        else {
            return 0.0;
        };
        let position = snapshot
            .player_position(player_id)
            .unwrap_or(player.position);
        let target = plan.target_point.unwrap_or_else(|| {
            if label == "route-one" {
                snapshot.route_one_target_for(player_id).unwrap_or_else(|| {
                    route_one_target_for_actor(
                        player.team,
                        position,
                        snapshot.field_width,
                        snapshot.field_length,
                        player.role,
                    )
                })
            } else {
                snapshot
                    .pressure_clearance_target_for(player_id)
                    .unwrap_or_else(|| {
                        clearance_target_for_player(
                            player.team,
                            position,
                            snapshot.field_width,
                            snapshot.field_length,
                        )
                    })
            }
        });
        let distance = position.distance(target).clamp(0.0, 120.0);
        let observation = snapshot.observation_for(player_id);
        let launch_skill = (ability01(player.skills.passing_completion_rate) * 0.30
            + ability01(player.skills.vision) * 0.18
            + ability01(
                player
                    .skills
                    .right_foot_shot_power
                    .max(player.skills.left_foot_shot_power),
            ) * 0.30
            + ability01(player.skills.first_touch) * 0.22)
            .clamp(0.0, 1.0);
        let target_fit = if label == "route-one" {
            (1.0 - ((distance - 46.0).abs() / 58.0)).clamp(0.34, 1.0)
        } else {
            (0.72 + (distance / 70.0).clamp(0.0, 1.0) * 0.28).clamp(0.0, 1.0)
        };
        let pressure_fit =
            (1.0 - observation.perceived_pressure.clamp(0.0, 1.0) * 0.16).clamp(0.72, 1.0);
        let decision_confidence = player_decision_confidence(&observation, &player.skills);
        (0.08 + launch_skill * 0.42 + target_fit * 0.24 + decision_confidence * 0.26)
            .clamp(0.0, 0.99)
            * pressure_fit
    }

    fn learned_movement_mpc_target(
        snapshot: &WorldSnapshot,
        player: &PlayerSnapshot,
        plan: &SoccerLearnedPlan,
        label: &str,
    ) -> Vec2 {
        if let Some(target) = plan.target_point {
            return target.clamp_to_pitch(snapshot.field_width, snapshot.field_length);
        }
        let current = snapshot.player_snapshot_position(player);
        let target = match label {
            "tackle" | "blindside-steal" => snapshot
                .ball
                .holder
                .and_then(|holder| snapshot.player_position(holder)),
            "defend" | "press-cover" => {
                Some(snapshot.defensive_assignment_for(player.id, player.home_position, false))
            }
            "keeper-position" | "keeper-save" => {
                Some(snapshot.goalkeeper_ball_goal_tracking_target(player.team))
            }
            "hold" if player.role == PlayerRole::Goalkeeper => {
                Some(snapshot.goalkeeper_ball_goal_tracking_target(player.team))
            }
            "hold" => Some(player.home_position),
            "space" => {
                if snapshot.controlled_possession_team() == Some(player.team) {
                    if player.role == PlayerRole::Goalkeeper {
                        Some(snapshot.goalkeeper_ball_goal_tracking_target(player.team))
                    } else {
                        Some(snapshot.positional_open_space_for(
                            player.id,
                            player.home_position,
                            false,
                        ))
                    }
                } else if snapshot.controlled_possession_team() == Some(player.team.other()) {
                    Some(snapshot.defensive_assignment_for(player.id, player.home_position, false))
                } else {
                    Some(snapshot.defensive_shape_for(player.id, player.home_position))
                }
            }
            "keeper-survey-hands" | "keeper-foot-control-outside-box" | "control-touch" => {
                Some(current)
            }
            _ => snapshot
                .formation_lp_guidance_for(player.id)
                .map(|guidance| guidance.target),
        };
        target
            .or_else(|| {
                snapshot
                    .formation_lp_guidance_for(player.id)
                    .map(|guidance| guidance.target)
            })
            .unwrap_or(current)
            .clamp_to_pitch(snapshot.field_width, snapshot.field_length)
    }

    fn learned_movement_mpc_execution_probability(
        snapshot: &WorldSnapshot,
        player_id: usize,
        plan: &SoccerLearnedPlan,
        label: &str,
    ) -> f64 {
        let Some(player) = snapshot
            .players
            .iter()
            .find(|player| player.id == player_id)
        else {
            return 0.0;
        };
        let current = snapshot
            .player_position(player_id)
            .unwrap_or(player.position)
            .clamp_to_pitch(snapshot.field_width, snapshot.field_length);
        let target = Self::learned_movement_mpc_target(snapshot, player, plan, label);
        let dt = sane_dt_seconds(snapshot.dt_seconds, DEFAULT_DT_SECONDS).max(1e-6);
        let horizon = (dt * 2.0).clamp(2.0 / 15.0, 0.24);
        let velocity = snapshot
            .player_velocity(player_id)
            .unwrap_or(player.velocity);
        let execution_skill = match label {
            "tackle" | "defend" | "press-cover" | "keeper-save" => {
                ability01(player.skills.defending) * 0.48
                    + ability01(player.skills.acceleration) * 0.22
                    + ability01(player.skills.strength) * 0.18
                    + ability01(player.skills.aggression) * 0.12
            }
            "keeper-position" | "keeper-survey-hands" | "keeper-foot-control-outside-box" => {
                ability01(player.skills.goalkeeping) * 0.50
                    + ability01(player.skills.acceleration) * 0.22
                    + ability01(player.skills.first_touch) * 0.16
                    + ability01(player.skills.vision) * 0.12
            }
            "control-touch" => {
                ability01(player.skills.first_touch) * 0.48
                    + ability01(player.skills.dribbling) * 0.24
                    + ability01(player.skills.strength) * 0.16
                    + ability01(player.skills.acceleration) * 0.12
            }
            _ => {
                ability01(player.skills.acceleration) * 0.42
                    + ability01(player.skills.top_speed) * 0.34
                    + ability01(player.skills.dribbling) * 0.24
            }
        }
        .clamp(0.0, 1.0);
        let reachable_delta_yards = (velocity.len() * horizon
            + 0.5 * acceleration_yps2_from_score(player.skills.acceleration) * horizon * horizon
            + execution_skill * 1.6)
            .max(0.75);
        let distance = current.distance(target);
        let distance_fit = if distance <= reachable_delta_yards {
            1.0
        } else {
            (1.0 - (distance - reachable_delta_yards)
                / tunables()
                    .decision_mpc
                    .reselect_max_target_delta_yards
                    .max(1.0))
            .clamp(0.0, 1.0)
        };
        let lp_alignment = snapshot
            .formation_lp_guidance_for(player_id)
            .map(|guidance| {
                (1.0 - target.distance(guidance.target) / 16.0)
                    .clamp(0.0, 1.0)
                    .max(if guidance.local_mpc_guidance {
                        0.35
                    } else {
                        0.0
                    })
            })
            .unwrap_or(0.72);
        let observation = snapshot.observation_for(player_id);
        let decision_confidence = player_decision_confidence(&observation, &player.skills);
        (0.08
            + distance_fit * 0.40
            + execution_skill * 0.26
            + decision_confidence * 0.18
            + lp_alignment * 0.08)
            .clamp(0.0, 0.99)
    }

    fn ensure_neural_learner(&mut self) {
        if !self.config.learning_enabled || !self.config.neural_learning.enabled {
            self.clear_all_neural_learners();
            return;
        }
        let backend = self.config.neural_learning.backend;
        let needs_new = self
            .neural_learner
            .as_ref()
            .map_or(true, |learner| learner.backend != backend);
        if needs_new {
            self.neural_learner = Some(SoccerNeuralLearner::new(&self.config));
        }
        // Refresh an existing dedicated away learner on a backend switch; never
        // *create* one here — per-team mode is opt-in via `set_team_neural_brain`.
        if self
            .away_neural_learner
            .as_ref()
            .is_some_and(|learner| learner.backend != backend)
        {
            self.away_neural_learner = Some(SoccerNeuralLearner::new(&self.config));
        }
    }

    fn neural_learning_due(&self, learning_due: bool) -> bool {
        if !learning_due || !self.config.learning_enabled || !self.config.neural_learning.enabled {
            return false;
        }
        let interval = self.config.neural_learning.sanitized_train_every_ticks();
        interval <= 1 || self.is_done() || self.tick as usize % interval == 0
    }

    pub(crate) fn neural_training_samples_for(
        &self,
        transitions: &[SoccerLearningTransition],
    ) -> Vec<SoccerNeuralTrainingSample> {
        self.neural_training_samples_filtered(transitions, None)
    }

    /// Build critic training samples. `team_filter` restricts which transitions
    /// *emit* a sample (used to feed each team's own brain), while centralized
    /// MARL reward shaping is always computed across the full replay so the
    /// reward signal is identical whether one shared net or per-team brains are
    /// trained.
    fn neural_training_samples_filtered(
        &self,
        transitions: &[SoccerLearningTransition],
        team_filter: Option<Team>,
    ) -> Vec<SoccerNeuralTrainingSample> {
        if transitions.is_empty() {
            return Vec::new();
        }
        let target_scale = self.config.neural_learning.sanitized_target_scale();
        let target_clip = self.config.neural_learning.sanitized_target_clip();
        let tick_rewards = soccer_marl_tick_rewards(transitions);
        transitions
            .iter()
            .filter(|transition| team_filter.map_or(true, |team| transition.team == team))
            .filter_map(|transition| {
                let adjusted_reward = soccer_marl_adjusted_reward(
                    transition,
                    &tick_rewards,
                    &self.config.neural_learning,
                );
                let next_state = SoccerQStateKey::from_next_transition(transition);
                let (gamma, max_next) = self
                    .team_policies
                    .as_ref()
                    .map(|policies| {
                        let policy = policies.policy(transition.team);
                        (
                            soccer_q_sanitized_gamma(policy.options.gamma),
                            if transition.done {
                                0.0
                            } else {
                                policy.best_value_hierarchical(&next_state).unwrap_or(0.0)
                            },
                        )
                    })
                    .or_else(|| {
                        self.learned_policy.as_ref().map(|policy| {
                            (
                                soccer_q_sanitized_gamma(policy.options.gamma),
                                if transition.done {
                                    0.0
                                } else {
                                    policy.best_value_hierarchical(&next_state).unwrap_or(0.0)
                                },
                            )
                        })
                    })
                    .unwrap_or((SoccerQPolicyOptions::default().gamma, 0.0));
                let (target, priority) = soccer_neural_target_and_priority(
                    adjusted_reward,
                    gamma,
                    max_next,
                    transition.done,
                    target_scale,
                    target_clip,
                );
                let sample = SoccerNeuralTrainingSample {
                    input: soccer_neural_transition_features(transition),
                    target,
                    priority,
                };
                soccer_neural_sample_is_valid(&sample).then_some(sample)
            })
            .collect()
    }

    fn train_neural_value_model(&mut self, samples: Vec<SoccerNeuralTrainingSample>) {
        if samples.is_empty() {
            return;
        }
        self.ensure_neural_learner();
        if let Some(learner) = &mut self.neural_learner {
            learner.submit_samples(samples, &self.config.neural_learning);
        }
    }

    /// Route critic training to the right brain(s). Single-net runs (no dedicated
    /// away learner) behave exactly as before: all transitions train the shared
    /// net. Per-team runs train each team's own critic on its own transitions and
    /// skip any team whose brain is frozen (frozen-opponent evaluation).
    fn train_neural_value_models(&mut self, replay: &[SoccerLearningTransition]) {
        if !self.config.neural_learning.enabled || replay.is_empty() {
            return;
        }
        if self.away_neural_learner.is_none() {
            let samples = self.neural_training_samples_filtered(replay, None);
            self.train_neural_value_model(samples);
            return;
        }
        // Per-team brains. Ensure learners exist / match the backend, then feed
        // each non-frozen team its own samples. Clone the (small) neural config so
        // the per-team learner field can be borrowed mutably alongside it.
        self.ensure_neural_learner();
        let neural_config = self.config.neural_learning.clone();
        for team in [Team::Home, Team::Away] {
            if self.neural_team_frozen(team) {
                continue;
            }
            let samples = self.neural_training_samples_filtered(replay, Some(team));
            if samples.is_empty() {
                continue;
            }
            let learner = match team {
                Team::Home => self.neural_learner.as_mut(),
                Team::Away => self.away_neural_learner.as_mut(),
            };
            if let Some(learner) = learner {
                learner.submit_samples(samples, &neural_config);
            }
        }
    }

    /// Critic estimate (in target units) for a realized/candidate transition,
    /// or `None` when neural learning is off or no trained net exists yet. This
    /// is the runtime read path that lets the discrete Q layer and the
    /// formation LP *consume* the gradient-trained value model.
    pub fn neural_value_for_transition(
        &self,
        transition: &SoccerLearningTransition,
    ) -> Option<f64> {
        if !self.config.neural_learning.enabled {
            return None;
        }
        // Score with the transition's own team brain (away falls back to the
        // shared net in single-net runs).
        let learner = self.neural_learner_for(transition.team)?;
        let features = soccer_neural_transition_features(transition);
        learner.predict_value(&features)
    }

    /// Build persistable **moment embeddings** from this match's recorded
    /// transitions — one fixed-width vector per moment plus the metadata a
    /// retrieval consumer needs (team, action, reward, critic value). These are
    /// written to pgvector for cross-game similarity search (RAG over moments),
    /// the durable, scalable successor to the in-process `SoccerMomentVectorIndex`.
    pub fn moment_embeddings(&self) -> Vec<SoccerMomentEmbeddingInsert> {
        self.episode_learning_transitions
            .iter()
            .map(|transition| SoccerMomentEmbeddingInsert {
                team: transition.team,
                tick: transition.tick,
                action: normalize_soccer_action_label(&transition.action).to_string(),
                reward: finite_metric(transition.reward),
                value: self.neural_value_for_transition(transition),
                embedding: soccer_moment_embedding(&soccer_neural_transition_features(transition)),
            })
            .collect()
    }

    /// Build the persisted **configuration moments** for the retrieval corpus:
    /// one record per captured ball-carrier decision, with the whole-field
    /// [`SoccerConfigVector`] embedding, the decision taken, and the outcome
    /// (immediate MDP reward + discounted **n-step return** over that player's
    /// subsequent transitions). Empty unless `config.retrieval.capture_enabled`
    /// populated [`Self::episode_config_captures`] during the match.
    ///
    /// The n-step return follows the acting player's own future reward trajectory
    /// — the realised MDP value of their decision — so a retrieval consumer can
    /// rank neighbours by how the same decision actually worked out, not just by
    /// similarity.
    /// Install (or clear) the per-team retrieval **action prior** — the result of
    /// looking up neighbours of the current configuration and aggregating their
    /// decisions/outcomes (see [`soccer_retrieval_action_prior`]). Takes effect
    /// only while `config.retrieval.decision_prior_enabled`; an empty map clears
    /// the team's prior. This is how the (postgres-backed) retrieval consumer
    /// feeds "what worked in similar configs" into the live decision.
    pub fn set_retrieval_action_prior(
        &mut self,
        team: Team,
        prior: std::collections::HashMap<String, f64>,
    ) {
        if prior.is_empty() {
            self.retrieval_action_prior.remove(&team);
        } else {
            self.retrieval_action_prior.insert(team, prior);
        }
    }

    /// The canonical config **query embedding** for `team`'s current state in the
    /// requested `comparison` mode — the vector to feed
    /// `search_nearest_config_moments` ("find the N closest configurations") for
    /// that mode's corpus. Built from a fresh snapshot with the configured
    /// ball-proximity weighting, so the query matches how the corpus was captured.
    pub fn retrieval_query_embedding(
        &self,
        team: Team,
        comparison: SoccerConfigComparison,
    ) -> Vec<f64> {
        let snapshot = WorldSnapshot::from_match(self);
        SoccerConfigVector::from_snapshot_with(
            &snapshot,
            team,
            comparison,
            self.config.retrieval.weight_options(),
        )
        .embedding()
    }

    pub fn config_moments(&self) -> Vec<SoccerConfigMomentInsert> {
        if self.episode_config_captures.is_empty() {
            return Vec::new();
        }
        // Per-player ordered (tick, reward) timeline from the episode replay, so an
        // n-step return can be summed forward from any captured tick.
        let mut timelines: HashMap<usize, Vec<(u64, f64)>> = HashMap::new();
        for transition in &self.episode_learning_transitions {
            if learned_mpc_rejected_action_counterexample(transition) {
                continue;
            }
            timelines
                .entry(transition.player_id)
                .or_default()
                .push((transition.tick, finite_metric(transition.reward)));
        }
        for series in timelines.values_mut() {
            series.sort_by_key(|(tick, _)| *tick);
        }

        let gamma = soccer_q_sanitized_gamma(self.config.retrieval.outcome_gamma);
        let horizon = self.config.retrieval.outcome_horizon.max(1);

        self.episode_config_captures
            .iter()
            .map(|capture| {
                let timeline = timelines.get(&capture.player_id);
                let immediate = timeline
                    .and_then(|series| {
                        series
                            .iter()
                            .find(|(tick, _)| *tick == capture.tick)
                            .map(|(_, reward)| *reward)
                    })
                    .unwrap_or(0.0);
                let nstep_return = timeline
                    .map(|series| {
                        let mut acc = 0.0;
                        let mut discount = 1.0;
                        for (_, reward) in series
                            .iter()
                            .filter(|(tick, _)| *tick >= capture.tick)
                            .take(horizon)
                        {
                            acc += discount * reward;
                            discount *= gamma;
                        }
                        acc
                    })
                    .unwrap_or(immediate);
                let features_f64: Vec<f64> = capture.features.iter().map(|&f| f as f64).collect();
                let features_assigned_f64: Vec<f64> = capture
                    .features_assigned
                    .iter()
                    .map(|&f| f as f64)
                    .collect();
                SoccerConfigMomentInsert {
                    team: capture.team,
                    tick: capture.tick,
                    role: capture.role,
                    action: capture.action.clone(),
                    reward: immediate,
                    nstep_return: finite_metric(nstep_return),
                    value: None,
                    embedding: soccer_moment_embedding(&features_f64),
                    features: capture.features.clone(),
                    embedding_assigned: soccer_moment_embedding(&features_assigned_f64),
                    features_assigned: capture.features_assigned.clone(),
                }
            })
            .collect()
    }

    /// State-only feature vector for the actor: the transition's critic features
    /// built with a **null action**, then extended with an explicit role one-hot
    /// so the shared policy can specialize by position without changing the
    /// critic/value feature schema.
    fn policy_state_features(
        &self,
        transition: &SoccerLearningTransition,
    ) -> [f64; SOCCER_POLICY_FEATURE_DIM] {
        // Null action ⇒ pure state features, with no per-row clone of the (heavy)
        // transition. NOTE (wm-2): a handful of channels are still derived from
        // `decision_context` geometry that the realised action shaped, so this is
        // "state-dominant", not perfectly action-independent — adequate as the
        // policy/world-model state encoding, and identical at train and inference.
        let state_features = soccer_neural_transition_features_with_action(transition, "");
        // Exact assigned position from the player's static formation anchor — gated so the
        // block is all-zero (role-only actor) unless the assigned-position embedding is on.
        let assigned = if dd_soccer_enable_assigned_position_embedding() {
            self.players
                .iter()
                .find(|player| player.id == transition.player_id)
                .map(|player| {
                    soccer_assigned_position_for(
                        transition.role,
                        player.home_position,
                        self.config.field_width_yards,
                        self.config.field_length_yards,
                        transition.team,
                    )
                })
        } else {
            None
        };
        soccer_policy_features_for_role(&state_features, transition.role, assigned)
    }

    /// Build actor-critic training samples from a replay: opponent-centered reward
    /// (the same zero-sum shaping the adversarial Q update uses), the critic's
    /// value per transition, and a **GAE(λ)** advantage accumulated backward along
    /// each agent's own trajectory. Only emits samples for actions inside the
    /// policy vocabulary. Empty unless the critic has a usable network.
    fn neural_policy_training_samples(
        &self,
        replay: &[SoccerLearningTransition],
    ) -> Vec<SoccerPolicySample> {
        // The actor trains once at least one team brain can score states. Each
        // transition is later valued by its own team's critic.
        let home_ready = self
            .neural_learner_for(Team::Home)
            .map_or(false, |learner| learner.has_prediction_network());
        let away_ready = self
            .neural_learner_for(Team::Away)
            .map_or(false, |learner| learner.has_prediction_network());
        if (!home_ready && !away_ready) || replay.is_empty() {
            return Vec::new();
        }
        let target_scale = self.config.neural_learning.sanitized_target_scale();
        // Per-team discount: the critic bootstraps each team's value with that
        // team's own gamma, so the advantage must discount with the same gamma
        // (home and away can carry independent policy options).
        let team_gamma = |team: Team| -> f64 {
            self.team_policies
                .as_ref()
                .map(|tp| soccer_q_sanitized_gamma(tp.policy(team).options.gamma))
                .unwrap_or_else(|| soccer_q_sanitized_gamma(SoccerQPolicyOptions::default().gamma))
        };

        // Per-tick team reward aggregation for centralized MARL shaping. Synthetic
        // learned-MPC rejected-action rows are actor counterexamples, not events
        // the team actually produced on the pitch, so they stay out of the team
        // mean and keep their own direct penalty below.
        let tick_rewards = soccer_actor_advantage_tick_rewards(replay);

        // Per-transition row: the MARL-adjusted reward (critic value in reward units), terminal
        // flag, action index, and state features. Both convergent cooperative-MARL shapings are
        // unified in `soccer_marl_adjusted_reward`: ours' MAPPO team-reward SHARE blends each
        // agent's reward toward its team's per-tick mean, and theirs' centralized weighting then
        // scales that (intermediate) signal and adds the zero-sum (own − opponent) team component.
        // Each knob reduces to a no-op at its default, so the default path is byte-identical.
        let reward_adv: Vec<f64> = replay
            .iter()
            .map(|transition| {
                soccer_actor_advantage_reward(
                    transition,
                    &tick_rewards,
                    &self.config.neural_learning,
                )
            })
            .collect();
        let values: Vec<f64> = replay
            .iter()
            .map(|transition| {
                self.neural_learner_for(transition.team)
                    .and_then(|learner| {
                        learner.predict_value(&soccer_neural_transition_features(transition))
                    })
                    .map(|value| value * target_scale)
                    .unwrap_or(0.0)
            })
            .collect();

        // Group transition indices by (team, player) and GAE backward per agent.
        let mut by_agent: HashMap<(Team, usize), Vec<usize>> = HashMap::new();
        for (index, transition) in replay.iter().enumerate() {
            if learned_mpc_rejected_action_counterexample(transition) {
                continue;
            }
            by_agent
                .entry((transition.team, transition.player_id))
                .or_default()
                .push(index);
        }
        let mut advantages = vec![0.0f64; replay.len()];
        for ((team, _player), mut indices) in by_agent {
            let gamma = team_gamma(team);
            indices.sort_by_key(|&i| replay[i].tick);
            // `values[i]` is the critic on the realised action ≈ Q(sᵢ,aᵢ); used as
            // the bootstrap/baseline (an on-policy/SARSA-style advantage). 0 at the
            // trajectory tail (terminal).
            let mut next_value = 0.0;
            let mut next_advantage = 0.0;
            let mut next_tick: Option<u64> = None;
            for &i in indices.iter().rev() {
                // Bootstrap only when the next decision is a real, immediate
                // successor. Terminal = trajectory end (`next_tick` is None) or a
                // large decision gap (idle / post-goal reset). The `done` flag is
                // unusable here — the full-game replay sets it on every row.
                let nonterminal = match next_tick {
                    Some(tick)
                        if tick.saturating_sub(replay[i].tick)
                            <= SOCCER_TRAJECTORY_MAX_DECISION_GAP_TICKS =>
                    {
                        1.0
                    }
                    _ => 0.0,
                };
                let delta = reward_adv[i] + gamma * next_value * nonterminal - values[i];
                let advantage =
                    delta + gamma * SOCCER_POLICY_GAE_LAMBDA * next_advantage * nonterminal;
                advantages[i] = advantage;
                next_value = values[i];
                next_advantage = advantage;
                next_tick = Some(replay[i].tick);
            }
        }

        let mut samples: Vec<SoccerPolicySample> = replay
            .iter()
            .enumerate()
            .filter_map(|(index, transition)| {
                let rejected_counterexample =
                    learned_mpc_rejected_action_counterexample(transition);
                if !soccer_actor_policy_sample_allowed(transition) {
                    return None;
                }
                let action_index = soccer_policy_action_index(&transition.action)?;
                let advantage = if rejected_counterexample {
                    reward_adv[index] - values[index]
                } else {
                    advantages[index]
                };
                let state_features = self.policy_state_features(transition);
                let actor_probability = self
                    .policy_head
                    .as_ref()
                    .and_then(|head| head.action_distribution(&state_features))
                    .and_then(|probs| probs.get(action_index).copied());
                // Stochastic top-k selection records the true behavior policy;
                // older/deterministic rows keep their chosen-action probability
                // before falling back to the actor head.
                let old_action_probability = soccer_behavior_old_action_probability(
                    transition
                        .decision_context
                        .behavior_policy_probability
                        .filter(|probability| probability.is_finite() && *probability > 0.0)
                        .or(Some(transition.decision_context.chosen_action_probability)),
                    actor_probability,
                );
                advantage.is_finite().then(|| SoccerPolicySample {
                    state_features,
                    action_index,
                    advantage,
                    old_action_probability,
                })
            })
            .collect();

        // PPO/MAPPO advantage standardization (zero-mean / unit-variance over the batch):
        // the standard variance-reduction trick that keeps the policy-gradient step scale
        // stable across episodes with different reward magnitudes. Opt-in via the
        // advantage-normalization gate, and FORCED on when the terminal won-game reward is
        // on (its flat label needs it — see `dd_soccer_standardize_policy_advantages`).
        // Default OFF ⇒ byte-identical; a degenerate (zero-variance) batch is left untouched.
        if dd_soccer_standardize_policy_advantages() {
            let advantages: Vec<f64> = samples.iter().map(|s| s.advantage).collect();
            if let Some((mean, std)) = policy_advantage_standardization(&advantages) {
                for sample in &mut samples {
                    sample.advantage = (sample.advantage - mean) / (std + 1e-8);
                }
            }
        }
        samples
    }

    fn ensure_policy_head(&mut self) {
        if self.policy_head.is_none() {
            self.policy_head = Some(SoccerPolicyHead::new(self.config.seed));
        }
    }

    fn ensure_skill_policy_heads(&mut self) {
        if self.skill_policy_heads.is_none() {
            self.skill_policy_heads = Some(SoccerSkillPolicyHeads::new(self.config.seed));
        }
    }

    fn ensure_keeper_policy_head(&mut self) {
        if self.keeper_policy_head.is_none() {
            self.keeper_policy_head = Some(SoccerKeeperPolicyHead::new(self.config.seed));
        }
    }

    /// The current specialist-training focus: the curriculum schedule when enabled, otherwise
    /// `Joint` (every head trains every round).
    fn specialist_curriculum_focus(&self) -> SoccerSpecialistFocus {
        if dd_soccer_enable_specialist_curriculum() {
            soccer_specialist_curriculum_focus(self.specialist_curriculum_round)
        } else {
            SoccerSpecialistFocus::Joint
        }
    }

    /// The dedicated GK head's sweep-vs-set commit preference for `team`'s keeper, evaluated on the
    /// given snapshot's features. `0.0` unless the head is built and produces a finite distribution.
    pub(crate) fn keeper_commit_bias_for(&self, team: Team, snapshot: &WorldSnapshot) -> f64 {
        let Some(keeper_head) = self.keeper_policy_head.as_ref() else {
            return 0.0;
        };
        let Some(keeper_id) = self.goalkeeper_for(team) else {
            return 0.0;
        };
        let mdp_state = snapshot.mdp_state_for_player(keeper_id);
        let observation = snapshot.observation_for(keeper_id);
        let transition = self.neural_decision_transition(
            snapshot,
            keeper_id,
            team,
            PlayerRole::Goalkeeper,
            &mdp_state,
            &observation,
        );
        let features = self.policy_state_features(&transition);
        keeper_head.commit_preference(&features).unwrap_or(0.0)
    }

    /// Build one-step training samples for the dedicated goalkeeper head from a replay: each
    /// keeper transition's realised behaviour mapped to a keeper-vocabulary action, with the
    /// transition reward (now carrying the keeper save reward + concede penalty) as the advantage.
    fn neural_keeper_policy_training_samples(
        &self,
        replay: &[SoccerLearningTransition],
    ) -> Vec<SoccerKeeperPolicySample> {
        let mut samples: Vec<SoccerKeeperPolicySample> = replay
            .iter()
            .filter(|transition| transition.role == PlayerRole::Goalkeeper)
            .filter(|transition| soccer_actor_policy_sample_allowed(transition))
            .filter_map(|transition| {
                // A keeper sitting near its own goal line is holding; one well off it has come out.
                let own_goal_y = match transition.team {
                    Team::Home => 0.0,
                    Team::Away => self.config.field_length_yards,
                };
                let keeper_left_line = self
                    .players
                    .iter()
                    .find(|player| player.id == transition.player_id)
                    .map(|player| (player.home_position.y - own_goal_y).abs() < f64::INFINITY)
                    .unwrap_or(false)
                    && self
                        .players
                        .iter()
                        .find(|player| player.id == transition.player_id)
                        .map(|player| (player.position.y - own_goal_y).abs() > 6.0)
                        .unwrap_or(false);
                let action_index =
                    soccer_keeper_action_index_for(&transition.action, keeper_left_line)?;
                let advantage = transition.reward;
                if !advantage.is_finite() {
                    return None;
                }
                let state_features = self.policy_state_features(transition);
                Some(SoccerKeeperPolicySample {
                    state_features,
                    action_index,
                    advantage,
                })
            })
            .collect();
        // The keeper head uses the raw one-step reward as its advantage (no critic
        // baseline), so the flat won-game label would dominate it. When that label is on,
        // standardize the keeper batch to remove the common-mode and bound the step scale.
        // Gated on the outcome reward alone ⇒ byte-identical for every pre-existing path
        // (the keeper head never standardized before).
        if match_outcome_reward_enabled() {
            let advantages: Vec<f64> = samples.iter().map(|s| s.advantage).collect();
            if let Some((mean, std)) = policy_advantage_standardization(&advantages) {
                for sample in &mut samples {
                    sample.advantage = (sample.advantage - mean) / (std + 1e-8);
                }
            }
        }
        samples
    }

    fn ensure_world_model(&mut self) {
        if self.world_model.is_none() {
            self.world_model = Some(SoccerWorldModel::new(self.config.seed));
        }
    }

    /// `(features_t, next_state_features)` training pairs for the world model:
    /// consecutive transitions of the *same* agent, input = `(s_t ⊕ a_t)` features
    /// (the real action), target = `s_{t+1}` features (built with a null action so
    /// the model predicts the next *state*, independent of the next action). Pairs
    /// are dropped across a `done` boundary (no real successor) and where features
    /// are non-finite.
    fn neural_world_model_training_pairs(
        &self,
        replay: &[SoccerLearningTransition],
    ) -> Vec<(
        [f64; SOCCER_NEURAL_FEATURE_DIM],
        [f64; SOCCER_NEURAL_FEATURE_DIM],
    )> {
        if replay.len() < 2 {
            return Vec::new();
        }
        let mut by_agent: HashMap<(Team, usize), Vec<usize>> = HashMap::new();
        for (index, transition) in replay.iter().enumerate() {
            if learned_mpc_rejected_action_counterexample(transition) {
                continue;
            }
            by_agent
                .entry((transition.team, transition.player_id))
                .or_default()
                .push(index);
        }
        let mut pairs = Vec::new();
        for (_, mut indices) in by_agent {
            indices.sort_by_key(|&i| replay[i].tick);
            for window in indices.windows(2) {
                let (current, next) = (window[0], window[1]);
                // Only pair real, immediate successors. A zero or large decision
                // gap (idle / post-goal reset) is not a valid 1-step transition.
                // `done` is unusable here (the full-game replay sets it everywhere).
                let gap = replay[next].tick.saturating_sub(replay[current].tick);
                if gap == 0 || gap > SOCCER_TRAJECTORY_MAX_DECISION_GAP_TICKS {
                    continue;
                }
                let input = soccer_neural_transition_features(&replay[current]);
                let target = soccer_neural_transition_features_with_action(&replay[next], "");
                if input.iter().all(|v| v.is_finite()) && target.iter().all(|v| v.is_finite()) {
                    pairs.push((input, target));
                }
            }
        }
        pairs
    }

    /// One-step model-based value estimate: roll the world model forward one step
    /// from `(s, a)` and score the predicted next state with the critic, returning
    /// it in reward units. `None` when no model/critic is available or the rollout
    /// is degenerate.
    ///
    /// Approximation (MBV-PARITY-01): the world model predicts *next-state* (null
    /// action) features, but the critic was trained on action-inclusive features —
    /// so the 4 action-family channels are off-distribution here (constant 0 / the
    /// empty-action hash) relative to critic training. The other 149 channels match.
    /// This is a diagnostic look-ahead signal and does **not** drive action
    /// selection, so the small mismatch is acceptable; revisit if it ever feeds
    /// decisions (e.g. score with each candidate action's channels instead).
    pub fn model_based_value(&self, transition: &SoccerLearningTransition) -> Option<f64> {
        let world_model = self.world_model.as_ref()?;
        let learner = self.neural_learner_for(transition.team)?;
        let predicted_next =
            world_model.predict_next(&soccer_neural_transition_features(transition))?;
        let target_scale = self.config.neural_learning.sanitized_target_scale();
        learner
            .predict_value(&predicted_next)
            .map(|value| value * target_scale)
    }

    /// Model-based look-ahead value of a candidate `action` at decision time
    /// (AlphaZero/MuZero-style planning): roll the learned world model forward from
    /// the current state + this candidate action and score the predicted state with
    /// the critic. This is the decision-DRIVING generalization of
    /// [`Self::model_based_value`] — but unlike that diagnostic, which scored a
    /// NULL-action next state (the MBV-PARITY-01 approximation), this builds the
    /// step's features with the candidate's OWN action channels, so the critic sees
    /// an in-distribution input and the look-ahead can legitimately steer selection.
    ///
    /// The rollout is cheap because `predict_next`/`predict_value` are single MLP
    /// forward passes over the learned dynamics + value heads — NOT a physics
    /// re-simulation — so this stays affordable on the live decision path.
    ///
    /// - `depth == 0` → the depth-0 critic value of `(s, action)`, byte-for-byte the
    ///   same as the non-look-ahead path (`predict_value(features(s, a))`).
    /// - `depth >= 1` → predict the next state via the world model and score THAT
    ///   with the critic (a one-step rollout; multi-step latent branching over
    ///   follow-up action families is a follow-up commit).
    ///
    /// Returns RAW critic units (the caller applies `target_scale`). `None` when no
    /// critic value is available, no world model exists for a `depth >= 1` request,
    /// or a forward pass is degenerate — so the caller falls back to the depth-0
    /// value and play degrades gracefully rather than feeding garbage into selection.
    fn model_based_lookahead_value(
        &self,
        base: &SoccerLearningTransition,
        action: &str,
        learner: &SoccerNeuralLearner,
        depth: usize,
    ) -> Option<f64> {
        let features = soccer_neural_transition_features_with_action(base, action);
        if depth == 0 {
            // Depth-0 is the established direct-critic path — left unbounded to stay
            // byte-identical to the pre-look-ahead behaviour.
            return learner.predict_value(&features);
        }
        let next = self.world_model.as_ref()?.predict_next(&features)?;
        // Bound the world-model-rolled critic value to the critic's training-target range so a
        // diverging dynamics model can't drive an off-distribution critic extrapolation into
        // action selection. In-range predictions are untouched.
        let value_clip = self.config.neural_learning.sanitized_target_clip();
        learner
            .predict_value(&next)
            .map(|value| value.clamp(-value_clip, value_clip))
    }

    fn apply_full_game_learning_if_ready(&mut self) {
        if !self.config.learning_enabled
            || !self.config.full_game_learning_enabled
            || self.full_game_learning_applied
            || !self.is_done()
        {
            return;
        }

        self.full_game_learning_applied = true;
        // Terminal won-game reward (the "long" rung): label every transition with the
        // realised result when the gate is on. Off ⇒ `None`, byte-identical replay.
        let match_outcome = match_outcome_reward_enabled()
            .then(|| MatchOutcomeReward::from_score(self.score_home, self.score_away));
        let replay =
            soccer_full_game_replay_transitions(&self.episode_learning_transitions, match_outcome);
        self.full_game_learning_replay_transitions = replay.len();
        if replay.is_empty() {
            return;
        }

        // Actor-critic baseline: score every replay transition with the current
        // critic so the discrete Q trainer can subtract it as a control variate.
        // Only computed when the coupling weight is non-zero (default off).
        let critic_weight = if self.config.neural_learning.enabled {
            self.config
                .neural_learning
                .sanitized_critic_baseline_weight()
        } else {
            0.0
        };
        let critic_baselines: Option<Vec<Option<f64>>> = (critic_weight > 0.0).then(|| {
            replay
                .iter()
                .map(|transition| {
                    self.neural_value_for_transition(transition)
                        .map(|value| value * critic_weight)
                })
                .collect()
        });
        if let Some(team_policies) = &mut self.team_policies {
            match &critic_baselines {
                Some(baselines) => {
                    team_policies.train_adversarial_with_baselines(&replay, baselines)
                }
                None => team_policies.train_adversarial(&replay),
            }
        }
        if let Some(policy) = &mut self.learned_policy {
            policy.train(&replay);
        }
        // Actor (policy head): compute GAE advantages with the *current* critic
        // (before this episode's value update), then take a policy-gradient step.
        let policy_samples =
            if self.neural_blend.actor_critic && self.config.neural_learning.enabled {
                self.neural_policy_training_samples(&replay)
            } else {
                Vec::new()
            };
        // Dedicated goalkeeper head samples: keeper transitions only, one-step reward as advantage.
        let keeper_policy_samples = if self.neural_blend.actor_critic
            && self.config.neural_learning.enabled
            && dd_soccer_enable_keeper_policy_head()
        {
            self.neural_keeper_policy_training_samples(&replay)
        } else {
            Vec::new()
        };
        // World model: predict-next-state pairs from the *current* features
        // (built before the value update, like the actor's advantages).
        let world_model_pairs =
            if self.neural_blend.world_model && self.config.neural_learning.enabled {
                self.neural_world_model_training_pairs(&replay)
            } else {
                Vec::new()
            };
        self.train_neural_value_models(&replay);
        if !policy_samples.is_empty() {
            self.ensure_policy_head();
            let mappo_clip_epsilon = self
                .config
                .neural_learning
                .mappo_enabled()
                .then(|| self.config.neural_learning.sanitized_mappo_clip_epsilon());
            if let Some(policy_head) = &mut self.policy_head {
                // PPO/MAPPO sample reuse: take K clipped epochs over the same frozen
                // batch (`policy_samples` — `old_action_probability` baked in once, from
                // the behavior policy that played the game). Epoch 1's ratio ≈ 1 (clip
                // is a no-op); epochs 2..K compute the ratio against that frozen old-prob,
                // so the clipped surrogate enforces the trust region. Multi-epoch only
                // when the clip is active — re-iterating an unclipped batch would just
                // overfit it. `SOCCER_MAPPO_EPOCHS=1` ⇒ prior single-pass behavior.
                let epochs = if mappo_clip_epsilon.is_some() {
                    soccer_mappo_epochs()
                } else {
                    1
                };
                for _ in 0..epochs {
                    policy_head.train(&policy_samples, mappo_clip_epsilon);
                }
            }
            // Specialist pass/dribble/shot heads: trained on the same frozen batch but bucketed
            // by skill with balanced sizes and separate (unclipped) losses. Gated, default off.
            // Under the curriculum, a focused phase trains only the matching specialist.
            if dd_soccer_enable_skill_policy_heads() {
                self.ensure_skill_policy_heads();
                let focus = self.specialist_curriculum_focus();
                if let Some(skill_heads) = &mut self.skill_policy_heads {
                    skill_heads.train_focused(&policy_samples, focus);
                }
            }
        }
        // Dedicated goalkeeper head: trained on the keeper's own transitions (gate checked when
        // the samples were built, so a non-empty batch already implies the gate is on). Under the
        // curriculum, the keeper only trains in its focused phase or the joint phase.
        if !keeper_policy_samples.is_empty() {
            let focus = self.specialist_curriculum_focus();
            let keeper_phase = matches!(
                focus,
                SoccerSpecialistFocus::Goalkeeper | SoccerSpecialistFocus::Joint
            );
            if keeper_phase {
                self.ensure_keeper_policy_head();
                if let Some(keeper_head) = &mut self.keeper_policy_head {
                    keeper_head.train(&keeper_policy_samples);
                }
            }
        }
        // Advance the curriculum round once per actor training pass (only meaningful when the
        // curriculum is enabled; harmless otherwise).
        if !policy_samples.is_empty() || !keeper_policy_samples.is_empty() {
            self.specialist_curriculum_round = self.specialist_curriculum_round.saturating_add(1);
        }
        if !world_model_pairs.is_empty() {
            self.ensure_world_model();
            if let Some(world_model) = &mut self.world_model {
                world_model.train(&world_model_pairs);
            }
        }
    }

    pub fn controller_yield_stats(&self) -> ControllerYieldStats {
        self.controller_yield_stats
    }

    pub fn step_timing_stats(&self) -> SoccerStepTimingStats {
        self.step_timing_stats
    }

    pub fn reset_step_timing_stats(&mut self) {
        self.step_timing_stats = SoccerStepTimingStats::default();
    }

    fn clear_finished_set_play_if_needed(&mut self) {
        let should_clear = self.active_set_play.as_ref().is_some_and(|call| {
            self.tick > call.expires_tick
                || self.clock_seconds > call.expires_clock_seconds
                || (self.ball.holder.is_some()
                    && self.ball.last_touch_team == Some(call.team.other())
                    && self.pending_pass.is_none()
                    && self.pending_shot.is_none())
        });
        if should_clear {
            self.active_set_play = None;
        }
    }

    fn yield_for_controller_threads(&mut self) {
        let assigned_players = self
            .players
            .iter()
            .filter(|player| player.controller_slot.is_some())
            .count();
        if assigned_players == 0 {
            self.controller_yield_stats.record_no_assignment(
                self.human_inputs.queued_len(),
                self.human_inputs.notification_version(),
            );
            return;
        }
        let mut assigned_slots = self
            .players
            .iter()
            .filter_map(|player| player.controller_slot)
            .collect::<Vec<_>>();
        assigned_slots.sort_unstable();
        assigned_slots.dedup();
        let wait_started = Instant::now();
        let result = self.human_inputs.wait_for_pending_input_for_slots_result(
            &assigned_slots,
            Duration::from_millis(CONTROLLER_INPUT_YIELD_MS),
        );
        let wait_ms = soccer_live_duration_ms(wait_started.elapsed());
        self.controller_yield_stats
            .record_wait(assigned_players, result, wait_ms);
        thread::yield_now();
    }

    pub(crate) fn late_yield_for_controller_slot(
        &mut self,
        controller_slot: usize,
        assigned_players: usize,
        remaining_budget: &mut Duration,
    ) {
        if remaining_budget.is_zero()
            || self.human_inputs.queued_len_for_slots(&[controller_slot]) > 0
        {
            return;
        }
        let wait_for =
            (*remaining_budget).min(Duration::from_millis(CONTROLLER_INPUT_LATE_YIELD_SLICE_MS));
        if wait_for.is_zero() {
            return;
        }

        let wait_started = Instant::now();
        let result = self
            .human_inputs
            .wait_for_pending_input_for_slots_result(&[controller_slot], wait_for);
        let elapsed = wait_started.elapsed();
        *remaining_budget = remaining_budget.saturating_sub(elapsed);
        self.controller_yield_stats.record_late_wait(
            assigned_players,
            result,
            soccer_live_duration_ms(elapsed),
        );
        if result.pending() {
            thread::yield_now();
        }
    }

    pub(crate) fn player_index_for_id(&self, player_id: usize) -> Option<usize> {
        if self
            .players
            .get(player_id)
            .is_some_and(|player| player.id == player_id)
        {
            Some(player_id)
        } else {
            self.players
                .iter()
                .position(|player| player.id == player_id)
        }
    }

    fn official_index_for_id(&self, official_id: usize) -> Option<usize> {
        if let Some(default_index) = official_id.checked_sub(22) {
            if self
                .officials
                .get(default_index)
                .is_some_and(|official| official.id == official_id)
            {
                return Some(default_index);
            }
        }
        self.officials
            .iter()
            .position(|official| official.id == official_id)
    }

    pub(crate) fn player_decision_timing_context_for(
        &self,
        actor_index: usize,
        scheduled_id: usize,
    ) -> SoccerPlayerDecisionTimingContext {
        if self.ball.holder == Some(scheduled_id) {
            return SoccerPlayerDecisionTimingContext::Possession;
        }
        let player_team = self.players[actor_index].team;
        match self.ball.holder.and_then(|holder_id| {
            self.players
                .iter()
                .find(|player| player.id == holder_id)
                .map(|player| player.team)
        }) {
            Some(team) if team == player_team => SoccerPlayerDecisionTimingContext::Support,
            Some(_) => SoccerPlayerDecisionTimingContext::Defense,
            None => SoccerPlayerDecisionTimingContext::Loose,
        }
    }

    /// True if a point lies inside either 18-yard penalty area (within 18 yards of a
    /// goal line and within ~22 yards of centre — the ~44-yard-wide box). Mirrors the
    /// [`WorldSnapshot`] check; lives here so the per-tick spacing pass needs no
    /// snapshot.
    pub(crate) fn point_in_either_penalty_area(&self, p: Vec2) -> bool {
        let length = self.config.field_length_yards;
        let near_goal_line = p.y <= 18.0 || p.y >= length - 18.0;
        let central = (p.x - self.config.field_width_yards * 0.5).abs() <= 22.0;
        near_goal_line && central
    }

    fn teammate_axis_clump_pressure_at(
        &self,
        team: Team,
        position: Vec2,
        exclude_player_id: Option<usize>,
    ) -> f64 {
        if !position.x.is_finite() || !position.y.is_finite() {
            return 0.0;
        }
        let axis_radius = if self.point_in_either_penalty_area(position) {
            TEAMMATE_MIN_SPACING_BOX_YARDS
        } else {
            TEAMMATE_MIN_SPACING_YARDS
        };
        self.players
            .iter()
            .filter(|player| player.team == team && exclude_player_id != Some(player.id))
            .filter(|player| player.position.x.is_finite() && player.position.y.is_finite())
            .map(|player| {
                teammate_axis_clump_pressure_from_delta_with_radius(
                    player.position - position,
                    axis_radius,
                )
            })
            .fold(0.0, f64::max)
    }

    /// True if `p` is inside `team`'s OWN 18-yard penalty area (the box in front of the goal
    /// they defend): Home defends the y=0 end, Away the y=field_length end. Mirrors the
    /// identically-named [`WorldSnapshot`] helper, used for Law 16 goal-kick enforcement.
    pub(crate) fn point_in_own_penalty_area(&self, team: Team, p: Vec2) -> bool {
        if !p.x.is_finite()
            || !p.y.is_finite()
            || !self.config.field_width_yards.is_finite()
            || !self.config.field_length_yards.is_finite()
        {
            return false;
        }
        let central = (p.x - self.config.field_width_yards * 0.5).abs() <= 22.0;
        let near_own_line = match team {
            Team::Home => (0.0..=18.0).contains(&p.y),
            Team::Away => (self.config.field_length_yards - 18.0..=self.config.field_length_yards)
                .contains(&p.y),
        };
        central && near_own_line
    }

    /// Advances the territory-spacing clocks from the settled end-of-tick positions
    /// and, for any pair that has overstayed its grace window, marks the
    /// worse-positioned player to vacate. Read by
    /// [`Self::teammate_spacing_disciplined_intent`] on the following tick. Keepers are
    /// exempt (they own their box) and the ball carrier still counts for spacing but is
    /// never the one nudged (handled at intent time).
    pub(crate) fn update_teammate_spacing_separation(&mut self) {
        let dt = sane_dt_seconds(self.config.dt_seconds, DEFAULT_DT_SECONDS);
        let params = self.config.spacing.sanitized();
        // The live formation-LP slot per player is "your position on the field" this
        // tick: the nudge spreads toward it, and the player further from its slot is the
        // one told to move. Fall back to the static home slot when LP guidance is absent.
        let lp_anchor: HashMap<usize, Vec2> = self
            .central_brain
            .formation_lp_guidance()
            .into_iter()
            .map(|guidance| (guidance.player_id, guidance.target))
            .collect();
        let anchor_for = |id: usize, home: Vec2| lp_anchor.get(&id).copied().unwrap_or(home);

        // Snapshot the field players (keepers excluded, non-finite positions skipped) once
        // so clock mutation does not alias the position reads.
        let field: Vec<(usize, Team, Vec2, Vec2)> = self
            .players
            .iter()
            .filter(|player| {
                player.role != PlayerRole::Goalkeeper
                    && player.position.x.is_finite()
                    && player.position.y.is_finite()
            })
            .map(|player| {
                (
                    player.id,
                    player.team,
                    player.position,
                    player.home_position,
                )
            })
            .collect();

        self.teammate_spacing_yield.clear();

        for &(id, team, pos, home) in &field {
            let nearest = field
                .iter()
                .filter(|&&(other_id, other_team, _, _)| other_team == team && other_id != id)
                .map(|&(other_id, _, other_pos, other_home)| {
                    let delta = other_pos - pos;
                    let distance = (delta.x * delta.x + delta.y * delta.y).sqrt();
                    let occupied_pressure =
                        teammate_occupied_space_pressure_from_distance(distance)
                            .max(teammate_axis_clump_pressure_from_delta(delta));
                    (other_id, other_pos, other_home, distance, occupied_pressure)
                })
                // Most crowded teammate, ties broken by nearest distance and id for determinism.
                .max_by(|a, b| {
                    a.4.partial_cmp(&b.4)
                        .unwrap_or(std::cmp::Ordering::Equal)
                        .then_with(|| b.3.partial_cmp(&a.3).unwrap_or(std::cmp::Ordering::Equal))
                        .then(b.0.cmp(&a.0))
                });
            let Some((partner_id, partner_pos, partner_home, distance, _occupied_pressure)) =
                nearest
            else {
                self.teammate_spacing_near_clocks.remove(&id);
                self.teammate_spacing_far_clocks.remove(&id);
                continue;
            };

            // Inside either box the minimum-spacing radii shrink by one yard.
            let box_cut = if self.point_in_either_penalty_area(pos) {
                params.box_radius_reduction_yards
            } else {
                0.0
            };
            let near_radius = (params.near_radius_yards - box_cut).max(0.0);
            let far_radius = (params.far_radius_yards - box_cut).max(0.0);
            let axis_pressure =
                teammate_axis_clump_pressure_from_delta_with_radius(partner_pos - pos, far_radius);

            let decay = dt * params.clock_decay_rate;
            let near_elapsed =
                if distance <= near_radius || axis_pressure >= TEAMMATE_AXIS_CLUMP_NEAR_PRESSURE {
                    let elapsed = self.teammate_spacing_near_clocks.entry(id).or_insert(0.0);
                    *elapsed += dt;
                    *elapsed
                } else {
                    // Decay (not snap to zero) so brief separations don't excuse persistent
                    // crowding; a sustained break still clears it.
                    let decayed = self
                        .teammate_spacing_near_clocks
                        .get(&id)
                        .map(|elapsed| elapsed - decay)
                        .unwrap_or(0.0);
                    if decayed > 0.0 {
                        self.teammate_spacing_near_clocks.insert(id, decayed);
                        decayed
                    } else {
                        self.teammate_spacing_near_clocks.remove(&id);
                        0.0
                    }
                };
            let far_elapsed =
                if distance <= far_radius || axis_pressure > TEAMMATE_AXIS_CLUMP_PRESSURE_EPSILON {
                    let elapsed = self.teammate_spacing_far_clocks.entry(id).or_insert(0.0);
                    *elapsed += dt;
                    *elapsed
                } else {
                    let decayed = self
                        .teammate_spacing_far_clocks
                        .get(&id)
                        .map(|elapsed| elapsed - decay)
                        .unwrap_or(0.0);
                    if decayed > 0.0 {
                        self.teammate_spacing_far_clocks.insert(id, decayed);
                        decayed
                    } else {
                        self.teammate_spacing_far_clocks.remove(&id);
                        0.0
                    }
                };

            let breached = near_elapsed >= params.near_grace_seconds
                || far_elapsed >= params.far_grace_seconds;
            if !breached {
                continue;
            }
            // Both players are now past the grace window. The one further from its own
            // slot (more out of position) yields and moves; the better-placed teammate
            // holds. A symmetric nearest pair resolves to exactly one mover; ties break
            // by id. The ball carrier never yields (it is exempted at intent time), so
            // a carrier's redundant neighbour is the one that peels off.
            let my_gap = pos.distance(anchor_for(id, home));
            let partner_gap = partner_pos.distance(anchor_for(partner_id, partner_home));
            let carrier_holds = self.ball.holder == Some(partner_id);
            let i_carry = self.ball.holder == Some(id);
            let i_yield = !i_carry
                && (carrier_holds
                    || my_gap > partner_gap + 1e-6
                    || ((my_gap - partner_gap).abs() <= 1e-6 && id > partner_id));
            if i_yield {
                self.teammate_spacing_yield.insert(id, partner_id);
            }
        }
    }

    /// Applies the territory-spacing nudge to a decided intent. If this player has been
    /// told to vacate a teammate's space (see
    /// [`Self::update_teammate_spacing_separation`]) and its own plain off-ball move
    /// would keep it inside the minimum spacing, the decided target is *nudged* outward —
    /// a bounded bias away from the teammate and toward the player's own formation slot,
    /// never a replacement. The player keeps making its own movement decision; this just
    /// adds a gentle "spread out / cover your ground" pressure that resolves over a few
    /// ticks. Carriers, keepers, humans, and set-play shape are left untouched.
    pub(crate) fn teammate_spacing_disciplined_intent(
        &self,
        mut intent: PlayerIntent,
    ) -> PlayerIntent {
        let Some(&partner_id) = self.teammate_spacing_yield.get(&intent.player_id) else {
            return intent;
        };
        if self.active_set_play.is_some() {
            return intent;
        }
        // Only plain off-ball movement is nudged. A standing/holding player still
        // relocates (its "target" is its current position); ball actions pass through.
        let decided_target = match intent.action {
            SoccerAction::MoveTo(target) => Some(target),
            SoccerAction::HoldShape => None,
            _ => return intent,
        };
        let Some(me) = self
            .players
            .iter()
            .find(|player| player.id == intent.player_id)
        else {
            return intent;
        };
        if me.role == PlayerRole::Goalkeeper
            || me.controller_slot.is_some()
            || self.ball.holder == Some(me.id)
        {
            return intent;
        }
        let Some(partner) = self.players.iter().find(|player| player.id == partner_id) else {
            return intent;
        };
        let params = self.config.spacing.sanitized();
        let me_pos = me.position;
        let partner_pos = partner.position;
        let target = decided_target.unwrap_or(me_pos);

        let box_cut = if self.point_in_either_penalty_area(me_pos) {
            params.box_radius_reduction_yards
        } else {
            0.0
        };
        let min_spacing =
            (params.far_radius_yards - box_cut).max(0.0) + params.separation_margin_yards;

        // If the player's own decided move already clears the radius, it is vacating on
        // its own — leave the plan alone.
        let target_axis_pressure =
            teammate_axis_clump_pressure_from_delta_with_radius(target - partner_pos, min_spacing);
        if decided_target.is_some()
            && target.distance(partner_pos) >= min_spacing
            && target_axis_pressure <= TEAMMATE_AXIS_CLUMP_PRESSURE_EPSILON
        {
            return intent;
        }

        // How far inside the minimum-spacing ring the decided target sits. The nudge
        // closes a bounded fraction of this each tick — a bias, not a snap.
        let radial_deficit = (min_spacing - target.distance(partner_pos)).max(0.0);
        let axis_deficit = target_axis_pressure * min_spacing;
        let deficit = radial_deficit.max(axis_deficit);
        if deficit <= 1e-6 {
            return intent;
        }

        // Bias the decided target outward (away from the teammate) with a mild pull back
        // toward the player's live formation slot (LP) so it drifts into its own ground
        // rather than just scattering.
        let anchor = self
            .central_brain
            .formation_lp_guidance()
            .into_iter()
            .find(|guidance| guidance.player_id == me.id)
            .map(|guidance| guidance.target)
            .unwrap_or(me.home_position);

        let from_partner = target - partner_pos;
        let away_dir = if from_partner.len() > 1e-3 {
            from_partner.normalized()
        } else {
            let fallback = me_pos - partner_pos;
            if fallback.len() > 1e-3 {
                fallback.normalized()
            } else {
                let to_anchor = anchor - me_pos;
                if to_anchor.len() > 1e-3 {
                    to_anchor.normalized()
                } else {
                    Vec2::new(0.0, -me.team.attack_dir())
                }
            }
        };
        let anchor_dir = {
            let toward = anchor - target;
            if toward.len() > 1e-3 {
                toward.normalized()
            } else {
                away_dir
            }
        };
        let blended = away_dir * 0.75 + anchor_dir * 0.25;
        let push_dir = if blended.len() > 1e-3 {
            blended.normalized()
        } else {
            away_dir
        };
        // Bounded nudge: a fraction of the deficit, capped per tick.
        let nudge_yards = (deficit * params.nudge_bias).min(params.max_nudge_yards);
        let nudged = target + push_dir * nudge_yards;
        if !nudged.x.is_finite() || !nudged.y.is_finite() {
            return intent;
        }
        intent.action = SoccerAction::MoveTo(nudged.clamp_to_pitch(
            self.config.field_width_yards,
            self.config.field_length_yards,
        ));
        intent
    }

    /// Relational-shape nudge (integration #1): biases an off-ball player's decided move
    /// toward the position that holds its ideal offsets to its formation neighbours, so
    /// the team keeps its statistical inter-role distances and moves as a unit. It is a
    /// bounded proclivity — only the out-of-band error is corrected, a capped amount per
    /// tick — never a takeover. Players whose job is the ball (carrier, pass receiver,
    /// nearest to a loose ball), keepers, humans, and set-play shape are left to their own
    /// decision.
    /// Soft fore-aft (depth) restoring nudge that keeps adjacent positional lines
    /// (Defender → Midfielder → Forward) from compacting vertically onto each
    /// other. Returns the signed y-delta to add to the player's target (0.0 when
    /// in-band or not applicable). Computed from current line *means* so the whole
    /// line shifts coherently; each adjacent pair shares the correction (half the
    /// shortfall each) so it converges to the padding without either line
    /// over-shooting. Soft + capped — a nudge, never a hard constraint.
    pub(crate) fn relational_shape_disciplined_intent(
        &self,
        mut intent: PlayerIntent,
    ) -> PlayerIntent {
        if self.active_set_play.is_some() {
            return intent;
        }
        // The territory-spacing nudge already owns this player's move this tick; don't
        // layer a second, possibly opposing, pull on top of it.
        if self.teammate_spacing_yield.contains_key(&intent.player_id) {
            return intent;
        }
        let decided_target = match intent.action {
            SoccerAction::MoveTo(target) => Some(target),
            SoccerAction::HoldShape => None,
            _ => return intent,
        };
        let Some(me) = self
            .players
            .iter()
            .find(|player| player.id == intent.player_id)
        else {
            return intent;
        };
        if me.role == PlayerRole::Goalkeeper
            || me.controller_slot.is_some()
            || self.ball.holder == Some(me.id)
        {
            return intent;
        }
        // A player meeting a pass intended for it follows the ball, not the shape.
        if self
            .pending_pass
            .as_ref()
            .and_then(|pass| pass.target)
            .is_some_and(|receiver| receiver == me.id)
        {
            return intent;
        }
        // The likely retriever of a loose ball (nearest outfield teammate to it) chases
        // the ball, not the shape.
        if self.ball.holder.is_none() {
            let ball = self.ball.position;
            let nearest_to_ball = self
                .players
                .iter()
                .filter(|player| player.team == me.team && player.role != PlayerRole::Goalkeeper)
                .min_by(|a, b| {
                    a.position
                        .distance(ball)
                        .partial_cmp(&b.position.distance(ball))
                        .unwrap_or(std::cmp::Ordering::Equal)
                })
                .map(|player| player.id);
            if nearest_to_ball == Some(me.id) {
                return intent;
            }
        }

        let params = self.config.spacing.sanitized();
        let target = decided_target.unwrap_or(me.position);
        let roster: Vec<(usize, Team, PlayerRole, Vec2, Vec2)> = self
            .players
            .iter()
            .map(|player| {
                (
                    player.id,
                    player.team,
                    player.role,
                    player.position,
                    player.home_position,
                )
            })
            .collect();
        let mut working = target;
        // Lateral (intra-line) relational cohesion: pull a player that has drifted
        // out of its relative shape back toward its implied slot.
        if let Some(relational) =
            relational_shape_cohesion_target(&roster, me.id, me.team, me.home_position, &params)
        {
            let to_cohesive = relational - working;
            let error = to_cohesive.len();
            if error > params.relational_tolerance_yards {
                let pull = ((error - params.relational_tolerance_yards)
                    * params.relational_nudge_bias)
                    .min(params.relational_max_nudge_yards);
                let cand = working + to_cohesive.normalized() * pull;
                if cand.x.is_finite() && cand.y.is_finite() {
                    working = cand;
                }
            }
        }
        // NOTE: inter-line depth bands and ball-attraction compactness are owned by the
        // dedicated team-line and ball-proximity stages in `run_time_step`; this method
        // only does the lateral, intra-line relational cohesion pull above.
        if !working.x.is_finite() || !working.y.is_finite() {
            return intent;
        }
        if (working - target).len() <= 1e-6 {
            return intent;
        }
        intent.action = SoccerAction::MoveTo(working.clamp_to_pitch(
            self.config.field_width_yards,
            self.config.field_length_yards,
        ));
        intent
    }

    /// Enable/disable the on-ball decision-trace capture (the live "Pause & Analyze" tool).
    /// Disabling clears the buffer. Off by default; the live server turns it on.
    pub fn set_decision_trace_capture(&mut self, enabled: bool) {
        self.decision_trace_capture_enabled = enabled;
        if !enabled {
            self.decision_trace_by_player.clear();
        }
    }

    pub fn decision_trace_capture_enabled(&self) -> bool {
        self.decision_trace_capture_enabled
    }

    /// Every captured player decision (all 22 players' rings flattened), NEWEST
    /// first (index 0 = most recent tick). Only the last
    /// `SOCCER_DECISION_TRACE_WINDOW_SECONDS` of distinct decisions are returned —
    /// re-applied here so a paused match (clock frozen, no new writes pruning)
    /// still reports only the final window.
    pub fn decision_trace_recent(&self) -> Vec<LiveDecisionTraceEntry> {
        let cutoff = self.clock_seconds - SOCCER_DECISION_TRACE_WINDOW_SECONDS;
        let mut all: Vec<LiveDecisionTraceEntry> = self
            .decision_trace_by_player
            .values()
            .flat_map(|ring| ring.iter())
            .filter(|entry| entry.clock_seconds >= cutoff)
            .cloned()
            .collect();
        all.sort_by(|a, b| b.tick.cmp(&a.tick).then(a.player_id.cmp(&b.player_id)));
        all
    }

    /// Append each player's last decision to that player's ring, but ONLY when the
    /// chosen action changed from their previous recorded decision (decisions
    /// repeat every tick; we keep distinct ones so the ring spans seconds). Records
    /// ALL 22 players (on- and off-ball). The team brain is intentionally not
    /// captured — the trace is player decisions only. No-op unless capture is
    /// enabled.
    fn record_decision_trace_if_enabled(&mut self) {
        if !self.decision_trace_capture_enabled {
            return;
        }
        let tick = self.tick;
        let clock = self.clock_seconds;
        // Build this tick's per-player entries first (immutable borrow of players),
        // then fold them into the rings (mutable borrow of the map).
        let entries: Vec<LiveDecisionTraceEntry> =
            self.players
                .iter()
                .filter_map(|player| {
                    player.last_decision.as_ref().map(|decision| {
                        build_live_decision_trace_entry(player, decision, tick, clock)
                    })
                })
                .collect();
        let cutoff = clock - SOCCER_DECISION_TRACE_WINDOW_SECONDS;
        for entry in entries {
            let ring = self
                .decision_trace_by_player
                .entry(entry.player_id)
                .or_default();
            let changed = ring.back().map_or(true, |last| {
                normalize_soccer_action_label(&last.action)
                    != normalize_soccer_action_label(&entry.action)
            });
            if changed {
                ring.push_back(entry);
            }
            // Keep only the last `SOCCER_DECISION_TRACE_WINDOW_SECONDS` of decisions
            // (entries are appended in clock order, so the front is the oldest), with
            // the per-player count as a hard memory-safety backstop.
            while ring
                .front()
                .is_some_and(|front| front.clock_seconds < cutoff)
                || ring.len() > SOCCER_DECISION_TRACE_PER_PLAYER
            {
                ring.pop_front();
            }
        }
    }

    /// Persist the settled per-player MDP/POMDP/MPC decision summary for the next
    /// `run_time_step`. `WorldSnapshot`s are rebuilt many times inside one tick, so
    /// this match-owned cache is the durable bridge: the next observation can read
    /// what the player believed, chose, targeted, and what MPC reported last tick.
    fn update_player_tick_carryover(&mut self) {
        let live_player_ids = self
            .players
            .iter()
            .map(|player| player.id)
            .collect::<HashSet<_>>();
        self.player_tick_carryover
            .retain(|player_id, _| live_player_ids.contains(player_id));

        for player in &self.players {
            let Some(decision) = player.last_decision.as_ref() else {
                continue;
            };
            let previous_carryover = self.player_tick_carryover.get(&player.id);
            let same_action_ticks = previous_carryover
                .filter(|previous| {
                    normalize_soccer_action_label(&previous.action)
                        == normalize_soccer_action_label(&decision.action)
                })
                .map(|previous| previous.same_action_ticks.saturating_add(1))
                .unwrap_or(1);
            let decision_tick = decision.mdp_state.tick;
            let commitment_ticks = soccer_decision_commitment_history_after_decision(
                previous_carryover,
                &decision.action,
                decision_tick,
            );
            let observation = &decision.observation;
            let mut carryover = SoccerPlayerTickCarryover {
                player_id: player.id,
                decision_tick,
                observed_at_tick: self.tick,
                age_ticks: self.tick.saturating_sub(decision_tick),
                clock_seconds: self.clock_seconds,
                action: decision.action.clone(),
                action_target: decision.action_target.clone(),
                mdp_phase: decision.mdp_state.phase,
                mdp_ball_grid: decision.mdp_state.ball_grid,
                mdp_player_grid: decision.mdp_state.player_grid,
                mdp_receive_facing: decision.mdp_state.receive_facing,
                mdp_action_facing: decision.mdp_state.action_facing,
                pomdp_visible_ball: observation.visible_ball,
                pomdp_visible_teammates: observation.visible_teammates,
                pomdp_visible_opponents: observation.visible_opponents,
                pomdp_ball_position_confidence: finite_unit_interval(
                    observation.ball_position_confidence,
                ),
                pomdp_teammate_position_confidence: finite_unit_interval(
                    observation.teammate_position_confidence,
                ),
                pomdp_opponent_position_confidence: finite_unit_interval(
                    observation.opponent_position_confidence,
                ),
                pomdp_perceived_pressure: finite_unit_interval(observation.perceived_pressure),
                pomdp_decision_urgency: finite_unit_interval(observation.decision_urgency),
                decision_confidence: finite_unit_interval(player.decision_confidence),
                mpc_guidance_present: decision.mdp_mpc_comparison.is_some(),
                chosen_action_mpc_feasibility: decision
                    .mdp_mpc_comparison
                    .as_ref()
                    .map(|comparison| finite_unit_interval(comparison.mpc_execution_probability))
                    .unwrap_or(1.0),
                mpc_comparison: decision.mdp_mpc_comparison.clone(),
                executed_position: player.position,
                executed_velocity: player.velocity,
                executed_acceleration: player.acceleration,
                has_ball_after_action: self.ball.holder == Some(player.id),
                same_action_ticks,
                commitment_ticks,
                ticks_since_commitment: 0,
                recent_commitment_count_7_ticks: 0,
                decision_cadence_switch_locked: false,
            };
            soccer_refresh_decision_commitment_cadence(&mut carryover, self.tick);
            self.player_tick_carryover.insert(player.id, carryover);
        }
    }

    /// Arm the no-double-touch guard for the opening kickoff, lazily, on the first
    /// tick of a real match. A freshly constructed match holds the ball on the centre
    /// spot with the home kickoff taker and no recorded ball decision; we make sure
    /// the opening kickoff obeys the same no-double-touch rule as every other restart
    /// — once the taker plays it, they cannot be the next player to control it until a
    /// teammate (or opponent) has touched it.
    ///
    /// Unlike the in-game kickoffs (after a goal, start of a half) this does NOT record
    /// a "kickoff" decision, so the taker is not forced into a tick-0 held-restart
    /// release: the opening kickoff plays out through the normal policy, while the guard
    /// still forbids a double touch. Arming the guard is invisible unless the taker
    /// actually tries to re-control a loose ball, so match-start dynamics are unchanged.
    ///
    /// Doing this lazily — rather than in the constructor — keeps decision/snapshot
    /// sandbox tests untouched: they build a match and hijack the ball (a different
    /// holder, the ball off the centre spot) without ever calling the match-level step,
    /// so they never match the pristine opening-kickoff pattern below.
    fn stage_opening_kickoff_if_pending(&mut self) {
        if self.tick != 0
            || self.ball.last_decision.is_some()
            || self.restart_double_touch_guard.is_some()
        {
            return;
        }
        let Some(holder_id) = self.ball.holder else {
            return;
        };
        let center = Vec2::new(
            self.config.field_width_yards * 0.5,
            self.config.field_length_yards * 0.5,
        );
        let ball_on_spot = self.ball.position.distance(center) <= 0.25;
        let holder_on_spot = self
            .players
            .get(holder_id)
            .is_some_and(|player| player.position.distance(center) <= 0.25);
        if !ball_on_spot || !holder_on_spot {
            return;
        }
        // The kickoff taker may not touch the ball twice in a row.
        self.restart_double_touch_guard = Some(holder_id);
    }

    /// Expire stale one-two commitments at the top of the tick. A runner who has
    /// regained the ball (received the return or otherwise), a turnover to the
    /// opponent, or a return that never came within the time-out all end the
    /// give-and-go. A loose ball mid-combination (the give or return in flight) is
    /// left untouched so the run stays live until it resolves.
    fn maintain_one_two_commitments(&mut self) {
        let holder = self.ball.holder;
        let holder_team = holder
            .and_then(|h| self.players.iter().find(|p| p.id == h))
            .map(|p| p.team);
        let clock = self.clock_seconds;
        for player in self.players.iter_mut() {
            if let Some(one_two) = player.one_two {
                let turnover = holder_team.is_some() && holder_team != Some(player.team);
                let regained = holder == Some(player.id);
                let timed_out = clock - one_two.launch_clock_seconds > WALL_PASS_RUN_TTL_SECONDS;
                if turnover || regained || timed_out {
                    player.one_two = None;
                }
            }
        }
    }

    /// Resolve run-around-dribble commitments (see [`RunaroundDribble`]): clear when the attacker
    /// re-collects the ball (success), an opponent wins the loose ball (failure — the canonical
    /// turnover engine penalizes it), or the short time-out elapses. A success re-collected
    /// goal-side of the beaten defender earns the beat-the-man reward.
    fn maintain_runaround_commitments(&mut self) {
        let holder = self.ball.holder;
        let holder_team = holder
            .and_then(|h| self.players.iter().find(|p| p.id == h))
            .map(|p| p.team);
        let clock = self.clock_seconds;
        let mut clears: Vec<usize> = Vec::new();
        let mut successes: Vec<usize> = Vec::new();
        for player in self.players.iter() {
            let Some(run) = player.runaround else {
                continue;
            };
            let regained = holder == Some(player.id);
            let turnover = holder_team.is_some() && holder_team != Some(player.team);
            let timed_out = clock - run.launch_clock_seconds > RUNAROUND_TTL_SECONDS;
            if regained || turnover || timed_out {
                clears.push(player.id);
                if regained && !turnover {
                    // Success only counts if re-collected goal-side of the beaten defender.
                    let beaten = self.players.get(run.defender).map_or(true, |defender| {
                        (player.position.y - defender.position.y) * player.team.attack_dir() > 0.0
                    });
                    if beaten {
                        successes.push(player.id);
                    }
                }
            }
        }
        for id in &clears {
            if let Some(player) = self.players.get_mut(*id) {
                player.runaround = None;
            }
        }
        for id in successes {
            self.record_reward_event(id, RUNAROUND_SUCCESS_REWARD_POINTS);
        }
    }

    /// Bleed off the carrier's hold-and-summon commitment (see [`HoldForSupport`]). It is only
    /// meaningful while THIS player is on the ball, so it clears the instant the ball leaves its
    /// feet (a pass / turnover / loose ball) and on the safety TTL — the bounded pause itself is
    /// enforced in [`WorldSnapshot::hold_for_support_option_for`], which stops re-arming the wait
    /// once `HOLD_FOR_SUPPORT_MAX_HOLD_SECONDS` has elapsed.
    fn maintain_hold_for_support_commitments(&mut self) {
        let holder = self.ball.holder;
        let clock = self.clock_seconds;
        for player in self.players.iter_mut() {
            if let Some(hold) = player.hold_for_support.as_ref() {
                let still_on_the_ball = holder == Some(player.id);
                let timed_out = clock - hold.launch_clock_seconds > HOLD_FOR_SUPPORT_TTL_SECONDS;
                if !still_on_the_ball || timed_out {
                    player.hold_for_support = None;
                }
            }
        }
    }

    /// Bleed down the grounded-recovery clock of any player flat on the grass after a
    /// missed slide tackle, by one live step of `dt`, and freeze it in place while it is
    /// down (no residual coast). A prone player's decision/intent is skipped entirely in
    /// the field loop, so this is what actually keeps it pinned and counts it back up.
    fn maintain_slide_recoveries(&mut self) {
        let dt = sane_dt_seconds(self.config.dt_seconds, DEFAULT_DT_SECONDS).max(0.0);
        for player in self.players.iter_mut() {
            if player.slide_recovery_seconds > 0.0 {
                player.slide_recovery_seconds = (player.slide_recovery_seconds - dt).max(0.0);
                player.velocity = Vec2::zero();
                player.acceleration = Vec2::zero();
            }
        }
    }

    /// Advance the per-player Bayesian press belief one tick (a lightweight Beta-Bernoulli
    /// filter). For each player within contesting range of the ball we fold a soft Bernoulli
    /// observation of how strongly they are stepping toward it (closing speed toward the ball,
    /// normalized); every player also forgets toward the neutral prior, so the belief reflects
    /// the last ~tau seconds. The resulting posterior tendency shades the analytic pass-lane
    /// interception risk in [`WorldSnapshot::pass_lane_interception_risk`]. No-op (and the
    /// belief map is left empty) unless `opponent_belief_enabled`, so a disabled match is
    /// byte-identical. Deterministic (no RNG) => parity-safe.
    pub(crate) fn update_opponent_press_beliefs(&mut self, snapshot: &WorldSnapshot) {
        if !opponent_belief_enabled(&self.config) {
            return;
        }
        let dt = self.config.dt_seconds.max(0.0);
        let forget = (-dt / OPPONENT_PRESS_FORGET_TAU_SECONDS.max(1e-3)).exp();
        let ball = snapshot.ball.position;
        for p in &snapshot.players {
            let position = snapshot.player_snapshot_position(p);
            let to_ball = ball - position;
            let distance = to_ball.len();
            let observation = if distance <= OPPONENT_PRESS_OBSERVE_RADIUS_YARDS && distance > 1e-6
            {
                // Soft Bernoulli evidence: how strongly is this player closing on the ball
                // right now (proactive press) vs holding/dropping off? Compute the raw closing
                // speed first and only fold it if finite — `.max(0.0)` would otherwise silently
                // coerce a non-finite velocity into a spurious "holding" (e = 0) observation.
                let velocity = snapshot.player_velocity(p.id).unwrap_or(p.velocity);
                let closing = velocity.dot(to_ball.normalized());
                if closing.is_finite() {
                    Some((closing.max(0.0) / OPPONENT_PRESS_REFERENCE_CLOSING_YPS).clamp(0.0, 1.0))
                } else {
                    None
                }
            } else {
                None
            };
            self.opponent_press_belief
                .entry(p.id)
                .or_default()
                .step(forget, observation);
        }
    }

    /// Snapshot view of the current per-player posterior press tendency theta-hat in [0,1],
    /// copied by value into each [`WorldSnapshot`]. Empty when the belief is disabled, so
    /// consumers fall back to the analytic lane risk unchanged.
    pub(crate) fn opponent_press_tendency_map(&self) -> HashMap<usize, f64> {
        self.opponent_press_belief
            .iter()
            .map(|(id, belief)| (*id, belief.mean()))
            .collect()
    }

    pub fn run_time_step(&mut self) {
        if self.is_done() {
            return;
        }
        // Post-goal celebration: freeze play with the ball in the net for a brief
        // hold so the goal sequence completes on screen, then set up the kickoff.
        // The game clock does not advance during the hold (it is a dead ball); the
        // tick counter does, so the celebration still streams frames.
        if self.goal_celebration_remaining_ticks > 0 {
            self.goal_celebration_remaining_ticks -= 1;
            self.tick += 1;
            if self.goal_celebration_remaining_ticks == 0 {
                if let Some(team) = self.goal_celebration_kickoff_team.take() {
                    self.reset_after_goal(team);
                }
            }
            super::inspect::record_frame(self);
            return;
        }
        self.stage_opening_kickoff_if_pending();
        self.maintain_one_two_commitments();
        self.maintain_runaround_commitments();
        self.maintain_hold_for_support_commitments();
        self.maintain_slide_recoveries();
        let step_started = Instant::now();
        let mut pre_field_elapsed = Duration::from_secs(0);
        let mut pre_field_snapshot_elapsed = Duration::from_secs(0);
        let mut pre_field_adversarial_elapsed = Duration::from_secs(0);
        let mut central_brain_elapsed = Duration::from_secs(0);
        let mut controller_yield_elapsed = Duration::from_secs(0);
        let mut field_loop_elapsed = Duration::from_secs(0);
        let mut field_schedule_elapsed = Duration::from_secs(0);
        let mut field_snapshot_elapsed = Duration::from_secs(0);
        let mut field_player_decision_elapsed = Duration::from_secs(0);
        let mut field_player_possession_decision_elapsed = Duration::from_secs(0);
        let mut field_player_support_decision_elapsed = Duration::from_secs(0);
        let mut field_player_defensive_decision_elapsed = Duration::from_secs(0);
        let mut field_player_loose_decision_elapsed = Duration::from_secs(0);
        let mut field_intent_elapsed = Duration::from_secs(0);
        let mut field_official_elapsed = Duration::from_secs(0);
        let mut field_ball_elapsed = Duration::from_secs(0);
        let mut post_field_elapsed = Duration::from_secs(0);
        let mut learning_defense_elapsed = Duration::from_secs(0);
        let mut learning_transition_elapsed = Duration::from_secs(0);
        let mut recent_learning_elapsed = Duration::from_secs(0);
        let mut neural_sample_elapsed = Duration::from_secs(0);
        let mut policy_train_elapsed = Duration::from_secs(0);
        let mut learning_log_elapsed = Duration::from_secs(0);
        let mut full_game_learning_elapsed = Duration::from_secs(0);

        let pre_field_started = Instant::now();
        let phase_started = Instant::now();
        let brain_input_snapshot = WorldSnapshot::from_match_for_agent_decision(self);
        pre_field_snapshot_elapsed += phase_started.elapsed();
        // Advance the Bayesian opponent-press belief from this tick's geometry BEFORE the
        // per-player decision snapshots are built in the field loop, so pass selection reads
        // the fresh posterior. No-op when the feature is disabled. (Reuses the snapshot above
        // for geometry only — its embedded tendency map is last tick's and unused here.)
        self.update_opponent_press_beliefs(&brain_input_snapshot);
        let score_home_before = self.score_home;
        let score_away_before = self.score_away;
        // `reward_events` is a per-tick scratch buffer: every consumer reads only
        // the `[reward_event_start..]` slice recorded during this step, and the
        // events are folded into learning transitions before the step returns.
        // Clearing here (rather than letting it grow for the whole match) keeps it
        // bounded to one tick instead of accumulating unboundedly.
        self.reward_events.clear();
        let reward_event_start = self.reward_events.len();
        let phase_started = Instant::now();
        // Hand the value head's whole-field forward-intent to the brain so it
        // feeds the formation LP this tick (zero unless the blend is opted in).
        let neural_formation_intent = self.neural_formation_intent(&brain_input_snapshot);
        self.central_brain.neural_formation_intent = neural_formation_intent;
        // Fold the neural LP embedding signals into the adversarial embedding
        // signals so both the value-head formation intent and the LP-derived
        // signals reach the brain this tick.
        let adversarial_embedding_signals = merge_soccer_adversarial_embedding_signals(
            self.adversarial_embedding_signals(),
            self.neural_lp_embedding_signals(),
        );
        pre_field_adversarial_elapsed += phase_started.elapsed();
        let phase_started = Instant::now();
        self.central_brain
            .run_time_step_with_adversarial_embeddings(
                &brain_input_snapshot,
                &mut self.rng,
                adversarial_embedding_signals.as_ref(),
            );
        central_brain_elapsed += phase_started.elapsed();
        let phase_started = Instant::now();
        self.yield_for_controller_threads();
        controller_yield_elapsed += phase_started.elapsed();
        let controller_late_yield_enabled = self.controller_yield_stats.assigned_players > 0
            && !self.controller_yield_stats.last_immediate_pending
            && !self.controller_yield_stats.last_notified
            && self.controller_yield_stats.last_queued_after == 0;
        let controller_late_yield_assigned_players = self.controller_yield_stats.assigned_players;
        let mut controller_late_yield_budget = if controller_late_yield_enabled {
            Duration::from_millis(CONTROLLER_INPUT_LATE_YIELD_BUDGET_MS)
        } else {
            Duration::from_secs(0)
        };
        let phase_started = Instant::now();
        let tick_start_snapshot = WorldSnapshot::from_match_for_learning(self);
        pre_field_snapshot_elapsed += phase_started.elapsed();
        let ball_velocity_before = self.ball.velocity;
        let ball_acceleration_before = self.ball.acceleration;
        pre_field_elapsed += pre_field_started.elapsed();

        let field_loop_started = Instant::now();
        let phase_started = Instant::now();
        let mut field_schedule = self.agent_schedule_for_field_entities();
        if dd_soccer_enable_fisher_yates_schedule() {
            // Fisher-Yates: randomize the per-tick processing order of ALL field entities
            // (22 players + officials + ball) so no agent has a systematic act-first advantage when
            // contested events (possession, collisions, keep-out, shielding) resolve in schedule
            // order. Uses the match RNG, so it stays deterministic for a fixed seed.
            for i in (1..field_schedule.len()).rev() {
                let j = ((self.rng.next_float() * ((i + 1) as f64)) as usize).min(i);
                field_schedule.swap(i, j);
            }
        }
        self.last_agent_schedule = vec![AgentScheduleEntry {
            kind: AgentScheduleKind::CentralBrain,
            id: CENTRAL_BRAIN_AGENT_ID,
            label: "central brain".to_string(),
        }];
        self.last_agent_schedule.extend(field_schedule.clone());
        field_schedule_elapsed += phase_started.elapsed();

        for scheduled in &field_schedule {
            match scheduled.kind {
                AgentScheduleKind::Player => {
                    let Some(actor) = self.player_index_for_id(scheduled.id) else {
                        continue;
                    };
                    // Flat on the grass after a missed slide tackle: prone and out of the
                    // play. Make no decision and run no movement/shape pipeline this tick —
                    // `maintain_slide_recoveries` keeps it pinned and counts it back up, so
                    // the attacker advances past it unchallenged. (The defender drew no
                    // decision RNG while down; this never fires unless a slide has missed.)
                    if self.players[actor].slide_recovery_seconds > 0.0 {
                        continue;
                    }
                    // Decision-compute cadence (MPC receding-horizon decomposition): run the
                    // expensive PLANNING pass (MDP/POMDP + MPC/QP) at most a few times per `window`
                    // ticks per player, STAGGERED by id; on the other ticks the player EXECUTES its
                    // existing optimal plan — it replays the held intent and the movement model still
                    // does optimal approach to the planned target every tick (movement + ball advance
                    // on ALL ticks). Plan slow, execute fast → control stays optimal while per-tick
                    // CPU drops, so the loop holds real-time. The budget is ADAPTIVE by ball
                    // proximity: at most 3 plans / `window` ON or near the ball (where reactions
                    // matter), 2 at mid range, 1 when far off the ball — capped by `cadence_cap`
                    // (default 3, window 7 ≈ ≤3 plans per 0.47s, back-to-back allowed). Humans are
                    // never gated, and a player whose held plan is a spent one-shot
                    // (`continuation_intent()`==None, e.g. a played pass/shot/tackle) re-plans
                    // regardless.
                    let (cadence_cap, cadence_window) = soccer_decision_cadence_max_window();
                    let ball_distance = self.players[actor].position.distance(self.ball.position);
                    let proximity_budget = if self.ball.holder == Some(scheduled.id)
                        || ball_distance <= DECISION_CADENCE_NEAR_YARDS
                    {
                        3
                    } else if ball_distance <= DECISION_CADENCE_MID_YARDS {
                        2
                    } else {
                        1
                    };
                    let plan_budget = proximity_budget.min(cadence_cap);
                    let plan_this_tick = cadence_window <= plan_budget
                        || self.players[actor].controller_slot.is_some()
                        || (self.tick.wrapping_add(scheduled.id as u64) % cadence_window) < plan_budget;
                    if !plan_this_tick {
                        if let Some(held_intent) = self.players[actor].continuation_intent() {
                            self.pending_human_control = None;
                            let intent_player_id = held_intent.player_id;
                            self.apply_player_intent(held_intent);
                            if self.ball.holder == Some(intent_player_id) {
                                self.sync_held_ball_to_holder();
                            }
                            self.enforce_restart_keepout_for(intent_player_id);
                            self.enforce_shield_body_barrier_for(intent_player_id);
                            continue;
                        }
                    }
                    let decision_context =
                        self.player_decision_timing_context_for(actor, scheduled.id);
                    let phase_started = Instant::now();
                    let snapshot = match decision_context {
                        SoccerPlayerDecisionTimingContext::Possession
                        | SoccerPlayerDecisionTimingContext::Support => {
                            WorldSnapshot::from_match_for_agent_decision(self)
                        }
                        SoccerPlayerDecisionTimingContext::Defense
                        | SoccerPlayerDecisionTimingContext::Loose => {
                            WorldSnapshot::from_match_for_defensive_or_loose_agent_decision(self)
                        }
                    };
                    field_snapshot_elapsed += phase_started.elapsed();
                    let controller_slot = self.players[actor].controller_slot;
                    if let Some(slot) = controller_slot {
                        if controller_late_yield_enabled
                            && controller_late_yield_budget > Duration::from_secs(0)
                        {
                            let late_yield_started = Instant::now();
                            self.late_yield_for_controller_slot(
                                slot,
                                controller_late_yield_assigned_players,
                                &mut controller_late_yield_budget,
                            );
                            controller_yield_elapsed += late_yield_started.elapsed();
                        }
                    }
                    let phase_started = Instant::now();
                    let input_frame = controller_slot
                        .and_then(|slot| {
                            match self.human_inputs.drain_latest_for_slot_with_age(slot) {
                                Some(result) => {
                                    // Fresh input: latch the movement so it replays on the
                                    // gap ticks between frames; a release (axis ~0) un-latches
                                    // and returns the player to the AI. Commands never latch.
                                    if result.input.axis.len() > 1e-3 {
                                        let mut latched = result.clone();
                                        latched.input.pass = false;
                                        latched.input.shoot = false;
                                        latched.input.action = None;
                                        self.latched_human_inputs.insert(slot, latched);
                                    } else {
                                        self.latched_human_inputs.remove(&slot);
                                    }
                                    Some(result)
                                }
                                // No fresh input this tick: keep following the latched axis so
                                // the player stays fully under human control, not the AI.
                                None => self.latched_human_inputs.get(&slot).cloned(),
                            }
                        })
                        .filter(|frame| {
                            frame.input.player_id.is_none()
                                || frame.input.player_id == Some(scheduled.id)
                        });
                    let mdp_state = snapshot.mdp_state_for_player(scheduled.id);
                    let mut observation = snapshot.observation_for(scheduled.id);
                    if let Some(input_frame) = input_frame.as_ref() {
                        observation.human_input_queue_age_ms =
                            Some(input_frame.queue_age_ms.min(60_000));
                    }
                    let learned_decision = if self.learned_policy_inference_enabled() {
                        self.learned_action_for_player_with_context(
                            &snapshot,
                            scheduled.id,
                            &mdp_state,
                            &observation,
                        )
                    } else {
                        None
                    };
                    let intent = self.players[actor].run_time_step_with_context(
                        &snapshot,
                        mdp_state,
                        observation,
                        input_frame.as_ref().map(|frame| &frame.input),
                        learned_decision.as_ref().map(|decision| &decision.plan),
                        &mut self.rng,
                    );
                    if let Some(learned_decision) = learned_decision.as_ref() {
                        Self::stamp_learned_policy_behavior_probability(
                            &mut self.players[actor],
                            learned_decision.behavior_probability,
                        );
                    }
                    let intent = self.players[actor]
                        .apply_post_decision_movement_discipline(&snapshot, self, intent);
                    let player_decision_elapsed = phase_started.elapsed();
                    field_player_decision_elapsed += player_decision_elapsed;
                    match decision_context {
                        SoccerPlayerDecisionTimingContext::Possession => {
                            field_player_possession_decision_elapsed += player_decision_elapsed
                        }
                        SoccerPlayerDecisionTimingContext::Support => {
                            field_player_support_decision_elapsed += player_decision_elapsed
                        }
                        SoccerPlayerDecisionTimingContext::Defense => {
                            field_player_defensive_decision_elapsed += player_decision_elapsed
                        }
                        SoccerPlayerDecisionTimingContext::Loose => {
                            field_player_loose_decision_elapsed += player_decision_elapsed
                        }
                    }
                    let phase_started = Instant::now();
                    // Stage the controller's movement directive so a human-controlled
                    // player is driven responsively (tiered pace, hard brake on
                    // release) instead of through the AI movement model. An assigned
                    // controller player with no active input holds at a stop rather
                    // than handing movement back to the AI — once you take a player you
                    // keep it, and it stays put when you let go instead of wandering.
                    self.pending_human_control = match input_frame.as_ref() {
                        Some(frame) => {
                            Some(human_control_directive(intent.player_id, &frame.input))
                        }
                        None if self.players[intent.player_id].controller_slot.is_some() => {
                            Some((intent.player_id, Vec2::zero(), 0))
                        }
                        None => None,
                    };
                    let intent_player_id = intent.player_id;
                    self.apply_player_intent(intent);
                    if self.ball.holder == Some(intent_player_id) {
                        self.sync_held_ball_to_holder();
                    }
                    // Hold opponents off the ball until a held restart is played.
                    self.enforce_restart_keepout_for(intent_player_id);
                    // Block a shielded-out defender at the carrier's body so it cannot
                    // overlap the carrier / reach the ball through the body on screen.
                    self.enforce_shield_body_barrier_for(intent_player_id);
                    field_intent_elapsed += phase_started.elapsed();
                }
                AgentScheduleKind::Official => {
                    let phase_started = Instant::now();
                    let snapshot = WorldSnapshot::from_match_for_official_decision(self);
                    field_snapshot_elapsed += phase_started.elapsed();
                    if let Some(official_idx) = self.official_index_for_id(scheduled.id) {
                        let phase_started = Instant::now();
                        self.officials[official_idx].run_time_step(&snapshot, &mut self.rng);
                        field_official_elapsed += phase_started.elapsed();
                    }
                }
                AgentScheduleKind::Ball => {
                    let phase_started = Instant::now();
                    self.run_ball_time_step();
                    field_ball_elapsed += phase_started.elapsed();
                }
                AgentScheduleKind::CentralBrain => {}
            }
        }
        field_loop_elapsed += field_loop_started.elapsed();

        let phase_started = Instant::now();
        // Resolve the on-ball duel before generic body separation. Shielding,
        // exposed-ball geometry, and defender pressure decide possession while the
        // players are still in contact; collision resolution then separates bodies
        // before the held-ball sync snaps the ball to the carrier's final position.
        self.resolve_dribble_hold_up_contests();
        self.resolve_player_collisions();
        self.sync_held_ball_to_holder();
        self.ball.update_kinematics_from(
            ball_velocity_before,
            ball_acceleration_before,
            self.config.dt_seconds,
        );
        self.clock_seconds += self.config.dt_seconds;
        self.tick += 1;
        // Territorial spacing discipline (runs every step, learning or not): tick the
        // per-pair "too close for too long" clocks on the final positions and rebuild
        // this tick's spacing notices for the next tick's decisions/observations.
        self.update_teammate_spacing_proximity();
        self.record_player_position_histories();
        // Debug "Pause & Analyze" capture (no-op unless enabled): snapshot the holder's
        // just-made on-ball MDP/POMDP decision into the bounded ring buffer.
        self.record_decision_trace_if_enabled();
        // Territory-spacing: advance the teammate-proximity clocks from the settled
        // positions and flag any over-grace pair's worse-positioned player to move on
        // the next tick.
        self.update_teammate_spacing_separation();
        self.record_ball_position_history();
        self.shared_positions.sync_from_players_and_ball(
            &self.players,
            &self.officials,
            &self.ball,
            self.tick,
            self.clock_seconds,
        );
        self.clear_finished_set_play_if_needed();
        // Law 16: once the goal kick has left the penalty area it is legally in play —
        // retire the must-clear-the-box guard (runs every tick, independent of learning).
        self.update_goal_kick_clearance();
        // Body rotation / dizziness / rotational-and-involvement energy run every
        // tick on the final positions (independent of learning).
        self.update_player_facing_dizziness_energy();
        self.update_player_tick_carryover();
        // The current holder is interacting with the ball this tick (covers a long dribble,
        // where `record_possession_touch` only fired at the receive). No-op when the feature
        // is off. Touch/interception/receive events are timestamped in `record_possession_touch`.
        if wasted_energy_tracking_active() {
            if let Some(holder) = self.ball.holder {
                self.player_last_ball_interaction_tick
                    .insert(holder, self.tick);
            }
        }
        let next_snapshot = WorldSnapshot::from_match_for_learning(self);
        // Gap 5: collect line-depth RL samples off the per-tick snapshot (no-op +
        // byte-identical unless a line-depth model is enabled).
        self.collect_line_depth_rl_samples(&next_snapshot);
        // Maintain the loose-ball urgency clock (every tick) and, when the commit model
        // is enabled, collect its per-candidate RL samples (no-op + byte-identical off).
        self.update_loose_ball_urgency(&next_snapshot);
        self.collect_loose_ball_commit_rl_samples(&next_snapshot);
        // Learnable receive-approach RL samples (no-op + byte-identical unless
        // `DD_SOCCER_ENABLE_RECEIVE_APPROACH_MODEL` is set).
        self.collect_receive_approach_rl_samples(&next_snapshot);
        self.collect_long_pass_run_rl_samples(&next_snapshot);
        // Learnable attacking-spacing target RL samples (no-op + byte-identical unless
        // `DD_SOCCER_ENABLE_LEARNED_SPACING_TARGET` is set).
        self.collect_attack_spacing_rl_samples(&next_snapshot);
        // Learnable aerial-reception control RL samples (no-op + byte-identical unless
        // `DD_SOCCER_ENABLE_LEARNED_AERIAL_RECEPTION` is set).
        self.collect_aerial_reception_rl_samples(&next_snapshot);
        // Learnable shot-trigger (when to shoot) RL samples. Default-ON model, but the
        // collector is a no-op when the kill-switch `DD_SOCCER_DISABLE_SHOT_TRIGGER_MDP`
        // is set.
        self.collect_shot_trigger_rl_samples(&next_snapshot);
        self.update_possession_progress_milestones(
            &tick_start_snapshot,
            &next_snapshot,
            self.config.learning_enabled || self.config.learning_logging_enabled,
        );
        self.update_possession_chase_trackers(
            &tick_start_snapshot,
            &next_snapshot,
            self.config.learning_enabled || self.config.learning_logging_enabled,
        );
        self.update_pass_chain_continuation_rewards(
            &tick_start_snapshot,
            &next_snapshot,
            self.config.learning_enabled || self.config.learning_logging_enabled,
        );
        self.update_offside_lingering_rewards(
            &next_snapshot,
            self.config.learning_enabled || self.config.learning_logging_enabled,
        );
        post_field_elapsed += phase_started.elapsed();
        if self.config.learning_enabled || self.config.learning_logging_enabled {
            let phase_started = Instant::now();
            self.update_defensive_reward_trackers(&tick_start_snapshot, &next_snapshot);
            self.detect_and_penalize_open_play_turnover(&next_snapshot);
            self.update_defensive_clear_and_hold_reward_tracker(
                &tick_start_snapshot,
                &next_snapshot,
                true,
            );
            if self.is_done() {
                self.finish_possession_progress_chain(false);
                self.record_match_result_rewards_at(tick_start_snapshot.tick);
            }
            learning_defense_elapsed += phase_started.elapsed();
            let tick_reward_events = &self.reward_events[reward_event_start..];
            let has_tick_reward_events = !tick_reward_events.is_empty();
            let has_significant_learning_event =
                Self::has_significant_learning_event(tick_reward_events);
            let score_changed =
                self.score_home != score_home_before || self.score_away != score_away_before;
            let period_start = self.config.period_start_after_tick(self.tick);
            let interval = self.config.learning_interval_ticks.max(1);
            let capture_full_game =
                self.config.learning_enabled && self.config.full_game_learning_enabled;
            let cadence_learning_due = interval <= 1 || self.tick as usize % interval == 0;
            let learning_due = self.is_done()
                || period_start.is_some()
                || has_significant_learning_event
                || score_changed
                || cadence_learning_due;
            // Retrieval capture must retain this episode's transitions itself: the
            // n-step outcome in `config_moments()` is summed from
            // `episode_learning_transitions`, so without this a corpus-builder that
            // enables only `retrieval.capture_enabled` (full-game learning off) would
            // get silently zeroed outcomes — the "how the decision turned out" signal.
            let capture_config_moments = self.config.retrieval.capture_enabled;
            let capture_reward_transitions = has_tick_reward_events && !learning_due;
            if learning_due
                || capture_full_game
                || capture_config_moments
                || capture_reward_transitions
            {
                let phase_started = Instant::now();
                let tick_transitions = self.learning_transitions_for(
                    &tick_start_snapshot,
                    &next_snapshot,
                    score_home_before,
                    score_away_before,
                    tick_reward_events,
                );
                learning_transition_elapsed += phase_started.elapsed();
                if capture_full_game || capture_config_moments {
                    self.episode_learning_transitions
                        .extend(tick_transitions.iter().cloned());
                }
                // Retrieval corpus: capture the whole-field configuration for the
                // ball carrier's decision this tick (≤1 per tick). The outcome
                // (n-step return) is attached later by joining with the transition
                // stream retained for `config_moments`. Gated off by default.
                if capture_config_moments {
                    if let Some(holder) = tick_start_snapshot.ball.holder {
                        if let Some(carrier) =
                            tick_transitions.iter().find(|t| t.player_id == holder)
                        {
                            // Capture both comparison orderings (position-agnostic
                            // + assigned-position) from the one snapshot, sharing
                            // the configured ball-proximity weighting, so each is
                            // independently searchable downstream.
                            let weights = self.config.retrieval.weight_options();
                            let features_for = |comparison| {
                                SoccerConfigVector::from_snapshot_with(
                                    &tick_start_snapshot,
                                    carrier.team,
                                    comparison,
                                    weights,
                                )
                                .to_features()
                                .iter()
                                .map(|&f| f as f32)
                                .collect::<Vec<f32>>()
                            };
                            self.episode_config_captures.push(SoccerConfigCapture {
                                tick: tick_start_snapshot.tick,
                                player_id: holder,
                                team: carrier.team,
                                role: carrier.role,
                                action: normalize_soccer_action_label(&carrier.action).to_string(),
                                features: features_for(SoccerConfigComparison::PositionAgnostic),
                                features_assigned: features_for(
                                    SoccerConfigComparison::AssignedPosition,
                                ),
                            });
                        }
                    }
                }
                let phase_started = Instant::now();
                self.remember_recent_learning_transitions(&tick_transitions);
                recent_learning_elapsed += phase_started.elapsed();
                self.tactical_summary.record_transitions(&tick_transitions);
                if self.config.learning_logging_enabled {
                    let phase_started = Instant::now();
                    self.learning_transitions
                        .extend(tick_transitions.iter().cloned());
                    learning_log_elapsed += phase_started.elapsed();
                }
                if learning_due {
                    let mut train_transitions = tick_transitions.clone();
                    let train_limit = self.config.policy_train_max_transitions_per_tick.max(1);
                    if train_transitions.len() > train_limit {
                        let overflow = train_transitions.split_off(train_limit);
                        self.deferred_reward_transitions.extend(overflow);
                    }
                    let deferred_limit = train_limit.saturating_sub(train_transitions.len());
                    if deferred_limit > 0 && !self.deferred_reward_transitions.is_empty() {
                        let drain_count =
                            deferred_limit.min(self.deferred_reward_transitions.len());
                        let deferred = self
                            .deferred_reward_transitions
                            .drain(0..drain_count)
                            .collect::<Vec<_>>();
                        train_transitions.extend(deferred);
                    }
                    let neural_due = self.neural_learning_due(learning_due);
                    if self.config.learning_enabled {
                        let phase_started = Instant::now();
                        if let Some(team_policies) = &mut self.team_policies {
                            team_policies.train_adversarial(&train_transitions);
                        }
                        if let Some(policy) = &mut self.learned_policy {
                            policy.train(&train_transitions);
                        }
                        policy_train_elapsed += phase_started.elapsed();
                        if neural_due {
                            // Routes to the shared net or to each team's own brain
                            // (skipping frozen teams) depending on the match mode.
                            let phase_started = Instant::now();
                            self.train_neural_value_models(&train_transitions);
                            neural_sample_elapsed += phase_started.elapsed();
                        }
                    }
                } else if capture_reward_transitions {
                    self.deferred_reward_transitions.extend(tick_transitions);
                }
            }
            let phase_started = Instant::now();
            self.apply_full_game_learning_if_ready();
            full_game_learning_elapsed += phase_started.elapsed();
        }
        // Backstop: bound the deferred backlog every step regardless of the
        // learning mode (goal/turnover/out-of-bounds penalties can push from
        // paths outside the learning block).
        self.cap_deferred_reward_transitions();
        if let Some(period_number) = self.config.period_start_after_tick(self.tick) {
            self.start_new_period(period_number, kickoff_team_for_period(period_number));
        } else if self.config.is_half_boundary_tick(self.tick) {
            let half_ticks = self.config.half_ticks().max(1);
            self.reset_for_new_half((self.tick / half_ticks) as usize);
        }
        let total_elapsed = step_started.elapsed();
        let total_ms = soccer_live_duration_ms(total_elapsed);
        let learning_ms = soccer_live_duration_ms(learning_defense_elapsed)
            + soccer_live_duration_ms(learning_transition_elapsed)
            + soccer_live_duration_ms(recent_learning_elapsed)
            + soccer_live_duration_ms(neural_sample_elapsed)
            + soccer_live_duration_ms(policy_train_elapsed)
            + soccer_live_duration_ms(learning_log_elapsed)
            + soccer_live_duration_ms(full_game_learning_elapsed);
        let tick_budget_ms = finite_metric((self.config.dt_seconds * 1000.0).max(0.0));
        let learning_budget_ms = tick_budget_ms * SOCCER_LEARNING_TICK_BUDGET_RATIO;
        let over_budget = tick_budget_ms > 0.0 && total_ms > tick_budget_ms;
        let learning_over_budget = learning_budget_ms > 0.0 && learning_ms > learning_budget_ms;
        let timing_sample = SoccerStepTimingStats {
            ticks: 1,
            tick_budget_ms,
            learning_budget_ms,
            over_budget,
            learning_over_budget,
            over_budget_ticks: u64::from(over_budget),
            learning_over_budget_ticks: u64::from(learning_over_budget),
            max_budget_overrun_ms: if over_budget {
                total_ms - tick_budget_ms
            } else {
                0.0
            },
            max_learning_budget_overrun_ms: if learning_over_budget {
                learning_ms - learning_budget_ms
            } else {
                0.0
            },
            total_ms,
            pre_field_ms: soccer_live_duration_ms(pre_field_elapsed),
            pre_field_snapshot_ms: soccer_live_duration_ms(pre_field_snapshot_elapsed),
            pre_field_adversarial_ms: soccer_live_duration_ms(pre_field_adversarial_elapsed),
            central_brain_ms: soccer_live_duration_ms(central_brain_elapsed),
            controller_yield_ms: soccer_live_duration_ms(controller_yield_elapsed),
            field_loop_ms: soccer_live_duration_ms(field_loop_elapsed),
            field_schedule_ms: soccer_live_duration_ms(field_schedule_elapsed),
            field_snapshot_ms: soccer_live_duration_ms(field_snapshot_elapsed),
            field_player_decision_ms: soccer_live_duration_ms(field_player_decision_elapsed),
            field_player_possession_decision_ms: soccer_live_duration_ms(
                field_player_possession_decision_elapsed,
            ),
            field_player_support_decision_ms: soccer_live_duration_ms(
                field_player_support_decision_elapsed,
            ),
            field_player_defensive_decision_ms: soccer_live_duration_ms(
                field_player_defensive_decision_elapsed,
            ),
            field_player_loose_decision_ms: soccer_live_duration_ms(
                field_player_loose_decision_elapsed,
            ),
            field_intent_ms: soccer_live_duration_ms(field_intent_elapsed),
            field_official_ms: soccer_live_duration_ms(field_official_elapsed),
            field_ball_ms: soccer_live_duration_ms(field_ball_elapsed),
            post_field_ms: soccer_live_duration_ms(post_field_elapsed),
            learning_defense_ms: soccer_live_duration_ms(learning_defense_elapsed),
            learning_transitions_ms: soccer_live_duration_ms(learning_transition_elapsed),
            recent_learning_ms: soccer_live_duration_ms(recent_learning_elapsed),
            neural_samples_ms: soccer_live_duration_ms(neural_sample_elapsed),
            policy_train_ms: soccer_live_duration_ms(policy_train_elapsed),
            learning_log_ms: soccer_live_duration_ms(learning_log_elapsed),
            full_game_learning_ms: soccer_live_duration_ms(full_game_learning_elapsed),
            max_step_ms: soccer_live_duration_ms(total_elapsed),
            max_pre_field_ms: soccer_live_duration_ms(pre_field_elapsed),
            max_central_brain_ms: soccer_live_duration_ms(central_brain_elapsed),
            max_controller_yield_ms: soccer_live_duration_ms(controller_yield_elapsed),
            max_field_loop_ms: soccer_live_duration_ms(field_loop_elapsed),
            max_field_snapshot_ms: soccer_live_duration_ms(field_snapshot_elapsed),
            max_field_player_decision_ms: soccer_live_duration_ms(field_player_decision_elapsed),
            max_field_official_ms: soccer_live_duration_ms(field_official_elapsed),
            max_field_ball_ms: soccer_live_duration_ms(field_ball_elapsed),
            max_post_field_ms: soccer_live_duration_ms(post_field_elapsed),
            max_learning_ms: learning_ms,
        };
        self.step_timing_stats.record(timing_sample);
        if soccer_live_step_telemetry_forced() {
            eprintln!(
                concat!(
                    "# soccer-sim step telemetry tick={} totalMs={:.2} ",
                    "preFieldMs={:.2} preFieldSnapshotMs={:.2} preFieldAdversarialMs={:.2} ",
                    "centralBrainMs={:.2} controllerYieldMs={:.2} ",
                    "fieldLoopMs={:.2} fieldScheduleMs={:.2} ",
                    "fieldSnapshotMs={:.2} fieldPlayerDecisionMs={:.2} ",
                    "fieldPlayerPossessionMs={:.2} fieldPlayerSupportMs={:.2} ",
                    "fieldPlayerDefenseMs={:.2} fieldPlayerLooseMs={:.2} ",
                    "fieldIntentMs={:.2} fieldOfficialMs={:.2} fieldBallMs={:.2} ",
                    "postFieldMs={:.2} ",
                    "learningDefenseMs={:.2} learningTransitionsMs={:.2} ",
                    "recentLearningMs={:.2} neuralSamplesMs={:.2} policyTrainMs={:.2} ",
                    "learningLogMs={:.2} fullGameLearningMs={:.2}"
                ),
                self.tick,
                soccer_live_duration_ms(total_elapsed),
                soccer_live_duration_ms(pre_field_elapsed),
                soccer_live_duration_ms(pre_field_snapshot_elapsed),
                soccer_live_duration_ms(pre_field_adversarial_elapsed),
                soccer_live_duration_ms(central_brain_elapsed),
                soccer_live_duration_ms(controller_yield_elapsed),
                soccer_live_duration_ms(field_loop_elapsed),
                soccer_live_duration_ms(field_schedule_elapsed),
                soccer_live_duration_ms(field_snapshot_elapsed),
                soccer_live_duration_ms(field_player_decision_elapsed),
                soccer_live_duration_ms(field_player_possession_decision_elapsed),
                soccer_live_duration_ms(field_player_support_decision_elapsed),
                soccer_live_duration_ms(field_player_defensive_decision_elapsed),
                soccer_live_duration_ms(field_player_loose_decision_elapsed),
                soccer_live_duration_ms(field_intent_elapsed),
                soccer_live_duration_ms(field_official_elapsed),
                soccer_live_duration_ms(field_ball_elapsed),
                soccer_live_duration_ms(post_field_elapsed),
                soccer_live_duration_ms(learning_defense_elapsed),
                soccer_live_duration_ms(learning_transition_elapsed),
                soccer_live_duration_ms(recent_learning_elapsed),
                soccer_live_duration_ms(neural_sample_elapsed),
                soccer_live_duration_ms(policy_train_elapsed),
                soccer_live_duration_ms(learning_log_elapsed),
                soccer_live_duration_ms(full_game_learning_elapsed),
            );
        }
        // Keeper handling clock: with the holder/ball settled for the tick, start /
        // clear the in-hands no-steal timer and force a clearance once a keeper
        // overruns the handling time limit.
        self.update_keeper_handling();
        // Publish this tick's fully-advanced state to the zero-copy inspector ring
        // (no-op unless SOCCER_INSPECT=1). External tools read it without the
        // server serialising everything to I/O every tick.
        super::inspect::record_frame(self);
    }

    pub fn to_frame(&self) -> MatchFrame {
        self.to_frame_with_policy_traces(true)
    }

    pub(crate) fn to_live_http_frame(&self) -> MatchFrame {
        self.to_frame_with_snapshot_options(false, WorldSnapshotOptions::LIVE_HTTP_FRAME)
    }

    fn to_frame_with_policy_traces(&self, include_learned_policy_traces: bool) -> MatchFrame {
        self.to_frame_with_snapshot_options(
            include_learned_policy_traces,
            WorldSnapshotOptions::FULL,
        )
    }

    fn to_frame_with_snapshot_options(
        &self,
        include_learned_policy_traces: bool,
        snapshot_options: WorldSnapshotOptions,
    ) -> MatchFrame {
        let snapshot = WorldSnapshot::from_match_with_options(self, snapshot_options);
        let central_brain = self.central_brain.to_snapshot(&snapshot, &self.officials);
        let home_brain = self.team_brain_snapshot(Team::Home, &central_brain);
        let away_brain = self.team_brain_snapshot(Team::Away, &central_brain);
        let possession_team = central_brain
            .possession_team
            .or(self.ball.holder.and_then(|holder| {
                self.players
                    .iter()
                    .find(|player| player.id == holder)
                    .map(|player| player.team)
            }))
            .or(self.ball.last_touch_team);
        let intents = playback_intents_from_agents(
            &self.players,
            possession_team,
            self.ball.holder,
            self.config.field_width_yards,
            self.config.field_length_yards,
        );
        let schedule_lookup = AgentScheduleIndexLookup::from_entries(&self.last_agent_schedule);
        let mut players = snapshot.players.clone();
        for player in &mut players {
            if include_learned_policy_traces {
                player.learned_policy = self.learned_policy_trace_for_player(&snapshot, player.id);
            } else if self.ball.holder == Some(player.id) || player.controller_slot.is_some() {
                player.last_decision = self
                    .players
                    .iter()
                    .find(|agent| agent.id == player.id)
                    .and_then(|agent| agent.last_decision.clone());
                // Also surface the learned-policy probe + most recent learning reward
                // for the controlled/holder player so the UI shows the live policy and
                // reward (not "no policy"/"waiting").
                player.learned_policy = self.learned_policy_trace_for_player(&snapshot, player.id);
                player.recent_reward = self
                    .recent_learning_history
                    .iter()
                    .rev()
                    .find(|t| t.player_id == player.id)
                    .map(|t| t.reward);
            }
            player.scheduled_index = schedule_lookup.player(player.id);
        }
        let officials = self
            .officials
            .iter()
            .map(|o| OfficialSnapshot {
                id: o.id,
                kind: o.kind,
                position: o.position,
                position_history: o.position_history.iter().cloned().collect(),
                velocity: o.velocity,
                acceleration: o.acceleration,
                jerk: o.jerk,
                scheduled_index: schedule_lookup.official(o.id),
                offside_line: assistant_offside_line_snapshot(&snapshot, o.kind),
                last_decision: o.last_decision.clone(),
            })
            .collect();
        let ball_scheduled_index = schedule_lookup.ball();
        let mut ball = self.ball.to_state();
        ball.last_touch_player = self.last_touch_player;
        ball.scheduled_index = ball_scheduled_index;
        if let Some(decision) = ball.last_decision.as_mut() {
            if decision.scheduled_index.is_none() && ball_scheduled_index.is_some() {
                decision.scheduled_index = ball_scheduled_index;
            }
        }

        let agent_schedule = self.last_agent_schedule.clone();
        let agent_schedule_summary =
            agent_schedule_summary_for(&agent_schedule, self.players.len(), self.officials.len());

        MatchFrame {
            tick: self.tick,
            clock_seconds: self.clock_seconds,
            ball,
            ball_history: snapshot.ball_history,
            pending_pass: snapshot.pending_pass,
            pending_rebound: snapshot.pending_rebound,
            players,
            shared_positions: snapshot.shared_positions,
            officials,
            agent_schedule,
            agent_schedule_summary,
            active_set_play: self.active_set_play.clone(),
            score_home: self.score_home,
            score_away: self.score_away,
            phase: self.central_brain.phase,
            central_brain,
            home_brain,
            away_brain,
            home_directive: self.central_brain.home_directive.clone(),
            away_directive: self.central_brain.away_directive.clone(),
            intents,
        }
    }

    fn team_policy_entry_counts(&self, team: Team) -> (usize, usize) {
        self.team_policies
            .as_ref()
            .map(|policies| {
                let policy = policies.policy(team);
                (policy.q_values.len(), policy.target_values.len())
            })
            .unwrap_or((0, 0))
    }

    fn team_brain_snapshot(
        &self,
        team: Team,
        central_brain: &CentralBrainSnapshot,
    ) -> TeamBrainSnapshot {
        let directive = self.central_brain.directive_for(team).clone();
        let (policy_action_entries, policy_target_entries) = self.team_policy_entry_counts(team);
        let tracked_team_players = central_brain
            .tracked_players
            .iter()
            .filter(|player| player.team == team)
            .count();
        let controlled_human_players = central_brain
            .tracked_players
            .iter()
            .filter(|player| player.team == team && player.controller_slot.is_some())
            .count();
        let (team_centroid, team_average_velocity, team_spread_yards, players_near_ball) =
            team_brain_shape_from_awareness(
                &central_brain.tracked_players,
                team,
                central_brain.ball_position,
            );
        TeamBrainSnapshot {
            team,
            mode: team_brain_mode_for(
                team,
                self.central_brain.phase,
                central_brain.possession_team,
            ),
            phase: self.central_brain.phase,
            possession_team: central_brain.possession_team,
            in_possession: central_brain.possession_team == Some(team),
            ball_holder: central_brain.ball_holder,
            ball_position: central_brain.ball_position,
            ball_velocity: central_brain.ball_velocity,
            ball_acceleration: central_brain.ball_acceleration,
            ball_jerk: central_brain.ball_jerk,
            ball_altitude_yards: central_brain.ball_altitude_yards,
            ball_scheduled_index: central_brain.ball_scheduled_index,
            ball_last_action: central_brain.ball_last_action.clone(),
            tracked_team_players,
            controlled_human_players,
            team_centroid,
            team_average_velocity,
            team_spread_yards,
            players_near_ball,
            policy_action_entries,
            policy_target_entries,
            attacking_numbers_advantage: directive.attacking_numbers_advantage,
            attacking_overload_score: directive.attacking_overload_score,
            defensive_cover_target: directive.defensive_cover_target,
            defensive_cover_actual: directive.defensive_cover_actual,
            press_intensity: directive.press_intensity,
            risk_tolerance: directive.risk_tolerance,
            directive,
        }
    }

    fn agent_schedule_for_field_entities(&self) -> Vec<AgentScheduleEntry> {
        let mut schedule = self
            .players
            .iter()
            .map(|player| AgentScheduleEntry {
                kind: AgentScheduleKind::Player,
                id: player.id,
                label: format!("{} #{} {}", player.team.label(), player.shirt, player.name),
            })
            .collect::<Vec<_>>();
        schedule.extend(self.officials.iter().map(|official| AgentScheduleEntry {
            kind: AgentScheduleKind::Official,
            id: official.id,
            label: official.kind.label().to_string(),
        }));
        schedule.push(AgentScheduleEntry {
            kind: AgentScheduleKind::Ball,
            id: self.ball.id,
            label: "ball".to_string(),
        });
        schedule.sort_by(|a, b| {
            self.field_agent_schedule_score(b)
                .total_cmp(&self.field_agent_schedule_score(a))
                .then_with(|| {
                    Self::field_agent_schedule_kind_rank(&a.kind)
                        .cmp(&Self::field_agent_schedule_kind_rank(&b.kind))
                })
                .then_with(|| a.id.cmp(&b.id))
        });
        schedule
    }

    fn field_agent_schedule_kind_rank(kind: &AgentScheduleKind) -> usize {
        match kind {
            AgentScheduleKind::Player => 0,
            AgentScheduleKind::Official => 1,
            AgentScheduleKind::Ball => 2,
            AgentScheduleKind::CentralBrain => 3,
        }
    }

    fn field_agent_schedule_score(&self, entry: &AgentScheduleEntry) -> f64 {
        match &entry.kind {
            AgentScheduleKind::Player => self
                .players
                .iter()
                .find(|player| player.id == entry.id)
                .map(|player| self.player_field_schedule_score(player))
                .unwrap_or(-10_000.0),
            AgentScheduleKind::Official => 100.0,
            AgentScheduleKind::Ball => 0.0,
            AgentScheduleKind::CentralBrain => 10_000.0,
        }
    }

    fn player_field_schedule_score(&self, player: &PlayerAgent) -> f64 {
        let ball_distance = player.position.distance(self.ball.position).min(140.0);
        let to_ball = self.ball.position - player.position;
        let closing_speed = if to_ball.len() > 1e-6 {
            player.velocity.dot(to_ball.normalized()).max(0.0)
        } else {
            0.0
        };
        let ball_holder_team = self.ball.holder.and_then(|holder| {
            self.players
                .iter()
                .find(|candidate| candidate.id == holder)
                .map(|candidate| candidate.team)
        });
        let possession_team = self
            .central_brain
            .possession_team
            .or(ball_holder_team)
            .or(self.ball.last_touch_team);
        let mut score = 1_000.0 + (120.0 - ball_distance).max(0.0) * 4.0 + closing_speed * 6.0;
        if self.ball.holder == Some(player.id) {
            score += 800.0;
        } else if self.ball.holder.is_none() && !matches!(player.role, PlayerRole::Goalkeeper) {
            let loose_target = (self.ball.position
                + self.ball.velocity * (self.config.dt_seconds * 2.0))
                .clamp_to_pitch(
                    self.config.field_width_yards,
                    self.config.field_length_yards,
                );
            let loose_distance = player.position.distance(loose_target);
            score += (32.0 - loose_distance).max(0.0) * 8.0;
            if loose_distance <= 8.0 {
                score += 240.0;
            }
        }
        if let Some(holder_team) = ball_holder_team {
            if holder_team != player.team {
                score += (14.0 - ball_distance).max(0.0) * 12.0;
            }
        }
        if possession_team == Some(player.team) {
            score += 18.0;
        }
        if player.controller_slot.is_some() {
            score += 60.0;
        }
        if matches!(player.role, PlayerRole::Goalkeeper) && self.ball.holder != Some(player.id) {
            score -= 80.0;
        }
        score
    }

    fn mark_ball_received(&mut self, holder_id: usize) {
        mark_player_receive_facing(&mut self.players, holder_id);
        // Possession changed hands: reseed the carried-ball orbit from the new
        // carrier's geometry next tick (no winding carried over from the loser).
        self.ball.reset_carry_orbit();
    }

    fn record_reward_event(&mut self, player_id: usize, amount: f64) {
        self.record_reward_event_at(self.tick, player_id, amount);
    }

    fn record_reward_event_at(&mut self, tick: u64, player_id: usize, amount: f64) {
        self.record_reward_event_at_with_kind(
            tick,
            player_id,
            amount,
            SoccerRewardEventKind::Routine,
        );
    }

    fn record_reward_event_with_kind(
        &mut self,
        player_id: usize,
        amount: f64,
        kind: SoccerRewardEventKind,
    ) {
        self.record_reward_event_at_with_kind(self.tick, player_id, amount, kind);
    }

    fn record_reward_event_at_with_kind(
        &mut self,
        tick: u64,
        player_id: usize,
        amount: f64,
        kind: SoccerRewardEventKind,
    ) {
        // Drop non-finite amounts: `NaN.abs() <= 1e-9` is false, so without this
        // an upstream NaN/Inf would slip past the magnitude gate and pollute the
        // reward-event sum used in transition shaping.
        if !amount.is_finite() || amount.abs() <= 1e-9 || player_id >= self.players.len() {
            return;
        }
        // Sustained-effort variant: stamp the scoring team's most-recent positive-outcome tick
        // so a teammate's windowed sprint counts as "paid off" even when the sprinter never
        // personally touches the ball. Gated; zero-cost & byte-identical when off.
        if dd_soccer_enable_sustained_effort_no_outcome_penalty() && kind.is_positive_team_outcome()
        {
            let idx = team_index(self.players[player_id].team);
            if self.team_last_positive_outcome_tick[idx].map_or(true, |stamp| stamp < tick) {
                self.team_last_positive_outcome_tick[idx] = Some(tick);
            }
        }
        self.reward_events.push(SoccerRewardEvent {
            tick,
            player_id,
            amount,
            kind,
        });
    }

    pub(crate) fn has_significant_learning_event(events: &[SoccerRewardEvent]) -> bool {
        events.iter().any(|event| event.kind.triggers_learning())
    }

    pub(crate) fn record_possession_touch(&mut self, player_id: usize) {
        if player_id >= self.players.len() {
            return;
        }
        if wasted_energy_tracking_active() {
            self.player_last_ball_interaction_tick
                .insert(player_id, self.tick);
        }
        let previous_touch_team = self.previous_touch_team_for_goal();
        // Last-touch tracking + no-double-touch-on-restart: record who touched it,
        // and once any player other than the restart taker touches, clear the
        // restart guard (the taker is held-restarted into a pass, so they can't be
        // the next toucher by design).
        self.last_touch_player = Some(player_id);
        if self.restart_double_touch_guard != Some(player_id) {
            self.restart_double_touch_guard = None;
        }
        let team = self.players[player_id].team;
        if self
            .possession_progress_tracker
            .as_ref()
            .map_or(true, |tracker| tracker.team != team)
        {
            // Possession has changed hands: `finish_possession_progress_chain` also finalises
            // the consecutive-pass chain meter for the learning metrics.
            self.finish_possession_progress_chain(false);
            self.possession_chain.clear();
            self.possession_chain_previous_touch_team =
                previous_touch_team.filter(|previous_team| *previous_team != team);
            self.possession_progress_tracker = Some(PossessionProgressTracker::new_at(
                team,
                self.ball.position,
                self.clock_seconds,
            ));
        }
        if self
            .completed_pass_chain
            .back()
            .is_some_and(|entry| entry.team != team)
        {
            self.completed_pass_chain.clear();
        }
        if self
            .possession_chain
            .back()
            .is_some_and(|last_player| *last_player == player_id)
        {
            return;
        }
        self.possession_chain.push_back(player_id);
        while self.possession_chain.len() > 10 {
            self.possession_chain.pop_front();
        }
    }

    fn possession_chain_reward_sequence(
        &self,
        team: Team,
        primary_player: Option<usize>,
        max_recipients: usize,
    ) -> Vec<usize> {
        self.recent_possession_reward_sequence(team, primary_player, max_recipients)
    }

    fn record_weighted_possession_chain_reward_at(
        &mut self,
        tick: u64,
        team: Team,
        primary_player: Option<usize>,
        total_amount: f64,
        weights: &[f64],
    ) {
        if total_amount.abs() <= 1e-9 || weights.is_empty() {
            return;
        }
        let recipients = self.possession_chain_reward_sequence(team, primary_player, weights.len());
        if recipients.is_empty() {
            return;
        }
        let weight_total = weights.iter().take(recipients.len()).sum::<f64>();
        if weight_total <= 1e-9 || !weight_total.is_finite() {
            return;
        }
        for (player_id, weight) in recipients.into_iter().zip(weights.iter().copied()) {
            self.record_reward_event_at(tick, player_id, total_amount * weight / weight_total);
        }
    }

    pub(crate) fn finish_possession_progress_chain(&mut self, ended_with_goal: bool) {
        self.finish_possession_progress_chain_at(self.tick, ended_with_goal);
    }

    fn finish_possession_progress_chain_at(&mut self, tick: u64, ended_with_goal: bool) {
        // A possession sequence ending is exactly when the consecutive-pass chain ends, so
        // finalise the learning-metrics chain meter here. This covers EVERY possession-end /
        // reset path uniformly (turnover, goal, half-time, kickoff, dead ball), so an open
        // chain can never leak across a possession boundary or a half. Idempotent (the meter is
        // taken), and independent of whether a possession-progress tracker is present.
        self.finalize_pass_chain_metrics();
        let Some(tracker) = self.possession_progress_tracker.take() else {
            return;
        };
        if ended_with_goal || !tracker.qualifies_for_stall_penalty() {
            return;
        }
        self.record_weighted_possession_chain_reward_at(
            tick,
            tracker.team,
            None,
            -POSSESSION_STALL_PENALTY_POINTS,
            &POSSESSION_STALL_PENALTY_WEIGHTS,
        );
    }

    pub(crate) fn note_completed_possession_pass(
        &mut self,
        team: Team,
        origin: Vec2,
        controlled_end: Vec2,
    ) {
        if self
            .possession_progress_tracker
            .as_ref()
            .map_or(true, |tracker| tracker.team != team)
        {
            self.possession_progress_tracker = Some(PossessionProgressTracker::new_at(
                team,
                origin,
                self.clock_seconds,
            ));
        }
        if let Some(tracker) = self.possession_progress_tracker.as_mut() {
            tracker.completed_passes = tracker.completed_passes.saturating_add(1);
            tracker.update_gain(controlled_end);
            tracker.update_completed_pass_chain_gain(controlled_end);
        }
    }

    pub fn mpc_latent_objective(&self, team: Team) -> SoccerMpcLatentObjective {
        match team {
            Team::Home => self.home_mpc_latent_objective,
            Team::Away => self.away_mpc_latent_objective,
        }
        .sanitized()
    }

    fn mpc_latent_objective_mut(&mut self, team: Team) -> &mut SoccerMpcLatentObjective {
        match team {
            Team::Home => &mut self.home_mpc_latent_objective,
            Team::Away => &mut self.away_mpc_latent_objective,
        }
    }

    fn update_mpc_latent_objective(
        &mut self,
        team: Team,
        pass_chain_continuity: Option<f64>,
        shot_pressure: Option<f64>,
        goal_pressure: Option<f64>,
    ) {
        if !self.config.mpc.latent_objective_enabled {
            return;
        }
        let current = self.mpc_latent_objective(team);
        let target = SoccerMpcLatentObjective {
            pass_chain_continuity: pass_chain_continuity
                .map(finite_unit_interval)
                .unwrap_or(current.pass_chain_continuity),
            shot_pressure: shot_pressure
                .map(finite_unit_interval)
                .unwrap_or(current.shot_pressure),
            goal_pressure: goal_pressure
                .map(finite_unit_interval)
                .unwrap_or(current.goal_pressure),
            // This feeder only updates continuity/shot/goal; keep the pattern intents as-is.
            ..current
        };
        let updated = current.blended_with(target, self.config.mpc.latent_learning_rate);
        *self.mpc_latent_objective_mut(team) = updated;
    }

    /// Blend ONLY the wall-pass / through-ball pattern intents of the MPC latent toward the given
    /// unit targets (1.0 = the pattern just succeeded on this pass, 0.0 = it did not), leaving
    /// continuity/shot/goal pressure untouched. No-op unless the latent objective is enabled.
    fn note_mpc_pattern_latent(&mut self, team: Team, wall_pass: f64, through_ball: f64) {
        if !self.config.mpc.latent_objective_enabled {
            return;
        }
        let current = self.mpc_latent_objective(team);
        let target = SoccerMpcLatentObjective {
            wall_pass_intent: finite_unit_interval(wall_pass),
            through_ball_intent: finite_unit_interval(through_ball),
            ..current
        };
        let updated = current.blended_with(target, self.config.mpc.latent_learning_rate);
        *self.mpc_latent_objective_mut(team) = updated;
    }

    pub(crate) fn update_possession_progress_milestones(
        &mut self,
        before: &WorldSnapshot,
        after: &WorldSnapshot,
        record_rewards: bool,
    ) {
        let Some(team) = after.controlled_possession_team() else {
            return;
        };
        if self
            .possession_progress_tracker
            .as_ref()
            .map_or(true, |tracker| tracker.team != team)
        {
            self.possession_progress_tracker = Some(PossessionProgressTracker::new_at(
                team,
                before.ball.position,
                before.clock_seconds,
            ));
        }
        let mut earned = 0usize;
        if let Some(tracker) = self.possession_progress_tracker.as_mut() {
            tracker.update_gain(after.ball.position);
            let milestone_count = (tracker.best_completed_pass_chain_gain_yards
                / POSSESSION_PROGRESS_MILESTONE_YARDS)
                .floor() as usize;
            if milestone_count > tracker.rewarded_milestones {
                earned = milestone_count - tracker.rewarded_milestones;
                tracker.rewarded_milestones = milestone_count;
            }
        }
        if record_rewards {
            for _ in 0..earned {
                self.record_weighted_possession_chain_reward_at(
                    before.tick,
                    team,
                    after.ball.holder,
                    POSSESSION_PROGRESS_REWARD_POINTS,
                    &POSSESSION_PROGRESS_REWARD_WEIGHTS,
                );
            }
        }
    }

    /// Attacking-overload score [0,1] for `team` from its current tactical directive — how big a
    /// numbers advantage the team holds in the threat lane right now. Forced to 0.0 when the
    /// overload-weighted-progression gate is OFF, so callers stay byte-identical by default.
    fn overload_progression_weight(&self, team: Team) -> f64 {
        if !dd_soccer_enable_overload_weighted_progression() {
            return 0.0;
        }
        let score = self
            .central_brain
            .directive_for(team)
            .attacking_overload_score;
        if !score.is_finite() {
            return 0.0;
        }
        score.clamp(0.0, 1.0)
    }

    /// Additive reward for a completed forward pass that carried the ball forward into a numbers
    /// advantage — the forward yardage of the reception, capped, scaled by the attacking overload.
    /// 0.0 when the gate is off, when there is no overload, or when the ball did not go forward.
    fn overload_forward_pass_progression_bonus(&self, pass: &PendingPass, end: Vec2) -> f64 {
        let overload = self.overload_progression_weight(pass.team);
        let forward_yards = (end.y - pass.origin.y) * pass.team.attack_dir();
        overload_forward_pass_progression_points(
            forward_yards,
            overload,
            overload_forward_pass_progression_reward_per_yard(),
        )
    }

    /// Multiplier applied to a forward pass-chain event reward, uplifting it when the chain was
    /// played into a numbers advantage. 1.0 (no change) when the gate is off or there is no overload.
    fn overload_pass_chain_event_multiplier(&self, team: Team) -> f64 {
        overload_pass_chain_event_multiplier_for(
            self.overload_progression_weight(team),
            overload_pass_chain_event_bonus_fraction(),
        )
    }

    pub(crate) fn record_completed_pass_reward(&mut self, pass: &PendingPass, receiver: usize) {
        let Some(passer) = self.players.get(pass.from) else {
            return;
        };
        let Some(receiver_player) = self.players.get(receiver) else {
            return;
        };
        if pass.from == receiver || passer.team != pass.team || receiver_player.team != pass.team {
            return;
        }

        let killer_pass_reward = completed_killer_pass_reward(
            pass,
            receiver_player,
            self.config.field_width_yards,
            self.config.field_length_yards,
        );
        let amount = completed_pass_reward_for_pitch(
            pass.team,
            pass.origin,
            pass.intended_target,
            self.config.field_width_yards,
            self.config.field_length_yards,
        ) + completed_pass_anticipation_reward(pass)
            + completed_cross_reward(
                pass,
                receiver_player,
                self.config.field_width_yards,
                self.config.field_length_yards,
            )
            + killer_pass_reward
            + self.completed_pass_and_move_forward_reward(pass)
            + progressive_pass_escape_reward(pass, self.ball.position)
            + self.overload_forward_pass_progression_bonus(pass, self.ball.position);
        self.record_reward_event(pass.from, amount);
        if pass.is_cross {
            match pass.team {
                Team::Home => self.stats.crosses_completed_home += 1,
                Team::Away => self.stats.crosses_completed_away += 1,
            }
        }
        self.record_possession_touch(pass.from);
        self.record_possession_touch(receiver);
        self.note_completed_possession_pass(pass.team, pass.origin, self.ball.position);
        self.record_completed_pass_chain_entry(pass, receiver);
        self.note_mpc_completed_pass_chain_latent(pass.team, receiver);
        self.record_completed_wall_pass_reward(pass, receiver);
        self.record_combination_run_reward(pass, receiver);
        // Feed the MPC pattern latents so the (opt-in) latent objective biases execution toward
        // these patterns. No-op unless mpc.latent_objective_enabled, so zero cost on the default path.
        if self.config.mpc.latent_objective_enabled {
            let is_wall = self
                .players
                .get(receiver)
                .and_then(|runner| runner.one_two.as_ref())
                .is_some_and(|one_two| one_two.wall_partner == pass.from);
            self.note_mpc_pattern_latent(
                pass.team,
                if is_wall { 1.0 } else { 0.0 },
                if killer_pass_reward > 0.0 { 1.0 } else { 0.0 },
            );
        }
    }

    /// Extra credit for completing a WALL PASS (one-two / give-and-go): the receiver of this pass is
    /// the player who earlier laid the ball off and burst forward, and the current passer is the
    /// "wall" returning it first-time. The generic per-pass reward treats this as two ordinary short
    /// passes; crediting the give->burst->return PATTERN (both players) gives the POMDP a learnable
    /// signal to PREFER one-twos. Gated; default ON, byte-identical to baseline when disabled.
    fn record_completed_wall_pass_reward(&mut self, pass: &PendingPass, receiver: usize) {
        if dd_soccer_disable_wall_pass_reward() {
            return;
        }
        // This pass is the RETURN leg only if the receiver is mid-one-two and named THIS passer as
        // its wall. (one_two persists from the give until the runner regains the ball, so it still
        // names the partner at the instant the return is resolved.)
        let is_return = self
            .players
            .get(receiver)
            .and_then(|runner| runner.one_two.as_ref())
            .is_some_and(|one_two| one_two.wall_partner == pass.from);
        if !is_return {
            return;
        }
        let attack_dir = pass.team.attack_dir();
        let forward = (self.ball.position.y - pass.origin.y) * attack_dir;
        let openness = pass.receiver_openness.clamp(0.0, 1.0);
        let bonus = ((COMPLETED_WALL_PASS_BASE_BONUS_POINTS
            + forward.max(0.0) * COMPLETED_WALL_PASS_FORWARD_REWARD_PER_YARD)
            * (0.5 + 0.5 * openness))
            .clamp(0.0, COMPLETED_WALL_PASS_MAX_BONUS_POINTS);
        if bonus <= 1e-9 || !bonus.is_finite() {
            return;
        }
        // The runner (who beat the man via the one-two) gets full credit; the wall a share.
        self.record_reward_event(receiver, bonus);
        self.record_reward_event(pass.from, bonus * COMPLETED_WALL_PASS_WALL_CREDIT_SHARE);
    }

    fn pass_and_move_run_lane_score_from(
        &self,
        team: Team,
        origin: Vec2,
        exclude_player_id: Option<usize>,
    ) -> f64 {
        let attack_dir = team.attack_dir();
        let lane_y = PASS_AND_MOVE_RUN_LANE_REFERENCE_YARDS;
        let lane_x = 5.0;
        let candidates = [
            origin + Vec2::new(0.0, attack_dir * lane_y),
            origin + Vec2::new(lane_x, attack_dir * lane_y * 0.86),
            origin + Vec2::new(-lane_x, attack_dir * lane_y * 0.86),
        ];
        candidates
            .into_iter()
            .map(|raw| {
                let target = raw.clamp_to_pitch(
                    self.config.field_width_yards,
                    self.config.field_length_yards,
                );
                let opponent_score = pass_and_move_run_lane_score_from_distance(
                    self.players
                        .iter()
                        .filter(|player| player.team != team)
                        .map(|player| player.position.distance(target))
                        .fold(50.0_f64, f64::min),
                );
                let teammate_space = self
                    .players
                    .iter()
                    .filter(|player| player.team == team && Some(player.id) != exclude_player_id)
                    .map(|player| player.position.distance(target))
                    .fold(50.0_f64, f64::min);
                let open_space_score = (teammate_space / 18.0).clamp(0.0, 1.0);
                (opponent_score * 0.74 + open_space_score * 0.26).clamp(0.0, 1.0)
            })
            .fold(0.0_f64, f64::max)
    }

    fn completed_pass_and_move_forward_reward(&self, pass: &PendingPass) -> f64 {
        let numbers_advantage = pass_and_move_numbers_advantage_fit(
            self.central_brain
                .directive_for(pass.team)
                .attacking_numbers_advantage as f64,
        );
        if numbers_advantage <= 1e-6 {
            return 0.0;
        }
        let run_lane_score =
            self.pass_and_move_run_lane_score_from(pass.team, pass.origin, Some(pass.from));
        pass_and_move_forward_reward_from_parts(
            pass.team,
            pass.flight,
            pass.is_cross,
            pass.origin,
            self.ball.position,
            pass.receiver_openness,
            numbers_advantage,
            run_lane_score,
        )
    }

    /// Distinct credit to a RECEIVER who completes a combination via an off-ball forward RUN: a
    /// THIRD-MAN run (a prior pass fed this passer; the receiver is the running third man) or an
    /// OVERLAP (the receiver arrived wider than and beyond the passer on the same flank). Gated on
    /// the receiver actually moving forward onto the ball so it rewards the RUN, not a static
    /// outlet. Complements the passer-side "pass into stride" reward (which credits the passer).
    /// Gated; default ON, byte-identical to baseline when disabled.
    fn record_combination_run_reward(&mut self, pass: &PendingPass, receiver: usize) {
        if dd_soccer_disable_combination_run_reward() {
            return;
        }
        // Crosses / lofted balls have their own rewards; this targets ground combination play.
        if pass.is_cross || pass.flight.is_aerial() {
            return;
        }
        // Already credited as a one-two return — don't double-count.
        let is_one_two = self
            .players
            .get(receiver)
            .and_then(|r| r.one_two.as_ref())
            .is_some_and(|o| o.wall_partner == pass.from);
        if is_one_two {
            return;
        }
        let attack_dir = pass.team.attack_dir();
        let recv_pos = self.ball.position;
        let passer_pos = pass.origin;
        let forward = (recv_pos.y - passer_pos.y) * attack_dir;
        if forward < COMBINATION_RUN_MIN_FORWARD_YARDS {
            return;
        }
        // The receiver must be RUNNING forward onto the ball (an off-ball run), not standing.
        let runner_forward_velocity = pass
            .receiver_velocity_at_launch
            .map_or(0.0, |v| v.y * attack_dir);
        if runner_forward_velocity < COMBINATION_RUN_MIN_RUNNER_FORWARD_VELOCITY_YPS {
            return;
        }
        // THIRD-MAN: a recent completed pass fed THIS passer from a different player.
        let third_man = self
            .recent_completed_pass_chain_into(pass.team, pass.from, 1)
            .first()
            .is_some_and(|link| link.from != receiver);
        // OVERLAP: the runner arrived meaningfully wider than the passer on the SAME flank.
        let half_width = self.config.field_width_yards * 0.5;
        let passer_side = passer_pos.x - half_width;
        let recv_side = recv_pos.x - half_width;
        let same_flank = recv_side.abs() > 1e-3 && passer_side.signum() == recv_side.signum();
        let overlap =
            same_flank && recv_side.abs() > passer_side.abs() + COMBINATION_OVERLAP_MIN_WIDER_YARDS;
        if !third_man && !overlap {
            return;
        }
        let openness = pass.receiver_openness.clamp(0.0, 1.0);
        let bonus = ((COMBINATION_RUN_BASE_POINTS
            + forward.min(COMBINATION_RUN_FORWARD_CAP_YARDS)
                * COMBINATION_RUN_FORWARD_REWARD_PER_YARD)
            * (0.5 + 0.5 * openness))
            .clamp(0.0, COMBINATION_RUN_MAX_POINTS);
        if bonus <= 1e-9 || !bonus.is_finite() {
            return;
        }
        // Credit the RUNNER who completed the combination with their off-ball movement.
        self.record_reward_event(receiver, bonus);
    }

    fn recent_completed_pass_chain_into(
        &self,
        team: Team,
        receiver: usize,
        max_depth: usize,
    ) -> Vec<CompletedPassChainEntry> {
        let mut chain = Vec::new();
        let mut current_receiver = receiver;
        while chain.len() < max_depth {
            let Some(entry) = self
                .completed_pass_chain
                .iter()
                .rev()
                .find(|entry| {
                    let age_seconds = self.clock_seconds - entry.clock_seconds;
                    entry.team == team
                        && entry.to == current_receiver
                        && (0.0..=PASS_CHAIN_MAX_CONTINUATION_SECONDS).contains(&age_seconds)
                        && !chain.iter().any(|existing: &CompletedPassChainEntry| {
                            existing.tick == entry.tick
                                && existing.from == entry.from
                                && existing.to == entry.to
                        })
                })
                .cloned()
            else {
                break;
            };
            current_receiver = entry.from;
            chain.push(entry);
        }
        chain
    }

    fn mark_pass_chain_continuation_rewarded(&mut self, entry: &CompletedPassChainEntry) {
        if let Some(stored) = self.completed_pass_chain.iter_mut().rev().find(|stored| {
            stored.team == entry.team
                && stored.from == entry.from
                && stored.to == entry.to
                && stored.tick == entry.tick
        }) {
            stored.continuation_rewarded = true;
        }
    }

    fn queue_recent_significant_reward_transition(
        &mut self,
        player_id: usize,
        amount: f64,
        kind: SoccerRewardEventKind,
    ) {
        if !self.config.learning_enabled || amount <= 1e-9 || !amount.is_finite() {
            return;
        }
        let Some(mut transition) = self
            .recent_learning_history
            .iter()
            .rev()
            .take_while(|transition| {
                self.tick.saturating_sub(transition.tick) <= PASS_CHAIN_EVENT_CREDIT_MAX_AGE_TICKS
            })
            .find(|transition| {
                transition.player_id == player_id
                    && soccer_goal_credit_action_is_relevant(&transition.action)
            })
            .cloned()
        else {
            return;
        };
        transition.reward = amount;
        transition.done = false;
        if transition.tick != self.tick {
            self.record_reward_event_at_with_kind(transition.tick, player_id, amount, kind);
        }
        self.deferred_reward_transitions.push(transition);
    }

    fn record_significant_pass_chain_rewards(
        &mut self,
        chain: &[CompletedPassChainEntry],
        total_amount: f64,
        kind: SoccerRewardEventKind,
    ) {
        if chain.is_empty() || total_amount <= 1e-9 || !total_amount.is_finite() {
            return;
        }

        let player_count = self.players.len();
        let mut credits: Vec<(usize, f64)> = Vec::new();
        let mut add_credit = |player_id: usize, amount: f64| {
            if amount <= 1e-9 || player_id >= player_count {
                return;
            }
            if let Some((_, total)) = credits
                .iter_mut()
                .find(|(existing_player, _)| *existing_player == player_id)
            {
                *total += amount;
            } else {
                credits.push((player_id, amount));
            }
        };

        for (index, entry) in chain.iter().enumerate() {
            let link_weight = match (chain.len(), index) {
                (2, 0) => 0.56,
                (2, 1) => 0.44,
                (3, 0) => 0.44,
                (3, 1) => 0.34,
                (3, 2) => 0.22,
                _ => 1.0 / chain.len() as f64,
            };
            let link_amount = total_amount * link_weight;
            add_credit(entry.from, link_amount * 0.78);
            add_credit(entry.to, link_amount * 0.22);
        }

        for (player_id, amount) in credits {
            self.record_reward_event_with_kind(player_id, amount, kind);
            self.queue_recent_significant_reward_transition(player_id, amount, kind);
        }
    }

    fn record_completed_pass_chain_entry(&mut self, pass: &PendingPass, receiver: usize) {
        let direction = pass_direction_bucket(pass.team, pass.origin, pass.intended_target);
        if direction == PassDirectionBucket::Forward {
            let previous_chain = self.recent_completed_pass_chain_into(pass.team, pass.from, 1);
            if let Some(previous) = previous_chain.first() {
                let amount = pass_chain_link_reward(previous.direction, 1);
                self.record_reward_event(previous.from, amount);
            }
        }

        self.completed_pass_chain
            .push_back(CompletedPassChainEntry {
                team: pass.team,
                from: pass.from,
                to: receiver,
                direction,
                receiver_openness: pass.receiver_openness,
                target_forward_yards: (pass.intended_target.y - pass.origin.y)
                    * pass.team.attack_dir(),
                origin: pass.origin,
                end: self.ball.position,
                tick: self.tick,
                clock_seconds: self.clock_seconds,
                continuation_rewarded: false,
            });
        while self.completed_pass_chain.len() > PASS_CHAIN_HISTORY_LIMIT {
            self.completed_pass_chain.pop_front();
        }
        let chain = self.recent_completed_pass_chain_into(pass.team, receiver, 3);
        if chain.len() >= 2
            && chain[0].direction == PassDirectionBucket::Forward
            && chain[1].direction == PassDirectionBucket::Forward
        {
            self.record_significant_pass_chain_rewards(
                &chain[..2],
                PASS_CHAIN_TWO_FORWARD_EVENT_REWARD_POINTS
                    * self.overload_pass_chain_event_multiplier(pass.team),
                SoccerRewardEventKind::TwoForwardPasses,
            );
        }
        if chain.len() >= 3 {
            let net_forward_yards = (chain[0].end.y - chain[2].origin.y) * pass.team.attack_dir();
            if net_forward_yards >= PASS_CHAIN_THREE_NET_FORWARD_MIN_YARDS {
                self.record_significant_pass_chain_rewards(
                    &chain[..3],
                    PASS_CHAIN_THREE_NET_FORWARD_EVENT_REWARD_POINTS
                        * self.overload_pass_chain_event_multiplier(pass.team),
                    SoccerRewardEventKind::ThreePassForwardNetGain,
                );
            }
        }
        // The entry above is now part of the chain, so a sterile run that ends on this pass
        // (the ball tapped around inside a tiny pocket without escaping) is penalized here.
        self.record_stagnant_pass_penalty(pass.team, Some(pass.from));
    }

    fn note_mpc_completed_pass_chain_latent(&mut self, team: Team, receiver: usize) {
        let chain = self.recent_completed_pass_chain_into(team, receiver, 3);
        let Some(_) = chain.first() else {
            return;
        };
        let chain_target = match chain.len() {
            0 => 0.0,
            1 => MPC_LATENT_PASS_CHAIN_SINGLE_TARGET,
            2 => MPC_LATENT_PASS_CHAIN_TWO_TARGET,
            _ => MPC_LATENT_PASS_CHAIN_THREE_TARGET,
        };
        let forward_fit = (chain
            .iter()
            .map(|entry| entry.target_forward_yards.max(0.0))
            .sum::<f64>()
            / 30.0)
            .clamp(0.0, 1.0);
        let openness_fit = if chain.is_empty() {
            0.0
        } else {
            chain
                .iter()
                .map(|entry| entry.receiver_openness.clamp(0.0, 1.0))
                .sum::<f64>()
                / chain.len() as f64
        };
        let latent_target =
            (chain_target * 0.70 + forward_fit * 0.20 + openness_fit * 0.10).clamp(0.0, 1.0);
        self.update_mpc_latent_objective(team, Some(latent_target), None, None);
    }

    /// Size of the maximal run of trailing same-possession completed passes whose reception
    /// points all stayed within STAGNANT_PASS_RADIUS_YARDS of the run's starting ball
    /// position, together with the worst interceptability (1 - receiver openness) seen across
    /// that run. A run of STAGNANT_PASS_MIN_RUN+ means the possession is tapping the ball
    /// around inside a tiny pocket.
    pub(crate) fn trailing_stagnant_pass_run(&self, team: Team) -> (usize, f64) {
        let mut entries: Vec<&CompletedPassChainEntry> = Vec::new();
        for entry in self.completed_pass_chain.iter().rev() {
            if entry.team != team {
                break;
            }
            let age_seconds = self.clock_seconds - entry.clock_seconds;
            if !(0.0..=PASS_CHAIN_MAX_CONTINUATION_SECONDS).contains(&age_seconds) {
                break;
            }
            entries.push(entry);
        }
        // `entries` is most-recent first. For each candidate window length, anchor on the
        // earliest pass's origin and require every reception in the window to stay inside the
        // radius. Keep the largest window that qualifies.
        let mut best_run = 0;
        let mut worst_interceptability = 0.0_f64;
        for run in STAGNANT_PASS_MIN_RUN..=entries.len() {
            let window = &entries[0..run];
            let anchor = window[run - 1].origin;
            let contained = window
                .iter()
                .all(|entry| entry.end.distance(anchor) <= STAGNANT_PASS_RADIUS_YARDS);
            if contained {
                best_run = run;
                worst_interceptability = window
                    .iter()
                    .map(|entry| 1.0 - entry.receiver_openness.clamp(0.0, 1.0))
                    .fold(0.0_f64, f64::max);
            }
        }
        (best_run, worst_interceptability)
    }

    /// Detect a possession that is being recycled between a tiny set of players without the
    /// ball progressing goalward — the ball ping-ponging between the same ~2 men for 4+ passes
    /// while staying "level" with them. Returns an urgency in [0,1] (0 = not recycled) plus the
    /// set of players the run has bounced between, so the carrier's pass scoring can tilt toward
    /// a forward ball to a NEW player and demote handing it straight back to a recycle partner.
    ///
    /// Unlike `trailing_stagnant_pass_run`, this is NOT a tight ball-travel pocket: a square ball
    /// played 10 yards and immediately returned never "escapes the players", so this keys on the
    /// distinct PLAYER set and the run's net goalward gain, catching wider back-and-forth that
    /// the pocket detector misses.
    pub(crate) fn recycled_possession_urgency(&self, team: Team) -> (f64, Vec<usize>) {
        let mut entries: Vec<&CompletedPassChainEntry> = Vec::new();
        for entry in self.completed_pass_chain.iter().rev() {
            if entry.team != team {
                break;
            }
            let age_seconds = self.clock_seconds - entry.clock_seconds;
            if !(0.0..=PASS_CHAIN_MAX_CONTINUATION_SECONDS).contains(&age_seconds) {
                break;
            }
            entries.push(entry);
        }
        // `entries` is most-recent first. Grow the trailing window while the distinct player set
        // (each pass contributes its `from` and `to`) stays at or under the cap, and keep the
        // largest qualifying window. A run of 4+ passes bouncing among <= 2 players whose net
        // goalward gain is under the progress threshold is a recycled, non-progressing possession.
        let attack_dir = team.attack_dir();
        let mut best_run = 0;
        let mut best_participants: Vec<usize> = Vec::new();
        let mut participants: Vec<usize> = Vec::new();
        for (idx, entry) in entries.iter().enumerate() {
            for id in [entry.from, entry.to] {
                if !participants.contains(&id) {
                    participants.push(id);
                }
            }
            if participants.len() > RECYCLED_POSSESSION_MAX_DISTINCT {
                break;
            }
            let run = idx + 1;
            if run < RECYCLED_POSSESSION_MIN_RUN {
                continue;
            }
            // Net goalward gain across this window: earliest origin -> most recent reception.
            let anchor_y = entries[run - 1].origin.y;
            let latest_y = entries[0].end.y;
            let net_forward = (latest_y - anchor_y) * attack_dir;
            if net_forward <= RECYCLED_POSSESSION_PROGRESS_YARDS {
                best_run = run;
                best_participants = participants.clone();
            }
        }
        if best_run < RECYCLED_POSSESSION_MIN_RUN {
            return (0.0, Vec::new());
        }
        let urgency = (RECYCLED_POSSESSION_URGENCY_BASE
            + (best_run - RECYCLED_POSSESSION_MIN_RUN) as f64 * RECYCLED_POSSESSION_URGENCY_STEP)
            .clamp(0.0, 1.0);
        (urgency, best_participants)
    }

    /// Penalize a sterile pocket-passing run that ends on the just-recorded pass. The penalty
    /// compounds with the length of the run and with how interceptable the balls were (a
    /// short ball that risked a turnover yet still didn't advance is the worst), distributed
    /// back across the recent possession contributors.
    fn record_stagnant_pass_penalty(&mut self, team: Team, primary_player: Option<usize>) {
        let (run, interceptability) = self.trailing_stagnant_pass_run(team);
        if run < STAGNANT_PASS_MIN_RUN {
            return;
        }
        let extra = (run - STAGNANT_PASS_MIN_RUN) as f64 * STAGNANT_PASS_RUN_PENALTY_STEP;
        let risk_multiplier = 1.0 + interceptability.clamp(0.0, 1.0);
        let penalty =
            ((STAGNANT_PASS_BASE_PENALTY + extra) * risk_multiplier).min(STAGNANT_PASS_PENALTY_CAP);
        self.record_weighted_possession_chain_reward_at(
            self.tick,
            team,
            primary_player,
            -penalty,
            &STAGNANT_PASS_PENALTY_WEIGHTS,
        );
    }

    pub(crate) fn record_interception_reward(
        &mut self,
        interceptor: usize,
        intercepted_pass: Option<&PendingPass>,
    ) {
        self.record_reward_event(interceptor, 10.0);
        self.record_possession_touch(interceptor);
        if let Some(pass) = intercepted_pass {
            let penalty = intercepted_pass_passer_penalty(pass, self.config.field_length_yards);
            self.record_reward_event(pass.from, -penalty);
            // The intercepted team just turned the ball over — penalize its last ~5s.
            self.penalize_turnover_window(pass.team);
        }
    }

    fn record_quick_receiver_dispossession_penalty(&mut self, receiver: usize) {
        let Some(entry) = self
            .completed_pass_chain
            .iter()
            .rev()
            .find(|entry| entry.to == receiver)
            .cloned()
        else {
            return;
        };
        let age_seconds = self.clock_seconds - entry.clock_seconds;
        let penalty = quick_receiver_dispossession_passer_penalty(&entry, age_seconds);
        if penalty > 0.0 {
            self.record_reward_event(entry.from, -penalty);
        }
    }

    pub(crate) fn record_duel_rewards(&mut self, winner: usize) {
        if winner >= self.players.len() {
            return;
        }
        let winner_team = self.players[winner].team;
        let ball_position = self.ball.position;
        let contenders = self
            .players
            .iter()
            .filter(|player| {
                player.position.distance(ball_position) <= PLAYER_CONTROL_RADIUS_YARDS + 1.35
            })
            .map(|player| (player.id, player.team))
            .collect::<Vec<_>>();
        let has_teammate = contenders.iter().any(|(_, team)| *team == winner_team);
        let has_opponent = contenders.iter().any(|(_, team)| *team != winner_team);
        if !has_teammate || !has_opponent {
            return;
        }
        self.record_reward_event(winner, 6.0);
        for (player_id, team) in contenders {
            if team != winner_team {
                self.record_reward_event(player_id, -LOST_FIFTY_FIFTY_DUEL_PENALTY_POINTS);
            }
        }
    }

    fn record_untargeted_long_ball_outcome(
        &mut self,
        long_ball: Option<ResolvedUntargetedLongBall>,
        holder: usize,
        holder_team: Team,
    ) {
        let Some(long_ball) = long_ball else {
            return;
        };
        if long_ball.launcher_id >= self.players.len()
            || long_ball.launcher_id == holder
            || self.players[long_ball.launcher_id].team != long_ball.team
        {
            return;
        }

        let attack_dir = long_ball.team.attack_dir();
        let control_position = self.ball.position;
        let forward_yards = (control_position.y - long_ball.origin.y) * attack_dir;
        let intended_forward_yards = (long_ball.target.y - long_ball.origin.y) * attack_dir;
        let own_goal_relief = ball_distance_from_own_goal(
            long_ball.team,
            control_position,
            self.config.field_length_yards,
        ) - ball_distance_from_own_goal(
            long_ball.team,
            long_ball.origin,
            self.config.field_length_yards,
        );
        let outcome_fit = (forward_yards.max(own_goal_relief).max(0.0) / 44.0).clamp(0.0, 1.0);
        let intent_fit = (intended_forward_yards.max(0.0) / 44.0).clamp(0.0, 1.0);
        let distance_fit = (long_ball.distance_yards / 50.0).clamp(0.0, 1.0);
        let age_ticks = self.tick.saturating_sub(long_ball.launch_tick);
        let freshness = (1.0 - age_ticks as f64 / 180.0).clamp(0.45, 1.0);
        let action_scale = match normalize_soccer_action_label(&long_ball.action) {
            "clearance" => 0.92,
            "route-one" => 1.08,
            _ => 1.0,
        };

        let amount = if holder_team == long_ball.team {
            UNTARGETED_LONG_BALL_RECOVERY_REWARD_POINTS
                * (0.34 + outcome_fit * 0.36 + intent_fit * 0.18 + distance_fit * 0.12)
                * freshness
                * action_scale
        } else {
            -UNTARGETED_LONG_BALL_LOSS_PENALTY_POINTS
                * (0.42 + (1.0 - outcome_fit) * 0.36 + (1.0 - intent_fit) * 0.14)
                * freshness
                * action_scale
        };
        self.record_reward_event(long_ball.launcher_id, amount);
    }

    fn recent_possession_reward_sequence(
        &self,
        team: Team,
        primary_player: Option<usize>,
        max_recipients: usize,
    ) -> Vec<usize> {
        fn push_unique(sequence: &mut Vec<usize>, player_id: usize, max_recipients: usize) {
            if sequence.len() < max_recipients && !sequence.contains(&player_id) {
                sequence.push(player_id);
            }
        }

        let max_recipients = max_recipients.max(1);
        let mut sequence = Vec::new();
        if let Some(primary_player) = primary_player {
            if self
                .players
                .get(primary_player)
                .is_some_and(|player| player.team == team)
            {
                push_unique(&mut sequence, primary_player, max_recipients);
            }
        }

        for player_id in self
            .possession_chain
            .iter()
            .rev()
            .copied()
            .take(max_recipients * 2)
        {
            if self
                .players
                .get(player_id)
                .is_some_and(|player| player.team == team)
            {
                push_unique(&mut sequence, player_id, max_recipients);
            }
        }
        sequence
    }

    fn record_possession_reward_pattern(
        &mut self,
        team: Team,
        primary_player: Option<usize>,
        pattern: &[f64],
    ) {
        self.record_possession_reward_pattern_with_kind(
            team,
            primary_player,
            pattern,
            SoccerRewardEventKind::Routine,
        );
    }

    fn record_possession_reward_pattern_with_kind(
        &mut self,
        team: Team,
        primary_player: Option<usize>,
        pattern: &[f64],
        kind: SoccerRewardEventKind,
    ) {
        if pattern.is_empty() {
            return;
        }
        let sequence = self.recent_possession_reward_sequence(team, primary_player, pattern.len());
        for (player_id, amount) in sequence.into_iter().zip(pattern.iter().copied()) {
            self.record_reward_event_with_kind(player_id, amount, kind);
        }
    }

    pub(crate) fn record_shot_on_target_rewards(&mut self, shooting_team: Team, shooter: usize) {
        self.record_possession_touch(shooter);
        debug_assert!(
            (SHOT_ON_TARGET_REWARD_PATTERN.iter().sum::<f64>() - SHOT_ON_TARGET_REWARD_POINTS)
                .abs()
                < 1e-9
        );
        let scale = self.shot_reward_distance_scale(shooting_team, shooter);
        let contextual_pool = SHOT_ON_TARGET_REWARD_POINTS * scale;
        if self.record_contextual_attacking_rewards(
            shooting_team,
            Some(shooter),
            contextual_pool,
            SoccerRewardEventKind::ShotOnTarget,
        ) {
            self.update_mpc_latent_objective(shooting_team, None, Some(scale), None);
            return;
        }
        let scaled: Vec<f64> = SHOT_ON_TARGET_REWARD_PATTERN
            .iter()
            .map(|w| w * scale)
            .collect();
        self.record_possession_reward_pattern_with_kind(
            shooting_team,
            Some(shooter),
            &scaled,
            SoccerRewardEventKind::ShotOnTarget,
        );
        self.update_mpc_latent_objective(shooting_team, None, Some(scale), None);
    }

    fn record_goalkeeper_save_reward(&mut self, shot: &PendingShot, keeper_id: usize) {
        let Some(keeper) = self.players.iter().find(|player| player.id == keeper_id) else {
            return;
        };
        if keeper.role != PlayerRole::Goalkeeper || keeper.team == shot.team {
            return;
        }

        let attacked_goal = Vec2::new(
            self.config.field_width_yards * 0.5,
            shot.team.goal_y(self.config.field_length_yards),
        );
        let danger = (1.0
            - shot.origin.distance(attacked_goal) / GOALKEEPER_SAVE_DANGER_REFERENCE_YARDS)
            .clamp(0.0, 1.0);
        let amount =
            GOALKEEPER_SAVE_BASE_REWARD_POINTS + GOALKEEPER_SAVE_DANGER_REWARD_POINTS * danger;
        self.record_reward_event_with_kind(
            keeper_id,
            amount,
            SoccerRewardEventKind::GoalkeeperSave,
        );

        if !self.config.learning_enabled {
            return;
        }
        let Some(mut transition) = self
            .recent_learning_history
            .iter()
            .rev()
            .find(|transition| {
                transition.player_id == keeper_id && transition.role == PlayerRole::Goalkeeper
            })
            .cloned()
        else {
            return;
        };
        transition.reward = amount;
        transition.done = false;
        if transition.tick != self.tick {
            self.record_reward_event_at_with_kind(
                transition.tick,
                keeper_id,
                amount,
                SoccerRewardEventKind::GoalkeeperSave,
            );
        }
        self.deferred_reward_transitions.push(transition);
    }
    /// xG-prevented danger scale `∈ [KEEPER_SAVE_DANGER_FLOOR, 1.0]` for a shot the keeper
    /// just denied. Maximal for close, central efforts (high scoring chance), tapering to the
    /// floor for tame long-range / wide-angle ones. `shot_origin` is the shot's launch point;
    /// `defending_team` owns the goal being protected.
    fn keeper_save_danger_scale(&self, shot_origin: Vec2, defending_team: Team) -> f64 {
        let own_goal_y = match defending_team {
            Team::Home => 0.0,
            Team::Away => self.config.field_length_yards,
        };
        let goal_center = Vec2::new(self.config.field_width_yards * 0.5, own_goal_y);
        let dist = shot_origin.distance(goal_center);
        // Distance term: 1.0 inside the full-danger radius, linearly to 0 at the 18-yd box.
        let taper_span = (18.0 - KEEPER_SAVE_FULL_DANGER_DISTANCE_YARDS).max(1.0);
        let distance_danger = (1.0
            - (dist - KEEPER_SAVE_FULL_DANGER_DISTANCE_YARDS).max(0.0) / taper_span)
            .clamp(0.0, 1.0);
        // Angle term: a central effort is more dangerous than one from a tight angle. Penalise
        // lateral offset relative to how far out the shot is (a wide shot from deep is harmless).
        let lateral = (shot_origin.x - goal_center.x).abs();
        let depth = (shot_origin.y - own_goal_y).abs().max(1.0);
        let angle_danger =
            (1.0 - (lateral / (depth + lateral)).clamp(0.0, 1.0) * 0.6).clamp(0.0, 1.0);
        (distance_danger * angle_danger).clamp(0.0, 1.0) * (1.0 - KEEPER_SAVE_DANGER_FLOOR)
            + KEEPER_SAVE_DANGER_FLOOR
    }

    /// Credit the goalkeeper for a shot-stop, scaled by xG-prevented danger and the security
    /// of the outcome (`action_scale`: 1.0 for a clean catch/save, less for a parry/smother that
    /// only deflected the danger). Gated by `DD_SOCCER_ENABLE_KEEPER_SAVE_REWARD` — default off
    /// ⇒ no reward event emitted, baseline byte-identical. See [`dd_soccer_enable_keeper_save_reward`].
    fn record_keeper_save_reward(
        &mut self,
        keeper_id: usize,
        shot_origin: Vec2,
        defending_team: Team,
        action_scale: f64,
    ) {
        if !dd_soccer_enable_keeper_save_reward() {
            return;
        }
        let danger = self.keeper_save_danger_scale(shot_origin, defending_team);
        let amount = KEEPER_SAVE_REWARD_POINTS * danger * action_scale.clamp(0.0, 1.0);
        self.record_reward_event_with_kind(keeper_id, amount, SoccerRewardEventKind::KeeperSave);
    }

    /// Distance scale for a shot-on-target's CHAIN reward: it backprops credit to the build-up
    /// chain only for a genuine chance FROM WITHIN ~20yd (the user's "reward shooting closer"
    /// rule). Full inside `SHOT_FULL_REWARD_DISTANCE_YARDS`, then linearly to ZERO at the 20yd
    /// pivot, and none beyond — so an on-target effort from distance no longer reward-credits the
    /// attacking chain (it is also reward-penalised at decision time; see the shot-distance shaping).
    pub(crate) fn shot_reward_distance_scale(&self, shooting_team: Team, shooter: usize) -> f64 {
        self.players
            .iter()
            .find(|p| p.id == shooter)
            .map(|p| {
                let attack_dir = shooting_team.attack_dir();
                let goal_y = if attack_dir > 0.0 {
                    self.config.field_length_yards
                } else {
                    0.0
                };
                let goal = Vec2::new(self.config.field_width_yards * 0.5, goal_y);
                let dist = p.position.distance(goal);
                let taper_span =
                    (SHOT_DISTANCE_REWARD_PIVOT_YARDS - SHOT_FULL_REWARD_DISTANCE_YARDS).max(1.0);
                (1.0 - (dist - SHOT_FULL_REWARD_DISTANCE_YARDS).max(0.0) / taper_span)
                    .clamp(0.0, 1.0)
            })
            .unwrap_or(1.0)
    }

    /// Accuracy penalty for a missed shot: nothing inside the forgiveness margin, then a
    /// small per-yard bite (capped) for every yard the ball crossed the line wide of the
    /// post. Teaches the policy to hit the frame instead of blazing it wide.
    pub(crate) fn record_shot_off_target_penalty(
        &mut self,
        shooting_team: Team,
        shooter: usize,
        off_target_yards: f64,
    ) {
        let _ = shooting_team;
        if !off_target_yards.is_finite() {
            return;
        }
        let over = off_target_yards - SHOT_OFF_TARGET_FORGIVENESS_YARDS;
        if over <= 0.0 {
            return;
        }
        let penalty =
            (over * SHOT_OFF_TARGET_PENALTY_PER_YARD).min(SHOT_OFF_TARGET_MAX_PENALTY_POINTS);
        self.record_reward_event(shooter, -penalty);
    }

    /// A shot OFF the frame still earns a small attempt reward (10 vs the on-frame
    /// 40), distance-tapered the same way.
    fn record_shot_off_target_rewards(&mut self, shooting_team: Team, shooter: usize) {
        self.record_possession_touch(shooter);
        let scale = self.shot_reward_distance_scale(shooting_team, shooter)
            * (SHOT_OFF_TARGET_REWARD_POINTS / SHOT_ON_TARGET_REWARD_POINTS);
        let scaled: Vec<f64> = SHOT_ON_TARGET_REWARD_PATTERN
            .iter()
            .map(|w| w * scale)
            .collect();
        self.record_possession_reward_pattern(shooting_team, Some(shooter), &scaled);
    }

    fn current_goal_credit_transition(&self, player_id: usize) -> Option<SoccerLearningTransition> {
        let player = self.players.iter().find(|player| player.id == player_id)?;
        let decision = player.last_decision.as_ref()?;
        if !soccer_goal_credit_action_is_relevant(&decision.action) {
            return None;
        }
        let snapshot = WorldSnapshot::from_match(self);
        Some(SoccerLearningTransition {
            tick: decision.mdp_state.tick,
            player_id,
            team: player.team,
            role: player.role,
            state: decision.mdp_state.clone(),
            observation: decision.observation.clone(),
            belief: decision.belief.clone(),
            action: decision.action.clone(),
            action_target: decision.action_target.clone(),
            decision_context: soccer_decision_context_with_trace(
                player.id,
                player.team,
                decision,
                &snapshot,
                &snapshot,
            ),
            tactical_trace: SoccerTacticalLearningTrace::default(),
            reward: 0.0,
            next_state: snapshot.mdp_state_for_player(player_id),
            next_observation: snapshot.observation_for(player_id),
            done: self.is_done(),
        })
    }

    fn contextual_goal_credit_candidates(
        &self,
        scoring_team: Team,
        shooter: Option<usize>,
    ) -> Vec<SoccerGoalCreditCandidate> {
        let mut candidates = Vec::new();
        let mut seen_players = Vec::new();

        if let Some(shooter) = shooter {
            if let Some(transition) = self.current_goal_credit_transition(shooter) {
                if transition.team == scoring_team {
                    let score = soccer_goal_credit_transition_score(&transition, 0);
                    if score >= GOAL_CONTEXT_CREDIT_MIN_SCORE {
                        seen_players.push(shooter);
                        candidates.push(SoccerGoalCreditCandidate { transition, score });
                    }
                }
            }
        }

        let mut scanned = 0usize;
        for transition in self.recent_learning_history.iter().rev() {
            if scanned >= GOAL_CONTEXT_CREDIT_SCAN_ACTIONS {
                break;
            }
            scanned += 1;
            if transition.team != scoring_team || seen_players.contains(&transition.player_id) {
                continue;
            }
            if !soccer_goal_credit_action_is_relevant(&transition.action) {
                continue;
            }
            let age_ticks = self.tick.saturating_sub(transition.tick);
            if age_ticks > GOAL_CONTEXT_CREDIT_MAX_AGE_TICKS {
                continue;
            }
            let score = soccer_goal_credit_transition_score(transition, age_ticks);
            if score < GOAL_CONTEXT_CREDIT_MIN_SCORE {
                continue;
            }
            seen_players.push(transition.player_id);
            candidates.push(SoccerGoalCreditCandidate {
                transition: transition.clone(),
                score,
            });
        }

        candidates.sort_by(|a, b| {
            b.score
                .partial_cmp(&a.score)
                .unwrap_or(std::cmp::Ordering::Equal)
        });
        candidates.truncate(GOAL_CONTEXT_CREDIT_MAX_PLAYERS);
        candidates
    }

    fn record_contextual_attacking_rewards(
        &mut self,
        attacking_team: Team,
        shooter: Option<usize>,
        reward_pool: f64,
        kind: SoccerRewardEventKind,
    ) -> bool {
        if reward_pool <= 1e-9 || !reward_pool.is_finite() {
            return false;
        }
        let candidates = self.contextual_goal_credit_candidates(attacking_team, shooter);
        if candidates.len() < GOAL_CONTEXT_CREDIT_MIN_PLAYERS {
            return false;
        }
        let total_score = candidates
            .iter()
            .map(|candidate| candidate.score)
            .sum::<f64>();
        if total_score <= 1e-9 || !total_score.is_finite() {
            return false;
        }

        for candidate in candidates {
            let amount = reward_pool * candidate.score / total_score;
            if !amount.is_finite() || amount <= 1e-9 {
                continue;
            }
            let mut transition = candidate.transition;
            transition.reward = amount;
            transition.done = false;
            if transition.tick != self.tick {
                self.record_reward_event_at_with_kind(
                    transition.tick,
                    transition.player_id,
                    amount,
                    kind,
                );
            }
            self.deferred_reward_transitions.push(transition);
        }
        true
    }

    fn record_contextual_goal_rewards(
        &mut self,
        scoring_team: Team,
        shooter: Option<usize>,
        goal_reward_pool: f64,
    ) -> bool {
        self.record_contextual_attacking_rewards(
            scoring_team,
            shooter,
            goal_reward_pool,
            SoccerRewardEventKind::Goal,
        )
    }

    fn previous_touch_team_for_goal(&self) -> Option<Team> {
        self.last_touch_player
            .and_then(|player_id| self.players.get(player_id).map(|player| player.team))
            .or(self.ball.last_touch_team)
    }

    fn direct_turnover_goal_reward_points(
        &self,
        scoring_team: Team,
        shooter: Option<usize>,
        previous_touch_team: Option<Team>,
    ) -> Option<f64> {
        let shooter = shooter?;
        let previous_touch_team = self
            .possession_chain_previous_touch_team
            .or(previous_touch_team);
        if previous_touch_team != Some(scoring_team.other()) {
            return None;
        }
        if !self
            .players
            .get(shooter)
            .is_some_and(|player| player.team == scoring_team)
        {
            return None;
        }
        let mut scoring_team_touches = self.possession_chain.iter().copied().filter(|player_id| {
            self.players
                .get(*player_id)
                .is_some_and(|player| player.team == scoring_team)
        });
        if scoring_team_touches.next() == Some(shooter) && scoring_team_touches.next().is_none() {
            Some(DIRECT_TURNOVER_GOAL_REWARD_POINTS)
        } else {
            None
        }
    }

    /// Latch a "live cross" window when an **aerial cross is released from the flank in the
    /// attacking final third** under the situational crash-the-box recognizer, and pay the small
    /// bounded shaped reward to attackers already crashed into the box for the delivery. A no-op
    /// (byte-identical) unless `DD_SOCCER_ENABLE_FLANK_CRASH_BOX` is on. See [`crash_box`].
    pub(crate) fn register_flank_crash_box_cross(
        &mut self,
        team: Team,
        crosser: usize,
        origin: Vec2,
        is_cross: bool,
        flight: PassFlight,
    ) {
        if !crash_box::flank_crash_box_enabled()
            || self.active_set_play.is_some()
            || !(is_cross && flight.is_aerial())
        {
            return;
        }
        let length = self.config.field_length_yards;
        let width = self.config.field_width_yards;
        if !crash_box::flank_final_third_crash_box_geometry(
            origin,
            team.goal_y(length),
            width,
            length,
        ) {
            return;
        }
        self.flank_crash_box_cross = Some(crash_box::FlankCrashBoxCross {
            team,
            crosser,
            released_tick: self.tick,
        });
        self.reward_flank_crash_box_arrivals(team, crosser);
    }

    /// Pay [`crash_box::CRASH_BOX_ARRIVAL_SHAPED_POINTS`] (budget-bounded, split evenly) to this
    /// team's attackers already inside the opponent box as the cross is released, when at least
    /// [`crash_box::CRASH_BOX_ARRIVAL_MIN_RUNNERS`] of them have crashed in. Deterministic.
    fn reward_flank_crash_box_arrivals(&mut self, team: Team, crosser: usize) {
        let opponent_box_team = team.other();
        let mut crashers: Vec<usize> = self
            .players
            .iter()
            .filter(|player| {
                player.team == team
                    && player.id != crosser
                    && matches!(player.role, PlayerRole::Forward | PlayerRole::Midfielder)
                    && self.point_in_own_penalty_area(opponent_box_team, player.position)
            })
            .map(|player| player.id)
            .collect();
        crashers.sort_unstable();
        if crashers.len() < crash_box::CRASH_BOX_ARRIVAL_MIN_RUNNERS {
            return;
        }
        let total = apply_dense_shaping_budget(
            crash_box::CRASH_BOX_ARRIVAL_SHAPED_POINTS,
            tunables().reward.dense_shaping_budget_points,
        );
        let share = total / crashers.len() as f64;
        for id in crashers {
            self.record_reward_event_with_kind(id, share, SoccerRewardEventKind::CrashBoxArrival);
        }
    }

    /// Credit the terminal [`crash_box::HEADER_GOAL_FROM_CROSS_BONUS_POINTS`] bonus when the goal
    /// just scored was a **headed finish off a live flank crash-the-box cross**: the bonus is
    /// split between the header scorer and the deliverer of the cross (its assist share), so
    /// MARL/MAPPO reinforces the entire wide-delivery → bodies-in-the-box → header pattern.
    /// Returns `true` when the bonus was paid. A no-op unless the feature is on.
    fn record_flank_crash_box_header_goal(&mut self, scoring_team: Team, shooter: Option<usize>) -> bool {
        if !crash_box::flank_crash_box_enabled() {
            return false;
        }
        let Some(cross) = self.flank_crash_box_cross else {
            return false;
        };
        let Some(shooter) = shooter else {
            return false;
        };
        let dt = self.config.dt_seconds;
        let aerial_finish_now = self
            .pending_aerial_finish
            .is_some_and(|(id, tick)| id == shooter && tick == self.tick);
        if cross.team != scoring_team
            || !cross.is_open_at(self.tick, dt)
            || !aerial_finish_now
        {
            return false;
        }
        let assist = (crash_box::HEADER_GOAL_FROM_CROSS_BONUS_POINTS
            * crash_box::HEADER_GOAL_FROM_CROSS_ASSIST_SHARE)
            .max(0.0);
        let finisher = (crash_box::HEADER_GOAL_FROM_CROSS_BONUS_POINTS - assist).max(0.0);
        self.record_reward_event_with_kind(
            shooter,
            finisher,
            SoccerRewardEventKind::HeaderGoalFromCross,
        );
        if cross.crosser != shooter {
            self.record_reward_event_with_kind(
                cross.crosser,
                assist,
                SoccerRewardEventKind::HeaderGoalFromCross,
            );
        }
        self.flank_crash_box_cross = None;
        true
    }

    pub(crate) fn record_goal_rewards(&mut self, scoring_team: Team, shooter: Option<usize>) {
        self.record_flank_crash_box_header_goal(scoring_team, shooter);
        let previous_touch_team = self.previous_touch_team_for_goal();
        if let Some(shooter) = shooter {
            self.record_possession_touch(shooter);
        }
        if let Some(reward_points) =
            self.direct_turnover_goal_reward_points(scoring_team, shooter, previous_touch_team)
        {
            self.record_possession_reward_pattern_with_kind(
                scoring_team,
                shooter,
                &[reward_points],
                SoccerRewardEventKind::Goal,
            );
        } else if !self.record_contextual_goal_rewards(scoring_team, shooter, GOAL_REWARD_POINTS) {
            debug_assert!(
                (GOAL_CHAIN_REWARD_PATTERN.iter().sum::<f64>() - GOAL_REWARD_POINTS).abs() < 1e-9
            );
            self.record_possession_reward_pattern_with_kind(
                scoring_team,
                shooter,
                &GOAL_CHAIN_REWARD_PATTERN,
                SoccerRewardEventKind::Goal,
            );
        }
        self.update_mpc_latent_objective(scoring_team, None, Some(1.0), Some(1.0));
        self.record_recent_defensive_goal_penalties(scoring_team.other());
    }

    pub(crate) fn record_match_result_rewards_at(&mut self, tick: u64) {
        if self.score_home == self.score_away {
            return;
        }
        let (winning_team, margin) = if self.score_home > self.score_away {
            (Team::Home, self.score_home - self.score_away)
        } else {
            (Team::Away, self.score_away - self.score_home)
        };
        let margin = f64::from(margin.saturating_sub(1));
        let win_amount =
            MATCH_RESULT_WIN_PLAYER_REWARD + margin * MATCH_RESULT_MARGIN_REWARD_PER_GOAL;
        let loss_amount =
            -(MATCH_RESULT_LOSS_PLAYER_PENALTY + margin * MATCH_RESULT_MARGIN_PENALTY_PER_GOAL);
        let events = self
            .players
            .iter()
            .map(|player| {
                (
                    player.id,
                    if player.team == winning_team {
                        win_amount
                    } else {
                        loss_amount
                    },
                )
            })
            .collect::<Vec<_>>();
        for (player_id, amount) in events {
            self.record_reward_event_at_with_kind(
                tick,
                player_id,
                amount,
                SoccerRewardEventKind::MatchResult,
            );
        }
    }

    fn record_recent_defensive_goal_penalties(&mut self, conceding_team: Team) {
        let mut actions = 0usize;
        let history = self
            .recent_learning_history
            .iter()
            .rev()
            .filter(|transition| transition.team == conceding_team)
            .take(DEFENSIVE_GOAL_HISTORY_ACTIONS)
            .cloned()
            .collect::<Vec<_>>();

        for mut transition in history {
            let role_multiplier = match transition.role {
                PlayerRole::Goalkeeper => 1.10,
                PlayerRole::Defender => 1.00,
                PlayerRole::Midfielder => 0.65,
                PlayerRole::Forward => 0.35,
            };
            let recency = if DEFENSIVE_GOAL_HISTORY_ACTIONS <= 1 {
                1.0
            } else {
                1.0 - actions as f64 / (DEFENSIVE_GOAL_HISTORY_ACTIONS - 1) as f64
            };
            let base = DEFENSIVE_GOAL_HISTORY_MIN_PENALTY
                + (DEFENSIVE_GOAL_HISTORY_MAX_PENALTY - DEFENSIVE_GOAL_HISTORY_MIN_PENALTY)
                    * recency.clamp(0.0, 1.0);
            transition.reward = -(base * role_multiplier);
            transition.done = false;
            self.deferred_reward_transitions.push(transition);
            actions += 1;
        }
    }

    /// Detect an open-play turnover (controlled possession passing from one team
    /// to the other without an intervening dead ball — e.g. a miscontrol or a
    /// loose-ball recovery that the explicit interception/dispossession hooks
    /// don't cover) and route it through the single canonical turnover-penalty
    /// engine [`Self::penalize_turnover_window`]. Its per-tick `last_turnover_penalty_tick`
    /// guard de-duplicates against those explicit hooks, so a turnover is
    /// penalized exactly once no matter how it was detected. Maintains
    /// [`Self::last_controlled_possession_team`] across loose-ball ticks; a dead
    /// ball clears it (see [`Self::apply_restart_with_label`]) so a kickoff /
    /// throw-in / goal kick is never read as a turnover.
    pub(crate) fn detect_and_penalize_open_play_turnover(&mut self, after: &WorldSnapshot) {
        let Some(controlling) = after.controlled_possession_team() else {
            // Loose ball: keep the last controller pinned so a steal that resolves
            // a tick or two later still attributes to the team that had it.
            return;
        };
        if let Some(previous) = self.last_controlled_possession_team {
            if previous != controlling {
                self.penalize_turnover_window(previous);
            }
        }
        self.last_controlled_possession_team = Some(controlling);
    }

    /// Bound the deferred reward-transition backlog, dropping the oldest entries
    /// first (stale penalties matter least). Called after every push burst and
    /// once per step so a turnover/goal flurry can never grow it without limit.
    pub(crate) fn cap_deferred_reward_transitions(&mut self) {
        let len = self.deferred_reward_transitions.len();
        if len > MAX_DEFERRED_REWARD_TRANSITIONS {
            self.deferred_reward_transitions
                .drain(0..len - MAX_DEFERRED_REWARD_TRANSITIONS);
        }
    }

    /// Place a manual coaching position hint by dropping player `player_id` at
    /// `target` on the live pitch. If the player's team holds controlled
    /// possession at drop time, the hint means "get open here for a pass";
    /// otherwise it means "stand here on defense/offense". Returns the resolved
    /// hint so the caller can report which interpretation was applied.
    /// The team currently in *controlled* possession (the team of the actual ball
    /// holder), or `None` when the ball is loose.
    pub(crate) fn controlled_possession_team_now(&self) -> Option<Team> {
        self.ball
            .holder
            .and_then(|id| self.players.iter().find(|p| p.id == id))
            .map(|p| p.team)
    }

    pub(crate) fn set_coach_position_hint(
        &mut self,
        player_id: usize,
        target: Vec2,
    ) -> Option<CoachPositionHint> {
        if !target.x.is_finite() || !target.y.is_finite() {
            return None;
        }
        let player = self.players.iter().find(|p| p.id == player_id)?;
        let player_team = player.team;
        let target = target.clamp_to_pitch(
            self.config.field_width_yards,
            self.config.field_length_yards,
        );
        let possession_team = self.controlled_possession_team_now();
        let hint = CoachPositionHint {
            target,
            // "Same team as the ball-holder" → treat the drop as a receive spot.
            receive: possession_team == Some(player_team),
            possession_team,
            set_tick: self.tick,
        };
        self.coach_position_hints.insert(player_id, hint);
        Some(hint)
    }

    /// The active coaching target for a player, or `None` if there is no hint, it
    /// has expired, the player has arrived, or (for a receive hint) the player's
    /// team has since lost the ball. Expired/satisfied hints are pruned.
    pub(crate) fn active_coach_hint_target(&mut self, player_id: usize) -> Option<Vec2> {
        let hint = self.coach_position_hints.get(&player_id).copied()?;
        let lifetime_ticks = ((COACH_POSITION_HINT_LIFETIME_SECONDS
            / self.config.dt_seconds.max(1e-6))
        .round() as u64)
            .max(1);
        let expired = self.tick.saturating_sub(hint.set_tick) > lifetime_ticks;
        // A receive hint dies only when the OPPONENT wins controlled possession —
        // not while the ball is merely loose or a pass is in flight (holder None),
        // which is exactly when the player should be getting open to receive.
        let possession_lost = hint.receive
            && self.controlled_possession_team_now() == hint.possession_team.map(Team::other);
        let arrived = self
            .players
            .iter()
            .find(|p| p.id == player_id)
            .is_some_and(|p| p.position.distance(hint.target) <= COACH_POSITION_HINT_ARRIVAL_YARDS);
        if expired || possession_lost || arrived {
            self.coach_position_hints.remove(&player_id);
            return None;
        }
        Some(hint.target)
    }

    fn record_possession_team_reward_at(&mut self, tick: u64, team: Team, amount: f64) {
        if amount <= 1e-9 {
            return;
        }
        let mut recipients = Vec::new();
        if let Some(holder) = self.ball.holder {
            if self
                .players
                .get(holder)
                .is_some_and(|player| player.team == team)
            {
                recipients.push(holder);
            }
        }
        for player_id in self.possession_chain.iter().rev().copied().take(6) {
            if recipients.contains(&player_id) {
                continue;
            }
            if self
                .players
                .get(player_id)
                .is_some_and(|player| player.team == team)
            {
                recipients.push(player_id);
            }
        }
        if recipients.is_empty() {
            return;
        }

        if recipients.len() == 1 {
            self.record_reward_event_at(tick, recipients[0], amount);
            return;
        }

        let holder_amount = amount * 0.60;
        self.record_reward_event_at(tick, recipients[0], holder_amount);
        let support_amount = amount * 0.40 / (recipients.len() - 1) as f64;
        for player_id in recipients.into_iter().skip(1) {
            self.record_reward_event_at(tick, player_id, support_amount);
        }
    }

    fn current_possession_team_players(&self, team: Team) -> Vec<usize> {
        let mut involved = Vec::new();
        if let Some(holder) = self.ball.holder {
            if self
                .players
                .get(holder)
                .is_some_and(|player| player.team == team)
            {
                involved.push(holder);
            }
        }
        for player_id in self.possession_chain.iter().copied() {
            if involved.contains(&player_id) {
                continue;
            }
            if self
                .players
                .get(player_id)
                .is_some_and(|player| player.team == team)
            {
                involved.push(player_id);
            }
        }
        involved
    }

    fn record_involved_team_reward_at(
        &mut self,
        tick: u64,
        team: Team,
        amount: f64,
        involved_players: &[usize],
    ) {
        if amount <= 1e-9 {
            return;
        }
        let mut recipients = Vec::new();
        for player_id in involved_players.iter().copied() {
            if recipients.contains(&player_id) {
                continue;
            }
            if self
                .players
                .get(player_id)
                .is_some_and(|player| player.team == team)
            {
                recipients.push(player_id);
            }
        }
        if recipients.is_empty() {
            self.record_possession_team_reward_at(tick, team, amount);
            return;
        }
        let share = amount / recipients.len() as f64;
        for player_id in recipients {
            self.record_reward_event_at(tick, player_id, share);
        }
    }

    pub(crate) fn update_defensive_clear_and_hold_reward_tracker(
        &mut self,
        before: &WorldSnapshot,
        after: &WorldSnapshot,
        record_rewards: bool,
    ) {
        let after_possession = after.possession_team();
        for team in [Team::Home, Team::Away] {
            if Some(team) != after_possession {
                self.defensive_clear_hold_trackers.remove(&team);
            }
        }

        let Some(team) = after_possession else {
            return;
        };

        let possession_changed = before.possession_team() != Some(team);
        let dt = (after.clock_seconds - before.clock_seconds)
            .max(0.0)
            .max(before.dt_seconds.max(0.0));
        let current_involved = self.current_possession_team_players(team);
        let mut earned_rewards = Vec::new();
        {
            let tracker = self.defensive_clear_hold_trackers.entry(team).or_default();
            if possession_changed {
                *tracker = DefensiveClearAndHoldTracker::default();
            }
            for player_id in current_involved {
                if !tracker.involved_players.contains(&player_id) {
                    tracker.involved_players.push(player_id);
                }
            }
            let before_in_own_half =
                pass_origin_in_own_half(team, before.ball.position, before.field_length);
            let after_in_own_half =
                pass_origin_in_own_half(team, after.ball.position, after.field_length);
            let before_in_opponent_half =
                position_in_opponent_half(team, before.ball.position, before.field_length);
            let after_in_opponent_half =
                position_in_opponent_half(team, after.ball.position, after.field_length);
            if before_in_own_half || after_in_own_half {
                tracker.started_from_own_half = true;
            }
            if tracker.started_from_own_half && !before_in_opponent_half && after_in_opponent_half {
                tracker.crossed_half_from_own = true;
            }

            let controlled_in_opponent_half =
                after.controlled_possession_team() == Some(team) && after_in_opponent_half;
            if tracker.crossed_half_from_own && controlled_in_opponent_half {
                tracker.opponent_half_control_seconds += dt;
                if !tracker.first_rewarded
                    && tracker.opponent_half_control_seconds
                        >= DEFENSIVE_CLEAR_AND_HOLD_FIRST_SECONDS
                {
                    tracker.first_rewarded = true;
                    earned_rewards.push((
                        DEFENSIVE_CLEAR_AND_HOLD_FIRST_REWARD_POINTS,
                        tracker.involved_players.clone(),
                    ));
                }
                if !tracker.second_rewarded
                    && tracker.opponent_half_control_seconds
                        >= DEFENSIVE_CLEAR_AND_HOLD_SECOND_SECONDS
                {
                    tracker.second_rewarded = true;
                    earned_rewards.push((
                        DEFENSIVE_CLEAR_AND_HOLD_SECOND_REWARD_POINTS,
                        tracker.involved_players.clone(),
                    ));
                }
            } else if !controlled_in_opponent_half {
                tracker.opponent_half_control_seconds = 0.0;
            }
        }

        if record_rewards {
            for (amount, involved_players) in earned_rewards {
                self.record_involved_team_reward_at(before.tick, team, amount, &involved_players);
            }
        }
    }

    fn add_extra_chase_fatigue(&mut self, player_id: usize, load: f64, reward_cost: f64) {
        let Some(player) = self.players.get_mut(player_id) else {
            return;
        };
        let stamina_resistance = (1.18 - ability01(player.skills.stamina) * 0.58).clamp(0.58, 1.18);
        let fatigue_multiplier = 1.0 + player.fatigue.clamp(0.0, 1.0) * 0.45;
        let dt = self.config.dt_seconds.max(1e-6);
        let load_rate = load / dt;
        let load_delta = load_rate.max(0.0) / 12.0 * 0.001 * dt;
        let reward_delta = reward_cost.max(0.0) * 0.001;
        let delta = ((load_delta + reward_delta) * stamina_resistance * fatigue_multiplier)
            .clamp(0.0, 0.003);
        player.add_fatigue(delta);
    }

    fn record_possession_chase_stats(
        &mut self,
        defending_team: Team,
        possession_team: Team,
        defensive_load: f64,
        advantage: f64,
    ) {
        match defending_team {
            Team::Home => self.stats.defensive_chase_load_home += defensive_load.max(0.0),
            Team::Away => self.stats.defensive_chase_load_away += defensive_load.max(0.0),
        }
        match possession_team {
            Team::Home => self.stats.possession_chase_advantage_home += advantage.max(0.0),
            Team::Away => self.stats.possession_chase_advantage_away += advantage.max(0.0),
        }
    }

    fn record_teamwork_progress_stats(&mut self, signal: &TeamworkProgressSignal) {
        let combined_progress = signal.ball_progress.max(0.0)
            + signal.team_centroid_progress.max(0.0)
            + signal.near_ball_centroid_progress.max(0.0);
        match signal.possession_team {
            Team::Home => {
                self.stats.teamwork_upfield_progress_home += combined_progress;
                self.stats.teamwork_near_ball_progress_home +=
                    signal.near_ball_centroid_progress.max(0.0);
            }
            Team::Away => {
                self.stats.teamwork_upfield_progress_away += combined_progress;
                self.stats.teamwork_near_ball_progress_away +=
                    signal.near_ball_centroid_progress.max(0.0);
            }
        }
    }

    fn apply_teamwork_progress_signal(
        &mut self,
        tick: u64,
        signal: TeamworkProgressSignal,
        record_rewards: bool,
    ) {
        self.record_teamwork_progress_stats(&signal);
        if record_rewards {
            self.record_involved_team_reward_at(
                tick,
                signal.possession_team,
                signal.attacking_credit,
                &signal.support_players,
            );
        }
    }

    fn apply_possession_chase_signal(
        &mut self,
        tick: u64,
        signal: PossessionChaseSignal,
        record_rewards: bool,
    ) {
        let advantage = (signal.defensive_load - signal.attacking_load).max(0.0);
        self.record_possession_chase_stats(
            signal.defending_team,
            signal.possession_team,
            signal.defensive_load,
            advantage,
        );
        if record_rewards {
            self.record_possession_team_reward_at(
                tick,
                signal.possession_team,
                signal.attacking_credit,
            );
        }
        for penalty in signal.defender_penalties {
            self.add_extra_chase_fatigue(penalty.player_id, penalty.load, penalty.amount.abs());
            if record_rewards {
                self.record_reward_event_at(tick, penalty.player_id, penalty.amount);
            }
        }
    }

    fn apply_defensive_relaxation_signal(
        &mut self,
        tick: u64,
        signal: DefensiveRelaxationSignal,
        record_rewards: bool,
    ) {
        self.record_possession_chase_stats(
            signal.defending_team,
            signal.possession_team,
            0.0,
            signal.attacking_credit * 11.0,
        );
        if !record_rewards {
            return;
        }
        self.record_possession_team_reward_at(
            tick,
            signal.possession_team,
            signal.attacking_credit,
        );
        for penalty in signal.defender_penalties {
            self.record_reward_event_at(tick, penalty.player_id, penalty.amount);
        }
    }

    /// Maintain the "loose ball uncontested for too long" clock (runs every tick,
    /// learning or not). A loose ball is contested when an outfielder is right on it
    /// or genuinely closing it down; otherwise the clock runs and, once it passes
    /// [`LOOSE_BALL_MAX_UNCONTESTED_SECONDS`], [`WorldSnapshot::loose_ball_urgency_active`]
    /// forces the designated retriever to attack it (see `loose_ball_control_plan_for`).
    pub(crate) fn update_loose_ball_urgency(&mut self, snapshot: &WorldSnapshot) {
        if snapshot.ball.holder.is_some()
            || snapshot.pending_pass.is_some()
            || self.active_set_play.is_some()
        {
            self.loose_ball_uncontested_since_tick = None;
            return;
        }
        let ball_pos = snapshot.ball.position;
        let contested = snapshot.players.iter().any(|p| {
            if p.role == PlayerRole::Goalkeeper {
                return false;
            }
            let pos = snapshot.player_snapshot_position(p);
            let to_ball = ball_pos - pos;
            let dist = to_ball.len();
            if dist <= LOOSE_BALL_URGENCY_CONTEST_RADIUS_YARDS {
                return true;
            }
            if dist <= LOOSE_BALL_URGENCY_APPROACH_RADIUS_YARDS && dist > 1e-3 {
                let vel = snapshot.player_velocity(p.id).unwrap_or(p.velocity);
                return vel.dot(to_ball * (1.0 / dist)) >= LOOSE_BALL_URGENCY_APPROACH_CLOSING_YPS;
            }
            false
        });
        if contested {
            self.loose_ball_uncontested_since_tick = None;
        } else if self.loose_ball_uncontested_since_tick.is_none() {
            self.loose_ball_uncontested_since_tick = Some(self.tick);
        }
    }

    pub(crate) fn update_possession_chase_trackers(
        &mut self,
        before: &WorldSnapshot,
        after: &WorldSnapshot,
        record_rewards: bool,
    ) {
        let Some(possession_team) = before.controlled_possession_team() else {
            return;
        };
        if let Some(signal) = possession_chase_signal(before, after, possession_team) {
            self.apply_possession_chase_signal(before.tick, signal, record_rewards);
        }
        if let Some(signal) = teamwork_progress_signal(before, after, possession_team) {
            self.apply_teamwork_progress_signal(before.tick, signal, record_rewards);
        }
        if let Some(signal) = defensive_relaxation_signal(before, after, possession_team) {
            self.apply_defensive_relaxation_signal(before.tick, signal, record_rewards);
        }
    }

    pub(crate) fn update_pass_chain_continuation_rewards(
        &mut self,
        before: &WorldSnapshot,
        after: &WorldSnapshot,
        record_rewards: bool,
    ) {
        if !record_rewards {
            return;
        }
        let Some(holder_id) = before.ball.holder else {
            return;
        };
        let Some(holder) = before.players.iter().find(|player| player.id == holder_id) else {
            return;
        };
        let team = holder.team;
        if before.controlled_possession_team() != Some(team)
            || after.possession_team() != Some(team)
        {
            return;
        }
        let Some(decision) = self
            .players
            .get(holder_id)
            .and_then(|player| player.last_decision.as_ref())
        else {
            return;
        };
        if decision.mdp_state.tick != before.tick {
            return;
        }
        let Some(kind) = pass_chain_continuation_kind(&decision.action) else {
            return;
        };
        if !pass_chain_continuation_retained_possession(kind, team, after) {
            return;
        }

        let chain = self.recent_completed_pass_chain_into(team, holder_id, 2);
        let Some(latest) = chain.first() else {
            return;
        };
        if latest.continuation_rewarded {
            return;
        }

        for (depth, entry) in chain.iter().enumerate() {
            let amount = pass_chain_link_reward(entry.direction, depth);
            self.record_reward_event_at(before.tick, entry.from, amount);
        }
        self.mark_pass_chain_continuation_rewarded(latest);
    }

    pub(crate) fn facing_for_player_action(
        &self,
        player_id: usize,
        action: &SoccerAction,
    ) -> FacingBucket {
        let Some(player) = self.players.get(player_id) else {
            return FacingBucket::Unknown;
        };
        if matches!(action, SoccerAction::HoldShape | SoccerAction::MoveTo(_)) {
            let target = match action {
                SoccerAction::HoldShape => player.home_position,
                SoccerAction::MoveTo(target) => *target,
                _ => unreachable!(),
            };
            let facing = movement_action_facing_bucket(
                player.team,
                player.position,
                self.ball.position,
                target - player.position,
                player.velocity,
                player.movement_gait,
                self.ball.holder == Some(player_id),
                player.action_facing,
            );
            if facing != FacingBucket::Unknown {
                return facing;
            }
        }
        let target = match action {
            SoccerAction::HoldShape => Some(player.home_position),
            SoccerAction::MoveTo(target)
            | SoccerAction::Dribble(target)
            | SoccerAction::DribbleMove { target, .. }
            | SoccerAction::ControlTouch { target } => Some(*target),
            SoccerAction::Pass { target_player, .. } => target_player
                .and_then(|target_id| self.players.get(target_id).map(|target| target.position)),
            SoccerAction::Clearance { target, .. } | SoccerAction::RouteOne { target, .. } => {
                Some(*target)
            }
            SoccerAction::Shoot { .. } => Some(Vec2::new(
                self.config.field_width_yards * 0.5,
                player.team.goal_y(self.config.field_length_yards),
            )),
            SoccerAction::Tackle { target_player }
            | SoccerAction::SlideTackle { target_player } => self
                .players
                .get(*target_player)
                .map(|target| target.position),
        };
        let facing = target
            .map(|target| facing_bucket_from_vector(target - player.position))
            .unwrap_or(FacingBucket::Unknown);
        if facing == FacingBucket::Unknown {
            player.action_facing
        } else {
            facing
        }
    }

    fn apply_dribble_intent(
        &mut self,
        player_id: usize,
        target: Vec2,
        sprint: bool,
        kind: Option<DribbleMoveKind>,
        touch: Option<DribbleTouchDecision>,
    ) {
        let player_pos = self.players[player_id].position;
        let player_team = self.players[player_id].team;
        let snapshot = WorldSnapshot::from_match(self);
        let observation = snapshot.observation_for(player_id);
        let nearest_pressure = self
            .players
            .iter()
            .filter(|opponent| opponent.team != player_team)
            .map(|opponent| opponent.position.distance(player_pos))
            .fold(f64::INFINITY, f64::min);
        let pressure = pressure_from_observation(&observation)
            .max(pressure_from_nearest_distance(nearest_pressure));
        let requested_target = target;
        let stationary_escape_target = snapshot
            .stationary_holder_open_space_carry_target_for(player_id, requested_target, kind, touch)
            // Beat-the-defender duel (gated, default-ON): if the carrier would otherwise stall into
            // a back-to-goal shield, peel away into space to keep distance from the presser. Off =>
            // this returns None and the `.unwrap_or` is byte-identical to before.
            .or_else(|| {
                snapshot.dribble_away_from_pressure_target_for(player_id, requested_target, kind)
            });
        let target = stationary_escape_target.unwrap_or(requested_target);
        let pressured_shield_escape = stationary_escape_target.is_some()
            && matches!(kind, Some(DribbleMoveKind::ProtectBall))
            && target.distance(requested_target) > 0.10;
        if pressured_shield_escape {
            let escape = (target - player_pos).normalized();
            if escape.len() > 1e-6 {
                let velocity_along_escape = self.players[player_id].velocity.dot(escape);
                if velocity_along_escape < STATIONARY_HOLDER_ESCAPE_INITIAL_PUSH_YPS {
                    self.players[player_id].velocity += escape
                        * (STATIONARY_HOLDER_ESCAPE_INITIAL_PUSH_YPS - velocity_along_escape);
                }
            }
        }
        let dribble_dir = (target - player_pos).normalized();
        self.move_player_towards(player_id, target, sprint || pressured_shield_escape);
        if self.ball.holder == Some(player_id) {
            let kind_touch_multiplier = match kind {
                Some(DribbleMoveKind::CarryForward) => 0.78,
                Some(DribbleMoveKind::CarryOutLeft | DribbleMoveKind::CarryOutRight) => 0.86,
                Some(DribbleMoveKind::ProtectBall) => 0.48,
                // Close-control shielded turn: keep the ball glued to the feet.
                Some(DribbleMoveKind::XaviTurn) => 0.42,
                Some(DribbleMoveKind::Nutmeg) => 1.18,
                Some(DribbleMoveKind::LeftCut | DribbleMoveKind::RightCut) => 1.04,
                Some(DribbleMoveKind::FakeLeftCutRight | DribbleMoveKind::FakeRightCutLeft) => 1.10,
                None => 1.0,
            };
            let touch_probability =
                (dribble_heavy_touch_probability(&self.players[player_id], pressure)
                    * kind_touch_multiplier
                    + touch
                        .map(|touch| ((touch.distance_yards - 3.20) / 3.60).clamp(0.0, 1.0) * 0.12)
                        .unwrap_or(0.0))
                .clamp(0.004, 0.58);
            let player = &self.players[player_id];
            let dir = if dribble_dir.len() > 0.0 {
                dribble_dir
            } else {
                carried_ball_lead(player).normalized()
            };
            let touch_distance_risk = touch
                .map(|touch| ((touch.distance_yards - 3.00) / 3.80).clamp(0.0, 1.0))
                .unwrap_or(0.0);
            let control_fit = (ability01(player.skills.dribbling) * 0.46
                + ability01(player.skills.first_touch) * 0.30
                + ability01(player.skills.acceleration) * 0.14
                + ability01(player.skills.stamina) * (1.0 - player.fatigue.clamp(0.0, 1.0)) * 0.10)
                .clamp(0.0, 1.0);
            let touch_loss_pressure = touch_probability
                + pressure * 0.26
                + touch_distance_risk * 0.20
                + player.fatigue.clamp(0.0, 1.0) * 0.14
                + player.dizziness.clamp(0.0, DIZZINESS_MAX) * 0.08;
            let agentic_touch_loss = touch_loss_pressure > 0.62 + control_fit * 0.34;
            if agentic_touch_loss {
                let touch_distance = DRIBBLE_HEAVY_TOUCH_MIN_YARDS
                    + pressure * 0.9
                    + (1.0 - ability01(player.skills.dribbling)) * 0.65;
                self.ball.holder = None;
                self.ball.position = (player.position + dir * touch_distance).clamp_to_pitch(
                    self.config.field_width_yards,
                    self.config.field_length_yards,
                );
                self.ball.velocity =
                    player.velocity + dir * (4.0 + pressure * 8.0 + touch_distance);
                self.ball.curl_acceleration = Vec2::zero();
                self.ball.altitude_yards = 0.0;
                self.ball.last_touch_team = Some(player_team);
                self.pending_pass = None;
                self.pending_shot = None;
                self.events.push(MatchEvent {
                    tick: self.tick,
                    clock_seconds: self.clock_seconds,
                    kind: "heavy-touch".to_string(),
                    team: Some(player_team),
                    player_id: Some(player_id),
                    description: format!("{} heavy touch", player.name),
                    ..MatchEvent::default()
                });
            } else {
                let controlled_lead = touch
                    .map(|touch| {
                        (DRIBBLE_TOUCH_LEAD_YARDS + touch.distance_yards * 0.18).clamp(0.65, 1.92)
                    })
                    .unwrap_or(DRIBBLE_TOUCH_LEAD_YARDS);
                self.ball.position = (player.position + dir * controlled_lead).clamp_to_pitch(
                    self.config.field_width_yards,
                    self.config.field_length_yards,
                );
                self.ball.velocity = player.velocity;
                self.ball.curl_acceleration = Vec2::zero();
                self.ball.altitude_yards = 0.0;
                self.ball.last_touch_team = Some(player_team);
            }
        }
    }

    /// True when the carrier's body is physically between the ball and this
    /// defender (the carrier is shielding) AND the defender is more than a yard
    /// off the ball. From there a standing/passive dispossession is impossible;
    /// a committed slide has its own ball-reach gate. With the orbital carry model
    /// the ball can sit anywhere around the body, so this keys purely on the
    /// betweenness geometry (ball and defender on opposite sides of the carrier),
    /// not on the body facing.
    pub(crate) fn carrier_shields_ball_from_defender(
        &self,
        attacker_id: usize,
        defender_id: usize,
    ) -> bool {
        if attacker_id >= self.players.len() || defender_id >= self.players.len() {
            return false;
        }
        let attacker = &self.players[attacker_id];
        let defender = &self.players[defender_id];
        let attacker_pos = attacker.position;
        let ball = self.ball.position;
        let to_ball = ball - attacker_pos;
        let to_ball_dist = to_ball.len();
        if to_ball_dist < 1e-3 {
            return false;
        }
        let to_ball_dir = to_ball / to_ball_dist;
        let to_def = defender.position - attacker_pos;
        if to_def.len() < 1e-3 {
            return false;
        }
        let to_def_dir = to_def.normalized();
        // The defender must be on the opposite side of the carrier from the ball —
        // the body between them (ball and defender point roughly opposite ways).
        if to_ball_dir.dot(to_def_dir) > -SHIELD_DEFENDER_OPPOSITE_DOT {
            return false;
        }
        // And genuinely off the ball: within a yard a defender can still legally
        // poke it; beyond that, only a foul reaches past the carrier's body.
        defender.position.distance(ball) > SHIELD_DEFENDER_BALL_GAP_YARDS
    }

    /// Whether a defender at `defender_pos` is behind the ball-carrier (the held ball is
    /// led in front of the holder's body, away from the defender). Standing/passive
    /// steals are blocked from there; slide tackles must prove actual ball reach.
    /// See [`carried_ball_behind_defender`].
    pub(crate) fn tackle_blocked_from_behind(&self, holder_id: usize, defender_pos: Vec2) -> bool {
        let Some(holder) = self.players.get(holder_id) else {
            return false;
        };
        carried_ball_behind_defender(
            holder.position,
            holder.velocity,
            self.ball.position,
            defender_pos,
        )
    }

    pub(crate) fn surprise_behind_steal_profile_for(
        &self,
        defender_id: usize,
        holder_id: usize,
    ) -> SurpriseBehindStealProfile {
        let Some(defender) = self.players.get(defender_id) else {
            return SurpriseBehindStealProfile::default();
        };
        let Some(holder) = self.players.get(holder_id) else {
            return SurpriseBehindStealProfile::default();
        };
        let mut holder_start_clock = self.clock_seconds;
        for sample in self.ball.position_history.iter().rev() {
            if sample.holder == Some(holder_id) {
                holder_start_clock = sample.clock_seconds;
            } else {
                break;
            }
        }
        let holder_possession_seconds = (self.clock_seconds - holder_start_clock).max(0.0);
        surprise_behind_steal_profile_from_kinematics(
            defender.team,
            defender.role,
            defender.position,
            defender.velocity,
            &defender.skills,
            defender.fatigue,
            holder.team,
            holder.role,
            holder.position,
            holder.velocity,
            holder.movement_gait,
            holder.action_facing,
            &holder.skills,
            holder.fatigue,
            holder_possession_seconds,
        )
    }

    fn mpc_steal_execution_fit(
        &self,
        defender_id: usize,
        carrier_id: usize,
        committed: bool,
    ) -> MpcBallControlExecutionFit {
        let Some(defender) = self.players.get(defender_id) else {
            return MpcBallControlExecutionFit::default();
        };
        let Some(carrier) = self.players.get(carrier_id) else {
            return MpcBallControlExecutionFit::default();
        };
        let ball_target = self.ball.position;
        let distance = defender.position.distance(ball_target);
        let fatigue_factor = fatigue_speed_factor(defender.skills.stamina, defender.fatigue);
        let top_speed = (player_top_speed_yps(defender.role, &defender.skills)
            * fatigue_factor
            * MovementGait::Sprint.speed_multiplier())
        .max(0.85);
        let horizon =
            (distance / top_speed).clamp(DEFAULT_DT_SECONDS, if committed { 0.48 } else { 0.34 });
        let accel_cap = acceleration_yps2_from_score(defender.skills.acceleration) * fatigue_factor;
        let control_radius = if committed {
            SLIDE_TACKLE_MAX_REACH_YARDS
        } else {
            DEFENSIVE_IMMEDIATE_STEAL_CLEAN_RADIUS_YARDS.max(CONTESTABLE_STEAL_RADIUS_YARDS)
        };
        let qp_accel_fit = bounded_accel_qp_control_fit(
            defender.position,
            defender.velocity,
            ball_target,
            horizon,
            accel_cap,
            control_radius,
            if committed { 0.035 } else { 0.075 },
        );
        let facing_fit = player_facing_ball_control_multiplier(
            defender,
            ball_target,
            self.ball.velocity.len().max(carrier.velocity.len()),
        )
        .clamp(0.0, 1.0);
        let to_ball = ball_target - defender.position;
        let closing_fit = if to_ball.len() > 1e-6 {
            ((defender.velocity.dot(to_ball.normalized()) + 4.0) / 14.0).clamp(0.0, 1.0)
        } else {
            1.0
        };
        let velocity_match = (1.0
            - ((defender.velocity - self.ball.velocity).len() / 32.0).clamp(0.0, 1.0))
        .clamp(0.0, 1.0);
        let skill_fit = (ability01(defender.skills.defending) * 0.46
            + ability01(defender.skills.aggression) * 0.22
            + ability01(defender.skills.acceleration) * 0.20
            + ability01(defender.skills.strength) * 0.12)
            .clamp(0.0, 1.0);
        let close_fit = (1.0 - distance / control_radius.max(1.0)).clamp(0.0, 1.0);
        let probability = (0.03
            + qp_accel_fit * 0.48
            + skill_fit * 0.17
            + facing_fit * if committed { 0.08 } else { 0.13 }
            + closing_fit * 0.08
            + velocity_match * 0.08
            + close_fit * 0.08)
            .clamp(0.0, 0.99);
        MpcBallControlExecutionFit {
            probability,
            qp_accel_fit,
            velocity_match,
            facing_fit,
            miscontrol_risk: (1.0 - probability).clamp(0.0, 1.0),
        }
    }

    fn mpc_steal_success_multiplier(
        &self,
        fit: MpcBallControlExecutionFit,
        min_qp_accel_fit: f64,
    ) -> f64 {
        if fit.qp_accel_fit < min_qp_accel_fit {
            0.0
        } else {
            (MPC_STEAL_SUCCESS_MULTIPLIER_FLOOR
                + MPC_STEAL_SUCCESS_MULTIPLIER_SPAN * fit.probability.clamp(0.0, 1.0))
            .clamp(0.0, 1.08)
        }
    }

    /// The defending goalkeeper currently holding the ball IN HIS HANDS — the
    /// holder is his team's keeper and he is inside his own penalty area. While
    /// this holds the ball cannot be tackled/stolen; he must release within
    /// `GK_HANDLING_HOLD_LIMIT_SECONDS`. Returns the keeper's player id.
    pub(crate) fn keeper_handling_holder(&self) -> Option<usize> {
        let holder = self.ball.holder?;
        let keeper = self.players.iter().find(|player| player.id == holder)?;
        if keeper.role != PlayerRole::Goalkeeper {
            return None;
        }
        if !self.point_in_own_penalty_area(keeper.team, keeper.position) {
            return None;
        }
        Some(holder)
    }

    /// Seconds the keeper has been holding the ball in his hands, if he is the
    /// current handling holder. `None` when no keeper is handling. The clock is
    /// started lazily by `update_keeper_handling` at the end of the tick, so on
    /// the very first handling tick this reports ~0.
    pub(crate) fn keeper_handling_held_seconds(&self, keeper_id: usize) -> Option<f64> {
        if self.keeper_handling_holder() != Some(keeper_id) {
            return None;
        }
        Some(match self.gk_handling_since_clock {
            Some(since) if since.is_finite() => (self.clock_seconds - since).max(0.0),
            _ => 0.0,
        })
    }

    /// A keeper holding the ball in his hands is unstealable, so he has the whole
    /// handling window to find a clean outlet. This decides whether a chosen
    /// distribution is "intelligent" enough to release NOW, or whether he should
    /// keep holding (and look again next tick). A release is allowed only when the
    /// intended receiver is genuinely open — no opponent is tight to him AND no
    /// opponent sits in the passing lane — so the keeper stops rolling/throwing the
    /// ball straight back to the player who just pressed/shot. A clear (no target)
    /// is always allowed; the forced-clearance safety net (`update_keeper_handling`)
    /// still releases him at the limit if nothing ever opens up.
    pub(crate) fn keeper_handling_release_is_intelligent(
        &self,
        snapshot: &WorldSnapshot,
        keeper_id: usize,
        target_id: Option<usize>,
        target_point: Vec2,
    ) -> bool {
        snapshot.keeper_handling_release_is_intelligent(keeper_id, target_id, target_point)
    }

    /// Per-tick maintenance of the keeper-handling clock: start it when a keeper
    /// gathers the ball in his box, clear it when he is no longer handling, and
    /// force a clearance once he overruns the handling time limit. Called once at
    /// the end of every tick.
    pub(crate) fn update_keeper_handling(&mut self) {
        match self.keeper_handling_holder() {
            Some(keeper_id) => {
                let since = *self
                    .gk_handling_since_clock
                    .get_or_insert(self.clock_seconds);
                if self.clock_seconds - since >= GK_HANDLING_HOLD_LIMIT_SECONDS {
                    self.force_keeper_release(keeper_id);
                    self.gk_handling_since_clock = None;
                }
            }
            None => self.gk_handling_since_clock = None,
        }
    }

    /// A keeper who overruns the handling limit without distributing is forced to
    /// hurriedly clear the ball upfield (a firm punt), losing it to open play.
    fn force_keeper_release(&mut self, keeper_id: usize) {
        let Some(keeper) = self.players.iter().find(|player| player.id == keeper_id) else {
            return;
        };
        let team = keeper.team;
        let from = keeper.position;
        let attack_dir = team.attack_dir();
        let width = self.config.field_width_yards;
        let length = self.config.field_length_yards;
        // A forced clearance is a punt: clear toward the flank channel whose LANE is
        // clearest, NOT straight up the middle where the player who just pressed/shot
        // tends to be standing — a hoof into the central striker is exactly the "gift it
        // right back to them" we want to avoid. Choosing by the clearest LANE (not just an
        // open endpoint) keeps it off a presser sitting in the channel.
        let forward = (length * 0.45).min(50.0);
        let left_target =
            Vec2::new(width * 0.18, from.y + attack_dir * forward).clamp_to_pitch(width, length);
        let right_target =
            Vec2::new(width * 0.82, from.y + attack_dir * forward).clamp_to_pitch(width, length);
        let lane_clearance_to = |target: Vec2| -> f64 {
            self.players
                .iter()
                .filter(|player| player.team == team.other())
                .map(|player| segment_distance_to_point(from, target, player.position))
                .fold(f64::INFINITY, f64::min)
        };
        let clear_target = if lane_clearance_to(left_target) >= lane_clearance_to(right_target) {
            left_target
        } else {
            right_target
        };
        let clear_dir = (clear_target - from).normalized();
        self.ball.holder = None;
        self.ball.position = from;
        self.ball.velocity = clear_dir * GK_HANDLING_FORCED_CLEARANCE_YPS;
        // Loft it — a punt clears the press over a presser's head, rather than a ground
        // ball that a forward in the channel can simply step into.
        self.ball.altitude_yards = GK_HANDLING_FORCED_CLEARANCE_ALTITUDE_YARDS;
        self.ball.curl_acceleration = Vec2::zero();
        self.ball.last_touch_team = Some(team);
        self.pending_pass = None;
        self.pending_shot = None;
        self.events.push(MatchEvent {
            tick: self.tick,
            clock_seconds: self.clock_seconds,
            kind: "gk_handling_timeout_clearance".to_string(),
            team: Some(team),
            player_id: Some(keeper_id),
            description: format!(
                "keeper held the ball beyond {GK_HANDLING_HOLD_LIMIT_SECONDS:.0}s and was forced to clear"
            ),
            ..MatchEvent::default()
        });
    }

    fn apply_fresh_possession_pressure_escape(&mut self, player_id: usize) {
        let escape_target =
            WorldSnapshot::from_match(self).fresh_possession_pressure_escape_target_for(player_id);
        let Some(escape_target) = escape_target else {
            return;
        };
        let current = self.players[player_id].position;
        let escape = (escape_target - current).normalized();
        if escape.len() > 1e-6 {
            let escape_cfg = &tunables().fresh_possession_escape;
            let velocity_along_escape = self.players[player_id].velocity.dot(escape);
            if velocity_along_escape < escape_cfg.initial_push_yps {
                self.players[player_id].velocity +=
                    escape * (escape_cfg.initial_push_yps - velocity_along_escape);
            }
        }
        self.apply_dribble_intent(
            player_id,
            escape_target,
            true,
            Some(DribbleMoveKind::CarryForward),
            None,
        );
    }

    pub(crate) fn complete_defensive_dispossession(
        &mut self,
        defender_id: usize,
        attacker_id: usize,
        event_kind: &str,
    ) {
        if defender_id >= self.players.len() || attacker_id >= self.players.len() {
            return;
        }
        if self.players[defender_id].team == self.players[attacker_id].team
            || self.ball.holder != Some(attacker_id)
        {
            return;
        }
        // A goalkeeper holding the ball IN HIS HANDS (inside his own penalty area)
        // cannot be tackled or dispossessed — it is in his hands. He is instead
        // bound by the handling time limit (see `update_keeper_handling`).
        if self.keeper_handling_holder() == Some(attacker_id) {
            return;
        }
        let defender_team = self.players[defender_id].team;
        let defender_name = self.players[defender_id].name.clone();
        let attacker_name = self.players[attacker_id].name.clone();
        let defender_position = self.players[defender_id].position;
        let defender_lead = carried_ball_lead(&self.players[defender_id]);

        self.record_quick_receiver_dispossession_penalty(attacker_id);
        // Spread the turnover penalty back across the attacking team's recent
        // possession chain while it is still intact (taking the ball clears it).
        let attacker_team = self.players[attacker_id].team;
        self.record_weighted_possession_chain_reward_at(
            self.tick,
            attacker_team,
            Some(attacker_id),
            -LOST_POSSESSION_CHAIN_PENALTY_POINTS,
            &LOST_POSSESSION_CHAIN_PENALTY_WEIGHTS,
        );
        // Retroactively penalize the dispossessed team's last ~5s of actions across all
        // gradient learners (the chain penalty above only hits the turnover-tick touchers).
        self.penalize_turnover_window(attacker_team);
        self.ball.holder = Some(defender_id);
        self.ball.position = (defender_position + defender_lead * 0.35).clamp_to_pitch(
            self.config.field_width_yards,
            self.config.field_length_yards,
        );
        self.ball.velocity = self.players[defender_id].velocity;
        self.ball.altitude_yards = 0.0;
        self.ball.curl_acceleration = Vec2::zero();
        self.ball.last_touch_team = Some(defender_team);
        self.pending_pass = None;
        self.pending_shot = None;
        self.mark_ball_received(defender_id);
        self.record_reward_event_with_kind(
            defender_id,
            DEFENSIVE_DISPOSSESSION_REWARD_POINTS,
            SoccerRewardEventKind::DefensiveDispossession,
        );
        self.record_possession_touch(defender_id);
        // Log this flip for the ping-pong livelock detector, then arm the
        // anti-ping-pong grace. The more the ball has just been oscillating in
        // this zone, the longer the new (shielding) winner is protected from an
        // instant return steal — escalating grace makes the body-shield hold.
        let swap_position = self.ball.position;
        let escalation = self.recent_zone_swap_count(swap_position) as u64
            * POSSESSION_REGAIN_GRACE_ESCALATION_PER_SWAP;
        let grace_ticks =
            (POSSESSION_REGAIN_GRACE_TICKS + escalation).min(POSSESSION_REGAIN_GRACE_MAX_TICKS);
        self.possession_swaps.push_back(PossessionSwap {
            tick: self.tick,
            winner: defender_id,
            loser: attacker_id,
            position: swap_position,
        });
        while self.possession_swaps.len() > LIVELOCK_SWAP_LOG_CAPACITY {
            self.possession_swaps.pop_front();
        }
        self.recent_dispossession = Some(RecentDispossession {
            tick: self.tick,
            winner: defender_id,
            loser: attacker_id,
            grace_ticks,
        });
        self.apply_fresh_possession_pressure_escape(defender_id);
        self.events.push(MatchEvent {
            tick: self.tick,
            clock_seconds: self.clock_seconds,
            kind: event_kind.to_string(),
            team: Some(defender_team),
            player_id: Some(defender_id),
            description: format!("{defender_name} dispossessed {attacker_name}"),
            ..MatchEvent::default()
        });
    }

    pub(crate) fn record_dribble_beat_event(
        &mut self,
        attacker_id: usize,
        defender_id: usize,
        kind: DribbleMoveKind,
    ) {
        if attacker_id >= self.players.len() || defender_id >= self.players.len() {
            return;
        }
        if self.players[attacker_id].team == self.players[defender_id].team
            || self.ball.holder != Some(attacker_id)
        {
            return;
        }
        let attacker_team = self.players[attacker_id].team;
        let attacker_name = self.players[attacker_id].name.clone();
        let defender_name = self.players[defender_id].name.clone();
        let attacker_position = self.players[attacker_id].position;
        let defender_position = self.players[defender_id].position;
        let attacker_before = self.players[attacker_id]
            .position_history
            .back()
            .copied()
            .unwrap_or(attacker_position);
        let defender_before = self.players[defender_id]
            .position_history
            .back()
            .copied()
            .unwrap_or(defender_position);
        if !dribble_beat_geometry_is_valid(
            attacker_team,
            attacker_before,
            attacker_position,
            defender_before,
            defender_position,
        ) {
            return;
        }
        let attacker_lead = carried_ball_lead(&self.players[attacker_id]);

        self.ball.holder = Some(attacker_id);
        self.ball.position = (attacker_position + attacker_lead).clamp_to_pitch(
            self.config.field_width_yards,
            self.config.field_length_yards,
        );
        self.ball.velocity = self.players[attacker_id].velocity;
        self.ball.altitude_yards = 0.0;
        self.ball.curl_acceleration = Vec2::zero();
        self.ball.last_touch_team = Some(attacker_team);
        // The dribbler re-secured the ball past the defender: reseed the orbit.
        self.ball.reset_carry_orbit();
        self.pending_pass = None;
        self.pending_shot = None;
        self.record_reward_event_with_kind(
            attacker_id,
            kind.beat_reward_points(),
            SoccerRewardEventKind::DribbleBeat,
        );
        self.record_reward_event_with_kind(
            defender_id,
            -BEATEN_BY_DRIBBLE_PENALTY_POINTS,
            SoccerRewardEventKind::DribbleBeat,
        );
        self.stat_dribble_beat(attacker_team);
        self.record_possession_touch(attacker_id);
        self.events.push(MatchEvent {
            tick: self.tick,
            clock_seconds: self.clock_seconds,
            kind: kind.event_kind().to_string(),
            team: Some(attacker_team),
            player_id: Some(attacker_id),
            description: format!(
                "{} beat {} with {}",
                attacker_name,
                defender_name,
                kind.label()
            ),
            ..MatchEvent::default()
        });
    }

    pub(crate) fn resolve_dribble_hold_up_contests(&mut self) {
        let Some(attacker_id) = self.ball.holder else {
            return;
        };
        if attacker_id >= self.players.len() {
            return;
        }
        let attacker_action = self.players[attacker_id]
            .last_decision
            .as_ref()
            .map(|decision| normalize_soccer_action_label(&decision.action))
            .unwrap_or("hold");
        let Some(kind) = dribble_move_kind_for_action_label(attacker_action) else {
            return;
        };
        let attacker_team = self.players[attacker_id].team;
        let attacker_position = self.players[attacker_id].position;
        let Some((defender_id, defender_distance)) = self
            .players
            .iter()
            .filter(|player| player.team == attacker_team.other())
            .filter(|player| {
                player
                    .last_decision
                    .as_ref()
                    .map(|decision| normalize_soccer_action_label(&decision.action) == "defend")
                    .unwrap_or(false)
            })
            .filter_map(|player| {
                let distance = player.position.distance(attacker_position);
                (distance <= DRIBBLE_HOLD_UP_CONTEST_RADIUS_YARDS).then_some((player.id, distance))
            })
            .min_by(|a, b| a.1.partial_cmp(&b.1).unwrap_or(std::cmp::Ordering::Equal))
        else {
            return;
        };

        // Anti-ping-pong grace: the defender cannot win the ball straight back
        // from the player who just took it from them.
        let regain_blocked = self.recent_dispossession.is_some_and(|recent| {
            self.tick.saturating_sub(recent.tick) < recent.grace_ticks
                && recent.winner == attacker_id
                && recent.loser == defender_id
        });
        let mut dispossession_probability = (dribble_dispossession_probability(
            &self.players[defender_id].skills,
            &self.players[attacker_id].skills,
            DefenderDribbleResponse::HoldUp,
        ) * dribble_dispossession_kind_multiplier(kind)
            * DRIBBLE_POSSESSION_RETENTION_FACTOR)
            .clamp(0.02, 0.82);
        let attacker_control = ability01(self.players[attacker_id].skills.dribbling) * 0.70
            + ability01(self.players[attacker_id].skills.first_touch) * 0.30;
        let defender_pressure = ability01(self.players[defender_id].skills.defending) * 0.82
            + ability01(self.players[defender_id].skills.aggression) * 0.18;
        let contact_fit =
            (1.0 - defender_distance / DRIBBLE_HOLD_UP_CONTEST_RADIUS_YARDS).clamp(0.0, 1.0);
        let skill_edge = (defender_pressure - attacker_control).max(0.0);
        let exposed_control_gap = (1.0 - attacker_control).max(0.0);
        dispossession_probability = (dispossession_probability
            + contact_fit * skill_edge * 0.40
            + contact_fit * exposed_control_gap * 0.22)
            .clamp(0.0, 0.95);
        // A disoriented carrier (too much swivelling around the ball in a short window)
        // controls it less surely and is easier to dispossess.
        let attacker_dizziness = self.players[attacker_id]
            .dizziness
            .clamp(0.0, DIZZINESS_MAX);
        dispossession_probability = (dispossession_probability
            * (1.0 + attacker_dizziness * DIZZINESS_DISPOSSESSION_RISK))
            .clamp(0.0, 0.95);
        // A body-shielding move forces possession: cap the hold-up steal — ~20% for a
        // static `protect-ball` shield, ~10% while turning the man with a `xavi-turn`.
        if let Some(cap) = xavi_turn_tackle_success_cap(kind) {
            dispossession_probability = dispossession_probability.min(cap);
        }
        // Physical body-shield / rear challenge: if the carrier has the ball pushed
        // out in front and this defender is behind the body or the led ball, there is
        // no passive clean steal from there. The explicit slide action is the only
        // legal exception, and it is gated by actual ball reach.
        if self.carrier_shields_ball_from_defender(attacker_id, defender_id)
            || self.tackle_blocked_from_behind(attacker_id, self.players[defender_id].position)
        {
            dispossession_probability = 0.0;
        }
        let mpc_steal_fit = self.mpc_steal_execution_fit(defender_id, attacker_id, false);
        dispossession_probability = (dispossession_probability
            * self
                .mpc_steal_success_multiplier(mpc_steal_fit, MPC_STEAL_STANDING_MIN_QP_ACCEL_FIT))
        .clamp(0.0, 0.95);
        if kind == DribbleMoveKind::XaviTurn {
            dispossession_probability = XAVI_TURN_DISPOSSESSION_PROBABILITY;
        }
        let beat_probability = if kind != DribbleMoveKind::ProtectBall {
            dribble_beat_probability(
                kind,
                &self.players[attacker_id].skills,
                &self.players[defender_id].skills,
                DefenderDribbleResponse::HoldUp,
            )
        } else {
            0.0
        };
        if !regain_blocked && dispossession_probability >= 0.54 {
            self.complete_defensive_dispossession(
                defender_id,
                attacker_id,
                "hold-up-dispossession",
            );
        } else if kind != DribbleMoveKind::ProtectBall && beat_probability >= 0.52 {
            self.record_dribble_beat_event(attacker_id, defender_id, kind);
        }
    }

    fn record_near_goal_no_shot_penalty(&mut self, player_id: usize, action: &SoccerAction) {
        if player_id >= self.players.len()
            || self.ball.holder != Some(player_id)
            || matches!(action, SoccerAction::Shoot { .. })
        {
            return;
        }
        let snapshot = WorldSnapshot::from_match(self);
        let observation = snapshot.observation_for(player_id);
        let amount = near_goal_no_shot_penalty_points(&observation, self.players[player_id].role);
        if amount > 0.0 {
            self.record_reward_event(player_id, -amount);
        }
    }

    fn record_excessive_hold_penalty(&mut self, player_id: usize, action: &SoccerAction) {
        if player_id >= self.players.len()
            || self.ball.holder != Some(player_id)
            || !matches!(
                action,
                SoccerAction::Dribble(_)
                    | SoccerAction::DribbleMove { .. }
                    | SoccerAction::HoldShape
            )
        {
            return;
        }
        // A keeper legally holding the ball in his hands is unstealable and entitled to
        // the full handling window — don't teach him that holding is a mistake. The hard
        // time limit (`update_keeper_handling`) is what bounds him, not a learning nudge.
        if self.keeper_handling_holder() == Some(player_id) {
            return;
        }
        let snapshot = WorldSnapshot::from_match(self);
        let observation = snapshot.observation_for(player_id);
        let dribbling = ability01(self.players[player_id].skills.dribbling);
        let amount = excessive_hold_penalty_points(&observation, dribbling)
            * self.config.dt_seconds.clamp(0.05, 1.0);
        if amount > 0.0 {
            self.record_reward_event(player_id, -amount);
        }
    }

    /// While a restart is held (the taker still has the ball and has not yet played
    /// it), this returns the team that must be kept off the ball while the restart is
    /// held, the ball spot, and the keep-out radius (10yd for kickoffs / free kicks /
    /// corners / goal kicks per Laws 8/13/16; 2yd for throw-ins per Law 15). `None`
    /// outside a held restart.
    fn held_restart_keepout(&self) -> Option<(Team, Vec2, f64)> {
        let holder = self.ball.holder?;
        let label = self
            .ball
            .last_decision
            .as_ref()
            .and_then(|decision| restart_action_label(&decision.action))?;
        let radius = if label == "throw-in" {
            THROW_IN_OPPONENT_KEEPOUT_YARDS
        } else {
            RESTART_OPPONENT_KEEPOUT_YARDS
        };
        let restarting_team = self.players.get(holder)?.team;
        Some((restarting_team.other(), self.ball.position, radius))
    }

    /// Push a single player back out to the restart keep-out radius if it is an
    /// opponent of the team taking a currently-held restart and has crept inside it
    /// (10yd for most restarts, 2yd for throw-ins). Called each tick after the player
    /// moves, so opponents are held at the line until the taker plays the ball (Laws
    /// 8/13/15/16). The defending keeper is exempt so it can keep its goal-line
    /// position on a corner / short free kick near the byline.
    pub(crate) fn enforce_restart_keepout_for(&mut self, player_id: usize) {
        let Some((keepout_team, spot, radius)) = self.held_restart_keepout() else {
            return;
        };
        if player_id >= self.players.len() || self.players[player_id].team != keepout_team {
            return;
        }
        if self.goalkeeper_for(keepout_team) == Some(player_id) {
            return;
        }
        let pos = self.players[player_id].position;
        let offset = pos - spot;
        let dist = offset.len();
        if dist >= radius {
            return;
        }
        let dir = if dist > 1e-6 {
            offset / dist
        } else {
            // Degenerate: standing on the ball — retreat toward own goal.
            Vec2::new(0.0, -self.players[player_id].team.attack_dir())
        };
        let target = (spot + dir * radius).clamp_to_pitch(
            self.config.field_width_yards,
            self.config.field_length_yards,
        );
        let player = &mut self.players[player_id];
        player.position = target;
        // Kill inward momentum so they hold at the line instead of drifting back in.
        player.velocity = Vec2::zero();
        player.acceleration = Vec2::zero();
    }

    /// Physically block a shielded-out defender at the carrier's body so the animation
    /// reflects the no-steal-through-the-body rule. When the carrier is shielding this
    /// defender (its body is between the ball and the defender, and the ball is more
    /// than a yard from the defender — see `carrier_shields_ball_from_defender`), the
    /// defender cannot step inside the carrier's body ring: it is pushed radially back
    /// out, so on screen it presses against the carrier's back instead of overlapping
    /// the body and the ball orbiting on the far side. The defender may still run AROUND
    /// to the ball's side — there the shield no longer holds (or the ball comes within a
    /// yard) and a legal challenge resumes. Called each tick after the player moves,
    /// mirroring `enforce_restart_keepout_for`. No-op during dead-ball set plays.
    pub(crate) fn enforce_shield_body_barrier_for(&mut self, player_id: usize) {
        if self.active_set_play.is_some() || player_id >= self.players.len() {
            return;
        }
        let Some(carrier_id) = self.ball.holder else {
            return;
        };
        if carrier_id == player_id || carrier_id >= self.players.len() {
            return;
        }
        if self.players[carrier_id].team == self.players[player_id].team {
            return;
        }
        // Only while the body is actually shielding this defender out (geometry + the
        // 1yd ball gap). A defender goal-side, or with the ball within a yard, is not
        // shielded and may challenge — no barrier then.
        if !self.carrier_shields_ball_from_defender(carrier_id, player_id) {
            return;
        }
        let carrier_pos = self.players[carrier_id].position;
        let offset = self.players[player_id].position - carrier_pos;
        let dist = offset.len();
        if dist >= SHIELD_BODY_BARRIER_YARDS {
            return;
        }
        // Push the defender out to the body ring along its own approach direction
        // (fall back to the ball→defender side, i.e. away from the ball, if it is
        // standing on the carrier).
        let dir = if dist > 1e-6 {
            offset / dist
        } else {
            let from_ball = carrier_pos - self.ball.position;
            if from_ball.len() > 1e-6 {
                from_ball.normalized()
            } else {
                Vec2::new(0.0, -self.players[player_id].team.attack_dir())
            }
        };
        let target = (carrier_pos + dir * SHIELD_BODY_BARRIER_YARDS).clamp_to_pitch(
            self.config.field_width_yards,
            self.config.field_length_yards,
        );
        let player = &mut self.players[player_id];
        player.position = target;
        // Cancel the component of momentum driving it into the body so it stays pressed
        // against the carrier instead of jittering through.
        let into_body = dir * -1.0;
        let inward = player.velocity.dot(into_body);
        if inward > 0.0 {
            player.velocity = player.velocity - into_body * inward;
        }
        let inward_acc = player.acceleration.dot(into_body);
        if inward_acc > 0.0 {
            player.acceleration = player.acceleration - into_body * inward_acc;
        }
    }

    /// Rule B helper: if a midfielder/forward has lingered in a genuine offside position beyond the
    /// recovery grace window, return the spot to move back to to get onside; otherwise
    /// `None`. Marginal offside runs keep the normal [`OFFSIDE_GRACE_SECONDS`] timing,
    /// while clearly deep offside positions are recovered sooner. "Offside" is the real
    /// thing — in the opponents' half, beyond the 2nd-last opponent (the keeper counts as a
    /// defender) AND beyond the ball, with our team the last to touch it. An attacker through
    /// on goal WITH the ball, or the intended receiver of an in-flight pass, is exempt and
    /// keeps its run.
    pub(crate) fn attacker_offside_recovery_target(&self, player_id: usize) -> Option<Vec2> {
        let me = self.players.iter().find(|p| p.id == player_id)?;
        if !matches!(me.role, PlayerRole::Forward | PlayerRole::Midfielder) {
            return None;
        }
        // Through on goal WITH the ball, or being played in — keep the run.
        if self.ball.holder == Some(player_id) {
            return None;
        }
        if self.pending_pass.as_ref().and_then(|pass| pass.target) == Some(player_id) {
            return None;
        }
        // A LOOSE ball the opponent (or anyone) last played does not leave you offside — Law 11
        // is only ever assessed off a team-mate's deliberate touch — and a ball this player is
        // genuinely placed to win must not be abandoned. So keep the run while the ball is loose
        // and this player is a committed chaser of it. In every OTHER case (the opponent is in
        // clear possession, or the ball is loose but out of this player's reach) a mid/forward
        // stranded beyond the line is doing nothing useful and should drift back into shape,
        // regardless of who touched it last.
        //
        // The old code bailed on ANY opponent touch. In scrappy midfield play the last-touch
        // flag flickers team-to-team every few seconds, so that gate kept cancelling the recovery
        // jog mid-stride and re-stranding the attacker — live measurement (GET /api/inspect)
        // showed strikers sitting offside for 6-8s instead of recovering shortly after the ~3s
        // grace.
        if self.ball.holder.is_none() {
            let ball_pos = self.ball.position;
            let my_dist = me.position.distance(ball_pos);
            let i_am_closest = !self.players.iter().any(|p| {
                p.id != player_id
                    && p.team == me.team
                    && p.role != PlayerRole::Goalkeeper
                    && p.position.distance(ball_pos) < my_dist
            });
            if my_dist <= LOOSE_BALL_FIFTY_FIFTY_CONTEST_RADIUS_YARDS && i_am_closest {
                return None;
            }
        }
        // Confirm STILL offside now (guards a stale clock from a prior possession): in the
        // opponents' half, beyond the 2nd-last opponent (keeper included), beyond the ball.
        let pos = me.position;
        let attack_dir = me.team.attack_dir();
        let half_line = self.config.field_length_yards * 0.5;
        if (pos.y - half_line) * attack_dir <= 0.0 {
            return None;
        }
        let mut opp_ys: Vec<f64> = self
            .players
            .iter()
            .filter(|p| p.team == me.team.other())
            .map(|p| p.position.y)
            .collect();
        if opp_ys.len() < 2 {
            return None;
        }
        // index 1 = the second-last opponent in the attacking direction.
        match me.team {
            Team::Home => {
                opp_ys.sort_by(|a, b| b.partial_cmp(a).unwrap_or(std::cmp::Ordering::Equal))
            }
            Team::Away => {
                opp_ys.sort_by(|a, b| a.partial_cmp(b).unwrap_or(std::cmp::Ordering::Equal))
            }
        }
        let line_y = opp_ys[1];
        let offside_yards = (pos.y - line_y) * attack_dir;
        let beyond_line = offside_yards > 0.0;
        let beyond_ball = (pos.y - self.ball.position.y) * attack_dir > 0.0;
        if !beyond_line || !beyond_ball {
            return None;
        }
        let recovery_grace = if offside_yards >= DEEP_OFFSIDE_RECOVERY_MARGIN_YARDS {
            DEEP_OFFSIDE_RECOVERY_GRACE_SECONDS
        } else {
            OFFSIDE_GRACE_SECONDS
        };
        if self.offside_clocks.get(&player_id).copied().unwrap_or(0.0) <= recovery_grace {
            return None;
        }
        // Move back to just onside of the 2nd-last line, holding lateral position.
        let onside_y = line_y - STRIKER_ONSIDE_BUFFER_YARDS * attack_dir;
        Some(Vec2::new(pos.x, onside_y).clamp_to_pitch(
            self.config.field_width_yards,
            self.config.field_length_yards,
        ))
    }

    pub(crate) fn apply_player_intent(&mut self, intent: PlayerIntent) {
        if intent.player_id >= self.players.len() {
            return;
        }
        let player_id = intent.player_id;
        let action_facing = self.facing_for_player_action(player_id, &intent.action);
        self.players[player_id].action_facing = action_facing;
        self.record_near_goal_no_shot_penalty(player_id, &intent.action);
        self.record_excessive_hold_penalty(player_id, &intent.action);
        // Run-around-dribble KNOCK: the carrier has just committed (runaround set, not yet knocked)
        // and still holds the ball — release it toward the push target as a loose ball at a pace
        // sized to the distance (so it rolls just past the defender, not overhit). The carrier's
        // own MoveTo intent (to the re-collect point) then sprints the body around the other side.
        if let Some(mut run) = self.players[player_id].runaround {
            if !run.knocked && self.ball.holder == Some(player_id) {
                let ball_pos = self.ball.position;
                let to_target = run.push_target - ball_pos;
                let dist = to_target.len().max(0.5);
                let dir = to_target / dist;
                let speed = (dist * RUNAROUND_KNOCK_SPEED_PER_YARD)
                    .clamp(RUNAROUND_KNOCK_MIN_SPEED_YPS, RUNAROUND_KNOCK_MAX_SPEED_YPS);
                // Firm first touch: push the ball off the foot past the carrier's own control reach
                // so it is not re-grabbed the same tick and actually travels past the defender.
                self.ball.position = (ball_pos + dir * RUNAROUND_KNOCK_NUDGE_YARDS).clamp_to_pitch(
                    self.config.field_width_yards,
                    self.config.field_length_yards,
                );
                self.ball.velocity = dir * speed;
                self.ball.altitude_yards = 0.0;
                self.ball.curl_acceleration = Vec2::zero();
                self.ball.holder = None;
                self.players[player_id].incoming_ball = None;
                self.pending_pass = None;
                self.pending_shot = None;
                self.record_possession_touch(player_id);
                run.knocked = true;
                self.players[player_id].runaround = Some(run);
            }
        }
        // Direct human control: drive a controlled player's off-ball movement
        // responsively (tiered pace, hard brake on release) rather than via the AI
        // gait model. Only movement actions are overridden; on-ball actions
        // (dribble/pass/shoot) keep their own logic.
        if let Some((_, dir, pace)) = self
            .pending_human_control
            .take()
            .filter(|(pid, _, _)| *pid == player_id)
        {
            if matches!(
                intent.action,
                SoccerAction::MoveTo(_) | SoccerAction::HoldShape
            ) {
                self.apply_human_control_movement(player_id, dir, pace);
                return;
            }
        }
        // Manual drag-and-drop coaching hint: steer an AI player to the spot it
        // was dropped on (where to stand on D/O, or where to get open to receive
        // a pass). Only overrides off-ball movement of an un-controlled,
        // non-carrier player; on-ball actions and human-controlled players keep
        // their own logic.
        if self.ball.holder != Some(player_id)
            && self.players[player_id].controller_slot.is_none()
            && matches!(
                intent.action,
                SoccerAction::MoveTo(_) | SoccerAction::HoldShape
            )
        {
            if let Some(target) = self.active_coach_hint_target(player_id) {
                self.move_player_towards(player_id, target, intent.sprint);
                return;
            }
        }
        let player_pos = self.players[player_id].position;
        let player_team = self.players[player_id].team;
        // First-touch settle gate: a holder is the ball's owner (`has_ball`) the
        // instant control is won, but a ball won from a stretched trap is still 1.4–2.8yd
        // out being drawn to the feet over ~2 ticks (see CONTROL_FIRST_TOUCH_SETTLE_*).
        // Striking it in that window launched the ball from out there (or teleported it
        // onto the feet first) — a "ghost kick" with no player visibly at the ball. Until
        // the ball has settled within strike reach, downgrade any ball-RELEASE to a
        // settling touch: step onto the ball and keep possession; `sync_held_ball_to_holder`
        // draws it smoothly to the feet, and the strike fires cleanly a tick later.
        if self.ball.holder == Some(player_id)
            && matches!(
                intent.action,
                SoccerAction::Pass { .. }
                    | SoccerAction::Clearance { .. }
                    | SoccerAction::RouteOne { .. }
                    | SoccerAction::Shoot { .. }
            )
            && player_pos.distance(self.ball.position) > CONTROLLED_STRIKE_REACH_YARDS
        {
            let ball_pos = self.ball.position;
            self.move_player_towards(player_id, ball_pos, false);
            let settle_facing =
                facing_bucket_from_vector(ball_pos - self.players[player_id].position);
            if settle_facing != FacingBucket::Unknown {
                self.players[player_id].action_facing = settle_facing;
            }
            return;
        }
        // Rule B (attacker onside discipline): a mid/forward that has loitered in an offside
        // position beyond the 3s grace is pulled back onside — at a jog, no forced sprint
        // (soft, eventual consistency). Offside here is the real thing (opponents' half,
        // beyond the 2nd-last opponent incl. the keeper, beyond the ball, our ball last).
        // An attacker through ON GOAL WITH THE BALL, or the target of an in-flight pass, is
        // exempt and keeps its run. Overrides off-ball movement only.
        if matches!(
            intent.action,
            SoccerAction::HoldShape
                | SoccerAction::MoveTo(_)
                | SoccerAction::Dribble(_)
                | SoccerAction::DribbleMove { .. }
                | SoccerAction::ControlTouch { .. }
        ) {
            if let Some(onside) = self.attacker_offside_recovery_target(player_id) {
                let urgent = self.players[player_id].position.distance(onside)
                    >= DEEP_OFFSIDE_RECOVERY_MARGIN_YARDS;
                self.move_player_towards(player_id, onside, urgent);
                return;
            }
        }
        // Keep-rolling momentum (gated, default-ON): if the decided action would pull an unpressured
        // carrier up to a near-stop, keep the ball rolling forward into the open space instead of
        // stopping dead (the walk-stop-walk flicker). Only the carrier's hold/settle/carry actions
        // are eligible — a pass, shot, clearance or tackle is never touched — and the redirect only
        // fires when `carrier_keep_rolling_target_for` confirms the near-stop-in-space case, so the
        // path is byte-identical to baseline otherwise. Routed through the dribble executor so the
        // led ball stays glued to the feet exactly as a normal carry.
        let keep_rolling = &tunables().carrier_keep_rolling;
        if keep_rolling.enabled && self.ball.holder == Some(player_id) {
            // `ControlTouch` is deliberately excluded: it is a first-touch reception/settle with its
            // own ball-settling semantics (it clears `incoming_ball` and draws the ball to the feet),
            // not a "stop on a ball you already hold". Only the settle/hold/carry actions that
            // produce the walk-stop freeze are eligible.
            let settling_target = match intent.action {
                SoccerAction::HoldShape => Some(self.players[player_id].home_position),
                SoccerAction::MoveTo(target) | SoccerAction::Dribble(target) => Some(target),
                SoccerAction::DribbleMove { target, kind, .. }
                    if matches!(
                        kind,
                        DribbleMoveKind::CarryForward
                            | DribbleMoveKind::CarryOutLeft
                            | DribbleMoveKind::CarryOutRight
                            | DribbleMoveKind::ProtectBall
                    ) =>
                {
                    Some(target)
                }
                _ => None,
            };
            if let Some(settling_target) = settling_target {
                let roll_target = WorldSnapshot::from_match(self)
                    .carrier_keep_rolling_target_for(player_id, settling_target);
                if let Some(roll_target) = roll_target {
                    self.apply_dribble_intent(
                        player_id,
                        roll_target,
                        false,
                        Some(DribbleMoveKind::CarryForward),
                        None,
                    );
                    return;
                }
            }
        }
        match intent.action {
            SoccerAction::HoldShape => {
                let target = self.players[player_id].home_position;
                self.move_player_towards(player_id, target, intent.sprint);
            }
            SoccerAction::MoveTo(target) => {
                self.move_player_towards(player_id, target, intent.sprint);
            }
            SoccerAction::Dribble(target) => {
                self.apply_dribble_intent(player_id, target, true, None, None);
            }
            SoccerAction::DribbleMove {
                target,
                kind,
                touch,
            } => {
                self.apply_dribble_intent(
                    player_id,
                    target,
                    intent.sprint,
                    Some(kind),
                    Some(touch),
                );
            }
            SoccerAction::ControlTouch { target } => {
                let sprint_touch = intent.sprint
                    || self.players[player_id]
                        .incoming_ball
                        .as_ref()
                        .is_some_and(|context| {
                            self.tick.saturating_sub(context.received_tick)
                                <= FIRST_TOUCH_WINDOW_TICKS
                        })
                        && self.players[player_id].velocity.len()
                            <= FIRST_TOUCH_ESCAPE_STATIONARY_SPEED_YPS
                        && pressure_from_nearest_distance(
                            self.players
                                .iter()
                                .filter(|opponent| opponent.team != player_team)
                                .map(|opponent| {
                                    opponent.position.distance(self.players[player_id].position)
                                })
                                .fold(f64::INFINITY, f64::min),
                        ) >= FIRST_TOUCH_ESCAPE_SPRINT_PRESSURE;
                self.move_player_towards(player_id, target, sprint_touch);
                if self.ball.holder == Some(player_id) {
                    let player = &mut self.players[player_id];
                    self.ball.position = (player.position + carried_ball_lead(player) * 0.45)
                        .clamp_to_pitch(
                            self.config.field_width_yards,
                            self.config.field_length_yards,
                        );
                    self.ball.velocity = player.velocity * 0.35;
                    self.ball.curl_acceleration = Vec2::zero();
                    self.ball.altitude_yards = 0.0;
                    self.ball.last_touch_team = Some(player_team);
                    player.incoming_ball = None;
                    self.pending_pass = None;
                    self.pending_shot = None;
                }
            }
            SoccerAction::Pass {
                target_player,
                mut power,
                flight,
            } => {
                let mut release_facing = action_facing;
                if self.ball.holder == Some(player_id) {
                    let snapshot = WorldSnapshot::from_match(self);
                    let observation = snapshot.observation_for(player_id);
                    let explicit_target_id = target_player.filter(|target_id| {
                        self.players.iter().any(|player| {
                            player.id == *target_id
                                && player.id != player_id
                                && player.team == player_team
                        })
                    });
                    // MPC determines the keeper's play-out: when the keeper is choosing freely
                    // (no explicit target named), MPC picks which team-mate and which technique
                    // (a ground roll vs a lofted throw/punt) the receding-horizon rendezvous can
                    // best DELIVER, in place of the generic ranked target. An explicitly named
                    // target (a learned plan / human input) is still honoured, and a restart he
                    // is taking keeps its own goal-kick rules. The execution-layer MPC then sets
                    // the launch pace below, so the whole play-out is MPC-driven.
                    let keeper_mpc_distribution = if self.players[player_id].role
                        == PlayerRole::Goalkeeper
                        && self.restart_double_touch_guard != Some(player_id)
                        && explicit_target_id.is_none()
                    {
                        snapshot.goalkeeper_mpc_distribution_for(player_id)
                    } else {
                        None
                    };
                    let mut target_id = explicit_target_id.or_else(|| {
                        keeper_mpc_distribution.map(|(id, _)| id).or_else(|| {
                            if flight.is_aerial() {
                                snapshot.best_aerial_pass_target(player_id)
                            } else {
                                snapshot.best_pass_target(player_id)
                            }
                        })
                    });
                    let mut flight = flight;
                    if let Some((_, mpc_flight)) = keeper_mpc_distribution {
                        flight = mpc_flight;
                    }
                    // Resolve the aim point. With no ranked receiver, fall back to a purposeful
                    // forward outlet — and if that outlet is aimed at a genuinely open advanced
                    // teammate, ADOPT them as the receiver so the ball is played TO someone. Only
                    // a true delivery into open space (the channel-point fallback) stays a "pass
                    // to nobody", which the guard below restricts to forward, long balls.
                    let resolve_outlet = |target_id: &mut Option<usize>| -> Vec2 {
                        // No explicit target (e.g. a restart/learned-plan pass): play a
                        // purposeful forward ball to the most OPEN advanced teammate ~20-40
                        // yards ahead, clamped inside the pitch — never a blind hoof into
                        // space (which is what dropped the ball straight to an opponent).
                        let (point, receiver) = snapshot.no_target_forward_outlet_target(
                            player_id,
                            player_pos,
                            player_team,
                        );
                        *target_id = receiver;
                        point
                    };
                    let mut target = match target_id {
                        Some(id) => {
                            let aerial_point = if flight.is_aerial() {
                                snapshot.projected_in_behind_pass_point(player_id, id)
                            } else {
                                None
                            };
                            aerial_point
                                .or_else(|| {
                                    self.players.iter().find(|p| p.id == id).map(|p| p.position)
                                })
                                .unwrap_or_else(|| resolve_outlet(&mut target_id))
                        }
                        None => resolve_outlet(&mut target_id),
                    };
                    let goalkeeper_play_out_plan =
                        if self.players[player_id].role == PlayerRole::Goalkeeper {
                            snapshot.goalkeeper_mpc_play_out_plan(player_id, target_id)
                        } else {
                            None
                        };
                    // Calm keeper distribution: a keeper holding in his hands inside his
                    // box is unstealable, so he is in no hurry. Rather than rolling/throwing
                    // the ball straight back to a nearby presser (e.g. the player who just
                    // shot), he keeps holding until a genuinely open team-mate appears, up
                    // to the handling limit (then `update_keeper_handling` forces a clear).
                    // Skipped on a restart he is taking (a goal kick has its own hold/clear
                    // rules in `restart_release_action`) — only open-play gathers hold here.
                    if self.restart_double_touch_guard != Some(player_id) {
                        if let Some(held) = self.keeper_handling_held_seconds(player_id) {
                            if held < GK_HANDLING_HOLD_LIMIT_SECONDS
                                && !self.keeper_handling_release_is_intelligent(
                                    &snapshot, player_id, target_id, target,
                                )
                            {
                                // Survey the field (face the outlet) and hold the ball.
                                let look = target - player_pos;
                                if look.len() > 1e-6 {
                                    let face = facing_bucket_from_vector(look);
                                    if face != FacingBucket::Unknown {
                                        self.players[player_id].action_facing = face;
                                    }
                                }
                                return;
                            }
                        }
                    }
                    if let Some(plan) = goalkeeper_play_out_plan {
                        target_id = plan.target_player;
                        target = plan.target.clamp_to_pitch(
                            self.config.field_width_yards,
                            self.config.field_length_yards,
                        );
                        power = plan.power;
                        flight = plan.flight;
                    }
                    let pressure = pressure_from_observation(&observation);
                    if target_id.is_some_and(|id| {
                        !snapshot.players.iter().any(|player| {
                            player.id == id && player.id != player_id && player.team == player_team
                        })
                    }) {
                        target_id = None;
                        target = resolve_outlet(&mut target_id);
                    }
                    let mut slip_break_profile = target_id
                        .map(|id| snapshot.slip_break_offside_trap_profile_for(player_id, id))
                        .unwrap_or_default();
                    if slip_break_profile.available {
                        flight = PassFlight::Floor;
                        target = slip_break_profile.aim_point.clamp_to_pitch(
                            self.config.field_width_yards,
                            self.config.field_length_yards,
                        );
                        power = 0.86;
                    }
                    let mut marked_target_to_rewrite = None;
                    if let Some(current_target_id) = target_id {
                        if let Some(receiver) = snapshot.players.iter().find(|player| {
                            player.id == current_target_id && player.team == player_team
                        }) {
                            let receiver_position = snapshot
                                .player_position(current_target_id)
                                .unwrap_or(receiver.position);
                            let one_two_give_to_wall = self.players[player_id]
                                .one_two
                                .map(|one_two| one_two.wall_partner)
                                == Some(current_target_id);
                            let forward = (target.y - player_pos.y) * player_team.attack_dir();
                            if !slip_break_profile.available
                                && !one_two_give_to_wall
                                && snapshot.pass_target_marked_under_pressure(
                                    player_team,
                                    receiver_position,
                                    target,
                                    pressure,
                                    forward,
                                )
                            {
                                marked_target_to_rewrite = Some(current_target_id);
                            }
                        } else {
                            target_id = None;
                            target = resolve_outlet(&mut target_id);
                        }
                    }
                    if let Some(unsafe_target_id) = marked_target_to_rewrite {
                        if let Some((replacement_id, replacement_point)) = snapshot
                            .safe_pass_replacement_for(
                                player_id,
                                player_team,
                                player_pos,
                                flight,
                                unsafe_target_id,
                                pressure,
                            )
                        {
                            target_id = Some(replacement_id);
                            target = replacement_point.clamp_to_pitch(
                                self.config.field_width_yards,
                                self.config.field_length_yards,
                            );
                            slip_break_profile = SlipBreakOffsideTrapProfile::default();
                        } else {
                            target_id = None;
                            target = resolve_outlet(&mut target_id);
                            slip_break_profile = SlipBreakOffsideTrapProfile::default();
                        }
                    }
                    let over_top_killer_aim = if flight.is_over_top() {
                        target_id.and_then(|id| {
                            snapshot.killer_pass_over_top_aim_point_for(player_id, id)
                        })
                    } else {
                        None
                    };
                    if let Some(aim) = over_top_killer_aim {
                        target = aim.clamp_to_pitch(
                            self.config.field_width_yards,
                            self.config.field_length_yards,
                        );
                    } else if flight.is_over_top() {
                        flight = PassFlight::Aerial;
                    }
                    let initial_is_cross = pass_would_be_cross(
                        player_pos,
                        target,
                        player_team,
                        self.config.field_width_yards,
                        self.config.field_length_yards,
                    );
                    let initial_pass_skill = pass_execution_skill(
                        &self.players[player_id].skills,
                        flight,
                        initial_is_cross,
                    );
                    let initial_raw_speed = pass_speed_yps_from_power(
                        power,
                        flight,
                        initial_is_cross,
                        &self.players[player_id].skills,
                    );
                    let receiver_openness_at_player =
                        pass_receiver_openness_for_agents(&self.players, player_team, target);
                    let initial_speed = modulated_pass_speed_yps(
                        initial_raw_speed,
                        player_pos,
                        target,
                        flight,
                        initial_is_cross,
                        initial_pass_skill,
                        receiver_openness_at_player,
                        &mut self.rng,
                    );
                    // A one-two "give" is a firm lay-off to the wall partner's FEET so they can
                    // play it back first-time — NOT a led through-ball. The generic lead
                    // (`anticipated_pass_reception_point`) biases the aim forward toward goal by
                    // the receiver's role bias even for a stationary partner, throwing the give
                    // ahead into space the partner never occupies; meanwhile the passer has
                    // already burst into the return run, so the ball is left to nobody. When the
                    // carrier is committing the give of a live one-two naming THIS target as the
                    // wall, aim straight at the partner and skip the lead/MPC.
                    let is_one_two_give = !dd_soccer_disable_one_two_give_to_feet()
                        && target_id.is_some()
                        && self.players[player_id].one_two.map(|o| o.wall_partner) == target_id;
                    let mut led_target = if slip_break_profile.available {
                        slip_break_profile.aim_point.clamp_to_pitch(
                            self.config.field_width_yards,
                            self.config.field_length_yards,
                        )
                    } else if let Some(aim) = over_top_killer_aim {
                        aim.clamp_to_pitch(
                            self.config.field_width_yards,
                            self.config.field_length_yards,
                        )
                    } else if is_one_two_give {
                        target.clamp_to_pitch(
                            self.config.field_width_yards,
                            self.config.field_length_yards,
                        )
                    } else {
                        target_id
                            .and_then(|id| {
                                snapshot.anticipated_pass_reception_point(
                                    player_id,
                                    id,
                                    flight,
                                    initial_speed,
                                )
                            })
                            .unwrap_or(target)
                            .clamp_to_pitch(
                                self.config.field_width_yards,
                                self.config.field_length_yards,
                            )
                    };
                    // MPC pass execution: for a ground pass to a real receiver, replace the analytic
                    // lead with the receding-horizon rendezvous (lead point + launch speed) so the
                    // ball is delivered onto the receiver's predicted run, into space, beating the
                    // defenders' reach. Falls back to the analytic lead when the solver declines.
                    // (Skipped for a one-two give — that is aimed to the partner's feet above.)
                    let mut mpc_pass_speed =
                        goalkeeper_play_out_plan.and_then(|plan| plan.launch_speed_yps);
                    if slip_break_profile.available {
                        mpc_pass_speed = Some(slip_break_profile.pass_speed_yps);
                    }
                    if let Some(plan) = goalkeeper_play_out_plan {
                        led_target = plan.target.clamp_to_pitch(
                            self.config.field_width_yards,
                            self.config.field_length_yards,
                        );
                    }
                    if mpc_pass_speed.is_none()
                        && !flight.is_aerial()
                        && !is_one_two_give
                        && !slip_break_profile.available
                    {
                        if let Some(id) = target_id {
                            if let Some((aim, v)) = snapshot.mpc_pass_execution(
                                player_id,
                                id,
                                led_target,
                                initial_speed,
                            ) {
                                led_target = aim.clamp_to_pitch(
                                    self.config.field_width_yards,
                                    self.config.field_length_yards,
                                );
                                mpc_pass_speed = Some(v);
                            }
                        }
                    }
                    if let Some(current_target_id) = target_id {
                        if let Some(receiver) = snapshot.players.iter().find(|player| {
                            player.id == current_target_id && player.team == player_team
                        }) {
                            let receiver_position = snapshot
                                .player_position(current_target_id)
                                .unwrap_or(receiver.position)
                                .clamp_to_pitch(
                                    self.config.field_width_yards,
                                    self.config.field_length_yards,
                                );
                            let led_forward =
                                (led_target.y - player_pos.y) * player_team.attack_dir();
                            let led_unsafe = snapshot.pass_target_marked_under_pressure(
                                player_team,
                                receiver_position,
                                led_target,
                                pressure,
                                led_forward,
                            );
                            if led_unsafe && !slip_break_profile.available {
                                let feet_forward =
                                    (receiver_position.y - player_pos.y) * player_team.attack_dir();
                                let receiver_feet_safe = !snapshot
                                    .pass_target_marked_under_pressure(
                                        player_team,
                                        receiver_position,
                                        receiver_position,
                                        pressure,
                                        feet_forward,
                                    );
                                if receiver_feet_safe {
                                    led_target = receiver_position;
                                    mpc_pass_speed = None;
                                } else if let Some((replacement_id, replacement_point)) = snapshot
                                    .safe_pass_replacement_for(
                                        player_id,
                                        player_team,
                                        player_pos,
                                        flight,
                                        current_target_id,
                                        pressure,
                                    )
                                {
                                    target_id = Some(replacement_id);
                                    target = replacement_point.clamp_to_pitch(
                                        self.config.field_width_yards,
                                        self.config.field_length_yards,
                                    );
                                    led_target = target;
                                    mpc_pass_speed = None;
                                } else {
                                    let look = led_target - player_pos;
                                    if look.len() > 1e-6 {
                                        let face = facing_bucket_from_vector(look);
                                        if face != FacingBucket::Unknown {
                                            self.players[player_id].action_facing = face;
                                        }
                                    }
                                    return;
                                }
                            }
                        }
                    }
                    // A ball with no resolved receiver ("to nobody in particular") is not an
                    // open-play pass anymore. The outlet resolver above first tries to adopt a real
                    // teammate; if that fails, the carrier keeps possession, faces the intended lane,
                    // and lets support movement create an option. Restart takers may still release
                    // an explicit long forward ball, but only through the old safety gate.
                    let no_target_release_is_legal = pass_to_nobody_is_legal(
                        player_pos,
                        led_target,
                        player_team,
                        self.config.field_width_yards,
                        self.config.field_length_yards,
                    ) && !snapshot
                        .no_target_pass_point_directly_favors_opponent(
                            player_team,
                            player_id,
                            led_target,
                        );
                    if target_id.is_none()
                        && (self.restart_double_touch_guard != Some(player_id)
                            || !no_target_release_is_legal)
                    {
                        let look = led_target - player_pos;
                        if look.len() > 1e-6 {
                            let face = facing_bucket_from_vector(look);
                            if face != FacingBucket::Unknown {
                                self.players[player_id].action_facing = face;
                            }
                        }
                        return;
                    }
                    if flight.is_aerial() {
                        let bounds = long_aerial_bounds_risk_for_target(
                            player_pos,
                            led_target,
                            self.config.field_width_yards,
                            self.config.field_length_yards,
                            flight,
                        );
                        if bounds.risk >= 0.45 || bounds.inward_correction_yards >= 1.5 {
                            led_target = long_aerial_safe_in_bounds_target(
                                led_target,
                                self.config.field_width_yards,
                                self.config.field_length_yards,
                            );
                            mpc_pass_speed = None;
                        }
                    }
                    let is_cross = pass_would_be_cross(
                        player_pos,
                        led_target,
                        player_team,
                        self.config.field_width_yards,
                        self.config.field_length_yards,
                    );
                    let pass_skill =
                        pass_execution_skill(&self.players[player_id].skills, flight, is_cross);
                    // Body-facing gate: you can only strike the ball with the slice of your
                    // range the body is turned toward. Evaluate the intended pass line against
                    // the carrier's CURRENT facing (this tick's body orientation, before the
                    // end-of-tick turn integrates) — no kicking one way while facing the other.
                    let intended_dir = led_target - player_pos;
                    let facing_outcome = pass_facing_outcome(
                        self.players[player_id].facing_yaw,
                        intended_dir,
                        pass_origin_in_own_half(
                            player_team,
                            player_pos,
                            self.config.field_length_yards,
                        ),
                    );
                    if facing_outcome.forbidden {
                        // A backward ball in our own half is not a legal backheel — the player
                        // can't play it from this body shape. Turn to face it (so a later
                        // decision can pass it) and keep possession rather than releasing an
                        // impossible reverse-strike.
                        if intended_dir.len() > 1e-6 {
                            let face = facing_bucket_from_vector(intended_dir);
                            if face != FacingBucket::Unknown {
                                self.players[player_id].action_facing = face;
                            }
                        }
                        return;
                    }
                    if flight.is_aerial()
                        && facing_outcome.power_factor < AERIAL_PASS_MIN_LAUNCH_POWER_FACTOR
                    {
                        // A loft needs a planted body shape. If the carrier is too side-on /
                        // twisted, releasing now turns a calibrated aerial into a weak capped
                        // lob that crawls in x-y while the gravity timer keeps ticking. Face up
                        // and re-decide next tick instead.
                        if intended_dir.len() > 1e-6 {
                            let face = facing_bucket_from_vector(intended_dir);
                            if face != FacingBucket::Unknown {
                                self.players[player_id].action_facing = face;
                            }
                        }
                        return;
                    }
                    let effective_pass_skill =
                        (pass_skill * facing_outcome.accuracy_factor).clamp(0.0, 1.0);
                    let raw_speed = pass_speed_yps_from_power(
                        power,
                        flight,
                        is_cross,
                        &self.players[player_id].skills,
                    );
                    let receiver_openness =
                        pass_receiver_openness_for_agents(&self.players, player_team, led_target);
                    let modulated_speed = modulated_pass_speed_yps(
                        raw_speed,
                        player_pos,
                        led_target,
                        flight,
                        is_cross,
                        pass_skill,
                        receiver_openness,
                        &mut self.rng,
                    );
                    // The MPC chose a launch speed for the ball/receiver rendezvous; nudge the
                    // analytic speed toward it (kept close so it stays a real ground pass and does
                    // not outrun the receiver's control), else keep the analytic modulated speed.
                    let speed = match mpc_pass_speed {
                        Some(v) => {
                            // Lean on the MPC rendezvous speed (it times the ball to the receiver
                            // and beats the press) and let it FIRM the ball well above the analytic
                            // pace — the old ±25% clamp pinned it to a too-slow baseline.
                            if pass_accuracy_calibration_enabled() {
                                let blended = modulated_speed * 0.45 + v * 0.55;
                                blended.clamp(modulated_speed * 0.85, modulated_speed * 1.5)
                            } else {
                                let blended = modulated_speed * 0.6 + v * 0.4;
                                blended.clamp(modulated_speed * 0.85, modulated_speed * 1.25)
                            }
                        }
                        None => modulated_speed,
                    };
                    // Learnable pass velocity (execution side): honor the speed the decision
                    // priced. The value trade-off (receipt-aware) elects a power bucket; when
                    // it chose to DRIVE the ball (above the 0.68 nominal) the lane was
                    // contested and a firmer pass beats the defender to the corridor, so firm
                    // the struck ball UP to that chosen pace. When it kept a weighted ball (an
                    // open lane) the executed speed is left untouched — an uncontested pass is
                    // never firmed or slowed. Firming to the CHOSEN speed (not the raw
                    // `min_clearing` floor) keeps a contested ball receivable: the chosen speed
                    // already balances threading the lane against the receiver controlling it,
                    // so it can't over-drive into an uncontrollable rocket. Ground only;
                    // aerials keep their gravity-fixed calibration. Disabled ⇒ unchanged.
                    let speed =
                        if !flight.is_aerial() && !dd_soccer_disable_learnable_pass_velocity() {
                            if let Some(passer_snap) =
                                snapshot.players.iter().find(|p| p.id == player_id)
                            {
                                let receiver = target_id.and_then(|id| {
                                    snapshot
                                        .players
                                        .iter()
                                        .find(|p| p.id == id)
                                        .map(|p| (p, p.position))
                                });
                                let plan = pass_velocity_plan_for_snapshot(
                                    &snapshot,
                                    passer_snap,
                                    player_pos,
                                    led_target,
                                    flight,
                                    is_cross,
                                    receiver,
                                );
                                if plan.power > 0.68 {
                                    speed.max(plan.speed_yps).min(mph_to_yps(
                                        GROUND_PASS_CEILING_MPH + PASS_SPEED_CEILING_OVERSHOOT_MPH,
                                    ))
                                } else {
                                    speed
                                }
                            } else {
                                speed
                            }
                        } else {
                            speed
                        };
                    let speed = if slip_break_profile.available {
                        slip_break_profile.pass_speed_yps.clamp(
                            mph_to_yps(SLIP_BREAK_OFFSIDE_TRAP_MIN_PASS_MPH),
                            mph_to_yps(SLIP_BREAK_OFFSIDE_TRAP_MAX_PASS_MPH),
                        )
                    } else {
                        speed
                    };
                    let mut distance = player_pos.distance(led_target);
                    let mut aimed_target = if flight.is_over_top() || slip_break_profile.available {
                        led_target
                    } else {
                        noisy_pass_target_with_receiver_openness(
                            player_pos,
                            led_target,
                            effective_pass_skill,
                            pressure,
                            distance,
                            receiver_openness,
                            &mut self.rng,
                        )
                    }
                    .clamp_to_pitch(
                        self.config.field_width_yards,
                        self.config.field_length_yards,
                    );
                    if !slip_break_profile.available {
                        if let Some(receiver_position) = target_id.and_then(|target| {
                            self.players
                                .iter()
                                .find(|player| player.id == target && player.team == player_team)
                                .map(|player| player.position)
                        }) {
                        let aimed_risk = snapshot.pass_point_direct_opponent_control_risk(
                            player_team,
                            receiver_position,
                            player_pos,
                            aimed_target,
                            speed,
                        );
                        let led_risk = snapshot.pass_point_direct_opponent_control_risk(
                            player_team,
                            receiver_position,
                            player_pos,
                            led_target,
                            speed,
                        );
                        let receiver_risk = snapshot.pass_point_direct_opponent_control_risk(
                            player_team,
                            receiver_position,
                            player_pos,
                            receiver_position,
                            speed,
                        );
                        let safer_release_risk = led_risk.min(receiver_risk);
                        if aimed_risk >= PASS_DIRECT_OPPONENT_AIM_RELEASE_CORRECTION_RISK
                            || aimed_risk
                                >= safer_release_risk
                                    + PASS_DIRECT_OPPONENT_AIM_NOISE_CORRECTION_MARGIN
                        {
                            aimed_target = if led_risk < aimed_risk && led_risk <= receiver_risk {
                                led_target
                            } else if receiver_risk < aimed_risk {
                                receiver_position
                            } else {
                                aimed_target
                            };
                        }
                        // Aim noise — and a marker SHADOWING the receiver at the same range, which
                        // the closer-than-receiver risk model above scores at zero — can still send
                        // the ball toward an opponent. Combine BOTH guards but keep their resolutions
                        // distinct. `favours_opponent` is alex-1's STRONG danger (high residual risk
                        // or the aim clearly favouring an opponent); `concedes` is HEAD's shadow-aware
                        // reception concede. For either danger, first try to RE-AIM to a safe release
                        // (the receiver's own feet, else the led point). If a safe release exists, use
                        // it. If none does, only ABORT on the STRONG danger — turn to look up the led
                        // channel and keep the ball rather than gift it; a mere shadow-concede with no
                        // safe alternative keeps the deliberately-chosen pass (so a human/AI pass is
                        // never silently swallowed on a soft read).
                        let favours_opponent = |point: Vec2| {
                            snapshot.pass_point_direct_opponent_control_risk(
                                player_team,
                                receiver_position,
                                player_pos,
                                point,
                                speed,
                            ) >= PASS_DIRECT_OPPONENT_AIM_RELEASE_CORRECTION_RISK
                                || snapshot.pass_point_directly_favors_opponent(
                                    player_team,
                                    receiver_position,
                                    point,
                                )
                        };
                        let concedes = |point: Vec2| {
                            snapshot.pass_reception_conceded_to_opponent(
                                player_team,
                                receiver_position,
                                player_pos,
                                point,
                                speed,
                                pressure,
                            )
                        };
                        let unsafe_release =
                            |point: Vec2| concedes(point) || favours_opponent(point);
                        if unsafe_release(aimed_target) {
                            if !unsafe_release(receiver_position) {
                                aimed_target = receiver_position;
                            } else if !unsafe_release(led_target) {
                                aimed_target = led_target;
                            } else if favours_opponent(aimed_target) {
                                // Every correction remains a strong turnover risk. Keep possession
                                // and face the intended run instead of forcing the ball to an opponent.
                                let look = led_target - player_pos;
                                if look.len() > 1e-6 {
                                    let face = facing_bucket_from_vector(look);
                                    if face != FacingBucket::Unknown {
                                        self.players[player_id].action_facing = face;
                                    }
                                }
                                return;
                            }
                        }
                    }
                    }
                    if flight.is_aerial() {
                        let final_bounds = long_aerial_bounds_risk_for_target(
                            player_pos,
                            aimed_target,
                            self.config.field_width_yards,
                            self.config.field_length_yards,
                            flight,
                        );
                        if final_bounds.risk >= 0.10 || final_bounds.inward_correction_yards >= 0.25
                        {
                            aimed_target = long_aerial_safe_in_bounds_target(
                                aimed_target,
                                self.config.field_width_yards,
                                self.config.field_length_yards,
                            );
                        }
                    }
                    distance = player_pos.distance(aimed_target);
                    // MPC/execution side of the aerial-OOB loop: after receiver selection,
                    // lead, aim-noise correction, and opponent-safety re-aiming have all settled,
                    // cap a lofted ball's launch pace against that final target. The passer still
                    // chooses a receiver and pass distance; this guard only prevents the final
                    // physical release from carrying beyond the playable landing band.
                    let speed = if flight.is_aerial() {
                        aerial_pass_in_bounds_launch_speed(
                            player_pos,
                            aimed_target,
                            speed,
                            player_pos.distance(aimed_target),
                            flight,
                            self.config.field_width_yards,
                            self.config.field_length_yards,
                        )
                    } else {
                        speed
                    };
                    let pass_curl_probability = pass_curl_probability_for_player(
                        &self.players[player_id].skills,
                        flight,
                        is_cross,
                        distance,
                        pressure,
                    );
                    let mut curve = DiscretizedKickCurve::None;
                    let mut curve_bend_yards = 0.0;
                    if pass_curl_probability >= 0.46 && !slip_break_profile.available {
                        let path = aimed_target - player_pos;
                        if path.len() > 1e-6 {
                            let side = if aimed_target.x >= self.config.field_width_yards * 0.5 {
                                -1.0
                            } else {
                                1.0
                            };
                            curve = if side >= 0.0 {
                                DiscretizedKickCurve::Left
                            } else {
                                DiscretizedKickCurve::Right
                            };
                            curve_bend_yards = (0.55 + distance / 24.0).clamp(0.55, 2.8)
                                * (0.72
                                    + ability01(self.players[player_id].skills.flair_passing)
                                        * 0.56);
                        }
                    }
                    let elevation = DiscretizedKickElevation::from_pass_flight(flight);
                    // Phase 0 of the discretized kick action (roadmap Priority 1): when the
                    // gate is on, route this heuristic pass through the DISCRETE kick
                    // representation — quantize its power + aim direction into buckets, then
                    // lower. Off (default) ⇒ the continuous release below, byte-identical.
                    // Buckets here come from the heuristic; later phases swap that source for
                    // learned heads. See docs/discretized-kick-action-plan.md.
                    let release = if dd_soccer_enable_discretized_kick() {
                        let envelope_min = mph_to_yps(DISCRETIZED_KICK_PASS_MIN_SPEED_MPH);
                        let envelope_max = mph_to_yps(DISCRETIZED_KICK_PASS_MAX_SPEED_MPH);
                        let action = DiscretizedKickAction::from_power_direction(
                            discretized_kick_power_for_speed(speed, envelope_min, envelope_max),
                            aimed_target - player_pos,
                            curve,
                            elevation,
                        );
                        discretized_kick_release_clamped_to_pitch(
                            player_pos,
                            action,
                            envelope_min,
                            envelope_max,
                            distance,
                            curve_bend_yards,
                            DiscretizedKickDither::none(),
                            self.config.field_width_yards,
                            self.config.field_length_yards,
                        )
                    } else {
                        kick_release_clamped_to_pitch(
                            KickReleaseSpec {
                                origin: player_pos,
                                intended_target: aimed_target,
                                speed_yps: speed,
                                curve,
                                curve_bend_yards,
                                elevation,
                            },
                            self.config.field_width_yards,
                            self.config.field_length_yards,
                        )
                    };
                    let release_target = release.intended_target;
                    let release_distance = player_pos.distance(release_target);
                    let target_current_distance = target_id
                        .and_then(|target| snapshot.player_position(target))
                        .map(|target_position| player_pos.distance(target_position))
                        .unwrap_or(release_distance);
                    if pass_distance_is_illegal_short(release_distance)
                        || pass_distance_is_illegal_short(target_current_distance)
                    {
                        let look = release_target - player_pos;
                        if look.len() > 1e-6 {
                            let face = facing_bucket_from_vector(look);
                            if face != FacingBucket::Unknown {
                                self.players[player_id].action_facing = face;
                            }
                        }
                        return;
                    }
                    let launch_target = release.launch_target;
                    let resolved_facing = facing_bucket_from_vector(launch_target - player_pos);
                    if resolved_facing != FacingBucket::Unknown {
                        release_facing = resolved_facing;
                        self.players[player_id].action_facing = resolved_facing;
                    }
                    self.ball.holder = None;
                    self.ball.position = player_pos;
                    let actual_launch_speed_yps = {
                        // Kick power vs body momentum: driving the ball against your
                        // own motion (e.g. back-pedalling toward your own goal, then
                        // trying to blast it upfield) loses power — you can't plant and
                        // generate force. Forces a controlling touch + turn before a
                        // hard upfield play, rather than an impossible instant clearance.
                        let kd = release.velocity.normalized();
                        let momentum_f = self.kick_power_factor_for(player_id, kd);
                        // Off-centre strikes lose power; near-perpendicular prods and backheels
                        // are additionally hard-capped (10mph / 20mph) by the body-facing model.
                        let mut launch_speed = speed * facing_outcome.power_factor * momentum_f;
                        if let Some(cap) = facing_outcome.speed_cap_yps {
                            launch_speed = launch_speed.min(cap);
                        }
                        if slip_break_profile.available {
                            launch_speed = launch_speed.clamp(
                                mph_to_yps(SLIP_BREAK_OFFSIDE_TRAP_MIN_PASS_MPH),
                                mph_to_yps(SLIP_BREAK_OFFSIDE_TRAP_MAX_PASS_MPH),
                            );
                        }
                        self.ball.velocity = kd * launch_speed;
                        launch_speed
                    };
                    self.ball.curl_acceleration = release.curl_acceleration;
                    self.ball.altitude_yards = release.altitude_yards;
                    self.ball.last_touch_team = Some(player_team);
                    self.players[player_id].incoming_ball = None;
                    let offside = target_id
                        .and_then(|target| snapshot.pending_offside_for_pass(player_id, target));
                    // Captured before `offside` is moved into the pending pass below; the
                    // slip-break reward only fires when the runner was onside (trap beaten).
                    let pass_is_onside = offside.is_none();
                    let offside_candidates = snapshot.offside_candidates_for_pass(player_id);
                    let receiver_position_at_launch = target_id.and_then(|target| {
                        snapshot.player_position(target).or_else(|| {
                            self.players
                                .iter()
                                .find(|player| player.id == target)
                                .map(|player| player.position)
                        })
                    });
                    let receiver_velocity_at_launch = target_id.and_then(|target| {
                        snapshot.player_velocity(target).or_else(|| {
                            self.players
                                .iter()
                                .find(|player| player.id == target)
                                .map(|player| player.velocity)
                        })
                    });
                    self.pending_pass = Some(PendingPass {
                        team: player_team,
                        from: player_id,
                        target: target_id,
                        flight,
                        is_cross,
                        launch_tick: self.tick,
                        origin: player_pos,
                        intended_target: release_target,
                        distance_yards: release_distance,
                        receiver_openness,
                        passer_skill: pass_skill,
                        launch_speed_yps: actual_launch_speed_yps,
                        receiver_position_at_launch,
                        receiver_velocity_at_launch,
                        offside,
                        offside_candidates,
                        learn_features: snapshot.pass_completion_learn_features(
                            player_team,
                            player_pos,
                            release_target,
                            release_distance,
                            pressure,
                            receiver_openness,
                            flight,
                        ),
                    });
                    // Slip-and-break-the-offside-trap execution: a firm forward GROUND ball slipped
                    // to an ONSIDE runner who timed his break into a two-defender seam. Detect the
                    // opportunity once (the actual pass target IS the breaking runner) and use it
                    // for two gated, independent effects. Both off ⇒ byte-identical.
                    let slip_break_executed = if !flight.is_aerial() && !is_cross && pass_is_onside {
                        target_id.and_then(|runner| {
                            snapshot
                                .slip_break_runner_opportunity(
                                    player_team,
                                    player_id,
                                    player_pos,
                                    runner,
                                )
                                .map(|opportunity| (runner, opportunity))
                        })
                    } else {
                        None
                    };
                    if let Some((runner, opportunity)) = slip_break_executed {
                        // Decision side: firm the slip into the 25–35 mph band so it beats the
                        // recovering defender into the space (a tentative ground ball gets cut
                        // out). Only ever raises the speed; never softens it.
                        if dd_soccer_enable_slip_break_offside() {
                            let firm_yps = mph_to_yps(slip_break_pass_speed_mph(release_distance));
                            let current_speed = self.ball.velocity.len();
                            if current_speed.is_finite()
                                && current_speed > 1e-6
                                && current_speed < firm_yps
                            {
                                self.ball.velocity = self.ball.velocity * (firm_yps / current_speed);
                                if let Some(pending) = self.pending_pass.as_mut() {
                                    pending.launch_speed_yps = firm_yps;
                                }
                            }
                        }
                        // Shared (centralized MAPPO) reward: the passer AND the runner split the
                        // credit (the cooperative team-reward path), reinforcing the coordinated
                        // pattern — the runner starting first, the carrier slipping it through at
                        // the right moment. A pass flagged offside never reaches here: the trap
                        // was not beaten, so there is nothing to reward.
                        if dd_soccer_enable_slip_break_offside_reward() {
                            let amount = opportunity.opportunity * SLIP_BREAK_REWARD_POINTS;
                            self.record_involved_team_reward_at(
                                self.tick,
                                player_team,
                                amount,
                                &[player_id, runner],
                            );
                        }
                    }
                    self.pending_shot = None;
                    self.record_possession_touch(player_id);
                    self.stat_pass_attempt(player_team);
                    let attempt_own_half = self.pass_from_own_half(player_team, player_pos);
                    self.stat_pass_attempt_half(attempt_own_half);
                    // PENALTY: an isolated attacking carrier who panicked a backward/square ball
                    // instead of driving at goal or holding it up. Trains the policy off the bug.
                    if isolated_carrier_drive_enabled()
                        && self.isolated_carrier_panic_back_pass(
                            player_id,
                            player_pos,
                            release_target,
                            attempt_own_half,
                        )
                    {
                        self.record_reward_event_with_kind(
                            player_id,
                            -ISOLATED_CARRIER_PANIC_BACK_PASS_PENALTY_POINTS,
                            SoccerRewardEventKind::IsolatedCarrierPanicBackPass,
                        );
                    }
                    self.register_flank_crash_box_cross(
                        player_team,
                        player_id,
                        player_pos,
                        is_cross,
                        flight,
                    );
                }
                self.move_player_towards(player_id, self.players[player_id].home_position, false);
                if release_facing != FacingBucket::Unknown {
                    self.players[player_id].action_facing = release_facing;
                }
            }
            SoccerAction::Clearance { target, power } => {
                self.launch_untargeted_long_ball(player_id, target, power, "clearance");
                self.move_player_towards(player_id, self.players[player_id].home_position, false);
                if action_facing != FacingBucket::Unknown {
                    self.players[player_id].action_facing = action_facing;
                }
            }
            SoccerAction::RouteOne { target, power } => {
                self.launch_untargeted_long_ball(player_id, target, power, "route-one");
                self.move_player_towards(player_id, self.players[player_id].home_position, false);
                if action_facing != FacingBucket::Unknown {
                    self.players[player_id].action_facing = action_facing;
                }
            }
            SoccerAction::Shoot { power } => {
                let mut release_facing = action_facing;
                if self.ball.holder == Some(player_id) {
                    // The ball altitude before this contact overwrites it: a finish struck while
                    // the ball is up in the heading band is an aerial (headed) finish — the signal
                    // the flank crash-the-box bonus keys off.
                    let incoming_ball_altitude = self.ball.altitude_yards;
                    self.pending_aerial_finish =
                        if incoming_ball_altitude >= AERIAL_HEADER_MIN_ALTITUDE_YARDS {
                            Some((player_id, self.tick))
                        } else {
                            None
                        };
                    let snapshot = WorldSnapshot::from_match(self);
                    let observation = snapshot.observation_for(player_id);
                    let pressure = pressure_from_observation(&observation);
                    let goal_y = player_team.goal_y(self.config.field_length_yards);
                    let goal_center_x = self.config.field_width_yards * 0.5;
                    let half_goal = self.config.goal_width_yards * 0.5;
                    let curl_probability = shot_curl_probability_for_player(
                        &self.players[player_id].skills,
                        pressure,
                        observation.yards_to_goal,
                        observation.opponent_goal_angle_degrees,
                    );
                    let use_curl = curl_probability >= 0.46;
                    let base_goal_x = if use_curl {
                        let keeper_x = snapshot
                            .goalkeeper_for(player_team.other())
                            .and_then(|keeper_id| snapshot.player_position(keeper_id))
                            .map(|position| position.x)
                            .unwrap_or(goal_center_x);
                        let keeper_opposite_corner = if keeper_x <= goal_center_x {
                            goal_center_x + half_goal * 0.86
                        } else {
                            goal_center_x - half_goal * 0.86
                        };
                        let far_post = if player_pos.x <= goal_center_x {
                            goal_center_x + half_goal * 0.74
                        } else {
                            goal_center_x - half_goal * 0.74
                        };
                        keeper_opposite_corner * 0.68 + far_post * 0.32
                    } else if dd_soccer_enable_scored_shot_placement() {
                        // Price the placement: aim a non-curl shot at the goal-mouth spot
                        // the keeper can least reach, instead of dead-centre into them.
                        let shot_speed =
                            shot_speed_yps_from_power(power, &self.players[player_id].skills);
                        snapshot.scored_shot_placement_x(
                            player_team,
                            player_pos,
                            goal_y,
                            shot_speed,
                            ability01(self.players[player_id].skills.shooting),
                        )
                    } else {
                        goal_center_x
                    };
                    let goal = Vec2::new(
                        noisy_shot_target_x(
                            base_goal_x,
                            self.config.goal_width_yards,
                            ability01(self.players[player_id].skills.shooting),
                            pressure,
                            observation.yards_to_goal,
                            &mut self.rng,
                        )
                        .clamp(
                            goal_center_x - half_goal * 1.25,
                            goal_center_x + half_goal * 1.25,
                        ),
                        goal_y,
                    );
                    let speed = shot_speed_yps_from_power(power, &self.players[player_id].skills);
                    let mut curve = DiscretizedKickCurve::None;
                    let mut curve_bend_yards = 0.0;
                    if use_curl {
                        let path = goal - player_pos;
                        if path.len() > 1e-6 {
                            let side = if goal.x >= goal_center_x { -1.0 } else { 1.0 };
                            curve = if side >= 0.0 {
                                DiscretizedKickCurve::Left
                            } else {
                                DiscretizedKickCurve::Right
                            };
                            curve_bend_yards = (0.75
                                + observation.yards_to_goal.clamp(0.0, 34.0) / 18.0)
                                .clamp(0.75, 3.6)
                                * (0.78
                                    + ability01(self.players[player_id].skills.shooting) * 0.46);
                        }
                    }
                    let release = kick_release_clamped_to_pitch(
                        KickReleaseSpec {
                            origin: player_pos,
                            intended_target: goal,
                            speed_yps: speed,
                            curve,
                            curve_bend_yards,
                            elevation: DiscretizedKickElevation::Floor,
                        },
                        self.config.field_width_yards,
                        self.config.field_length_yards,
                    );
                    let launch_target = release.launch_target;
                    let resolved_facing = facing_bucket_from_vector(launch_target - player_pos);
                    if resolved_facing != FacingBucket::Unknown {
                        release_facing = resolved_facing;
                        self.players[player_id].action_facing = resolved_facing;
                    }
                    self.ball.holder = None;
                    self.ball.position = player_pos;
                    {
                        // Kick power vs body momentum: driving the ball against your
                        // own motion (e.g. back-pedalling toward your own goal, then
                        // trying to blast it upfield) loses power — you can't plant and
                        // generate force. Forces a controlling touch + turn before a
                        // hard upfield play, rather than an impossible instant clearance.
                        let kd = release.velocity.normalized();
                        let f = self
                            .kick_power_factor_for(player_id, kd)
                            .max(SHOT_MIN_KICK_POWER_FACTOR);
                        let launch_speed = (speed * f).clamp(
                            mph_to_yps(SHOT_MIN_SPEED_MPH),
                            mph_to_yps(SHOT_MAX_SPEED_MPH),
                        );
                        self.ball.velocity = kd * launch_speed;
                    }
                    self.ball.curl_acceleration = release.curl_acceleration;
                    self.ball.altitude_yards = release.altitude_yards;
                    self.ball.last_touch_team = Some(player_team);
                    self.players[player_id].incoming_ball = None;
                    self.pending_pass = None;
                    self.pending_shot = Some(PendingShot {
                        team: player_team,
                        shooter: player_id,
                        origin: player_pos,
                    });
                    self.record_possession_touch(player_id);
                    self.stat_shot(player_team);
                    self.events.push(MatchEvent {
                        tick: self.tick,
                        clock_seconds: self.clock_seconds,
                        kind: "shot".to_string(),
                        team: Some(player_team),
                        player_id: Some(player_id),
                        description: format!("{} shot", self.players[player_id].name),
                        ..MatchEvent::default()
                    });
                }
                self.move_player_towards(player_id, self.players[player_id].home_position, false);
                if release_facing != FacingBucket::Unknown {
                    self.players[player_id].action_facing = release_facing;
                }
            }
            SoccerAction::Tackle { target_player } => {
                self.stat_tackle(player_team);
                let mut failed_dispossession = false;
                let mut beaten_by_dribble = false;
                if self.ball.holder == Some(target_player)
                    && self
                        .players
                        .get(target_player)
                        .is_some_and(|target| target.team == player_team.other())
                {
                    let contact_distance =
                        self.players[target_player].position.distance(player_pos);
                    let target_action = self.players[target_player]
                        .last_decision
                        .as_ref()
                        .map(|decision| normalize_soccer_action_label(&decision.action).to_string())
                        .unwrap_or_else(|| "hold".to_string());
                    let target_dribble_kind = dribble_move_kind_for_action_label(&target_action);
                    // Anti-ping-pong: a player who just lost the ball cannot win
                    // it straight back from the player who took it, for a short
                    // grace window. Breaks the 1v1 duel livelock where the ball
                    // oscillates between two players every tick.
                    let regain_blocked = self.recent_dispossession.is_some_and(|recent| {
                        self.tick.saturating_sub(recent.tick) < recent.grace_ticks
                            && recent.winner == target_player
                            && recent.loser == player_id
                    });
                    if regain_blocked || contact_distance >= 2.2 {
                        failed_dispossession = true;
                    } else {
                        let contact_speed = (self.players[player_id].velocity
                            - self.players[target_player].velocity)
                            .len();
                        let foul_probability = tackle_foul_probability(
                            &self.players[player_id].skills,
                            &self.players[target_player].skills,
                            contact_distance,
                            contact_speed,
                        );
                        if foul_probability >= 0.62 {
                            self.record_reward_event(
                                player_id,
                                -FAILED_DISPOSSESSION_PENALTY_POINTS,
                            );
                            self.call_foul(
                                player_team,
                                player_id,
                                target_player,
                                self.players[target_player].position,
                            );
                            return;
                        }
                        let mut success_probability = tackle_success_probability(
                            &self.players[player_id].skills,
                            &self.players[target_player].skills,
                        ) * DRIBBLE_POSSESSION_RETENTION_FACTOR;
                        // A disoriented carrier (over-swivelled around the ball) is easier
                        // to tackle cleanly.
                        let holder_dizziness = self.players[target_player]
                            .dizziness
                            .clamp(0.0, DIZZINESS_MAX);
                        success_probability = (success_probability
                            * (1.0 + holder_dizziness * DIZZINESS_DISPOSSESSION_RISK))
                            .clamp(0.0, 0.95);
                        let holder_is_xavi_turn =
                            matches!(target_dribble_kind, Some(DribbleMoveKind::XaviTurn));
                        // Shielding (body between ball and defender) forces possession:
                        // cap the steal — ~20% for a static shield, ~10% mid xavi-turn.
                        let shield_cap = target_dribble_kind.and_then(xavi_turn_tackle_success_cap);
                        let holder_is_shielding = shield_cap.is_some();
                        if let Some(cap) = shield_cap {
                            success_probability = success_probability.min(cap);
                        }
                        let surprise_behind_steal =
                            self.surprise_behind_steal_profile_for(player_id, target_player);
                        let surprise_behind_ball_reach = surprise_behind_steal.available
                            && self.players[player_id]
                                .position
                                .distance(self.ball.position)
                                <= SURPRISE_BEHIND_STEAL_BALL_REACH_YARDS;
                        let surprise_behind_success_floor = surprise_behind_ball_reach
                            .then(|| (0.56 + surprise_behind_steal.score * 0.18).clamp(0.56, 0.78));
                        // Physical body-shield: the carrier has the ball pushed out
                        // in front with this tackler behind the body and off the ball.
                        // A clean tackle is impossible from there — only the foul
                        // branch above could have won it.
                        if self.carrier_shields_ball_from_defender(target_player, player_id)
                            && !surprise_behind_ball_reach
                        {
                            success_probability = 0.0;
                        }
                        // No tackle wins the ball from BEHIND the carrier: the ball is
                        // led in front of the body, out of a trailing defender's reach —
                        // except an explicit blind-side steal that has already reached the ball.
                        if self.tackle_blocked_from_behind(target_player, player_pos)
                            && !surprise_behind_ball_reach
                        {
                            success_probability = 0.0;
                        }
                        if surprise_behind_ball_reach {
                            success_probability = (success_probability
                                * (0.88 + surprise_behind_steal.score * 0.24))
                                .clamp(0.0, 0.95);
                        }
                        let mpc_steal_fit =
                            self.mpc_steal_execution_fit(player_id, target_player, false);
                        success_probability = (success_probability
                            * self.mpc_steal_success_multiplier(
                                mpc_steal_fit,
                                MPC_STEAL_STANDING_MIN_QP_ACCEL_FIT,
                            ))
                        .clamp(0.0, 0.95);
                        if let Some(floor) = surprise_behind_success_floor {
                            success_probability = success_probability.max(floor).clamp(0.0, 0.95);
                        }
                        if holder_is_xavi_turn {
                            success_probability = XAVI_TURN_DISPOSSESSION_PROBABILITY;
                        }
                        if success_probability >= 0.54 {
                            self.complete_defensive_dispossession(
                                player_id,
                                target_player,
                                "tackle",
                            );
                        } else {
                            failed_dispossession = true;
                            if let Some(kind) = target_dribble_kind {
                                let mut beat_probability = dribble_beat_probability(
                                    kind,
                                    &self.players[target_player].skills,
                                    &self.players[player_id].skills,
                                    DefenderDribbleResponse::Commit,
                                );
                                if holder_is_shielding && !holder_is_xavi_turn {
                                    // Shielding protects the ball but sacrifices the
                                    // dribble: halve the chance of beating the
                                    // defender while doing it.
                                    beat_probability *= 0.5;
                                } else if beat_defender_duel_enabled() {
                                    // Beat-the-defender duel (gated): the defender lunged into a
                                    // tackle and MISSED — they are over-committed, their momentum
                                    // carrying them past. Blend in the kinematic exploit so the
                                    // carrier accelerates past more often than the skill-only model
                                    // alone allows. Off ⇒ `beat_probability` is unchanged (parity).
                                    let carrier = &self.players[target_player];
                                    let defender = &self.players[player_id];
                                    let commitment = DefenderCommitmentState::evaluate(
                                        carrier.team.attack_dir(),
                                        carrier.position,
                                        defender.position,
                                        defender.velocity,
                                        &defender.skills,
                                        defender.fatigue,
                                    );
                                    let uplift = over_commit_beat_uplift(&commitment);
                                    beat_probability = (beat_probability
                                        + uplift * (1.0 - beat_probability))
                                        .clamp(0.0, 0.97);
                                }
                                beaten_by_dribble = beat_probability >= 0.52;
                            }
                        }
                    }
                }
                if failed_dispossession {
                    self.record_reward_event(player_id, -FAILED_DISPOSSESSION_PENALTY_POINTS);
                    if beaten_by_dribble {
                        let kind = dribble_move_kind_for_action_label(
                            self.players[target_player]
                                .last_decision
                                .as_ref()
                                .map(|decision| decision.action.as_str())
                                .unwrap_or("dribble"),
                        )
                        .unwrap_or(DribbleMoveKind::LeftCut);
                        self.record_dribble_beat_event(target_player, player_id, kind);
                    }
                }
                self.move_player_towards(player_id, self.ball.position, true);
            }
            SoccerAction::SlideTackle { target_player } => {
                // A committed, off-the-feet challenge. It reaches further than a standing
                // tackle and wins the ball more often (boosted probability, lower clearing
                // threshold), but a MISS puts the defender flat on the grass for ~2s while
                // the attacker carries on past — see the grounding branch below.
                self.stat_tackle(player_team);
                let mut won_ball = false;
                let mut beaten_by_dribble = false;
                if self.ball.holder == Some(target_player)
                    && self
                        .players
                        .get(target_player)
                        .is_some_and(|target| target.team == player_team.other())
                {
                    let contact_distance =
                        self.players[target_player].position.distance(player_pos);
                    let ball_contact_distance = self.ball.position.distance(player_pos);
                    let target_action = self.players[target_player]
                        .last_decision
                        .as_ref()
                        .map(|decision| normalize_soccer_action_label(&decision.action).to_string())
                        .unwrap_or_else(|| "hold".to_string());
                    let target_dribble_kind = dribble_move_kind_for_action_label(&target_action);
                    // Anti-ping-pong: a defender who just lost the ball cannot win it
                    // straight back from the player who took it within the grace window.
                    let regain_blocked = self.recent_dispossession.is_some_and(|recent| {
                        self.tick.saturating_sub(recent.tick) < recent.grace_ticks
                            && recent.winner == target_player
                            && recent.loser == player_id
                    });
                    // A slide lunges further than a standing poke, but it must reach
                    // the actual ball. From behind, the carrier's body may sit between
                    // player and ball; only a real ball-reaching lunge can win it.
                    if !regain_blocked
                        && contact_distance < SLIDE_TACKLE_MAX_REACH_YARDS
                        && ball_contact_distance <= SLIDE_TACKLE_MAX_REACH_YARDS
                    {
                        let contact_speed = (self.players[player_id].velocity
                            - self.players[target_player].velocity)
                            .len();
                        let foul_probability = slide_tackle_foul_probability(
                            &self.players[player_id].skills,
                            &self.players[target_player].skills,
                            contact_distance,
                            contact_speed,
                        );
                        if foul_probability >= 0.62 {
                            self.record_reward_event(
                                player_id,
                                -FAILED_SLIDE_TACKLE_PENALTY_POINTS,
                            );
                            self.call_foul(
                                player_team,
                                player_id,
                                target_player,
                                self.players[target_player].position,
                            );
                            return;
                        }
                        let mut success_probability = slide_tackle_success_probability(
                            &self.players[player_id].skills,
                            &self.players[target_player].skills,
                        ) * DRIBBLE_POSSESSION_RETENTION_FACTOR;
                        let holder_dizziness = self.players[target_player]
                            .dizziness
                            .clamp(0.0, DIZZINESS_MAX);
                        success_probability = (success_probability
                            * (1.0 + holder_dizziness * DIZZINESS_DISPOSSESSION_RISK))
                            .clamp(0.0, 0.97);
                        let holder_is_xavi_turn =
                            matches!(target_dribble_kind, Some(DribbleMoveKind::XaviTurn));
                        let shield_cap = target_dribble_kind.and_then(xavi_turn_tackle_success_cap);
                        let holder_is_shielding = shield_cap.is_some();
                        if let Some(cap) = shield_cap {
                            success_probability = success_probability.min(cap);
                        }
                        let mpc_steal_fit =
                            self.mpc_steal_execution_fit(player_id, target_player, true);
                        success_probability = (success_probability
                            * self.mpc_steal_success_multiplier(
                                mpc_steal_fit,
                                MPC_STEAL_SLIDE_MIN_QP_ACCEL_FIT,
                            ))
                        .clamp(0.0, 0.97);
                        if holder_is_xavi_turn {
                            success_probability = XAVI_TURN_DISPOSSESSION_PROBABILITY;
                        }
                        if success_probability >= SLIDE_TACKLE_SUCCESS_THRESHOLD {
                            won_ball = true;
                            self.complete_defensive_dispossession(
                                player_id,
                                target_player,
                                "slide-tackle",
                            );
                        } else if let Some(kind) = target_dribble_kind {
                            let mut beat_probability = dribble_beat_probability(
                                kind,
                                &self.players[target_player].skills,
                                &self.players[player_id].skills,
                                DefenderDribbleResponse::Commit,
                            );
                            if holder_is_shielding && !holder_is_xavi_turn {
                                beat_probability *= 0.5;
                            } else if beat_defender_duel_enabled() {
                                // Beat-the-defender duel (gated): a MISSED slide tackle is the most
                                // over-committed a defender can be — off their feet, momentum spent.
                                // Blend in the kinematic exploit. Off ⇒ unchanged (parity).
                                let carrier = &self.players[target_player];
                                let defender = &self.players[player_id];
                                let commitment = DefenderCommitmentState::evaluate(
                                    carrier.team.attack_dir(),
                                    carrier.position,
                                    defender.position,
                                    defender.velocity,
                                    &defender.skills,
                                    defender.fatigue,
                                );
                                let uplift = over_commit_beat_uplift(&commitment);
                                beat_probability = (beat_probability
                                    + uplift * (1.0 - beat_probability))
                                    .clamp(0.0, 0.97);
                            }
                            beaten_by_dribble = beat_probability >= 0.52;
                        }
                    }
                }
                if !won_ball {
                    // Committed and missed: down on the ground, out of the play. The
                    // attacker now advances past unchallenged by this player for the
                    // uniform 1.75-2.25s the defender takes to get back to its feet.
                    let recovery = SLIDE_TACKLE_RECOVERY_MIN_SECONDS
                        + self.rng.next_float()
                            * (SLIDE_TACKLE_RECOVERY_MAX_SECONDS
                                - SLIDE_TACKLE_RECOVERY_MIN_SECONDS);
                    self.players[player_id].slide_recovery_seconds = recovery;
                    self.record_reward_event(player_id, -FAILED_SLIDE_TACKLE_PENALTY_POINTS);
                    if beaten_by_dribble {
                        let kind = dribble_move_kind_for_action_label(
                            self.players[target_player]
                                .last_decision
                                .as_ref()
                                .map(|decision| decision.action.as_str())
                                .unwrap_or("dribble"),
                        )
                        .unwrap_or(DribbleMoveKind::LeftCut);
                        self.record_dribble_beat_event(target_player, player_id, kind);
                    }
                }
                // The lunge itself — commit the body toward the ball this tick. From the
                // next tick the grounding freeze (`maintain_slide_recoveries`) takes over.
                self.move_player_towards(player_id, self.ball.position, true);
            }
        }
    }

    fn role_line_consistency_urgency(&self, player_id: usize) -> f64 {
        let Some(me) = self.players.get(player_id) else {
            return 0.0;
        };
        if me.role == PlayerRole::Goalkeeper || self.ball.holder == Some(player_id) {
            return 0.0;
        }
        let attack_dir = me.team.attack_dir();
        let fwd = |position: Vec2| position.y * attack_dir;
        // Ramp urgency from 0 at the deadband up to 1.0 at FULL_ERROR. It must NOT start
        // at sprint level: a defender a few yards out of its band should ADJUST calmly
        // (sidestep, facing the ball), not sprint+turn-to-run. Only a genuinely stranded
        // line (large error, e.g. caught well up the pitch) reaches the sprint threshold.
        let urgency_for_error = |error: f64| {
            if error <= ROLE_LINE_CONSISTENCY_URGENCY_DEADBAND_YARDS {
                0.0
            } else {
                ((error - ROLE_LINE_CONSISTENCY_URGENCY_DEADBAND_YARDS)
                    / (ROLE_LINE_CONSISTENCY_URGENCY_FULL_ERROR_YARDS
                        - ROLE_LINE_CONSISTENCY_URGENCY_DEADBAND_YARDS))
                    .clamp(0.0, 1.0)
            }
        };
        let role_mean_fwd = |role: PlayerRole| -> Option<f64> {
            let mut total = 0.0;
            let mut count = 0usize;
            for teammate in self
                .players
                .iter()
                .filter(|teammate| teammate.team == me.team && teammate.role == role)
            {
                total += fwd(teammate.position);
                count += 1;
            }
            (count > 0).then(|| total / count as f64)
        };
        match me.role {
            PlayerRole::Defender => {
                let own_goal_y = match me.team {
                    Team::Home => 0.0,
                    Team::Away => self.config.field_length_yards,
                };
                let own_goal_fwd = own_goal_y * attack_dir;
                let ball_fwd = fwd(self.ball.position);
                let ball_from_own_goal = (ball_fwd - own_goal_fwd).max(0.0);
                if ball_from_own_goal <= DEFENSIVE_LINE_BAND_OWN_GOAL_EXEMPT_YARDS {
                    return 0.0;
                }
                let floor_depth =
                    if ball_from_own_goal > DEFENSIVE_LINE_SHELF_DEPTH_FROM_OWN_GOAL_YARDS {
                        DEFENSIVE_LINE_SHELF_DEPTH_FROM_OWN_GOAL_YARDS
                    } else {
                        ball_from_own_goal.max(BACK_FOUR_SIX_YARD_LINE_FLOOR_YARDS)
                    };
                let gap_room_to_floor = (ball_from_own_goal - floor_depth).max(0.0);
                let min_gap =
                    if ball_from_own_goal < DEFENSIVE_LINE_FULL_CUSHION_DEPTH_FROM_OWN_GOAL_YARDS {
                        gap_room_to_floor
                    } else {
                        DEFENSIVE_LINE_MIN_BEHIND_BALL_YARDS.min(gap_room_to_floor)
                    };
                let max_gap = DEFENSIVE_LINE_MAX_BEHIND_BALL_YARDS
                    .min(gap_room_to_floor)
                    .max(min_gap);
                let gap = ball_fwd - fwd(me.position);
                urgency_for_error(role_layer_gap_band_error_yards(gap, min_gap, max_gap))
            }
            PlayerRole::Midfielder => role_mean_fwd(PlayerRole::Defender)
                .zip(role_mean_fwd(PlayerRole::Midfielder))
                .map(|(def_mean, mid_mean)| {
                    urgency_for_error(role_layer_gap_band_error_yards(
                        mid_mean - def_mean,
                        MID_AHEAD_OF_DEF_MIN_YARDS,
                        MID_AHEAD_OF_DEF_MAX_YARDS,
                    ))
                })
                .unwrap_or(0.0),
            PlayerRole::Forward => role_mean_fwd(PlayerRole::Midfielder)
                .zip(role_mean_fwd(PlayerRole::Forward))
                .map(|(mid_mean, fwd_mean)| {
                    urgency_for_error(role_layer_gap_band_error_yards(
                        fwd_mean - mid_mean,
                        STRIKER_AHEAD_OF_MID_MIN_YARDS,
                        STRIKER_AHEAD_OF_MID_MAX_YARDS,
                    ))
                })
                .unwrap_or(0.0),
            PlayerRole::Goalkeeper => 0.0,
        }
    }

    /// Defensive-recovery effort (0–1): how hard an outfielder must sprint to get
    /// goalside when the opponent is threatening. It rises as fewer of our players
    /// are goalside of the ball (a counterattack with the line broken is max), and
    /// pins to 1.0 for a contestable 50:50 within reach of our back line (2nd-to-
    /// last defender, GK included) — players must sprint to those, not jog. Role-line
    /// consistency also feeds this urgency so the back/mid/forward bands actually move
    /// on their 2s/5s consistency clocks instead of being damped as calm far-ball runs.
    pub(crate) fn defensive_recovery_effort(&self, player_id: usize) -> f64 {
        if player_id >= self.players.len() {
            return 0.0;
        }
        let me = &self.players[player_id];
        if me.role == PlayerRole::Goalkeeper {
            return 0.0;
        }
        let role_line_effort = self.role_line_consistency_urgency(player_id);
        let my_team = me.team;
        let attack_dir = my_team.attack_dir();
        let ball = self.ball.position;
        let holder_is_opponent = self
            .ball
            .holder
            .and_then(|h| self.players.get(h))
            .is_some_and(|p| p.team != my_team);
        let loose = self.ball.holder.is_none();
        if !(holder_is_opponent || loose) {
            return role_line_effort;
        }
        // Goalside count (our team incl. GK): players between the ball and our goal.
        let goalside = self
            .players
            .iter()
            .filter(|p| p.team == my_team && (p.position.y - ball.y) * attack_dir < 0.0)
            .count();
        let me_goalside = (me.position.y - ball.y) * attack_dir < 0.0;
        // Fewer goalside ⇒ more urgent. A full back line+ (≥4 goalside) is calm; it
        // ramps to max as the count collapses (e.g. caught up the pitch on a turnover).
        let deficit = (1.0 - (goalside as f64 / 4.0)).clamp(0.0, 1.0);
        let mut effort = if me_goalside { deficit * 0.35 } else { deficit };
        // Contestable 50:50 right on our back line ⇒ max effort for anyone in reach.
        let own_goal_y = if attack_dir > 0.0 {
            0.0
        } else {
            self.config.field_length_yards
        };
        let mut depths: Vec<f64> = self
            .players
            .iter()
            .filter(|p| p.team == my_team)
            .map(|p| (p.position.y - own_goal_y).abs())
            .collect();
        depths.sort_by(|a, b| a.partial_cmp(b).unwrap_or(std::cmp::Ordering::Equal));
        if let Some(&second_last_depth) = depths.get(1) {
            let ball_depth = (ball.y - own_goal_y).abs();
            let near_back_line =
                (ball_depth - second_last_depth).abs() <= DEFENSIVE_RECOVERY_BACK_LINE_RADIUS_YARDS;
            let contestable = loose
                || self
                    .ball
                    .holder
                    .and_then(|h| self.players.get(h))
                    .is_some_and(|h| {
                        self.players.iter().any(|o| {
                            o.team != h.team
                                && o.position.distance(h.position)
                                    <= LOOSE_BALL_CONTEST_RADIUS_YARDS
                        })
                    });
            if near_back_line
                && contestable
                && me.position.distance(ball) <= DEFENSIVE_RECOVERY_BACK_LINE_RADIUS_YARDS
            {
                effort = 1.0;
            }
        }
        effort.max(role_line_effort).clamp(0.0, 1.0)
    }

    /// Power multiplier for a kick given the kicker's body momentum: full when
    /// planted or moving into the kick, sharply reduced when kicking against your own
    /// motion (you cannot plant and generate force back the other way).
    pub(crate) fn kick_power_factor_for(&self, player_id: usize, kick_dir: Vec2) -> f64 {
        let Some(p) = self.players.get(player_id) else {
            return 1.0;
        };
        let velocity = limit_vec2_len(p.velocity, SOCCER_PHYSICS_PLAYER_MAX_SPEED_YPS);
        let kick_dir = finite_vec2(kick_dir, Vec2::new(0.0, p.team.attack_dir()));
        let kick_dir = if kick_dir.len() > 1e-6 {
            kick_dir.normalized()
        } else {
            Vec2::new(0.0, p.team.attack_dir())
        };
        let speed = velocity.len();
        if speed <= 1.0 {
            return 1.0; // planted: full power
        }
        let top_speed = finite_metric(player_top_speed_yps(p.role, &p.skills)).max(1e-6);
        let speed_frac = (speed / top_speed).clamp(0.0, 1.0);
        let align = velocity.normalized().dot(kick_dir).clamp(-1.0, 1.0);
        let against = (1.0 - align).max(0.0);
        // The faster you move, the harder it is to drive the ball against that momentum — a
        // sprint can't reverse-blast (it forces a settling touch first), a jog keeps most power.
        let penalty = KICK_AGAINST_MOMENTUM_PENALTY * (0.5 + speed_frac);
        let floor = KICK_POWER_FACTOR_FLOOR
            - speed_frac * (KICK_POWER_FACTOR_FLOOR - KICK_REVERSE_AT_SPRINT_FLOOR);
        return (1.0 - against * penalty).clamp(floor, 1.0);
    }

    /// Drive a human-controlled player's movement directly: tiered pace toward the
    /// commanded direction with a high accel cap (responsive starts/turns), and a hard
    /// brake to a stop on release (pace 0). Bypasses the AI gait model so control is
    /// immediate and the player stops promptly instead of coasting toward the ball.
    fn apply_human_control_movement(&mut self, player_id: usize, dir: Vec2, pace: u8) {
        if player_id >= self.players.len() {
            return;
        }
        let dt = sane_dt_seconds(self.config.dt_seconds, DEFAULT_DT_SECONDS);
        let fw = self.config.field_width_yards;
        let fl = self.config.field_length_yards;
        let fallback_position = self.players[player_id].home_position;
        self.players[player_id].position =
            finite_pitch_point(self.players[player_id].position, fw, fl, fallback_position);
        let v0 = limit_vec2_len(
            self.players[player_id].velocity,
            SOCCER_PHYSICS_PLAYER_MAX_SPEED_YPS,
        );
        self.players[player_id].velocity = v0;
        self.players[player_id].acceleration = limit_vec2_len(
            self.players[player_id].acceleration,
            SOCCER_PHYSICS_PLAYER_MAX_ACCEL_YPS2,
        );
        let dir = finite_vec2(dir, Vec2::zero());
        if pace == 0 || dir.len() < 1e-6 {
            let mut v = v0 * HUMAN_CONTROL_BRAKE;
            if v.len() < 0.2 {
                v = Vec2::zero();
            }
            self.players[player_id].velocity = v;
            self.players[player_id].acceleration = Vec2::zero();
            let pos = (self.players[player_id].position + v * dt).clamp_to_pitch(fw, fl);
            self.players[player_id].position = pos;
            return;
        }
        let desired = dir.normalized() * human_pace_speed_yps(pace);
        let dv = desired - v0;
        let max_dv = HUMAN_CONTROL_ACCEL_YPS2 * dt;
        let v = if dv.len() > max_dv {
            v0 + dv * (max_dv / dv.len())
        } else {
            desired
        };
        self.players[player_id].velocity = v;
        self.players[player_id].acceleration = (v - v0) * (1.0 / dt.max(1e-6));
        let pos = (self.players[player_id].position + v * dt).clamp_to_pitch(fw, fl);
        self.players[player_id].position = pos;
    }

    pub(crate) fn move_player_towards(&mut self, player_id: usize, target: Vec2, sprint: bool) {
        if player_id >= self.players.len() {
            return;
        }
        let (field_width, field_length) = sane_pitch_dimensions(
            self.config.field_width_yards,
            self.config.field_length_yards,
        );
        let fallback_position = self.players[player_id].home_position;
        let current_position = finite_pitch_point(
            self.players[player_id].position,
            field_width,
            field_length,
            fallback_position,
        );
        self.players[player_id].position = current_position;
        self.players[player_id].velocity = limit_vec2_len(
            self.players[player_id].velocity,
            SOCCER_PHYSICS_PLAYER_MAX_SPEED_YPS,
        );
        self.players[player_id].acceleration = limit_vec2_len(
            self.players[player_id].acceleration,
            SOCCER_PHYSICS_PLAYER_MAX_ACCEL_YPS2,
        );
        self.players[player_id].jerk = finite_vec2(self.players[player_id].jerk, Vec2::zero());
        self.players[player_id].fatigue =
            finite_metric(self.players[player_id].fatigue).clamp(0.0, 1.0);
        self.players[player_id].anaerobic_load =
            finite_metric(self.players[player_id].anaerobic_load).clamp(0.0, 1.0);
        let target = finite_pitch_point(target, field_width, field_length, current_position);
        // Wing-back lane discipline is a movement resistance, not a wall. A wide
        // defender can cross the center when the chosen target really asks for it,
        // but off-ball movement is compressed after the normal tuck-in zone so the
        // GA/shape model pays for side-switching instead of having it forbidden.
        let target = {
            let me = &self.players[player_id];
            let width = self.config.field_width_yards;
            let is_wing_back = me.role == PlayerRole::Defender
                && (me.home_position.x < width * 0.28 || me.home_position.x > width * 0.72);
            if is_wing_back {
                let half = width * 0.5;
                let mut t = target;
                let in_possession = self.controlled_possession_team_now() == Some(me.team);
                let cross_retention = if in_possession { 0.58 } else { 0.36 };
                if me.home_position.x < half {
                    let soft_limit = half + WINGBACK_CENTER_CROSS_LIMIT_YARDS;
                    if t.x > soft_limit {
                        t.x = soft_limit + (t.x - soft_limit) * cross_retention;
                    }
                } else {
                    let soft_limit = half - WINGBACK_CENTER_CROSS_LIMIT_YARDS;
                    if t.x < soft_limit {
                        t.x = soft_limit + (t.x - soft_limit) * cross_retention;
                    }
                }
                t
            } else {
                target
            }
        };
        let dt = sane_dt_seconds(self.config.dt_seconds, DEFAULT_DT_SECONDS);
        let previous_acceleration = self.players[player_id].acceleration;
        let to_target = target - self.players[player_id].position;
        // Chased: a fast opponent (running/sprinting) is right on top of us, so a
        // retreat must become a turn-and-run rather than a back-pedal.
        let me_pos = self.players[player_id].position;
        let my_team = self.players[player_id].team;
        let chased = self.players.iter().any(|opp| {
            opp.team != my_team
                && opp.role != PlayerRole::Goalkeeper
                && opp.position.distance(me_pos) <= CHASE_EMERGENCY_RADIUS_YARDS
                && opp.velocity.len() >= CHASE_EMERGENCY_SPEED_YPS
        });
        // Defensive recovery: when the opponent threatens and we're not goalside,
        // sprint back at full effort (max near a back-line 50:50).
        let recover_effort = self.defensive_recovery_effort(player_id);
        // Overhead-ball discipline: while an aerial 50:50 is in flight TOWARD the opponent's
        // goal (no settled holder) and THIS player is dropping toward our OWN goal under it,
        // they walk back rather than sprint — the ball is going the other way and may be
        // ours to win. Lifts the instant a holder settles or the ball turns back toward our
        // goal; genuine ball-chasers (moving forward, at the ball) are unaffected. Human-
        // controlled players keep full control of their pace.
        let forward_aerial_walk_back = !dd_soccer_disable_forward_aerial_fifty_fifty_hold()
            && self.ball.holder.is_none()
            && self.ball.altitude_yards > BALL_ROLLING_ALTITUDE_YARDS
            && self.ball.velocity.y * my_team.attack_dir() > 0.0
            && to_target.y * my_team.attack_dir() < 0.0
            && self.players[player_id].controller_slot.is_none();
        // Suppress the flat-out recovery sprint while walking back under the overhead ball.
        let recover_effort = if forward_aerial_walk_back {
            0.0
        } else {
            recover_effort
        };
        // The recovery sprint only applies when the player is actually MOVING to recover.
        // A player holding station (target ≈ current position) is resting — it must not be
        // forced into a sprint by its line-consistency urgency (that would never let a
        // stranded player recover stamina).
        let gait = if recover_effort >= DEFENSIVE_RECOVERY_SPRINT_THRESHOLD
            && to_target.len() > DEFENSIVE_RECOVERY_MIN_MOVE_YARDS
        {
            MovementGait::Sprint
        } else {
            classify_movement_gait(self.players[player_id].team, to_target, sprint, chased)
        };
        // Counterattack break: our team has the ball, this player is pushing
        // forward, and few opponents are ahead — sprint into the space to offer
        // the pass instead of being damped for being far from the ball.
        let attack_dir = my_team.attack_dir();
        let on_break = to_target.y * attack_dir > 0.5
            && self
                .ball
                .holder
                .and_then(|holder| self.players.get(holder))
                .is_some_and(|holder| holder.team == my_team)
            && self
                .players
                .iter()
                .filter(|opp| {
                    opp.team != my_team
                        && opp.role != PlayerRole::Goalkeeper
                        && (opp.position.y - me_pos.y) * attack_dir > 0.0
                })
                .count()
                < COUNTERATTACK_DEFENDERS_AHEAD_THRESHOLD;
        // Join the attack: when we hold the ball and it's advanced (near/past
        // halfway), a teammate behind the ball who is moving forward sprints to
        // support — so a striker isn't left to go it alone.
        let attack_support = to_target.y * attack_dir > 0.5
            && self
                .ball
                .holder
                .and_then(|holder| self.players.get(holder))
                .is_some_and(|holder| holder.team == my_team)
            && (self.ball.position.y - me_pos.y) * attack_dir > ATTACK_SUPPORT_BEHIND_BALL_YARDS
            && (self.ball.position.y - self.config.field_length_yards * 0.5) * attack_dir
                > -ATTACK_SUPPORT_BALL_ADVANCED_YARDS;
        // A loose ball within striking range is attacked at full urgency — but ONLY by
        // the closest player on each team, so a single player commits decisively to the
        // scramble instead of the whole side swarming it (which breaks the shape).
        let loose_ball_attack = self.ball.holder.is_none() && {
            let my_dist = me_pos.distance(self.ball.position);
            my_dist <= LOOSE_BALL_COMMIT_RANGE_YARDS
                && !self.players.iter().any(|p| {
                    p.team == my_team
                        && p.id != player_id
                        && p.position.distance(self.ball.position) < my_dist
                })
        };
        // Transition push-up: the play has run well upfield of a player who is
        // moving forward, so they must hustle to push up / stay compact / hold
        // the line rather than coast. Ramps in from PUSH_UP_URGENCY_MIN_AHEAD
        // (the "20+ yards upfield" the back line and everyone else react to). This
        // is a real-urgency moment, so it overrides energy-conservation pacing.
        let ball_ahead = (self.ball.position.y - me_pos.y) * attack_dir;
        let pushing_up = to_target.y * attack_dir > 0.0;
        let push_up_urgency = if pushing_up {
            PUSH_UP_URGENCY_MAX
                * ((ball_ahead - PUSH_UP_URGENCY_MIN_AHEAD_YARDS)
                    / (PUSH_UP_URGENCY_FULL_AHEAD_YARDS - PUSH_UP_URGENCY_MIN_AHEAD_YARDS))
                    .clamp(0.0, 1.0)
        } else {
            0.0
        };
        // Urgency scales with proximity to the ball: a player far from the ball
        // moves and accelerates calmly, ramping up to full urgency as they close
        // on it. Linear ("uniform") in distance from 1.0 at the ball down to a
        // floor — except when chased, breaking, or committing to a loose ball.
        let proximity_urgency = if chased || on_break || attack_support || loose_ball_attack {
            1.0
        } else {
            let ball_distance = me_pos.distance(self.ball.position);
            (1.0 - (ball_distance / BALL_PROXIMITY_URGENCY_REFERENCE_YARDS).clamp(0.0, 1.0)
                * (1.0 - BALL_PROXIMITY_URGENCY_FLOOR))
                .clamp(BALL_PROXIMITY_URGENCY_FLOOR, 1.0)
                // ...but a defensive-recovery threat or a transition push-up both
                // override the calm-when-far damping (and the pacing throttle).
                .max(recover_effort)
                .max(push_up_urgency)
        };
        // Gait follows urgency: far from the ball and calm — not breaking, chased,
        // recovering, or awaiting a pass — a player jogs rather than running or
        // sprinting (speed is already damped; this matches the gait label/anim).
        let incoming_pass = self
            .pending_pass
            .as_ref()
            .is_some_and(|pp| pp.target == Some(player_id));
        let gait = if !chased
            && !on_break
            && !incoming_pass
            && recover_effort < DEFENSIVE_RECOVERY_SPRINT_THRESHOLD
            && proximity_urgency < GAIT_CALM_URGENCY_THRESHOLD
            && matches!(gait, MovementGait::Run | MovementGait::Sprint)
        {
            MovementGait::Jog
        } else {
            gait
        };
        // Off-ball cruise discipline (hold shape). With nothing urgent to chase, a
        // player that is roughly in its shape position JOGS to hold/adjust it and
        // STANDS once essentially arrived, instead of perpetually running at ~60% of top
        // speed after a target that slides a yard or two with the ball — the difference
        // between a settled block jockeying for shape and 22 players sprinting about
        // ("headless chickens"). It self-regulates: a player that has fallen more than
        // OFFBALL_SETTLE_REFERENCE_YARDS behind its target is genuinely out of position
        // and breaks back into a run to recover (the cap only touches Run/Sprint).
        // Bypassed for every real movement cue — being chased, a counter-break, joining
        // the attack, a loose-ball scramble, an incoming pass to receive, a flat-out
        // defensive recovery, a transition push-up, an active one-two run, the ball
        // carrier itself, and a human-controlled player — so it only ever quiets a
        // player with no reason to keep running. See OFFBALL_SETTLE_*.
        let settle_engaged = !(dd_soccer_disable_offball_settle()
            || chased
            || on_break
            || attack_support
            || loose_ball_attack
            || incoming_pass
            || self.ball.holder == Some(player_id)
            // The keeper continuously tracks the ball-goal line (its own positioning
            // model); it never "holds shape", so it is exempt from the cruise settle.
            || self.players[player_id].role == PlayerRole::Goalkeeper
            || self.players[player_id].controller_slot.is_some()
            || self.players[player_id].one_two.is_some()
            || recover_effort >= DEFENSIVE_RECOVERY_SPRINT_THRESHOLD
            || push_up_urgency > 0.0);
        let to_target_len = to_target.len();
        let gait = if settle_engaged && to_target_len <= OFFBALL_SETTLE_STAND_YARDS {
            // Essentially arrived: hold position rather than creep the last yard.
            MovementGait::Stand
        } else if settle_engaged
            && to_target_len <= OFFBALL_SETTLE_REFERENCE_YARDS
            && matches!(gait, MovementGait::Run | MovementGait::Sprint)
        {
            // Roughly in position: jockey at a calm jog rather than a run/sprint.
            MovementGait::Jog
        } else {
            gait
        };
        // Locomotion momentum: a decision is instant, but the body carries the effort
        // it has committed to — it can't oscillate sprint↔run tick-to-tick. Once an
        // effort tier is entered it is held for the dwell before changing, EXCEPT a
        // pull-up to a stop or an explosive emergency reaction (chase / flat-out
        // recovery / loose-ball scramble / an incoming pass to attack / a counterbreak)
        // which are never delayed. Dwell is accumulated per movement step from `dt`
        // rather than read off the match clock, so it is correct however the mover is
        // driven (one step per tick in live play; the clock need not advance between
        // calls). See `commit_gait`.
        let gait_emergency = chased
            || on_break
            || attack_support
            || loose_ball_attack
            || incoming_pass
            || recover_effort >= DEFENSIVE_RECOVERY_SPRINT_THRESHOLD;
        let previous_gait = self.players[player_id].movement_gait;
        let gait_held_seconds = self.players[player_id].locomotion.gait_held_seconds;
        let gait = commit_gait(previous_gait, gait, gait_held_seconds, gait_emergency);
        // Cap the drop-back under a forward overhead ball to a walk: keep the back-pedal /
        // forward orientation but never exceed walking pace (effort tier 1).
        let gait = if forward_aerial_walk_back && gait.effort_tier() > 1 {
            match gait {
                MovementGait::BackJog | MovementGait::BackSkip => MovementGait::BackWalk,
                _ => MovementGait::Walk,
            }
        } else {
            gait
        };
        // A turn-and-run to keep up with a fast attacker (chase / flat-out recovery)
        // bypasses the heading-reversal lock so the change of direction is never
        // delayed; ordinary play keeps its directional momentum.
        let heading_emergency = chased || recover_effort >= DEFENSIVE_RECOVERY_SPRINT_THRESHOLD;
        // This is the ONLY site that also applies `anaerobic_speed_ceiling`, so under the
        // aerobic/anaerobic split the W′-empty cliff is dropped from the fatigue factor here
        // (it would otherwise double-count with the ceiling); the aerobic taper remains. OFF =
        // the historical full factor. See `dd_soccer_enable_aerobic_anaerobic_speed_split`.
        let fatigue_factor = fatigue_speed_factor_inner(
            self.players[player_id].skills.stamina,
            self.players[player_id].fatigue,
            dd_soccer_enable_aerobic_anaerobic_speed_split(),
        );
        // Hard ceiling: a spent anaerobic battery (W′) sharply caps top-end
        // burst — when the reserve empties, the player simply can't reach top
        // speed until it recovers (the rare "legs are gone" moment).
        let anaerobic_factor = anaerobic_speed_ceiling(self.players[player_id].anaerobic_load);
        // Voluntary pacing: far more often than hitting the hard ceiling, a
        // player with a drawn-down reserve cruises in non-peak moments to bank
        // energy for the sprints that matter — peak moments (high urgency) spend
        // freely.
        let pacing_factor =
            effort_pacing_factor(self.players[player_id].anaerobic_load, proximity_urgency);
        // Far-from-ball off-ball energy conservation: a player with no urgent reason to run who
        // is well clear of the ball eases off by up to ~20% (smooth, no cliff) to bank energy
        // rather than drifting around at full pace. Every real movement cue — being chased, a
        // counter-break, joining the attack, a loose-ball scramble, an incoming pass to receive,
        // a flat-out defensive recovery, a transition push-up, the ball carrier itself, the
        // keeper (it tracks the goal line continuously), and a human-controlled player — is
        // exempt, so it only ever quiets a player with no reason to keep sprinting. Gated;
        // byte-identical & zero-cost when off. See `far_offball_conservation_factor`.
        let far_offball_factor = if dd_soccer_enable_far_offball_energy_conservation()
            && !chased
            && !on_break
            && !attack_support
            && !loose_ball_attack
            && !incoming_pass
            && recover_effort < DEFENSIVE_RECOVERY_SPRINT_THRESHOLD
            && push_up_urgency <= 0.0
            && self.ball.holder != Some(player_id)
            && self.players[player_id].controller_slot.is_none()
            && self.players[player_id].role != PlayerRole::Goalkeeper
        {
            far_offball_conservation_factor(me_pos.distance(self.ball.position))
        } else {
            1.0
        };
        let side_glance_speed_factor = if self.ball.holder == Some(player_id) {
            let cost = self.players[player_id]
                .last_decision
                .as_ref()
                .map(|decision| decision.observation.side_glance_control_cost)
                .unwrap_or(0.0)
                .clamp(0.0, SURPRISE_BEHIND_STEAL_MAX_GLANCE_CONTROL_COST);
            (1.0 - cost).clamp(0.88, 1.0)
        } else {
            1.0
        };
        let speed = player_top_speed_yps(
            self.players[player_id].role,
            &self.players[player_id].skills,
        ) * fatigue_factor
            * anaerobic_factor
            * pacing_factor
            * gait.speed_multiplier()
            * proximity_urgency
            // Decisiveness: an unsure player (low belief-grounded confidence) commits less
            // pace; a confident one moves full speed.
            * movement_decisiveness(self.players[player_id].decision_confidence)
            * far_offball_factor
            * side_glance_speed_factor;
        // Receive in stride (anti-overrun): the named receiver of an incoming ground ball who is
        // collecting it FREE (`!sprint` ⇒ the reception election deemed it uncontested/unpressured;
        // a contested or pressured reception keeps `sprint` set and must still attack the ball)
        // eases to a pace that lands them ~with the ball instead of sprinting through the spot so
        // the ball runs on behind them. Gated default-ON; factor is 1.0 (byte-identical) when off,
        // when sprinting, or when the receiver is not actually early. See
        // `receive_in_stride_speed_factor`.
        let speed = if dd_soccer_enable_receive_in_stride()
            && incoming_pass
            && !sprint
            && self.ball.holder.is_none()
            && self.players[player_id].controller_slot.is_none()
        {
            speed
                * receive_in_stride_speed_factor(
                    to_target_len,
                    speed,
                    self.ball.position.distance(target),
                    self.ball.velocity.len(),
                )
        } else {
            speed
        };
        // MPC execution + MDP↔MPC reconciliation layer. For the active subset
        // (carrier + nearby contesters) a short-horizon point-mass MPC plans a
        // dynamically-feasible movement; depending on config it either refines the
        // policy's speed profile (Tier-2) or is reconciled against the policy
        // decision (logged, and averaged only when sensible). Inert — byte-identical
        // to the analytic path — when `tier2_player_enabled` is off.
        let desired = self.mpc_movement_desired_velocity(player_id, target, speed);
        // Directional momentum: gentle steering is free, but a hard reversal (a
        // cut-back, >90° off the committed heading) is locked for a short dwell so the
        // player can't whip back and forth across ticks (see `commit_travel_heading`).
        let commitment = self.players[player_id].locomotion;
        let (desired, committed_heading, heading_held_seconds) = commit_travel_heading(
            desired,
            commitment.heading,
            commitment.heading_held_seconds,
            dt,
            heading_emergency,
        );
        let acceleration_factor = (0.62 + fatigue_factor * 0.38).clamp(0.45, 1.05)
            * proximity_urgency
            * side_glance_speed_factor;
        let strength_to_weight_factor =
            strength_to_weight_acceleration_multiplier(&self.players[player_id].skills);
        let p = &mut self.players[player_id];
        // Accumulate time-in-tier: reset on an effort-tier change, otherwise add this
        // step's dt so the dwell measures how long the current gait has been carried.
        p.locomotion.gait_held_seconds = if gait.effort_tier() != previous_gait.effort_tier() {
            dt
        } else {
            gait_held_seconds + dt
        };
        p.locomotion.heading = committed_heading;
        p.locomotion.heading_held_seconds = heading_held_seconds;
        p.movement_gait = gait;
        let max_accel = acceleration_yps2_from_score(p.skills.acceleration)
            * acceleration_factor
            * strength_to_weight_factor;
        let target_velocity = approach_velocity(p.velocity, desired, max_accel, dt);
        let target_acceleration = if dt > 0.0 {
            (target_velocity - p.velocity) / dt
        } else {
            Vec2::zero()
        };
        let max_accel_delta = PLAYER_ACCEL_JERK_LIMIT_YPS3
            * (0.72 + ability01(p.skills.acceleration) * 0.28)
            * (0.74 + proximity_urgency * 0.26)
            * dt.max(0.0);
        let accel_delta = target_acceleration - previous_acceleration;
        let mut limited_acceleration =
            if accel_delta.len() > max_accel_delta && max_accel_delta > 0.0 {
                previous_acceleration + accel_delta.normalized() * max_accel_delta
            } else {
                target_acceleration
            };
        if limited_acceleration.len() > max_accel && max_accel > 0.0 {
            limited_acceleration = limited_acceleration.normalized() * max_accel;
        }
        p.velocity += limited_acceleration * dt;
        if p.velocity.len() > SOCCER_PHYSICS_PLAYER_MAX_SPEED_YPS {
            p.velocity = p.velocity.normalized() * SOCCER_PHYSICS_PLAYER_MAX_SPEED_YPS;
        }
        let movement_facing = movement_action_facing_bucket(
            p.team,
            p.position,
            self.ball.position,
            to_target,
            p.velocity,
            gait,
            self.ball.holder == Some(player_id),
            p.action_facing,
        );
        if movement_facing != FacingBucket::Unknown {
            p.action_facing = movement_facing;
        }
        p.acceleration = limited_acceleration;
        p.jerk = if dt > 0.0 {
            (p.acceleration - previous_acceleration) / dt
        } else {
            Vec2::zero()
        };
        p.position += p.velocity * dt;
        p.position = p.position.clamp_to_pitch(
            self.config.field_width_yards,
            self.config.field_length_yards,
        );
        let gait_fatigue = gait.fatigue_delta(p.skills.stamina, dt);
        p.add_fatigue(gait_fatigue);
    }

    pub(crate) fn sync_held_ball_to_holder(&mut self) {
        let Some(holder_id) = self.ball.holder else {
            return;
        };
        let Some(player) = self.players.iter().find(|player| player.id == holder_id) else {
            self.ball.holder = None;
            return;
        };
        let field_width = self.config.field_width_yards;
        let field_length = self.config.field_length_yards;
        let player_pos = finite_pitch_point(
            player.position,
            field_width,
            field_length,
            player.home_position,
        );
        let velocity = limit_vec2_len(player.velocity, SOCCER_PHYSICS_PLAYER_MAX_SPEED_YPS);
        let acceleration =
            limit_vec2_len(player.acceleration, SOCCER_PHYSICS_PLAYER_MAX_ACCEL_YPS2);
        let jerk = finite_vec2(player.jerk, Vec2::zero());
        let team = player.team;
        let facing_yaw = finite_metric(player.facing_yaw);
        // A goalkeeper holding the ball IN HIS HANDS (inside his own box) is not
        // dribbling — the ball is gathered to his body, so it must NOT run the
        // orbit/close-control machinery (which would swing it 0.25-1yd around him
        // like a dribble, even toward a presser at the box edge). Tuck it in his
        // hands: a small fixed lead in front of his facing, no orbit, on the floor.
        if self.keeper_handling_holder() == Some(holder_id) {
            self.ball.reset_carry_orbit();
            let lead = Vec2::new(facing_yaw.cos(), facing_yaw.sin()) * GK_HANDLING_BALL_TUCK_YARDS;
            self.ball.position = (player_pos + lead).clamp_to_pitch(
                self.config.field_width_yards,
                self.config.field_length_yards,
            );
            self.ball.velocity = velocity;
            self.ball.acceleration = acceleration;
            self.ball.jerk = jerk;
            self.ball.curl_acceleration = Vec2::zero();
            self.ball.altitude_yards = 0.0;
            self.ball.last_touch_team = Some(team);
            return;
        }
        // The active dribble move (if any) decides where the ball orbits and whether it
        // may cut through the body line; the nearest opponent tightens close control.
        let move_kind = player
            .last_decision
            .as_ref()
            .map(|decision| normalize_soccer_action_label(&decision.action))
            .and_then(dribble_move_kind_for_action_label);
        let nearest_opponent = self
            .players
            .iter()
            .filter(|other| other.team != team)
            .map(|other| (other.position, other.position.distance(player_pos)))
            .min_by(|a, b| a.1.partial_cmp(&b.1).unwrap_or(std::cmp::Ordering::Equal));
        let nearest_opponent_distance = nearest_opponent.map(|(_, d)| d).unwrap_or(f64::INFINITY);
        let nearest_opponent_dir = nearest_opponent.and_then(|(pos, _)| {
            let to = pos - player_pos;
            (to.len() > 1e-6).then(|| to.normalized())
        });
        let (
            desired_dir,
            desired_radius,
            allow_through,
            prefer_long_orbit,
            winding_cap,
            orbit_rate,
        ) = carried_ball_orbit_command(
            facing_yaw,
            move_kind,
            nearest_opponent_distance,
            nearest_opponent_dir,
        );
        let tick = self.tick;
        // Orbit the ball around the carrier (advanced at most once per tick; later calls
        // in the same tick just re-anchor it to the carrier's current position).
        let target = self.ball.advance_carried_ball_orbit(
            tick,
            player_pos,
            desired_dir,
            desired_radius,
            allow_through,
            prefer_long_orbit,
            winding_cap,
            orbit_rate,
            self.config.dt_seconds,
            field_width,
            field_length,
            &mut self.rng,
        );
        // First-touch settle: if the ball is much further out than the orbit target
        // (just controlled from a distance), draw it in smoothly rather than snapping.
        let delta = target - self.ball.position;
        self.ball.position = if delta.len() > CONTROL_FIRST_TOUCH_SETTLE_MAX_STEP_YARDS {
            (self.ball.position + delta.normalized() * CONTROL_FIRST_TOUCH_SETTLE_MAX_STEP_YARDS)
                .clamp_to_pitch(field_width, field_length)
        } else {
            target
        };
        self.ball.velocity = velocity;
        self.ball.acceleration = acceleration;
        self.ball.jerk = jerk;
        self.ball.curl_acceleration = Vec2::zero();
        self.ball.altitude_yards = 0.0;
        self.ball.last_touch_team = Some(team);
    }

    /// Is this player in the Tier-2 MPC "active subset"? The ball carrier always
    /// is; an off-ball outfield player joins it while close to the current ball
    /// or while their chosen target is a reachable future ball point on an in-flight
    /// pass. This keeps MPC tied to the same trajectory-contest objective as the
    /// MDP movement decision without widening it to all 22 players.
    fn mpc_tier2_active(&self, player_id: usize, target: Vec2) -> bool {
        if self.ball.holder == Some(player_id) {
            return true;
        }
        let Some(player) = self.players.get(player_id) else {
            return false;
        };
        let radius = self.config.mpc.active_radius_yards.max(0.0);
        // The keeper now EXECUTES its positioning strategy (line height / angle /
        // sweep) through MPC as well, over a wider activation range than an outfield
        // presser since it tracks the ball from its line. (MPC is gated off by
        // default, so this is inert until a run enables it.)
        let effective_radius = if player.role == PlayerRole::Goalkeeper {
            radius.max(GK_MPC_ACTIVE_RADIUS_YARDS)
        } else {
            radius
        };
        if player.position.distance(self.ball.position) <= effective_radius {
            return true;
        }
        let Some(pass) = self.pending_pass.as_ref() else {
            return false;
        };
        if self.ball.holder.is_some() || !target.x.is_finite() || !target.y.is_finite() {
            return false;
        }
        let pass_lane_distance =
            segment_distance_to_point(self.ball.position, pass.intended_target, target);
        let target_near_live_pass = pass_lane_distance <= 1.25
            && target.distance(self.ball.position) <= effective_radius * 1.85
            && player.position.distance(target) <= effective_radius * 2.60;
        if !target_near_live_pass {
            return false;
        }
        if pass.team == player.team {
            pass.target == Some(player_id)
        } else {
            player.role != PlayerRole::Goalkeeper
        }
    }

    pub(crate) fn mpc_field_obstacles(
        &self,
        player_id: usize,
        my_team: Team,
        dt: f64,
    ) -> Vec<PlanarObstacle> {
        let (field_width, field_length) = sane_pitch_dimensions(
            self.config.field_width_yards,
            self.config.field_length_yards,
        );
        let half_dt2 = 0.5 * dt * dt;
        let sixth_dt3 = dt * dt * dt / 6.0; // 3rd-order (jerk) term, matching predicted_ball_position
        let opponent_radius = self.config.mpc.opponent_keepout_yards.max(0.0);
        let teammate_radius = self.config.mpc.teammate_keepout_yards.max(0.0);
        let keepout_weight = self.config.mpc.keepout_weight.max(0.0);
        let mut obstacles = Vec::with_capacity(self.players.len().saturating_add(1));

        for other in &self.players {
            if other.id == player_id {
                continue;
            }
            let position = finite_pitch_point(
                other.position,
                field_width,
                field_length,
                Vec2::new(field_width * 0.5, field_length * 0.5),
            );
            let velocity = finite_vec2(other.velocity, Vec2::zero());
            let acceleration = finite_vec2(other.acceleration, Vec2::zero());
            let jerk = finite_vec2(other.jerk, Vec2::zero());
            let center = finite_pitch_point(
                position + velocity * dt + acceleration * half_dt2 + jerk * sixth_dt3,
                field_width,
                field_length,
                position,
            );
            let obstacle_velocity =
                limit_vec2_len(velocity + acceleration * dt + jerk * half_dt2, 28.0);
            let opponent = other.team != my_team;
            let holder_bonus = if self.ball.holder == Some(other.id) {
                0.4
            } else {
                0.0
            };
            let kinematic_weight = 1.0
                + velocity.len().clamp(0.0, 18.0) / 54.0
                + acceleration.len().clamp(0.0, 14.0) / 56.0;
            obstacles.push(PlanarObstacle {
                center: [center.x, center.y],
                velocity: [obstacle_velocity.x, obstacle_velocity.y],
                radius: if opponent {
                    opponent_radius
                } else {
                    teammate_radius
                } + holder_bonus,
                weight: if opponent {
                    keepout_weight
                } else {
                    keepout_weight * 0.25
                } * kinematic_weight,
            });
        }

        if self.ball.holder != Some(player_id) {
            let position = finite_pitch_point(
                self.ball.position,
                field_width,
                field_length,
                Vec2::new(field_width * 0.5, field_length * 0.5),
            );
            let velocity = finite_vec2(self.ball.velocity, Vec2::zero());
            let acceleration = finite_vec2(self.ball.acceleration, Vec2::zero());
            let jerk = finite_vec2(self.ball.jerk, Vec2::zero());
            let center = finite_pitch_point(
                position + velocity * dt + acceleration * half_dt2 + jerk * sixth_dt3,
                field_width,
                field_length,
                position,
            );
            let obstacle_velocity =
                limit_vec2_len(velocity + acceleration * dt + jerk * half_dt2, 36.0);
            let ball_weight = keepout_weight
                * 0.15
                * (1.0
                    + velocity.len().clamp(0.0, 30.0) / 60.0
                    + acceleration.len().clamp(0.0, 30.0) / 90.0);
            obstacles.push(PlanarObstacle {
                center: [center.x, center.y],
                velocity: [obstacle_velocity.x, obstacle_velocity.y],
                radius: 0.75,
                weight: ball_weight,
            });
        }

        obstacles
    }

    /// Offside line (the second-last defender's `y`, GK included) for
    /// `attacking_team`, computed from the live players. `None` when the defending
    /// side has fewer than two players. Used to keep the xT terminal shaping onside.
    fn live_offside_line_for(&self, attacking_team: Team) -> Option<f64> {
        let attack = attacking_team.attack_dir();
        // Progress toward the opponent goal; the two largest are the last and
        // second-last defenders, and the offside line sits at the second-last.
        let mut progress: Vec<f64> = self
            .players
            .iter()
            .filter(|p| p.team != attacking_team && p.position.y.is_finite())
            .map(|p| p.position.y * attack)
            .collect();
        if progress.len() < 2 {
            return None;
        }
        progress.sort_by(|a, b| b.total_cmp(a));
        Some(progress[1] * attack)
    }

    /// Cap the xT-`shaped` reference so its attack-direction progress never exceeds
    /// the larger of the original (onside) target's progress and the offside line —
    /// i.e. the nudge may pull sideways/back freely but cannot advance an attacker
    /// past the line the support search kept it behind. No-op for non-attackers,
    /// when the line is unknown, or when the shaped point is already onside.
    fn xt_onside_capped_reference(
        &self,
        player_id: usize,
        my_team: Team,
        original: Vec2,
        shaped: Vec2,
    ) -> Vec2 {
        let is_attacker = self.players.get(player_id).map_or(false, |p| {
            matches!(p.role, PlayerRole::Forward | PlayerRole::Midfielder)
        });
        if !is_attacker {
            return shaped;
        }
        let Some(line_y) = self.live_offside_line_for(my_team) else {
            return shaped;
        };
        let attack = my_team.attack_dir();
        let cap_progress = (original.y * attack).max(line_y * attack);
        if shaped.y * attack > cap_progress {
            Vec2::new(shaped.x, cap_progress * attack)
        } else {
            shaped
        }
    }

    /// The desired velocity actually executed this tick, after the MPC execution
    /// and (optionally) MDP↔MPC reconciliation layers. The "MDP" decision is the
    /// learned-policy/heuristic [`Self::collision_aware_desired_velocity`]; the
    /// "MPC" decision is a horizon-aware point-mass plan. The whole method reduces
    /// to the analytic decision (byte-identical) whenever MPC is off or the player
    /// is not in the active subset.
    fn mpc_movement_desired_velocity(
        &mut self,
        player_id: usize,
        target: Vec2,
        speed: f64,
    ) -> Vec2 {
        let v_mdp = self.collision_aware_desired_velocity(player_id, target, speed);
        if !self.config.mpc.tier2_player_enabled || !self.mpc_tier2_active(player_id, target) {
            return v_mdp;
        }
        let Some(v_mpc) = self.mpc_desired_velocity(player_id, target, speed) else {
            return v_mdp;
        };
        if self.config.mpc.reconcile_enabled {
            return self.reconcile_mdp_mpc(v_mdp, v_mpc, speed);
        }
        // Tier-2 execution refinement (no reconciliation): keep the policy's
        // direction + collision steering, adopt only the MPC's feasible speed
        // profile (so it brakes into targets instead of overshooting). Re-running
        // the steering with the reduced speed preserves collision behaviour.
        let mpc_speed = v_mpc.len().min(speed);
        self.collision_aware_desired_velocity(player_id, target, mpc_speed)
    }

    fn team_is_attacking_for_mpc_latent(&self, team: Team) -> bool {
        self.ball
            .holder
            .and_then(|holder| self.players.get(holder).map(|player| player.team))
            == Some(team)
            || self
                .pending_pass
                .as_ref()
                .is_some_and(|pass| pass.team == team)
    }

    fn mpc_latent_execution_objective(
        &self,
        player_id: usize,
        team: Team,
    ) -> SoccerMpcLatentObjective {
        if !self.config.mpc.latent_objective_enabled {
            return SoccerMpcLatentObjective::default();
        }
        // The learned latent normally fine-tunes the MPC weights only for the team in
        // possession (pass/shot/goal pressure). It is ALSO activated for a player contesting
        // a LOOSE ball within the MPC active radius, so the neural-learned objective tunes
        // the QP arrival when fighting for a 50-50 — the ball is nobody's yet, but winning it
        // is exactly the team's live objective, so the chaser should arrive as decisively.
        // (Tier-2 MPC only runs for players inside this radius, so the proxy is exact for the
        // population that actually executes through the controller.)
        let loose_ball_duel = self.ball.holder.is_none()
            && self.players.get(player_id).is_some_and(|p| {
                p.position.distance(self.ball.position)
                    <= self.config.mpc.active_radius_yards.max(0.0)
            });
        if self.team_is_attacking_for_mpc_latent(team) || loose_ball_duel {
            self.mpc_latent_objective(team)
        } else {
            SoccerMpcLatentObjective::default()
        }
    }

    fn mpc_latent_shaped_target(
        &self,
        team: Team,
        target: Vec2,
        latent: SoccerMpcLatentObjective,
    ) -> Vec2 {
        let max_bias = if self.config.mpc.latent_reference_bias_yards.is_finite() {
            self.config.mpc.latent_reference_bias_yards.max(0.0)
        } else {
            default_soccer_mpc_latent_reference_bias_yards()
        };
        let bias_yards = max_bias * latent.combined_pressure();
        if bias_yards <= 1e-9 {
            return target;
        }
        let (field_width, field_length) = sane_pitch_dimensions(
            self.config.field_width_yards,
            self.config.field_length_yards,
        );
        finite_pitch_point(
            Vec2::new(target.x, target.y + team.attack_dir() * bias_yards),
            field_width,
            field_length,
            target,
        )
    }

    fn live_mpc_player_position(&self, player: &PlayerAgent) -> Vec2 {
        self.shared_positions
            .latest_for(player.id)
            .map(|sample| sample.position)
            .unwrap_or(player.position)
    }

    fn live_mpc_second_last_defender_line_for(&self, attacking_team: Team) -> Option<f64> {
        let mut defender_ys = self
            .players
            .iter()
            .filter(|player| player.team == attacking_team.other())
            .map(|player| self.live_mpc_player_position(player).y)
            .filter(|y| y.is_finite())
            .collect::<Vec<_>>();
        if defender_ys.len() < 2 {
            return None;
        }
        match attacking_team {
            Team::Home => {
                defender_ys.sort_by(|a, b| b.partial_cmp(a).unwrap_or(std::cmp::Ordering::Equal));
            }
            Team::Away => {
                defender_ys.sort_by(|a, b| a.partial_cmp(b).unwrap_or(std::cmp::Ordering::Equal));
            }
        }
        defender_ys.get(1).copied()
    }

    fn live_mpc_position_would_be_offside(&self, team: Team, position: Vec2) -> bool {
        let field_length = self.config.field_length_yards;
        let half_line = field_length * 0.5;
        match team {
            Team::Home if position.y <= half_line => return false,
            Team::Away if position.y >= half_line => return false,
            _ => {}
        }
        let Some(second_last_defender_y) = self.live_mpc_second_last_defender_line_for(team) else {
            return false;
        };
        match team {
            Team::Home => position.y > self.ball.position.y && position.y > second_last_defender_y,
            Team::Away => position.y < self.ball.position.y && position.y < second_last_defender_y,
        }
    }

    fn live_mpc_player_has_legal_self_touch_claim(&self, player_id: usize, team: Team) -> bool {
        if !self
            .players
            .iter()
            .any(|player| player.id == player_id && player.team == team)
        {
            return false;
        }
        self.ball.holder == Some(player_id)
            || (self.ball.holder.is_none() && self.last_touch_player == Some(player_id))
    }

    fn live_mpc_open_space_offside_excess_yards_for_player(
        &self,
        player_id: usize,
        team: Team,
        position: Vec2,
    ) -> f64 {
        if self.live_mpc_player_has_legal_self_touch_claim(player_id, team)
            || !self.live_mpc_position_would_be_offside(team, position)
        {
            return 0.0;
        }
        self.live_mpc_second_last_defender_line_for(team)
            .map_or(0.0, |line_y| {
                ((position.y - line_y) * team.attack_dir() - OPEN_SPACE_RUN_OFFSIDE_TOLERANCE_YARDS)
                    .max(0.0)
            })
    }

    fn live_mpc_teammate_occupied_space_pressure_at(
        &self,
        team: Team,
        position: Vec2,
        exclude_player_id: Option<usize>,
    ) -> f64 {
        let (field_width, field_length) = sane_pitch_dimensions(
            self.config.field_width_yards,
            self.config.field_length_yards,
        );
        let center = Vec2::new(field_width * 0.5, field_length * 0.5);
        let position = finite_pitch_point(position, field_width, field_length, center);
        let mut nearest_teammate_distance_sq = f64::INFINITY;
        let mut teammate_axis_clump_pressure: f64 = 0.0;
        let axis_radius =
            if soccer_point_in_either_penalty_area(position, field_width, field_length) {
                TEAMMATE_MIN_SPACING_BOX_YARDS
            } else {
                TEAMMATE_MIN_SPACING_YARDS
            };
        for player in self.players.iter().filter(|player| player.team == team) {
            if exclude_player_id == Some(player.id) {
                continue;
            }
            let player_position = finite_pitch_point(
                self.live_mpc_player_position(player),
                field_width,
                field_length,
                player.home_position,
            );
            let delta = player_position - position;
            let distance_sq = delta.x * delta.x + delta.y * delta.y;
            nearest_teammate_distance_sq = nearest_teammate_distance_sq.min(distance_sq);
            teammate_axis_clump_pressure = teammate_axis_clump_pressure.max(
                teammate_axis_clump_pressure_from_delta_with_radius(delta, axis_radius),
            );
        }
        teammate_occupied_space_pressure_from_distance(nearest_teammate_distance_sq.sqrt())
            .max(teammate_axis_clump_pressure)
    }

    pub(crate) fn mpc_pitch_value_terminal_gain_for(&self, player_id: usize, target: Vec2) -> f64 {
        let Some(player) = self.players.get(player_id) else {
            return 0.0;
        };
        let current = player.position;
        if !current.x.is_finite()
            || !current.y.is_finite()
            || !target.x.is_finite()
            || !target.y.is_finite()
        {
            return 0.0;
        }
        let (field_width, field_length) = sane_pitch_dimensions(
            self.config.field_width_yards,
            self.config.field_length_yards,
        );
        let gain = match self.controlled_possession_team_now() {
            Some(team) if team == player.team => {
                expected_threat(player.team, target, field_width, field_length)
                    - expected_threat(player.team, current, field_width, field_length)
            }
            Some(team) => {
                expected_threat(team, current, field_width, field_length)
                    - expected_threat(team, target, field_width, field_length)
            }
            None => 0.0,
        };
        gain.clamp(0.0, 0.55)
    }

    pub(crate) fn mpc_pitch_value_shaped_target(&self, player_id: usize, target: Vec2) -> Vec2 {
        let Some(player) = self.players.get(player_id) else {
            return target;
        };
        if self.controlled_possession_team_now() != Some(player.team)
            || player.role == PlayerRole::Goalkeeper
            || !target.x.is_finite()
            || !target.y.is_finite()
        {
            return target;
        }
        let (field_width, field_length) = sane_pitch_dimensions(
            self.config.field_width_yards,
            self.config.field_length_yards,
        );
        let base_value = expected_threat(player.team, target, field_width, field_length);
        let attack = Vec2::new(0.0, player.team.attack_dir());
        let lateral_home = (player.home_position.x - target.x).clamp(
            -MPC_PITCH_VALUE_REFERENCE_PROBE_YARDS,
            MPC_PITCH_VALUE_REFERENCE_PROBE_YARDS,
        );
        let probes = [
            target,
            target + attack * MPC_PITCH_VALUE_REFERENCE_PROBE_YARDS,
            target + Vec2::new(MPC_PITCH_VALUE_REFERENCE_PROBE_YARDS, 0.0),
            target + Vec2::new(-MPC_PITCH_VALUE_REFERENCE_PROBE_YARDS, 0.0),
            target
                + Vec2::new(
                    MPC_PITCH_VALUE_REFERENCE_PROBE_YARDS * 0.55,
                    player.team.attack_dir() * MPC_PITCH_VALUE_REFERENCE_PROBE_YARDS * 0.72,
                ),
            target
                + Vec2::new(
                    -MPC_PITCH_VALUE_REFERENCE_PROBE_YARDS * 0.55,
                    player.team.attack_dir() * MPC_PITCH_VALUE_REFERENCE_PROBE_YARDS * 0.72,
                ),
            target + Vec2::new(lateral_home, 0.0),
        ];
        let mut best = target.clamp_to_pitch(field_width, field_length);
        let mut best_score = 0.0;
        for probe in probes {
            let candidate = probe.clamp_to_pitch(field_width, field_length);
            let value_gain =
                expected_threat(player.team, candidate, field_width, field_length) - base_value;
            if value_gain <= MPC_PITCH_VALUE_REFERENCE_MIN_GAIN {
                continue;
            }
            let offside_excess = self.live_mpc_open_space_offside_excess_yards_for_player(
                player.id,
                player.team,
                candidate,
            );
            let teammate_pressure = self.live_mpc_teammate_occupied_space_pressure_at(
                player.team,
                candidate,
                Some(player.id),
            );
            let score = value_gain
                - offside_excess.max(0.0) * 0.018
                - teammate_pressure.clamp(0.0, 1.0) * 0.045;
            if score > best_score {
                best = candidate;
                best_score = score;
            }
        }
        if best_score <= 0.0 {
            return target;
        }
        let delta = best - target;
        let len = delta.len();
        if len > MPC_PITCH_VALUE_REFERENCE_MAX_NUDGE_YARDS && len > 1e-9 {
            (target + delta * (MPC_PITCH_VALUE_REFERENCE_MAX_NUDGE_YARDS / len))
                .clamp_to_pitch(field_width, field_length)
        } else {
            best
        }
    }

    fn mpc_planar_config(
        &self,
        horizon: usize,
        dt: f64,
        accel_cap: f64,
        latent: SoccerMpcLatentObjective,
        pitch_value_terminal_gain: f64,
    ) -> PlanarMpcConfig {
        let base = PlanarMpcConfig::default();
        let iters = ((horizon as f64 * 2.0).clamp(60.0, 200.0)) as usize;
        let obstacle_decay_per_step = 0.5_f64.powf(dt / 1.5);
        let weight_boost = if self.config.mpc.latent_weight_boost.is_finite() {
            self.config.mpc.latent_weight_boost.clamp(0.0, 2.0)
        } else {
            default_soccer_mpc_latent_weight_boost()
        };
        let latent = latent.sanitized();
        let pass = latent.pass_chain_continuity;
        let shot = latent.shot_pressure;
        let goal = latent.goal_pressure;
        let pitch_value_terminal = pitch_value_terminal_gain.clamp(0.0, 1.0);
        PlanarMpcConfig {
            horizon,
            dt,
            q_pos: base.q_pos * (1.0 + weight_boost * (0.35 * pass + 0.25 * shot + 0.40 * goal)),
            q_vel: base.q_vel * (1.0 + weight_boost * (0.60 * pass + 0.25 * shot + 0.15 * goal)),
            qf_pos: base.qf_pos
                * (1.0
                    + weight_boost * (0.25 * pass + 0.35 * shot + 0.40 * goal)
                    + pitch_value_terminal * MPC_PITCH_VALUE_TERMINAL_QF_POS_BOOST),
            qf_vel: base.qf_vel
                * (1.0
                    + weight_boost * (0.45 * pass + 0.35 * shot + 0.20 * goal)
                    + pitch_value_terminal * MPC_PITCH_VALUE_TERMINAL_QF_VEL_BOOST),
            a_max: accel_cap,
            iters,
            obstacle_decay_per_step,
            ..base
        }
    }

    fn mpc_config_stale(current: &PlanarMpcConfig, desired: &PlanarMpcConfig) -> bool {
        current.horizon != desired.horizon
            || (current.dt - desired.dt).abs() > 1e-9
            || (current.q_pos - desired.q_pos).abs() > 1e-9
            || (current.q_vel - desired.q_vel).abs() > 1e-9
            || (current.qf_pos - desired.qf_pos).abs() > 1e-9
            || (current.qf_vel - desired.qf_vel).abs() > 1e-9
            || (current.a_max - desired.a_max).abs() > 1e-6
            || current.iters != desired.iters
            || (current.obstacle_decay_per_step - desired.obstacle_decay_per_step).abs() > 1e-12
    }

    /// Run the player's receding-horizon MPC one step toward `target` and return
    /// the full dynamically-feasible velocity vector it plans for the next tick
    /// (direction *and* magnitude), capped to the heuristic `speed` envelope so it
    /// can never exceed the player's fatigue/gait-limited top speed. The controller
    /// is created lazily and retained on the match so its warm start persists
    /// across ticks. `None` on degenerate input (caller falls back to the policy).
    fn mpc_desired_velocity(&mut self, player_id: usize, target: Vec2, speed: f64) -> Option<Vec2> {
        use crate::des::general::mpc_point_mass::{
            PlanarObstacle, PlanarPointMassMpc, PlanarReference, PlanarState,
        };
        let player = self.players.get(player_id)?;
        let pos = player.position;
        let vel = player.velocity;
        let my_team = player.team;
        // Acceleration disk radius from the player's own acceleration attribute —
        // the dominant term in the downstream accel limit, which re-clamps anyway.
        let accel_cap = acceleration_yps2_from_score(player.skills.acceleration).max(0.5);
        let dt = sane_dt_seconds(self.config.dt_seconds, DEFAULT_DT_SECONDS).max(1e-6);
        let horizon = self.config.mpc.player_horizon.max(1);
        let latent = self.mpc_latent_execution_objective(player_id, my_team);
        let latent_target = self.mpc_latent_shaped_target(my_team, target, latent);
        let pitch_value_target = self.mpc_pitch_value_shaped_target(player_id, latent_target);
        // xT terminal-cost shaping (gated; identity when off): nudge the already pitch-value-shaped
        // reference up the control-weighted-threat gradient so an in-possession outfielder settles
        // in the most valuable controllable space within reach of its assigned slot.
        let reference_target = if xt_terminal_cost_enabled()
            && self.controlled_possession_team_now() == Some(my_team)
            && self
                .players
                .get(player_id)
                .map_or(false, |p| p.role != PlayerRole::Goalkeeper)
        {
            let (fw, fl) = sane_pitch_dimensions(
                self.config.field_width_yards,
                self.config.field_length_yards,
            );
            let points: Vec<XtControlPoint> = self
                .players
                .iter()
                .map(|p| XtControlPoint {
                    team: p.team,
                    position: p.position,
                    velocity: p.velocity,
                    top_speed: player_top_speed_yps(p.role, &p.skills),
                })
                .collect();
            let shaped = xt_terminal_shaped_target(&points, my_team, pitch_value_target, fw, fl);
            // Onside discipline: the support search already held this reference
            // onside; the goalward pull of the xT gradient must not undo that and
            // park an attacker offside. Cap the shaped reference's attack-direction
            // progress so it never advances FURTHER beyond the offside line than the
            // assigned target already was (a sanctioned in-behind run keeps its lead,
            // but the nudge can't extend it). Applies only to forwards/midfielders,
            // matching `clamp_forward_onside_support`.
            self.xt_onside_capped_reference(player_id, my_team, pitch_value_target, shaped)
        } else {
            pitch_value_target
        };
        let pitch_value_terminal_gain =
            self.mpc_pitch_value_terminal_gain_for(player_id, reference_target);
        let desired_cfg =
            self.mpc_planar_config(horizon, dt, accel_cap, latent, pitch_value_terminal_gain);

        // Field awareness: the controlled player is the MPC state; every other
        // player plus the ball becomes a moving soft keep-out, projected with
        // position, velocity, and acceleration before the mutable controller borrow.
        let obstacles: Vec<PlanarObstacle> = if self.config.mpc.field_aware_enabled {
            self.mpc_field_obstacles(player_id, my_team, dt)
        } else {
            Vec::new()
        };

        let stale = self
            .mpc_player_controllers
            .get(&player_id)
            .map(|c| {
                let cfg = c.config();
                Self::mpc_config_stale(cfg, &desired_cfg)
            })
            .unwrap_or(true);
        if stale {
            let controller = PlanarPointMassMpc::new(desired_cfg).ok()?;
            self.mpc_player_controllers.insert(player_id, controller);
        }

        // Cushioned trap: when this player is closing IN on a MOVING loose ball (heading at it,
        // within the active radius), the MPC arrives matching a fraction of the ball's velocity
        // — a give-with-the-ball first touch — instead of braking to a dead stop into it (which
        // bounces it away / miscontrols). Gated to players actually heading at the ball (target
        // nearer the ball than they are), so a peeling support runner is unaffected.
        let trap_match_velocity = (self.ball.holder.is_none()
            && self.ball.velocity.len() >= LOOSE_BALL_PROJECTION_MIN_SPEED_YPS
            && self.players.get(player_id).is_some_and(|p| {
                let to_ball = p.position.distance(self.ball.position);
                to_ball <= self.config.mpc.active_radius_yards.max(0.0)
                    && reference_target.distance(self.ball.position) < to_ball
            }))
        .then(|| self.ball.velocity * LOOSE_BALL_TRAP_CUSHION);

        let controller = self.mpc_player_controllers.get_mut(&player_id)?;
        let state = PlanarState {
            pos: [pos.x, pos.y],
            vel: [vel.x, vel.y],
        };
        let reference = match trap_match_velocity {
            Some(v) => {
                PlanarReference::through([reference_target.x, reference_target.y], [v.x, v.y])
            }
            None => PlanarReference::arrive([reference_target.x, reference_target.y]),
        };
        let accel = controller.control_with_obstacles(state, &[reference], &obstacles);
        let next = Vec2::new(vel.x + accel[0] * dt, vel.y + accel[1] * dt);
        // Cap to the heuristic speed envelope (MPC may only equal or undercut it).
        let len = next.len();
        if len > speed && len > 1e-9 {
            Some(next * (speed / len))
        } else {
            Some(next)
        }
    }

    /// Reconcile the learned-policy ("MDP") desired velocity with the MPC desired
    /// velocity. Records their divergence, then returns the executed velocity:
    /// a weighted average **only when the two are not directionally opposed** (an
    /// average of opposed vectors would cancel into a meaningless crawl); when
    /// they contradict, the learned policy owns WHERE to go and its decision is
    /// kept. Updates [`Self::mpc_reconcile_stats`].
    fn reconcile_mdp_mpc(&mut self, v_mdp: Vec2, v_mpc: Vec2, speed: f64) -> Vec2 {
        let mdp_len = v_mdp.len();
        let mpc_len = v_mpc.len();
        let deviation = (v_mdp - v_mpc).len();

        // Directional agreement (cosine). If either is ~stationary there is no
        // direction to oppose, so treat it as aligned (averaging magnitudes is fine).
        let alignment = if mdp_len > 1e-6 && mpc_len > 1e-6 {
            dot(v_mdp, v_mpc) / (mdp_len * mpc_len)
        } else {
            1.0
        };

        let stats = &mut self.mpc_reconcile_stats;
        stats.samples += 1;
        stats.sum_deviation_yps += deviation;
        if deviation > stats.max_deviation_yps {
            stats.max_deviation_yps = deviation;
        }
        if deviation > self.config.mpc.deviation_threshold_yps {
            stats.deviating_samples += 1;
        }

        if alignment >= self.config.mpc.blend_min_alignment {
            // Average makes sense — blend.
            self.mpc_reconcile_stats.blended_samples += 1;
            let alpha = self.config.mpc.blend_alpha.clamp(0.0, 1.0);
            let blended = v_mdp * (1.0 - alpha) + v_mpc * alpha;
            // Never exceed the speed envelope.
            let len = blended.len();
            if len > speed && len > 1e-9 {
                return blended * (speed / len);
            }
            return blended;
        }
        // Contradictory decisions — defer to the learned policy (no average).
        self.mpc_reconcile_stats.deferred_to_policy_samples += 1;
        v_mdp
    }

    /// Snapshot of the MDP↔MPC reconciliation telemetry accumulated this match.
    pub fn mpc_reconcile_stats(&self) -> SoccerMpcReconcileStats {
        self.mpc_reconcile_stats
    }

    fn collision_aware_desired_velocity(&self, player_id: usize, target: Vec2, speed: f64) -> Vec2 {
        let Some(player) = self.players.get(player_id) else {
            return Vec2::zero();
        };
        let to_target = target - player.position;
        let distance_to_target = to_target.len();
        if distance_to_target <= 1e-9 || speed <= 1e-9 {
            return Vec2::zero();
        }

        let desired_dir = to_target.normalized();
        let lookahead = distance_to_target
            .min((speed * PLAYER_AVOIDANCE_LOOKAHEAD_SECONDS).max(PLAYER_BODY_RADIUS_YARDS * 2.0));
        let path_end = player.position + desired_dir * lookahead;
        let path = path_end - player.position;
        let path_len_sq = dot(path, path);
        if path_len_sq <= 1e-12 {
            return desired_dir * speed;
        }
        let lateral_axis = Vec2::new(-desired_dir.y, desired_dir.x).normalized();
        let mut steer = Vec2::zero();
        let mut speed_scale: f64 = 1.0;

        for other in &self.players {
            if other.id == player_id {
                continue;
            }
            let projection = dot(other.position - player.position, path) / path_len_sq;
            if !(0.0..=1.0).contains(&projection) {
                continue;
            }
            let lateral_distance =
                segment_distance_to_point(player.position, path_end, other.position);
            if lateral_distance > PLAYER_AVOIDANCE_LANE_RADIUS_YARDS {
                continue;
            }

            let along_weight = 1.0 - projection * 0.45;
            let lateral_weight =
                1.0 - (lateral_distance / PLAYER_AVOIDANCE_LANE_RADIUS_YARDS).clamp(0.0, 1.0);
            let weight = (along_weight * lateral_weight).clamp(0.0, 1.0);
            if weight <= 1e-9 {
                continue;
            }

            let side_dot = dot(other.position - player.position, lateral_axis);
            let side = if side_dot.abs() > 1e-6 {
                -side_dot.signum()
            } else if (player.id + other.id) % 2 == 0 {
                1.0
            } else {
                -1.0
            };
            let other_speed = other.velocity.len();
            let head_on = other_speed > 0.75
                && dot(desired_dir, other.velocity.normalized()) < PLAYER_AVOIDANCE_HEAD_ON_DOT;
            let very_close =
                player.position.distance(other.position) < PLAYER_BODY_RADIUS_YARDS * 3.0;
            let slow = if head_on || very_close { 0.55 } else { 0.78 };
            speed_scale = speed_scale.min(1.0 - weight * (1.0 - slow));
            steer += lateral_axis * side * weight;
        }

        let adjusted_dir = if steer.len() > 1e-9 {
            (desired_dir + steer.normalized() * 0.48).normalized()
        } else {
            desired_dir
        };
        adjusted_dir * (speed * speed_scale.clamp(0.35, 1.0))
    }

    fn record_player_position_histories(&mut self) {
        for player in &mut self.players {
            player.record_position_history();
        }
    }

    pub(crate) fn record_ball_position_history(&mut self) {
        self.ball
            .record_position_history(self.tick, self.clock_seconds);
    }

    pub(crate) fn resolve_player_collisions(&mut self) {
        let min_sep = PLAYER_BODY_RADIUS_YARDS * 2.0;
        let (width, length) = sane_pitch_dimensions(
            self.config.field_width_yards,
            self.config.field_length_yards,
        );
        // Resolve pairwise overlaps in a state-scored order. When three or more
        // bodies pile up, order affects the settled positions; using contact pressure
        // and proximity to active play avoids both raw-index bias and external
        // random draws.
        let mut order: Vec<usize> = (0..self.players.len()).collect();
        let ball_position = self.ball.position;
        let holder = self.ball.holder;
        order.sort_by(|a, b| {
            let score = |idx: usize| {
                let player = &self.players[idx];
                let contact_pressure = self
                    .players
                    .iter()
                    .filter(|other| {
                        other.id != player.id
                            && other.position.distance(player.position) < min_sep * 1.5
                    })
                    .count() as f64;
                let ball_distance = player.position.distance(ball_position).min(140.0);
                let holder_bonus = if holder == Some(player.id) {
                    160.0
                } else {
                    0.0
                };
                holder_bonus
                    + contact_pressure * 80.0
                    + (80.0 - ball_distance).max(0.0)
                    + player.velocity.len() * 2.0
            };
            score(*b)
                .total_cmp(&score(*a))
                .then_with(|| self.players[*a].id.cmp(&self.players[*b].id))
        });
        let players = &mut self.players;
        for oi in 0..order.len() {
            for oj in oi + 1..order.len() {
                let (mut a_idx, mut b_idx) = (order[oi], order[oj]);
                if a_idx > b_idx {
                    std::mem::swap(&mut a_idx, &mut b_idx);
                }
                let (left, right) = players.split_at_mut(b_idx);
                let a = &mut left[a_idx];
                let b = &mut right[0];
                let delta = b.position - a.position;
                let dist = delta.len();
                if dist >= min_sep {
                    continue;
                }

                let normal = if dist <= 1e-9 {
                    // Exact overlaps need an arbitrary axis, but the axis is derived
                    // from the player ids instead of an act-of-god draw.
                    deterministic_separation_normal(a.id, b.id)
                } else {
                    delta / dist
                };
                let overlap = min_sep - dist.max(1e-9);
                let push = normal * (overlap * 0.5);
                a.position = (a.position - push).clamp_to_pitch(width, length);
                b.position = (b.position + push).clamp_to_pitch(width, length);

                let a_normal_speed = dot(a.velocity, normal);
                let b_normal_speed = dot(b.velocity, normal);
                if a_normal_speed > b_normal_speed {
                    let impulse = (a_normal_speed - b_normal_speed) * PLAYER_COLLISION_DAMPING;
                    a.velocity = a.velocity - normal * impulse;
                    b.velocity += normal * impulse;
                }
            }
        }
    }

    pub(crate) fn integrate_ball(&mut self) {
        self.run_ball_time_step();
    }

    pub(crate) fn run_ball_time_step(&mut self) {
        let (field_width, field_length) = sane_pitch_dimensions(
            self.config.field_width_yards,
            self.config.field_length_yards,
        );
        let field_center = Vec2::new(field_width * 0.5, field_length * 0.5);
        self.ball.position =
            finite_pitch_point(self.ball.position, field_width, field_length, field_center);
        self.ball.velocity = limit_vec2_len(self.ball.velocity, SOCCER_PHYSICS_BALL_MAX_SPEED_YPS);
        self.ball.acceleration =
            limit_vec2_len(self.ball.acceleration, SOCCER_PHYSICS_BALL_MAX_ACCEL_YPS2);
        self.ball.jerk = finite_vec2(self.ball.jerk, Vec2::zero());
        self.ball.curl_acceleration = limit_vec2_len(
            self.ball.curl_acceleration,
            SOCCER_PHYSICS_BALL_MAX_ACCEL_YPS2,
        );
        self.ball.altitude_yards = finite_metric(self.ball.altitude_yards).max(0.0);
        let dt_seconds = sane_dt_seconds(self.config.dt_seconds, DEFAULT_DT_SECONDS);
        // A shot that has slowed to a roll on the ground is no longer a credible attempt on goal —
        // it is a loose ball again. While `pending_shot` is set, control is never attempted (the
        // ball step only resolves control when `pending_shot.is_none()`), so EVERY player is locked
        // out and runs straight over the dead/dying shot ball without any attempt to collect it,
        // until the stuck-ball watchdog eventually hoofs it away. Demote it here so it becomes a
        // normal contestable loose ball. (Goal detection does not depend on `pending_shot` — a ball
        // crossing the line is still a goal — so a slow shot trickling in is unaffected; and a fast
        // shot still in flight stays a live shot and is left untouched.)
        if self.pending_shot.is_some()
            && self.ball.holder.is_none()
            && self.ball.altitude_yards <= BALL_ROLLING_ALTITUDE_YARDS
            && self.ball.velocity.len() <= DEAD_SHOT_LOOSE_BALL_SPEED_YPS
        {
            self.pending_shot = None;
        }
        let previous_position = self.ball.position;
        let previous_velocity = self.ball.velocity;
        let previous_acceleration = self.ball.acceleration;
        // Altitude when the receiver reaches the ball — drives the aerial header below.
        let control_altitude = self.ball.altitude_yards;
        let dummy_let_through_guard = self.pass_lane_dummy_guard();
        let context = BallStepContext {
            tick: self.tick,
            double_touch_guard: self.restart_double_touch_guard,
            dummy_let_through_guard,
            clock_seconds: self.clock_seconds,
            dt_seconds,
            ball_drag_per_tick: self.config.ball_drag_per_tick,
            ball_air_resistance: self.config.ball_air_resistance,
            ball_grass_resistance_yps2: self.config.ball_grass_resistance_yps2,
            ball_stop_speed_yps: self.config.ball_stop_speed_yps,
            field_length,
            field_width,
            goal_width: self.config.goal_width_yards,
            players: &self.players,
            pending_pass: self.pending_pass.clone(),
            pending_shot: self.pending_shot.clone(),
            scheduled_index: self.last_agent_schedule.iter().position(|entry| {
                entry.kind == AgentScheduleKind::Ball && entry.id == self.ball.id
            }),
        };
        let outcome = self.ball.run_time_step(context, &mut self.rng);
        let controlled_after_step = matches!(outcome, BallStepOutcome::Controlled { .. });
        // At most one special handler fires; `handled` short-circuits the rest. Crucially
        // this is NOT an early `return` — the live-lock watchdogs at the end must run on
        // every tick (see below).
        let mut handled = controlled_after_step
            && self.call_pending_offside_interference_before_control_if_needed(
                previous_position,
                self.ball.position,
            );
        // Aerial reception: a player meeting a falling ball under pressure heads it
        // away / flicks it on; unpressured it falls through to normal control (chest).
        if !handled {
            if let BallStepOutcome::Controlled {
                holder,
                holder_team,
                ..
            } = &outcome
            {
                let (holder, holder_team) = (*holder, *holder_team);
                // A header/flick is still a controlling touch. The in-flight interference
                // check above excludes the segment endpoint (the control point), and a
                // handled header SKIPS `apply_ball_outcome` (and its at-control offside
                // check) — so whistle an attacker who was offside when the ball was played
                // and is the one now meeting it in the air, BEFORE the header runs.
                if let Some(offside) = self
                    .effective_offside_candidates()
                    .into_iter()
                    .find(|offside| offside.target == holder && offside.team == holder_team)
                {
                    self.pending_pass = None;
                    self.ball.untargeted_long_ball_flight = None;
                    self.ball.untargeted_long_ball_launcher = None;
                    self.call_offside(offside);
                    handled = true;
                } else {
                    handled = self.try_aerial_header(holder, holder_team, control_altitude);
                }
            }
        }
        if !handled {
            let loose_after_step = matches!(outcome, BallStepOutcome::None);
            self.apply_ball_outcome(outcome);
            handled = loose_after_step
                && self.call_pending_offside_interference_if_needed(previous_position);
            if !handled {
                self.ball.update_kinematics_from(
                    previous_velocity,
                    previous_acceleration,
                    self.config.dt_seconds,
                );
            }
        }
        // Live-lock watchdogs run EVERY tick — even after an aerial header or an offside
        // interception took an early path above. Otherwise a header/control duel that
        // pins the ball in one spot (alt ~1.6yd, "controlled" every tick) evades them
        // forever — exactly the freeze seen in game 34137d02.
        let _ = handled;
        self.update_stuck_ball_recovery();
        self.detect_and_break_possession_livelock();
    }

    /// Aerial reception decision at the moment a player meets a falling ball. Under
    /// pressure the receiver heads it away / flicks it on (toward the opponent's goal
    /// and a teammate ahead) rather than trying to settle it in a crowd; with no
    /// pressure it returns false so the normal control settles it (chest control).
    /// Returns true if the ball was headed/flicked (the caller must not settle it).
    pub(crate) fn try_aerial_header(
        &mut self,
        holder: usize,
        holder_team: Team,
        control_altitude: f64,
    ) -> bool {
        if control_altitude < AERIAL_HEADER_MIN_ALTITUDE_YARDS
            || control_altitude > AERIAL_HEADER_MAX_ALTITUDE_YARDS
        {
            return false;
        }
        let Some(idx) = self.players.iter().position(|p| p.id == holder) else {
            return false;
        };
        let pos = self.players[idx].position;
        let pressure = self
            .players
            .iter()
            .filter(|p| p.team != holder_team)
            .map(|p| p.position.distance(pos))
            .fold(f64::INFINITY, f64::min);
        // Unpressured: bring it down with the chest (let normal control settle it).
        if pressure > AERIAL_HEADER_PRESSURE_RADIUS_YARDS {
            return false;
        }
        // Pressured: head it away / flick it on — toward the opponent's goal, biased
        // to the nearest teammate ahead. A defensive clear is powerful; an attacking
        // flick (in the opponent half) is softer to find a runner.
        let dir_sign = holder_team.attack_dir();
        let own_goal_y = holder_team.other().goal_y(self.config.field_length_yards);
        let own_half = (pos.y - own_goal_y).abs() < self.config.field_length_yards * 0.5;
        let target_x = self
            .players
            .iter()
            .filter(|p| {
                p.team == holder_team
                    && p.id != holder
                    && (p.position.y - pos.y) * dir_sign > AERIAL_HEADER_TEAMMATE_AHEAD_YARDS
            })
            .min_by(|a, b| {
                a.position
                    .distance(pos)
                    .total_cmp(&b.position.distance(pos))
            })
            .map(|p| p.position.x)
            .unwrap_or(self.config.field_width_yards * 0.5);
        let mut dir = Vec2::new((target_x - pos.x) * 0.45, dir_sign * 14.0);
        if dir.len() < 1e-6 {
            dir = Vec2::new(0.0, dir_sign);
        }
        let dir = dir.normalized();
        let speed = if own_half {
            AERIAL_HEADER_CLEAR_SPEED_YPS
        } else {
            AERIAL_HEADER_FLICK_SPEED_YPS
        };
        self.ball.holder = None;
        self.ball.velocity = dir * speed;
        self.ball.altitude_yards = AERIAL_HEADER_REDIRECT_ALTITUDE_YARDS;
        self.ball.last_touch_team = Some(holder_team);
        self.last_touch_player = Some(holder);
        self.restart_double_touch_guard = None;
        // A deliberate header/flick is a fresh play of the ball. Any offside
        // phase from the previous pass/long ball ends once this touch happens.
        self.pending_pass = None;
        self.ball.untargeted_long_ball_flight = None;
        self.ball.untargeted_long_ball_launcher = None;
        true
    }

    /// Watchdog against the "rat's nest" deadlock: if the ball sits in essentially
    /// the same spot for too long — a loose ball everyone circles, or a holder
    /// sitting on it — the nearest player decisively hoofs it clear of the cluster
    /// so play can never freeze. Tracks the ball position regardless of holder.
    pub(crate) fn update_stuck_ball_recovery(&mut self) {
        // A lone loose ball sitting/rolling in open space is NOT a livelock — it just
        // hasn't been collected yet (and there's no one to hoof it). The watchdog only
        // applies to a held ball or one with players around it (a genuine scrum), so a
        // ball decelerating untended in open space is never booted.
        let someone_on_it = self.ball.holder.is_some()
            || self
                .players
                .iter()
                .any(|p| p.position.distance(self.ball.position) <= STUCK_BALL_NEARBY_RADIUS_YARDS);
        if !someone_on_it {
            self.ball_stationary_ticks = 0;
            self.ball_stuck_anchor = self.ball.position;
            return;
        }
        let moved = self.ball.position.distance(self.ball_stuck_anchor);
        if moved > STUCK_BALL_MOVE_THRESHOLD_YARDS {
            self.ball_stationary_ticks = 0;
            self.ball_stuck_anchor = self.ball.position;
            return;
        }
        self.ball_stationary_ticks = self.ball_stationary_ticks.saturating_add(1);
        // Under congestion, resolve much faster so a rat's nest can't fester.
        let congestion = self
            .players
            .iter()
            .filter(|p| p.position.distance(self.ball.position) <= STUCK_BALL_CLUSTER_RADIUS_YARDS)
            .count();
        // A loose-ball "rat's nest" resolves fastest; a holder buried in a dogpile with no
        // outlet resolves on a medium clock (it may be waiting a beat for support, but a
        // shielded holder going nowhere in a crowd is still a livelock); everything else
        // keeps the normal grace so honest attacks aren't disrupted.
        let limit = if self.ball.holder.is_none() && congestion >= STUCK_BALL_CONGESTION_COUNT {
            STUCK_BALL_CONGESTED_TICKS_LIMIT
        } else if self.ball.holder.is_none() && congestion >= STUCK_BALL_CONTESTED_COUNT {
            STUCK_BALL_CONTESTED_TICKS_LIMIT
        } else if self.ball.holder.is_some() && congestion >= STUCK_BALL_HOLDER_CONGESTION_COUNT {
            STUCK_BALL_HOLDER_CONGESTED_TICKS_LIMIT
        } else {
            STUCK_BALL_TICKS_LIMIT
        };
        if self.ball_stationary_ticks < limit {
            return;
        }
        self.hoof_stuck_ball_clear();
        self.ball_stationary_ticks = 0;
        self.ball_stuck_anchor = self.ball.position;
    }

    /// Number of recent possession flips (inside LIVELOCK_WINDOW_TICKS) packed into
    /// the small zone around `position`. Drives both the escalating regain grace and
    /// the livelock detector.
    fn recent_zone_swap_count(&self, position: Vec2) -> usize {
        self.possession_swaps
            .iter()
            .filter(|swap| self.tick.saturating_sub(swap.tick) < LIVELOCK_WINDOW_TICKS)
            .filter(|swap| swap.position.distance(position) <= LIVELOCK_CLUSTER_RADIUS_YARDS)
            .count()
    }

    /// Ping-pong livelock breaker. If the ball has changed hands ≥
    /// LIVELOCK_SWAP_THRESHOLD times inside LIVELOCK_WINDOW_TICKS among only a
    /// handful of players (≤ LIVELOCK_MAX_DISTINCT_PLAYERS) confined to one small
    /// zone, the duel has become an unrealistic scrum. Break it the way a real match
    /// does: squirt the ball loose toward the nearest *uninvolved* player — the third
    /// man stepping in to sort it out — so a fresh body resolves possession.
    pub(crate) fn detect_and_break_possession_livelock(&mut self) {
        // Scan only the flips still inside the look-back window.
        let tick = self.tick;
        let recent: Vec<PossessionSwap> = self
            .possession_swaps
            .iter()
            .filter(|swap| tick.saturating_sub(swap.tick) < LIVELOCK_WINDOW_TICKS)
            .copied()
            .collect();
        if recent.len() < LIVELOCK_SWAP_THRESHOLD {
            return;
        }
        // Confined to a handful of bodies?
        let mut involved: Vec<usize> = Vec::new();
        for swap in &recent {
            for id in [swap.winner, swap.loser] {
                if !involved.contains(&id) {
                    involved.push(id);
                }
            }
        }
        if involved.len() > LIVELOCK_MAX_DISTINCT_PLAYERS {
            return;
        }
        // Confined to one small zone? Use the centroid of the flip positions and
        // require every flip to sit within the cluster radius of it.
        let mut centroid = Vec2::zero();
        for swap in &recent {
            centroid = centroid + swap.position;
        }
        centroid = centroid * (1.0 / recent.len() as f64);
        if recent
            .iter()
            .any(|swap| swap.position.distance(centroid) > LIVELOCK_CLUSTER_RADIUS_YARDS)
        {
            return;
        }
        // Livelock confirmed: bring in the third man. Find the nearest player NOT
        // tangled in the scrum and nudge the ball loose toward them.
        let ball = self.ball.position;
        let third_man = self
            .players
            .iter()
            .filter(|p| !involved.contains(&p.id))
            .map(|p| (p.id, p.position.distance(ball)))
            .filter(|(_, dist)| *dist <= LIVELOCK_THIRD_MAN_MAX_DISTANCE_YARDS)
            .min_by(|a, b| a.1.total_cmp(&b.1));
        let dir = if let Some((third_id, _)) = third_man {
            // Toward the incoming third man so they collect it.
            let target = self.players[third_id].position;
            let to_third = target - ball;
            if to_third.len() > 1e-6 {
                to_third.normalized()
            } else {
                self.livelock_escape_direction(&involved, centroid)
            }
        } else {
            // Nobody free nearby: just squirt it out of the cluster toward open play.
            self.livelock_escape_direction(&involved, centroid)
        };
        self.ball.holder = None;
        self.ball.velocity = dir * LIVELOCK_PERTURB_SPEED_YPS;
        self.ball.altitude_yards = LIVELOCK_PERTURB_ALTITUDE_YARDS;
        self.ball.curl_acceleration = Vec2::zero();
        // The ball is genuinely loose now: clear pending intents, the regain grace,
        // and the swap log so the breaker doesn't immediately re-fire.
        self.pending_pass = None;
        self.pending_shot = None;
        self.recent_dispossession = None;
        self.possession_swaps.clear();
        self.ball_stationary_ticks = 0;
        self.ball_stuck_anchor = self.ball.position;
        self.events.push(MatchEvent {
            tick: self.tick,
            clock_seconds: self.clock_seconds,
            kind: "livelock-break".to_string(),
            team: None,
            player_id: third_man.map(|(id, _)| id),
            description: "possession livelock broken: ball played loose to a third man".to_string(),
            ..MatchEvent::default()
        });
    }

    /// Fallback escape direction when no third man is in range: out of the scrum
    /// (away from the involved players' centroid) and biased toward the pitch centre
    /// so the loose ball stays in play.
    fn livelock_escape_direction(&self, involved: &[usize], cluster_centroid: Vec2) -> Vec2 {
        let ball = self.ball.position;
        let mut body_centroid = Vec2::zero();
        let mut count = 0.0;
        for &id in involved {
            if let Some(p) = self.players.get(id) {
                body_centroid = body_centroid + p.position;
                count += 1.0;
            }
        }
        let away = if count > 0.0 {
            ball - body_centroid * (1.0 / count)
        } else {
            ball - cluster_centroid
        };
        let centre = Vec2::new(
            self.config.field_width_yards * 0.5,
            self.config.field_length_yards * 0.5,
        );
        let mut dir = away.normalized() + (centre - ball).normalized() * 0.5;
        if dir.len() < 1e-6 {
            dir = centre - ball;
        }
        if dir.len() < 1e-6 {
            dir = Vec2::new(0.0, 1.0);
        }
        dir.normalized()
    }

    fn hoof_stuck_ball_clear(&mut self) {
        if self.players.is_empty() {
            return;
        }
        let ball = self.ball.position;
        // The player sitting on the ball boots it; otherwise the nearest player
        // attacks it. Either way, someone clears the congestion.
        let booter_idx = self
            .ball
            .holder
            .and_then(|id| self.players.iter().position(|p| p.id == id))
            .or_else(|| {
                (0..self.players.len()).min_by(|&a, &b| {
                    self.players[a]
                        .position
                        .distance(ball)
                        .total_cmp(&self.players[b].position.distance(ball))
                })
            });
        let Some(booter_idx) = booter_idx else {
            return;
        };
        let team = self.players[booter_idx].team;
        let booter_id = self.players[booter_idx].id;
        // Centroid of the congested cluster around the ball, to hoof away from it.
        let mut centroid = Vec2::new(0.0, 0.0);
        let mut count = 0.0;
        for p in &self.players {
            if p.position.distance(ball) <= STUCK_BALL_CLUSTER_RADIUS_YARDS {
                centroid = centroid + p.position;
                count += 1.0;
            }
        }
        let away = if count > 0.0 {
            ball - centroid * (1.0 / count)
        } else {
            Vec2::new(0.0, 0.0)
        };
        // Bias toward the open centre of the pitch so the clearance stays in play.
        let centre = Vec2::new(
            self.config.field_width_yards * 0.5,
            self.config.field_length_yards * 0.5,
        );
        let mut dir = (centre - ball).normalized() + away.normalized() * 0.6;
        if dir.len() < 1e-6 {
            dir = centre - ball;
        }
        if dir.len() < 1e-6 {
            dir = away;
        }
        if dir.len() < 1e-6 {
            dir = Vec2::new(0.0, 1.0); // last-resort fixed direction so the ball always moves
        }
        let dir = dir.normalized();
        self.ball.holder = None;
        // Physically displace the ball clear of the cluster, not just set its velocity:
        // a header/control duel re-redirects the ball's velocity every tick (two opposing
        // players head it opposite ways, pinning it), so a velocity-only hoof is instantly
        // undone. Jumping it beyond control reach means nobody can re-grab it this tick and
        // it actually escapes.
        self.ball.position = (ball + dir * STUCK_BALL_HOOF_CLEARANCE_YARDS).clamp_to_pitch(
            self.config.field_width_yards,
            self.config.field_length_yards,
        );
        self.ball.velocity = dir * STUCK_BALL_HOOF_SPEED_YPS;
        self.ball.altitude_yards = STUCK_BALL_HOOF_ALTITUDE_YARDS;
        self.ball.last_touch_team = Some(team);
        self.last_touch_player = Some(booter_id);
        self.restart_double_touch_guard = None;
    }

    pub(crate) fn nearest_ball_controller(&mut self) -> Option<(usize, Team)> {
        nearest_ball_controller_for(
            self.tick,
            self.ball.position,
            self.ball.velocity,
            &self.players,
            self.pending_pass.as_ref(),
            self.ball
                .untargeted_long_ball_team(self.pending_pass.as_ref()),
            self.ball
                .untargeted_long_ball_launch_exclusion(self.tick, self.pending_pass.as_ref()),
            self.ball.altitude_yards,
            &mut self.rng,
        )
    }

    fn pending_offside_interference_for_segment(
        &self,
        previous_ball_position: Vec2,
        current_ball_position: Vec2,
        ignore_current_holder: bool,
    ) -> Option<PendingOffside> {
        self.pending_offside_interference_for_segment_until(
            previous_ball_position,
            current_ball_position,
            1.0,
            ignore_current_holder,
        )
    }

    fn pending_offside_interference_for_segment_until(
        &self,
        previous_ball_position: Vec2,
        current_ball_position: Vec2,
        max_projection: f64,
        ignore_current_holder: bool,
    ) -> Option<PendingOffside> {
        if self.ball.holder.is_some() && !ignore_current_holder {
            return None;
        }
        if !vec2_is_finite(previous_ball_position) || !vec2_is_finite(current_ball_position) {
            return None;
        }
        let max_projection = max_projection.clamp(0.0, 1.0);
        // Assess EVERY attacker who was in an offside position at the moment of the pass,
        // not just the intended target. The closest such player who comes within the
        // interference radius of the ball (along its travelled segment, or at its current
        // position) is the one penalised — they are the player becoming involved in play.
        let mut best: Option<(f64, PendingOffside)> = None;
        for offside in self.effective_offside_candidates() {
            let Some(target_position) = self
                .players
                .iter()
                .find(|player| player.id == offside.target)
                .map(|player| player.position)
            else {
                continue;
            };
            if !vec2_is_finite(target_position) {
                continue;
            }
            let target_projection = segment_projection_factor(
                previous_ball_position,
                current_ball_position,
                target_position,
            );
            let projection = previous_ball_position
                + (current_ball_position - previous_ball_position) * target_projection;
            let segment_distance = target_position.distance(projection);
            let near_segment = target_projection <= max_projection
                && segment_distance <= OFFSIDE_INTERFERENCE_RADIUS_YARDS;
            let current_distance = target_position.distance(current_ball_position);
            let near_current = max_projection >= 1.0 - 1e-9
                && current_distance <= OFFSIDE_INTERFERENCE_RADIUS_YARDS;
            if !near_segment && !near_current {
                continue;
            }
            let proximity = if near_segment {
                segment_distance
            } else {
                current_distance
            };
            if best.as_ref().is_none_or(|(d, _)| proximity < *d) {
                best = Some((proximity, offside));
            }
        }
        best.map(|(_, offside)| offside)
    }

    /// The set of offside candidates carried by the live pending pass, used for enforcement.
    /// Falls back to the single intended-target offside if no broader candidate list was
    /// recorded (e.g. a pass constructed directly in a test).
    fn effective_offside_candidates(&self) -> Vec<PendingOffside> {
        if let Some(pass) = self.pending_pass.as_ref() {
            if !pass.offside_candidates.is_empty() {
                return pass.offside_candidates.clone();
            }
            return pass.offside.clone().into_iter().collect();
        }
        // No pending pass, but an untargeted long ball (clearance / route-one / hoof) is
        // still a ball played by our team — a teammate offside when it was launched is
        // flagged if they receive it.
        if let Some(flight) = self.ball.untargeted_long_ball_flight.as_ref() {
            return flight.offside_candidates.clone();
        }
        Vec::new()
    }

    pub(crate) fn call_pending_offside_interference_before_control_if_needed(
        &mut self,
        previous_ball_position: Vec2,
        control_position: Vec2,
    ) -> bool {
        let Some(offside) = self.pending_offside_interference_for_segment_until(
            previous_ball_position,
            control_position,
            1.0 - 1e-6,
            true,
        ) else {
            return false;
        };
        self.pending_pass = None;
        self.call_offside(offside);
        true
    }

    fn call_pending_offside_interference_if_needed(
        &mut self,
        previous_ball_position: Vec2,
    ) -> bool {
        let Some(offside) = self.pending_offside_interference_for_segment(
            previous_ball_position,
            self.ball.position,
            false,
        ) else {
            return false;
        };
        self.pending_pass = None;
        self.call_offside(offside);
        true
    }

    pub(crate) fn apply_ball_outcome(&mut self, outcome: BallStepOutcome) {
        match outcome {
            BallStepOutcome::None => {}
            BallStepOutcome::Controlled {
                holder,
                holder_team,
                possession_result,
                untargeted_long_ball,
            } => {
                let pending_pass_for_reward = self.pending_pass.clone();
                self.pending_rebound = None;
                let incoming_context = self.pending_pass.as_ref().map(|pass| {
                    incoming_context_from_pass(pass, holder, self.ball.velocity.len(), self.tick)
                });
                // Capture the offside candidates BEFORE the untargeted-long-ball flight is
                // cleared below (for an untargeted ball the candidates live on the flight,
                // so reading them after the clear would always come back empty).
                let offside_candidates_at_control = self.effective_offside_candidates();
                self.ball.holder = Some(holder);
                self.ball.altitude_yards = 0.0;
                self.ball.untargeted_long_ball_flight = None;
                self.ball.untargeted_long_ball_launcher = None;
                self.ball.last_touch_team = Some(holder_team);
                // Any attacker who was offside at the moment the ball was played and is now
                // the one controlling it is interfering with play — flag them, not only a
                // targeted pass's intended receiver.
                if let Some(offside) = offside_candidates_at_control
                    .into_iter()
                    .find(|offside| offside.target == holder && offside.team == holder_team)
                {
                    self.pending_pass = None;
                    self.call_offside(offside);
                    return;
                }
                // Law 16: if a goal kick is still pending and the ball is being controlled
                // while still inside the box, it never left the area on the first touch —
                // retake the goal kick rather than allowing the illegal short reception.
                let control_position = self
                    .players
                    .iter()
                    .find(|player| player.id == holder)
                    .map(|player| player.position)
                    .unwrap_or(self.ball.position);
                if self.enforce_goal_kick_clearance_on_control(control_position) {
                    return;
                }
                self.mark_ball_received(holder);
                self.record_possession_touch(holder);
                self.record_duel_rewards(holder);
                if let Some(player) = self.players.iter_mut().find(|player| player.id == holder) {
                    player.incoming_ball = incoming_context;
                }
                match possession_result {
                    BallPossessionResult::PassCompleted(team) => {
                        if let Some(pass) = pending_pass_for_reward.as_ref() {
                            self.record_completed_pass_reward(pass, holder);
                            let reception_y = self
                                .players
                                .iter()
                                .find(|player| player.id == holder)
                                .map(|player| player.position.y)
                                .unwrap_or(self.ball.position.y);
                            let forward_yards = (reception_y - pass.origin.y) * team.attack_dir();
                            self.stat_pass_completed_direction(team, forward_yards);
                            let own_half = self.pass_from_own_half(pass.team, pass.origin);
                            self.stat_pass_completed_half(own_half);
                            self.record_pass_outcome_sample(pass, true, own_half);
                        }
                        self.pending_pass = None;
                        self.stat_pass_completed(team);
                    }
                    BallPossessionResult::Interception(team) => {
                        if let Some(pass) = pending_pass_for_reward.as_ref() {
                            // Key on the PASSING team's origin half (where it was played from),
                            // not the intercepting team, so the by-half rate matches attempts.
                            let own_half = self.pass_from_own_half(pass.team, pass.origin);
                            self.stat_pass_intercepted_half(own_half);
                            self.record_pass_outcome_sample(pass, false, own_half);
                        }
                        self.record_interception_reward(holder, pending_pass_for_reward.as_ref());
                        self.pending_pass = None;
                        self.stat_interception(team);
                    }
                    BallPossessionResult::LooseBallRecovery(team) => {
                        // A targeted pass that went loose reached nobody — penalise the
                        // passer (an untargeted long ball / clearance is judged by its
                        // own outcome, not here).
                        if untargeted_long_ball.is_none() {
                            if let Some(pass) = pending_pass_for_reward.as_ref() {
                                let opponent_recovered = holder_team != pass.team;
                                let penalty = pass_to_nobody_passer_penalty(
                                    pass,
                                    self.config.field_length_yards,
                                    opponent_recovered,
                                );
                                self.record_reward_event(pass.from, -penalty);
                            }
                        }
                        self.record_untargeted_long_ball_outcome(
                            untargeted_long_ball,
                            holder,
                            holder_team,
                        );
                        self.stat_loose_ball_recovery(team);
                    }
                }
            }
            BallStepOutcome::Save {
                shot,
                defending_team,
                keeper_id,
                save_position,
            } => {
                self.pending_shot = None;
                self.pending_rebound = None;
                self.ball.altitude_yards = 0.0;
                self.ball.untargeted_long_ball_flight = None;
                self.ball.untargeted_long_ball_launcher = None;
                self.stat_shot_on_target(shot.team);
                self.record_shot_on_target_rewards(shot.team, shot.shooter);
                self.record_goalkeeper_save_reward(&shot, keeper_id);
                self.stat_save(defending_team);
                // A secured save (the keeper holds/claims it) is the most valuable stop.
                self.record_keeper_save_reward(keeper_id, shot.origin, defending_team, 1.0);
                self.mark_ball_received(keeper_id);
                let bounded_save_position = soccer_bounded_keeper_save_position(
                    &self.players,
                    keeper_id,
                    save_position,
                    self.config.dt_seconds,
                );
                if let Some(keeper) = self
                    .players
                    .iter_mut()
                    .find(|player| player.id == keeper_id)
                {
                    // Move to the save point only within the keeper's run+dive reach — never
                    // teleport it across to the ball.
                    keeper.position = bounded_save_position;
                    keeper.velocity = Vec2::zero();
                    keeper.acceleration = Vec2::zero();
                    keeper.jerk = Vec2::zero();
                    keeper.movement_gait = MovementGait::Stand;
                }
                let keeper_name = self
                    .players
                    .iter()
                    .find(|player| player.id == keeper_id)
                    .map(|player| player.name.as_str())
                    .unwrap_or("Keeper");
                let shooter_name = self
                    .players
                    .iter()
                    .find(|player| player.id == shot.shooter)
                    .map(|player| player.name.as_str())
                    .unwrap_or("shooter");
                self.events.push(MatchEvent {
                    tick: self.tick,
                    clock_seconds: self.clock_seconds,
                    kind: "save".to_string(),
                    team: Some(defending_team),
                    player_id: Some(keeper_id),
                    description: format!("{keeper_name} saved a shot by {shooter_name}"),
                    ..MatchEvent::default()
                });
            }
            BallStepOutcome::KeeperParry {
                shot,
                defending_team,
                keeper_id,
                save_position,
                parry_position,
                velocity,
            } => {
                self.pending_shot = None;
                self.pending_rebound = Some(PendingRebound {
                    attacking_team: shot.team,
                    shooter: shot.shooter,
                    keeper_id,
                    launch_tick: self.tick,
                    parry_position,
                });
                self.ball.holder = None;
                self.ball.position = parry_position;
                self.ball.velocity = velocity;
                self.ball.altitude_yards = 0.0;
                self.ball.untargeted_long_ball_flight = None;
                self.ball.untargeted_long_ball_launcher = None;
                self.ball.last_touch_team = Some(defending_team);
                self.stat_shot_on_target(shot.team);
                self.record_shot_on_target_rewards(shot.team, shot.shooter);
                self.stat_save(defending_team);
                // A parry denied the goal but conceded a live rebound — a less secure stop than
                // a clean catch, so it earns a fraction of the full save reward.
                self.record_keeper_save_reward(keeper_id, shot.origin, defending_team, 0.55);
                let bounded_save_position = soccer_bounded_keeper_save_position(
                    &self.players,
                    keeper_id,
                    save_position,
                    self.config.dt_seconds,
                );
                if let Some(keeper) = self
                    .players
                    .iter_mut()
                    .find(|player| player.id == keeper_id)
                {
                    // Move to the save point only within the keeper's run+dive reach — never
                    // teleport it across to the ball.
                    keeper.position = bounded_save_position;
                    keeper.velocity = Vec2::zero();
                    keeper.acceleration = Vec2::zero();
                    keeper.jerk = Vec2::zero();
                    keeper.movement_gait = MovementGait::Stand;
                }
                let keeper_name = self
                    .players
                    .iter()
                    .find(|player| player.id == keeper_id)
                    .map(|player| player.name.as_str())
                    .unwrap_or("Keeper");
                let shooter_name = self
                    .players
                    .iter()
                    .find(|player| player.id == shot.shooter)
                    .map(|player| player.name.as_str())
                    .unwrap_or("shooter");
                self.events.push(MatchEvent {
                    tick: self.tick,
                    clock_seconds: self.clock_seconds,
                    kind: "keeper-parry".to_string(),
                    team: Some(defending_team),
                    player_id: Some(keeper_id),
                    description: format!("{keeper_name} parried a shot by {shooter_name}"),
                    ..MatchEvent::default()
                });
            }
            BallStepOutcome::Goal { scoring_team, shot } => {
                self.pending_rebound = None;
                if let Some(shot) = shot.as_ref() {
                    self.record_shot_on_target_rewards(shot.team, shot.shooter);
                }
                self.record_goal_rewards(scoring_team, shot.as_ref().map(|shot| shot.shooter));
                self.ball.altitude_yards = 0.0;
                self.ball.untargeted_long_ball_flight = None;
                self.ball.untargeted_long_ball_launcher = None;
                if let Some(shot) = shot {
                    self.pending_shot = None;
                    self.stat_shot_on_target(shot.team);
                }
                self.score_goal(scoring_team);
            }
            BallStepOutcome::Miss { shot } => {
                self.record_shot_off_target_rewards(shot.team, shot.shooter);
                self.pending_shot = None;
                self.pending_rebound = None;
                self.ball.altitude_yards = 0.0;
                self.ball.untargeted_long_ball_flight = None;
                self.ball.untargeted_long_ball_launcher = None;
                let shooter_name = self
                    .players
                    .iter()
                    .find(|player| player.id == shot.shooter)
                    .map(|player| player.name.as_str())
                    .unwrap_or("Player");
                self.events.push(MatchEvent {
                    tick: self.tick,
                    clock_seconds: self.clock_seconds,
                    kind: "miss".to_string(),
                    team: Some(shot.team),
                    player_id: Some(shot.shooter),
                    description: format!("{shooter_name} missed"),
                    ..MatchEvent::default()
                });
            }
            BallStepOutcome::ShotBlocked {
                shot,
                blocker_id,
                defending_team,
                position,
                velocity,
                deflection_kind,
                keep_shot_active,
            } => {
                self.pending_pass = None;
                self.pending_rebound = None;
                self.pending_shot = if keep_shot_active {
                    Some(shot.clone())
                } else {
                    None
                };
                self.ball.position = position;
                self.ball.velocity = velocity;
                self.ball.holder = None;
                self.ball.altitude_yards = 0.0;
                self.ball.untargeted_long_ball_flight = None;
                self.ball.untargeted_long_ball_launcher = None;
                self.ball.last_touch_team = Some(defending_team);
                self.mark_ball_received(blocker_id);
                self.stat_shot_block(defending_team);
                self.record_reward_event(blocker_id, SHOT_BLOCK_DEFENDER_REWARD_POINTS);
                self.record_reward_event(shot.shooter, -BLOCKED_SHOT_SHOOTER_PENALTY_POINTS);
                let shooter_name = self
                    .players
                    .iter()
                    .find(|player| player.id == shot.shooter)
                    .map(|player| player.name.as_str())
                    .unwrap_or("Player");
                let blocker_name = self
                    .players
                    .iter()
                    .find(|player| player.id == blocker_id)
                    .map(|player| player.name.as_str())
                    .unwrap_or("Defender");
                let detail = match deflection_kind {
                    ShotDeflectionKind::Wide => "and deflected wide",
                    ShotDeflectionKind::GoalBound => "off the goal-bound line",
                    ShotDeflectionKind::Rebound => "back into play",
                };
                self.events.push(MatchEvent {
                    tick: self.tick,
                    clock_seconds: self.clock_seconds,
                    kind: "shot-blocked".to_string(),
                    team: Some(defending_team),
                    player_id: Some(blocker_id),
                    description: format!("{blocker_name} blocked {shooter_name}'s shot {detail}"),
                    ..MatchEvent::default()
                });
            }
            BallStepOutcome::OutOfPlay {
                restart,
                shot,
                shot_off_target_yards,
            } => {
                // A pass still pending when the ball leaves play sailed out untouched — the
                // unforced aerial-OOB error. Capture it BEFORE clearing so the passer can be
                // credited (see `record_aerial_pass_out_of_bounds_penalty`, which supersedes the
                // old inline long-aerial-bounds penalty and coordinates with the restart turnover).
                let oob_pass = self.pending_pass.take();
                let was_shot = shot.is_some();
                // Learning capture (kept from the inline path): a pass conceded out of play is a
                // failed pass — feed the pass-completion corpus before the deferred penalty acts.
                if let Some(pass) = oob_pass.as_ref() {
                    if restart.awarded_team != pass.team {
                        let own_half = self.pass_from_own_half(pass.team, pass.origin);
                        self.record_pass_outcome_sample(pass, false, own_half);
                    }
                }
                self.pending_shot = None;
                self.pending_rebound = None;
                self.ball.altitude_yards = 0.0;
                self.ball.untargeted_long_ball_flight = None;
                self.ball.untargeted_long_ball_launcher = None;
                if let Some(shot) = shot {
                    self.record_shot_off_target_penalty(
                        shot.team,
                        shot.shooter,
                        shot_off_target_yards,
                    );
                    self.record_miss_event(shot);
                }
                let restart_kind = restart.kind;
                let restart_awarded = restart.awarded_team;
                let restart_position = restart.position;
                // Apply the aerial-OOB penalty FIRST so it can claim the event; the generic
                // turnover penalty inside `apply_restart` then defers via the guard flag.
                if !was_shot {
                    self.suppress_generic_oob_turnover = self
                        .record_aerial_pass_out_of_bounds_penalty(
                            oob_pass.as_ref(),
                            restart_kind,
                            restart_awarded,
                            restart_position,
                        );
                }
                self.apply_restart(restart);
                self.suppress_generic_oob_turnover = false;
            }
        }
    }

    fn record_miss_event(&mut self, shot: PendingShot) {
        let shooter_name = self
            .players
            .iter()
            .find(|player| player.id == shot.shooter)
            .map(|player| player.name.as_str())
            .unwrap_or("Player");
        self.events.push(MatchEvent {
            tick: self.tick,
            clock_seconds: self.clock_seconds,
            kind: "miss".to_string(),
            team: Some(shot.team),
            player_id: Some(shot.shooter),
            description: format!("{shooter_name} missed"),
            ..MatchEvent::default()
        });
    }

    pub(crate) fn apply_restart(&mut self, restart: BallRestart) {
        self.apply_restart_with_label(
            restart.kind,
            restart.awarded_team,
            restart.position,
            restart_kind_action(restart.kind),
        );
    }

    fn apply_restart_with_label(
        &mut self,
        restart_kind: BallRestartKind,
        awarded_team: Team,
        position: Vec2,
        restart_label: &str,
    ) {
        let (field_width, field_length) = sane_pitch_dimensions(
            self.config.field_width_yards,
            self.config.field_length_yards,
        );
        let fallback = Vec2::new(field_width * 0.5, field_length * 0.5);
        let restart = BallRestart {
            kind: restart_kind,
            awarded_team,
            position: finite_pitch_point(position, field_width, field_length, fallback),
        };
        self.pending_pass = None;
        self.pending_shot = None;
        self.pending_rebound = None;
        self.stat_restart(restart.kind, restart.awarded_team);
        self.record_out_of_bounds_turnover_penalty(restart.kind, restart.awarded_team);
        // The ball is dead: the next controlled touch (kickoff, throw-in, goal
        // kick taker) must not be mistaken for an open-play turnover.
        self.last_controlled_possession_team = None;
        // A goal kick is taken by the keeper. Otherwise the nearest outfielder is
        // picked as taker and the keeper is left stranded on its goal-line (it never
        // gets repositioned to the ball), which looks broken.
        let restart_holder = if matches!(restart.kind, BallRestartKind::GoalKick) {
            self.goalkeeper_for(restart.awarded_team)
                .or_else(|| self.nearest_player_on_team(restart.awarded_team, restart.position))
        } else {
            self.nearest_player_on_team(restart.awarded_team, restart.position)
        };
        if let Some(holder_id) = restart_holder {
            if let Some(holder) = self.players.iter_mut().find(|p| p.id == holder_id) {
                holder.position = restart.position;
                holder.velocity = Vec2::zero();
                holder.acceleration = Vec2::zero();
                holder.jerk = Vec2::zero();
                holder.movement_gait = MovementGait::Stand;
                holder.record_position_history();
            }
        }

        self.arrange_restart_shape(
            restart.kind,
            restart.awarded_team,
            restart.position,
            restart_holder,
        );
        self.activate_set_play_for_restart(
            restart_label,
            Some(restart.kind),
            restart.awarded_team,
            restart.position,
            restart_holder,
        );

        match restart.kind {
            BallRestartKind::FreeKick => {
                if let Some(center_ref) = self
                    .officials
                    .iter_mut()
                    .find(|official| official.kind == OfficialKind::CenterReferee)
                {
                    center_ref.position = restart.position;
                    center_ref.velocity = Vec2::zero();
                    center_ref.acceleration = Vec2::zero();
                    center_ref.jerk = Vec2::zero();
                    center_ref.record_position_history();
                }
            }
            _ => {
                if let Some(assistant) = self.officials.iter_mut().find(|official| {
                    matches!(
                        official.kind,
                        OfficialKind::AssistantRefereeNear | OfficialKind::AssistantRefereeFar
                    )
                }) {
                    assistant.position = official_position_bounds(
                        assistant.kind,
                        Vec2::new(assistant.position.x, restart.position.y),
                        field_width,
                        field_length,
                    );
                    assistant.velocity = Vec2::zero();
                    assistant.acceleration = Vec2::zero();
                    assistant.jerk = Vec2::zero();
                    assistant.record_position_history();
                }
            }
        }

        self.ball.position = restart.position;
        self.ball.velocity = Vec2::zero();
        self.ball.acceleration = Vec2::zero();
        self.ball.jerk = Vec2::zero();
        self.ball.curl_acceleration = Vec2::zero();
        self.ball.altitude_yards = 0.0;
        self.ball.holder = restart_holder;
        self.ball.last_touch_team = Some(restart.awarded_team);
        self.finish_possession_progress_chain(false);
        if let Some(holder_id) = restart_holder {
            self.mark_ball_received(holder_id);
            self.record_possession_touch(holder_id);
            // The restart taker may not touch the ball twice in a row.
            self.restart_double_touch_guard = Some(holder_id);
        }
        // Law 16: a goal kick must leave the penalty area before a teammate touches it.
        // Arm the outcome guard (cleared the moment the ball exits the box; otherwise a
        // teammate's in-box touch forces a retake).
        self.goal_kick_must_clear_box = if matches!(restart.kind, BallRestartKind::GoalKick) {
            Some((restart.awarded_team, restart.position))
        } else {
            None
        };
        self.ball
            .record_decision(self.tick, restart_kind_action(restart.kind), None);
        self.shared_positions.sync_from_players_and_ball(
            &self.players,
            &self.officials,
            &self.ball,
            self.tick,
            self.clock_seconds,
        );

        let taker = restart_holder
            .and_then(|id| self.players.iter().find(|player| player.id == id))
            .map(|player| player.name.as_str())
            .unwrap_or("Restart");
        self.events.push(MatchEvent {
            tick: self.tick,
            clock_seconds: self.clock_seconds,
            kind: restart_kind_action(restart.kind).to_string(),
            team: Some(restart.awarded_team),
            player_id: restart_holder,
            description: format!(
                "{} {} for {}",
                taker,
                restart_kind_label(restart.kind),
                restart.awarded_team.label()
            ),
            ..MatchEvent::default()
        });
    }

    fn restart_team_ids(
        &self,
        team: Team,
        include_goalkeeper: bool,
        exclude: Option<usize>,
    ) -> Vec<usize> {
        let mut ids = self
            .players
            .iter()
            .filter(|player| player.team == team)
            .filter(|player| include_goalkeeper || player.role != PlayerRole::Goalkeeper)
            .filter(|player| exclude != Some(player.id))
            .map(|player| {
                let role_rank = match player.role {
                    PlayerRole::Forward => 0,
                    PlayerRole::Midfielder => 1,
                    PlayerRole::Defender => 2,
                    PlayerRole::Goalkeeper => 3,
                };
                (player.id, role_rank, player.home_position.x)
            })
            .collect::<Vec<_>>();
        ids.sort_by(|a, b| {
            a.1.cmp(&b.1)
                .then_with(|| a.2.partial_cmp(&b.2).unwrap_or(std::cmp::Ordering::Equal))
        });
        ids.into_iter().map(|(id, _, _)| id).collect()
    }

    fn set_dead_ball_player_position(&mut self, player_id: usize, position: Vec2) {
        let (width, length) = sane_pitch_dimensions(
            self.config.field_width_yards,
            self.config.field_length_yards,
        );
        if let Some(player) = self.players.iter_mut().find(|p| p.id == player_id) {
            player.position = finite_pitch_point(position, width, length, player.home_position);
            player.velocity = Vec2::zero();
            player.acceleration = Vec2::zero();
            player.jerk = Vec2::zero();
            player.movement_gait = MovementGait::Stand;
            player.record_position_history();
        }
    }

    /// Place a set of dead-ball participants into a set of slots with LANE AFFINITY:
    /// the caller picks *which* players take part (role ordering) and supplies the
    /// slots; here the i-th participant by home-x is matched to the i-th slot by x, so
    /// left-home players (e.g. the left wing-back) always take left-side slots and
    /// right-home players take right-side slots. Without this, the role-sorted player
    /// list was zipped against an x-unsorted slot array and wing-backs could be planted
    /// on the wrong side — appearing to "switch sides" on corners / goal kicks.
    pub(crate) fn assign_dead_ball_slots_lane_stable(
        &mut self,
        player_ids: &[usize],
        slots: &[Vec2],
    ) {
        let n = player_ids.len().min(slots.len());
        if n == 0 {
            return;
        }
        let mut players: Vec<(usize, f64)> = player_ids[..n]
            .iter()
            .map(|&id| {
                let home_x = self
                    .players
                    .iter()
                    .find(|p| p.id == id)
                    .map(|p| p.home_position.x)
                    .unwrap_or(0.0);
                (id, home_x)
            })
            .collect();
        players.sort_by(|a, b| a.1.partial_cmp(&b.1).unwrap_or(std::cmp::Ordering::Equal));
        let mut ordered_slots: Vec<Vec2> = slots[..n].to_vec();
        ordered_slots.sort_by(|a, b| a.x.partial_cmp(&b.x).unwrap_or(std::cmp::Ordering::Equal));
        for ((id, _), slot) in players.into_iter().zip(ordered_slots) {
            self.set_dead_ball_player_position(id, slot);
        }
    }

    fn set_play_role_ids(
        &self,
        team: Team,
        role: PlayerRole,
        exclude: Option<usize>,
    ) -> Vec<usize> {
        let mut ids = self
            .players
            .iter()
            .filter(|player| {
                player.team == team && player.role == role && exclude != Some(player.id)
            })
            .map(|player| (player.id, player.home_position.x))
            .collect::<Vec<_>>();
        ids.sort_by(|a, b| a.1.partial_cmp(&b.1).unwrap_or(std::cmp::Ordering::Equal));
        ids.into_iter().map(|(id, _)| id).collect()
    }

    fn matching_set_play_hint(
        &self,
        team: Team,
        restart_label: &str,
    ) -> Option<SoccerSetPlayVectorHint> {
        self.coach_set_play_hints
            .get(&team)
            .filter(|hint| {
                hint.score.is_finite()
                    && set_play_restart_labels_match(&hint.restart, restart_label)
            })
            .cloned()
    }

    fn select_set_play_routine(
        &self,
        restart_label: &str,
        kind: Option<BallRestartKind>,
        team: Team,
        spot: Vec2,
        hint: Option<&SoccerSetPlayVectorHint>,
    ) -> SoccerSetPlayRoutineKind {
        if let Some(hint) = hint {
            if set_play_restart_labels_match(&hint.restart, restart_label) {
                return match (restart_label, hint.routine) {
                    ("indirect-free-kick", SoccerSetPlayRoutineKind::FreeKickDirectShot) => {
                        SoccerSetPlayRoutineKind::FreeKickFarPostCross
                    }
                    _ => hint.routine,
                };
            }
        }

        match kind {
            None => SoccerSetPlayRoutineKind::KickoffPattern,
            Some(BallRestartKind::ThrowIn) => SoccerSetPlayRoutineKind::ThrowInTriangle,
            Some(BallRestartKind::GoalKick) => SoccerSetPlayRoutineKind::GoalKickBuildOut,
            Some(BallRestartKind::CornerKick) => SoccerSetPlayRoutineKind::CornerFarPost,
            Some(BallRestartKind::FreeKick) => {
                let (width, length) = sane_pitch_dimensions(
                    self.config.field_width_yards,
                    self.config.field_length_yards,
                );
                let goal = Vec2::new(width * 0.5, team.goal_y(length));
                if restart_label != "indirect-free-kick" && spot.distance(goal) <= 32.0 {
                    SoccerSetPlayRoutineKind::FreeKickDirectShot
                } else {
                    SoccerSetPlayRoutineKind::FreeKickFarPostCross
                }
            }
        }
    }

    fn activate_set_play_for_restart(
        &mut self,
        restart_label: &str,
        kind: Option<BallRestartKind>,
        team: Team,
        spot: Vec2,
        taker: Option<usize>,
    ) {
        let hint = self.matching_set_play_hint(team, restart_label);
        let routine = self.select_set_play_routine(restart_label, kind, team, spot, hint.as_ref());
        let call =
            self.build_set_play_call(restart_label, routine, team, spot, taker, hint.clone());
        self.apply_set_play_starting_positions(&call, spot);
        self.active_set_play = Some(call.clone());
        self.events.push(MatchEvent {
            tick: self.tick,
            clock_seconds: self.clock_seconds,
            kind: "set-play".to_string(),
            team: Some(team),
            player_id: taker,
            description: format!(
                "{} set play: {} from {}",
                team.label(),
                call.routine.as_label(),
                call.restart
            ),
            ..MatchEvent::default()
        });
    }

    fn apply_set_play_starting_positions(&mut self, call: &SoccerSetPlayCall, spot: Vec2) {
        if !matches!(
            call.routine,
            SoccerSetPlayRoutineKind::FreeKickFarPostCross
                | SoccerSetPlayRoutineKind::FreeKickDirectShot
                | SoccerSetPlayRoutineKind::CornerFarPost
        ) {
            return;
        }

        let (width, length) = sane_pitch_dimensions(
            self.config.field_width_yards,
            self.config.field_length_yards,
        );
        let dir = call.team.attack_dir();
        let goal = Vec2::new(width * 0.5, call.team.goal_y(length));
        let to_goal = (goal - spot).normalized();
        let lateral = Vec2::new(-to_goal.y, to_goal.x).normalized();
        for assignment in call.assignments.iter() {
            if assignment.role == SoccerSetPlayAssignmentRole::Taker {
                self.set_dead_ball_player_position(assignment.player_id, spot);
                continue;
            }
            if self
                .players
                .iter()
                .find(|player| player.id == assignment.player_id)
                .map(|player| player.team)
                != Some(call.team)
            {
                continue;
            }

            let side = if assignment.target.x >= width * 0.5 {
                1.0
            } else {
                -1.0
            };
            let start = match assignment.role {
                SoccerSetPlayAssignmentRole::PrimaryRunner => {
                    assignment.target - Vec2::new(0.0, dir * 13.0) + lateral * side * 2.8
                }
                SoccerSetPlayAssignmentRole::SecondaryRunner => {
                    assignment.target - Vec2::new(0.0, dir * 10.5) - lateral * side * 2.2
                }
                SoccerSetPlayAssignmentRole::Screen => assignment.target - to_goal * 5.0,
                SoccerSetPlayAssignmentRole::Outlet => {
                    assignment.target - Vec2::new(0.0, dir * 7.0)
                }
                SoccerSetPlayAssignmentRole::Safety
                | SoccerSetPlayAssignmentRole::Wall
                | SoccerSetPlayAssignmentRole::Marker
                | SoccerSetPlayAssignmentRole::Taker => assignment.target,
            }
            .clamp_to_pitch(width, length);
            self.set_dead_ball_player_position(assignment.player_id, start);
        }
    }

    fn build_set_play_call(
        &self,
        restart_label: &str,
        routine: SoccerSetPlayRoutineKind,
        team: Team,
        spot: Vec2,
        taker: Option<usize>,
        vector_hint: Option<SoccerSetPlayVectorHint>,
    ) -> SoccerSetPlayCall {
        let (width, length) = sane_pitch_dimensions(
            self.config.field_width_yards,
            self.config.field_length_yards,
        );
        let dir = team.attack_dir();
        let goal_y = team.goal_y(length);
        let own_goal_y = team.other().goal_y(length);
        let goal = Vec2::new(width * 0.5, goal_y);
        let side_sign = if spot.x <= width * 0.5 { 1.0 } else { -1.0 };
        let mut assignments = Vec::new();
        let mut add_assignment = |player_id: Option<usize>,
                                  role: SoccerSetPlayAssignmentRole,
                                  target: Vec2,
                                  release_after_seconds: f64| {
            if let Some(player_id) = player_id {
                let release_after_seconds = if release_after_seconds.is_finite() {
                    release_after_seconds.clamp(0.0, SOCCER_SET_PLAY_MAX_RELEASE_DELAY_SECONDS)
                } else {
                    0.0
                };
                assignments.push(SoccerSetPlayAssignment {
                    player_id,
                    role,
                    target: finite_pitch_point(target, width, length, spot),
                    release_after_seconds,
                });
            }
        };

        add_assignment(taker, SoccerSetPlayAssignmentRole::Taker, spot, 0.0);

        let teammates = self.restart_team_ids(team, false, taker);
        let forwards = self.set_play_role_ids(team, PlayerRole::Forward, taker);
        let midfielders = self.set_play_role_ids(team, PlayerRole::Midfielder, taker);
        let defenders = self.set_play_role_ids(team, PlayerRole::Defender, taker);
        let opponents = self.restart_team_ids(team.other(), false, None);

        let primary_attacker = forwards
            .first()
            .copied()
            .or_else(|| midfielders.first().copied())
            .or_else(|| teammates.first().copied());
        let secondary_attacker = forwards
            .get(1)
            .copied()
            .or_else(|| midfielders.get(1).copied())
            .or_else(|| teammates.get(1).copied());
        let outlet = midfielders
            .first()
            .copied()
            .or_else(|| defenders.first().copied())
            .or_else(|| teammates.first().copied());
        let safety = defenders
            .last()
            .copied()
            .or_else(|| midfielders.last().copied())
            .or_else(|| teammates.last().copied());

        let (release_kind, release_player, release_power) = match routine {
            SoccerSetPlayRoutineKind::KickoffPattern => {
                let support = midfielders
                    .first()
                    .copied()
                    .or_else(|| teammates.first().copied());
                add_assignment(
                    support,
                    SoccerSetPlayAssignmentRole::Outlet,
                    Vec2::new(width * 0.5 + side_sign * 7.0, length * 0.5 - dir * 2.5),
                    0.1,
                );
                add_assignment(
                    primary_attacker,
                    SoccerSetPlayAssignmentRole::PrimaryRunner,
                    Vec2::new(width * 0.50, length * 0.5 + dir * 18.0),
                    0.5,
                );
                (SoccerSetPlayReleaseKind::Pass, support, 0.54)
            }
            SoccerSetPlayRoutineKind::ThrowInTriangle => {
                let inside_x = (spot.x + side_sign * 8.0).clamp(4.0, width - 4.0);
                add_assignment(
                    primary_attacker,
                    SoccerSetPlayAssignmentRole::PrimaryRunner,
                    Vec2::new(inside_x, spot.y + dir * 7.0),
                    0.25,
                );
                add_assignment(
                    secondary_attacker,
                    SoccerSetPlayAssignmentRole::SecondaryRunner,
                    Vec2::new(inside_x + side_sign * 8.0, spot.y - dir * 5.0),
                    0.35,
                );
                add_assignment(
                    outlet,
                    SoccerSetPlayAssignmentRole::Outlet,
                    Vec2::new(width * 0.5, spot.y + dir * 13.0),
                    0.4,
                );
                (
                    SoccerSetPlayReleaseKind::AerialPass,
                    primary_attacker.or(outlet),
                    0.60,
                )
            }
            SoccerSetPlayRoutineKind::GoalKickBuildOut => {
                let left_back = defenders.first().copied().or(outlet);
                let right_back = defenders.last().copied().or(outlet);
                // Backs receive OUTSIDE the 18-yard line so the goal kick leaves the box (Law 16).
                add_assignment(
                    left_back,
                    SoccerSetPlayAssignmentRole::Outlet,
                    Vec2::new(width * 0.22, own_goal_y + dir * 20.0),
                    0.0,
                );
                add_assignment(
                    right_back,
                    SoccerSetPlayAssignmentRole::Outlet,
                    Vec2::new(width * 0.78, own_goal_y + dir * 20.0),
                    0.0,
                );
                add_assignment(
                    outlet,
                    SoccerSetPlayAssignmentRole::PrimaryRunner,
                    Vec2::new(width * 0.50, own_goal_y + dir * 30.0),
                    0.0,
                );
                (
                    SoccerSetPlayReleaseKind::Pass,
                    left_back.or(right_back).or(outlet),
                    0.64,
                )
            }
            SoccerSetPlayRoutineKind::CornerFarPost => {
                let far_post_x = if spot.x <= width * 0.5 {
                    width * 0.62
                } else {
                    width * 0.38
                };
                add_assignment(
                    primary_attacker,
                    SoccerSetPlayAssignmentRole::PrimaryRunner,
                    Vec2::new(far_post_x, goal_y - dir * 4.5),
                    1.10,
                );
                add_assignment(
                    secondary_attacker,
                    SoccerSetPlayAssignmentRole::SecondaryRunner,
                    Vec2::new(width * 0.50, goal_y - dir * 8.0),
                    0.90,
                );
                add_assignment(
                    safety,
                    SoccerSetPlayAssignmentRole::Safety,
                    Vec2::new(width * 0.50, goal_y - dir * 28.0),
                    0.2,
                );
                (
                    SoccerSetPlayReleaseKind::AerialPass,
                    primary_attacker.or(secondary_attacker),
                    0.82,
                )
            }
            SoccerSetPlayRoutineKind::FreeKickDirectShot => {
                let to_goal = (goal - spot).normalized();
                let lateral = Vec2::new(-to_goal.y, to_goal.x).normalized();
                add_assignment(
                    primary_attacker,
                    SoccerSetPlayAssignmentRole::Screen,
                    spot + lateral * 4.5 + to_goal * 3.0,
                    0.55,
                );
                add_assignment(
                    secondary_attacker,
                    SoccerSetPlayAssignmentRole::PrimaryRunner,
                    Vec2::new(width * 0.50, goal_y - dir * 6.5),
                    1.00,
                );
                add_assignment(
                    safety,
                    SoccerSetPlayAssignmentRole::Safety,
                    spot - to_goal * 10.0,
                    0.1,
                );
                for (player_id, offset) in opponents
                    .iter()
                    .copied()
                    .take(4)
                    .zip([-3.0, -1.0, 1.0, 3.0])
                {
                    add_assignment(
                        Some(player_id),
                        SoccerSetPlayAssignmentRole::Wall,
                        spot + to_goal * 10.0 + lateral * offset,
                        0.0,
                    );
                }
                (SoccerSetPlayReleaseKind::Shoot, None, 0.88)
            }
            SoccerSetPlayRoutineKind::FreeKickFarPostCross => {
                let far_post_x = if spot.x <= width * 0.5 {
                    width * 0.62
                } else {
                    width * 0.38
                };
                add_assignment(
                    primary_attacker,
                    SoccerSetPlayAssignmentRole::PrimaryRunner,
                    Vec2::new(far_post_x, goal_y - dir * 4.5),
                    1.25,
                );
                add_assignment(
                    secondary_attacker,
                    SoccerSetPlayAssignmentRole::SecondaryRunner,
                    Vec2::new(width * 0.46, goal_y - dir * 8.0),
                    1.05,
                );
                add_assignment(
                    outlet,
                    SoccerSetPlayAssignmentRole::Screen,
                    spot + Vec2::new(side_sign * 5.0, -dir * 2.0),
                    0.45,
                );
                add_assignment(
                    safety,
                    SoccerSetPlayAssignmentRole::Safety,
                    Vec2::new(width * 0.50, spot.y - dir * 12.0),
                    0.1,
                );
                (
                    SoccerSetPlayReleaseKind::AerialPass,
                    primary_attacker.or(secondary_attacker),
                    0.78,
                )
            }
        };

        let dt = self.config.dt_seconds.max(1e-6);
        let duration_ticks = (SOCCER_SET_PLAY_WINDOW_SECONDS / dt).ceil() as u64;
        SoccerSetPlayCall {
            team,
            restart: restart_label.to_string(),
            routine,
            started_tick: self.tick,
            started_clock_seconds: self.clock_seconds,
            expires_tick: self.tick.saturating_add(duration_ticks),
            expires_clock_seconds: self.clock_seconds + SOCCER_SET_PLAY_WINDOW_SECONDS,
            assignments,
            release_kind,
            release_player,
            release_power,
            vector_hint,
        }
    }

    fn kickoff_own_half_position(&self, team: Team, mut position: Vec2) -> Vec2 {
        let half_line = self.config.field_length_yards * 0.5;
        match team {
            Team::Home => position.y = position.y.min(half_line - 1.0),
            Team::Away => position.y = position.y.max(half_line + 1.0),
        }
        position.clamp_to_pitch(
            self.config.field_width_yards,
            self.config.field_length_yards,
        )
    }

    fn arrange_kickoff_shape(&mut self, kickoff_team: Team, taker: Option<usize>, center: Vec2) {
        let half_line = self.config.field_length_yards * 0.5;
        let radius = KICKOFF_CENTER_CIRCLE_RADIUS_YARDS;
        let player_ids = self
            .players
            .iter()
            .map(|player| player.id)
            .collect::<Vec<_>>();
        for player_id in player_ids {
            if taker == Some(player_id) {
                continue;
            }
            let (team, home_position) =
                match self.players.iter().find(|player| player.id == player_id) {
                    Some(player) => (player.team, player.home_position),
                    None => continue,
                };
            let mut position = self.kickoff_own_half_position(team, home_position);
            // Stagger BOTH teams' shapes by stable roster/home-position identity (before
            // the centre-circle exclusion below, so own-half/outside-circle invariants hold)
            // instead of using a tick draw to perturb live set-piece positions.
            {
                let team_ordinal = player_id % SOCCER_MATCH_TEAM_PLAYER_COUNT;
                let lateral_phase = (team_ordinal as f64 % 5.0 - 2.0) / 2.0;
                let depth_phase = ((team_ordinal / 5) as f64 - 1.0).clamp(-1.0, 1.0);
                let field_width = self.config.field_width_yards;
                let home_side = ((home_position.x - field_width * 0.5)
                    / (field_width * 0.5).max(1.0))
                .clamp(-1.0, 1.0);
                let kickoff_side = if team == kickoff_team { -0.25 } else { 0.25 };
                let jx =
                    (lateral_phase * 0.65 + home_side * 0.35) * KICKOFF_DEFENSIVE_PERTURB_YARDS;
                let jy = (depth_phase * 0.55 + kickoff_side)
                    * KICKOFF_DEFENSIVE_PERTURB_YARDS
                    * team.attack_dir();
                position = self
                    .kickoff_own_half_position(team, Vec2::new(position.x + jx, position.y + jy));
            }
            if team != kickoff_team && position.distance(center) < radius + 0.5 {
                position.y = half_line - team.attack_dir() * (radius + 1.0);
            }
            self.set_dead_ball_player_position(player_id, position);
        }

        // Per-team back-four shape pass: (1) pull the line up so its average sits no
        // more than 30yd behind the ball (on the halfway line) — never start 35-45yd
        // deep; (2) separate any two defenders that ended up on top of each other.
        for team in [Team::Home, Team::Away] {
            let attack = team.attack_dir();
            let mut defenders: Vec<(usize, Vec2)> = self
                .players
                .iter()
                .filter(|p| p.team == team && p.role == PlayerRole::Defender && taker != Some(p.id))
                .map(|p| (p.id, p.position))
                .collect();
            if defenders.is_empty() {
                continue;
            }
            let avg_y = defenders.iter().map(|(_, p)| p.y).sum::<f64>() / defenders.len() as f64;
            let gap_behind = (half_line - avg_y) * attack;
            if gap_behind > KICKOFF_BACK_FOUR_MAX_BEHIND_BALL_YARDS {
                let shift = gap_behind - KICKOFF_BACK_FOUR_MAX_BEHIND_BALL_YARDS;
                for (_, pos) in defenders.iter_mut() {
                    pos.y += attack * shift;
                }
            }
            for i in 0..defenders.len() {
                for j in (i + 1)..defenders.len() {
                    let delta = defenders[j].1 - defenders[i].1;
                    let dist = delta.len();
                    if dist > 1e-3 && dist < KICKOFF_DEFENDER_MIN_SPACING_YARDS {
                        let push = (KICKOFF_DEFENDER_MIN_SPACING_YARDS - dist) * 0.5;
                        let dir = delta.normalized();
                        defenders[i].1 = defenders[i].1 - dir * push;
                        defenders[j].1 = defenders[j].1 + dir * push;
                    }
                }
            }
            for (id, pos) in defenders {
                let placed = self.kickoff_own_half_position(team, pos);
                self.set_dead_ball_player_position(id, placed);
            }
        }

        let support = self
            .players
            .iter()
            .filter(|player| player.team == kickoff_team && taker != Some(player.id))
            .min_by(|a, b| {
                a.home_position
                    .distance(center)
                    .partial_cmp(&b.home_position.distance(center))
                    .unwrap_or(std::cmp::Ordering::Equal)
            })
            .map(|player| player.id);
        if let Some(support_id) = support {
            let side = if kickoff_team == Team::Home {
                1.0
            } else {
                -1.0
            };
            let support_spot = Vec2::new(
                center.x + side * 5.5,
                center.y - kickoff_team.attack_dir() * 2.5,
            );
            self.set_dead_ball_player_position(
                support_id,
                self.kickoff_own_half_position(kickoff_team, support_spot),
            );
        }
        if let Some(taker_id) = taker {
            self.set_dead_ball_player_position(taker_id, center);
        }
    }

    fn arrange_restart_shape(
        &mut self,
        kind: BallRestartKind,
        awarded_team: Team,
        spot: Vec2,
        taker: Option<usize>,
    ) {
        match kind {
            BallRestartKind::CornerKick => {
                self.arrange_corner_shape(awarded_team, spot, taker);
            }
            BallRestartKind::GoalKick => {
                self.arrange_goal_kick_shape(awarded_team, spot, taker);
            }
            BallRestartKind::ThrowIn => {
                self.arrange_throw_in_shape(awarded_team, spot, taker);
            }
            BallRestartKind::FreeKick => {
                self.arrange_free_kick_shape(awarded_team, spot, taker);
            }
        }
        if let Some(taker_id) = taker {
            self.set_dead_ball_player_position(taker_id, spot);
        }
    }

    fn arrange_corner_shape(&mut self, attacking_team: Team, spot: Vec2, taker: Option<usize>) {
        let width = self.config.field_width_yards;
        let length = self.config.field_length_yards;
        let dir = attacking_team.attack_dir();
        let goal_y = attacking_team.goal_y(length);
        let goal_center = Vec2::new(width * 0.5, goal_y);
        let attacking_slots = [
            Vec2::new(width * 0.42, goal_y - dir * 7.0),
            Vec2::new(width * 0.55, goal_y - dir * 8.5),
            Vec2::new(width * 0.34, goal_y - dir * 12.0),
            Vec2::new(width * 0.64, goal_y - dir * 13.5),
            Vec2::new(width * 0.50, goal_y - dir * 18.0),
            Vec2::new(width * 0.28, goal_y - dir * 22.0),
            Vec2::new(width * 0.72, goal_y - dir * 24.0),
        ];
        let attacking_ids = self.restart_team_ids(attacking_team, false, taker);
        self.assign_dead_ball_slots_lane_stable(&attacking_ids, &attacking_slots);

        let defending_team = attacking_team.other();
        if let Some(keeper_id) = self.goalkeeper_for(defending_team) {
            self.set_dead_ball_player_position(keeper_id, goal_center - Vec2::new(0.0, dir * 2.0));
        }
        let defending_slots = [
            Vec2::new(width * 0.40, goal_y - dir * 4.5),
            Vec2::new(width * 0.56, goal_y - dir * 5.5),
            Vec2::new(width * 0.32, goal_y - dir * 8.5),
            Vec2::new(width * 0.68, goal_y - dir * 9.0),
            Vec2::new(width * 0.48, goal_y - dir * 13.0),
            Vec2::new(width * 0.22, goal_y - dir * 17.0),
            Vec2::new(width * 0.78, goal_y - dir * 18.0),
        ];
        let defending_ids = self.restart_team_ids(defending_team, false, None);
        self.assign_dead_ball_slots_lane_stable(&defending_ids, &defending_slots);

        if let Some(taker_id) = taker {
            self.set_dead_ball_player_position(taker_id, spot);
        }
    }

    fn arrange_goal_kick_shape(&mut self, team: Team, spot: Vec2, taker: Option<usize>) {
        let width = self.config.field_width_yards;
        let length = self.config.field_length_yards;
        let dir = team.attack_dir();
        let own_goal_y = team.other().goal_y(length);
        // Outlet slots sit OUTSIDE the 18-yard line (>=20yd from the own goal line) so a
        // goal-kick pass to any of them clears the penalty area on the first touch (Law 16).
        let outlet_slots = [
            Vec2::new(width * 0.20, own_goal_y + dir * 20.0),
            Vec2::new(width * 0.36, own_goal_y + dir * 22.0),
            Vec2::new(width * 0.64, own_goal_y + dir * 22.0),
            Vec2::new(width * 0.80, own_goal_y + dir * 20.0),
            Vec2::new(width * 0.34, own_goal_y + dir * 36.0),
            Vec2::new(width * 0.66, own_goal_y + dir * 36.0),
        ];
        // Reverse role order so the deepest players (defenders, then mids) take the
        // goal-kick outlet slots; lane-stable assignment then keeps each on his side.
        let outlet_ids: Vec<usize> = self
            .restart_team_ids(team, false, taker)
            .into_iter()
            .rev()
            .collect();
        self.assign_dead_ball_slots_lane_stable(&outlet_ids, &outlet_slots);
        let press_ids = self.restart_team_ids(team.other(), false, None);
        self.assign_dead_ball_slots_lane_stable(
            &press_ids,
            &[
                Vec2::new(width * 0.28, own_goal_y + dir * 45.0),
                Vec2::new(width * 0.50, own_goal_y + dir * 50.0),
                Vec2::new(width * 0.72, own_goal_y + dir * 45.0),
                Vec2::new(width * 0.38, own_goal_y + dir * 58.0),
            ],
        );
        if let Some(taker_id) = taker.or_else(|| self.goalkeeper_for(team)) {
            self.set_dead_ball_player_position(taker_id, spot);
        }
    }

    fn arrange_throw_in_shape(&mut self, team: Team, spot: Vec2, taker: Option<usize>) {
        let width = self.config.field_width_yards;
        let length = self.config.field_length_yards;
        let dir = team.attack_dir();
        let side_sign = if spot.x <= width * 0.5 { 1.0 } else { -1.0 };
        let inside_x = (spot.x + side_sign * 8.0).clamp(4.0, width - 4.0);
        let receiver_slots = [
            Vec2::new(inside_x, spot.y - dir * 7.0),
            Vec2::new(inside_x + side_sign * 8.0, spot.y + dir * 6.0),
            Vec2::new(inside_x, spot.y + dir * 15.0),
            Vec2::new(width * 0.5, spot.y + dir * 10.0),
        ];
        for (player_id, slot) in self
            .restart_team_ids(team, false, taker)
            .into_iter()
            .zip(receiver_slots)
        {
            self.set_dead_ball_player_position(player_id, slot.clamp_to_pitch(width, length));
        }

        let defender_slots = receiver_slots.map(|slot| {
            Vec2::new(slot.x + side_sign * 2.0, slot.y + dir * 2.8).clamp_to_pitch(width, length)
        });
        for (player_id, slot) in self
            .restart_team_ids(team.other(), false, None)
            .into_iter()
            .zip(defender_slots)
        {
            self.set_dead_ball_player_position(player_id, slot);
        }

        let defending_team = team.other();
        let back_line_y = throw_in_no_offside_defender_line_y(defending_team, spot.y, length);
        let defending_ids = self.set_play_role_ids(defending_team, PlayerRole::Defender, None);
        let tracking_slots = receiver_slots
            .iter()
            .filter_map(|slot| {
                throw_in_no_offside_defender_tracking_target(
                    defending_team,
                    spot.y,
                    *slot,
                    width,
                    length,
                )
            })
            .collect::<Vec<_>>();
        let defending_slots = defending_ids
            .iter()
            .enumerate()
            .filter_map(|(idx, player_id)| {
                self.players
                    .iter()
                    .find(|player| player.id == *player_id)
                    .map(|player| {
                        let home_slot =
                            Vec2::new(player.home_position.x.clamp(6.0, width - 6.0), back_line_y);
                        let tracked_slot = tracking_slots
                            .get(idx.min(tracking_slots.len().saturating_sub(1)))
                            .copied()
                            .unwrap_or(home_slot);
                        Vec2::new(
                            home_slot.x * (1.0 - THROW_IN_RUNNER_TRACK_LATERAL_WEIGHT)
                                + tracked_slot.x * THROW_IN_RUNNER_TRACK_LATERAL_WEIGHT,
                            tracked_slot.y,
                        )
                        .clamp_to_pitch(width, length)
                    })
            })
            .collect::<Vec<_>>();
        self.assign_dead_ball_slots_lane_stable(&defending_ids, &defending_slots);
    }

    /// Clamp a dead-ball slot so an attacker is not placed beyond the defending
    /// team's second-last defender (offside). Frames are read from current
    /// positions, GK included, so a high keeper is handled by the sort.
    fn clamp_dead_ball_slot_onside(&self, attacking_team: Team, slot: Vec2) -> Vec2 {
        let dir = attacking_team.attack_dir();
        let mut depths: Vec<f64> = self
            .players
            .iter()
            .filter(|p| p.team == attacking_team.other())
            .map(|p| p.position.y * dir)
            .collect();
        if depths.len() < 2 {
            return slot;
        }
        depths.sort_by(|a, b| b.partial_cmp(a).unwrap_or(std::cmp::Ordering::Equal));
        let onside_depth = depths[1] - DEAD_BALL_ONSIDE_BUFFER_YARDS;
        if slot.y * dir > onside_depth {
            Vec2::new(slot.x, onside_depth * dir).clamp_to_pitch(
                self.config.field_width_yards,
                self.config.field_length_yards,
            )
        } else {
            slot
        }
    }

    fn arrange_free_kick_shape(&mut self, team: Team, spot: Vec2, taker: Option<usize>) {
        let width = self.config.field_width_yards;
        let length = self.config.field_length_yards;
        let dir = team.attack_dir();
        let goal = Vec2::new(width * 0.5, team.goal_y(length));
        let distance_to_goal = spot.distance(goal);
        if distance_to_goal <= 32.0 {
            let defending_team = team.other();
            if let Some(keeper_id) = self.goalkeeper_for(defending_team) {
                self.set_dead_ball_player_position(
                    keeper_id,
                    Vec2::new(width * 0.5, goal.y - dir * 2.0),
                );
            }
            let to_goal = (goal - spot).normalized();
            let wall_center = (spot + to_goal * 10.0).clamp_to_pitch(width, length);
            let lateral = Vec2::new(-to_goal.y, to_goal.x).normalized();
            let wall_ids = self.restart_team_ids(defending_team, false, None);
            for (player_id, offset) in wall_ids.into_iter().take(4).zip([-3.0, -1.0, 1.0, 3.0]) {
                self.set_dead_ball_player_position(player_id, wall_center + lateral * offset);
            }
            let attack_slots = [
                Vec2::new(spot.x + 5.0, spot.y - dir * 2.0),
                Vec2::new(width * 0.38, goal.y - dir * 9.0),
                Vec2::new(width * 0.60, goal.y - dir * 10.0),
                Vec2::new(width * 0.50, goal.y - dir * 16.0),
            ];
            for (player_id, slot) in self
                .restart_team_ids(team, false, taker)
                .into_iter()
                .zip(attack_slots)
            {
                // Offside applies at free kicks: never place an attacker beyond
                // the last line, or they spawn offside.
                let slot = self.clamp_dead_ball_slot_onside(team, slot);
                self.set_dead_ball_player_position(player_id, slot);
            }
        } else {
            let support_slots = [
                Vec2::new(spot.x - 8.0, spot.y - dir * 5.0),
                Vec2::new(spot.x + 8.0, spot.y - dir * 4.0),
                Vec2::new(spot.x, spot.y + dir * 10.0),
                Vec2::new(width * 0.34, spot.y + dir * 18.0),
                Vec2::new(width * 0.66, spot.y + dir * 18.0),
            ];
            for (player_id, slot) in self
                .restart_team_ids(team, false, taker)
                .into_iter()
                .zip(support_slots)
            {
                self.set_dead_ball_player_position(player_id, slot.clamp_to_pitch(width, length));
            }
        }
    }

    pub(crate) fn call_foul(
        &mut self,
        fouling_team: Team,
        fouler_id: usize,
        fouled_id: usize,
        spot: Vec2,
    ) {
        let awarded_team = fouling_team.other();
        let restart_spot = spot.clamp_to_pitch(
            self.config.field_width_yards,
            self.config.field_length_yards,
        );
        self.stat_foul(fouling_team);
        self.pending_pass = None;
        self.pending_shot = None;
        self.events.push(MatchEvent {
            tick: self.tick,
            clock_seconds: self.clock_seconds,
            kind: "foul".to_string(),
            team: Some(fouling_team),
            player_id: Some(fouler_id),
            description: format!(
                "{} fouled {}",
                self.players[fouler_id].name, self.players[fouled_id].name
            ),
            ..MatchEvent::default()
        });
        self.apply_restart(BallRestart {
            kind: BallRestartKind::FreeKick,
            awarded_team,
            position: restart_spot,
        });
    }

    pub(crate) fn call_offside(&mut self, offside: PendingOffside) {
        let defending_team = offside.team.other();
        let restart_spot = offside.position.clamp_to_pitch(
            self.config.field_width_yards,
            self.config.field_length_yards,
        );
        let restart_holder = self.nearest_player_on_team(defending_team, restart_spot);

        self.pending_pass = None;
        if let Some(holder_id) = restart_holder {
            if let Some(holder) = self.players.iter_mut().find(|p| p.id == holder_id) {
                holder.position = restart_spot;
                holder.velocity = Vec2::zero();
                holder.acceleration = Vec2::zero();
                holder.jerk = Vec2::zero();
                holder.movement_gait = MovementGait::Stand;
                holder.record_position_history();
            }
        }

        let assistant_kind = if restart_spot.x < self.config.field_width_yards * 0.5 {
            OfficialKind::AssistantRefereeNear
        } else {
            OfficialKind::AssistantRefereeFar
        };
        if let Some(assistant) = self
            .officials
            .iter_mut()
            .find(|official| official.kind == assistant_kind)
        {
            assistant.position = official_position_bounds(
                assistant.kind,
                Vec2::new(assistant.position.x, restart_spot.y),
                self.config.field_width_yards,
                self.config.field_length_yards,
            );
            assistant.velocity = Vec2::zero();
            assistant.acceleration = Vec2::zero();
            assistant.jerk = Vec2::zero();
            assistant.record_position_history();
        }

        self.stat_offside(offside.team);
        self.finish_possession_progress_chain(false);
        self.ball.position = restart_spot;
        self.ball.velocity = Vec2::zero();
        self.ball.acceleration = Vec2::zero();
        self.ball.jerk = Vec2::zero();
        self.ball.curl_acceleration = Vec2::zero();
        self.ball.altitude_yards = 0.0;
        self.ball.holder = restart_holder;
        self.ball.last_touch_team = Some(defending_team);
        if let Some(holder_id) = restart_holder {
            self.mark_ball_received(holder_id);
            self.record_possession_touch(holder_id);
            // The restart taker may not touch the ball twice in a row.
            self.restart_double_touch_guard = Some(holder_id);
        }
        self.ball.record_decision(self.tick, "offside", None);
        self.pending_shot = None;
        self.shared_positions.sync_from_players_and_ball(
            &self.players,
            &self.officials,
            &self.ball,
            self.tick,
            self.clock_seconds,
        );

        let target_name = self
            .players
            .iter()
            .find(|player| player.id == offside.target)
            .map(|player| player.name.as_str())
            .unwrap_or("runner");
        let passer_name = self
            .players
            .iter()
            .find(|player| player.id == offside.passer)
            .map(|player| player.name.as_str())
            .unwrap_or("passer");
        self.events.push(MatchEvent {
            tick: self.tick,
            clock_seconds: self.clock_seconds,
            kind: "offside".to_string(),
            team: Some(offside.team),
            player_id: Some(offside.target),
            description: format!(
                "{target_name} flagged offside on {passer_name}'s pass ({:.1} beyond line {:.1}, ball {:.1})",
                restart_spot.y, offside.second_last_defender_y, offside.ball_y
            ),
            offside_line_y: Some(offside.second_last_defender_y),
            offside_ball_y: Some(offside.ball_y),
            offside_player_x: Some(offside.position.x),
            offside_player_y: Some(offside.position.y),
            ..MatchEvent::default()
        });
    }

    fn nearest_player_on_team(&self, team: Team, point: Vec2) -> Option<usize> {
        self.players
            .iter()
            .filter(|player| player.team == team)
            .min_by(|a, b| {
                a.position
                    .distance(point)
                    .partial_cmp(&b.position.distance(point))
                    .unwrap_or(std::cmp::Ordering::Equal)
            })
            .map(|player| player.id)
    }

    pub(crate) fn update_player_facing_dizziness_energy(&mut self) {
        let dt = sane_dt_seconds(self.config.dt_seconds, DEFAULT_DT_SECONDS).max(1e-3);
        let ball_position = self.ball.position;
        let ball_holder = self.ball.holder;
        for player in &mut self.players {
            player.update_body_orientation_dizziness_energy(dt, ball_position, ball_holder);
        }
    }

    /// Tick the per-pair "too close for too long" clocks on the final post-step
    /// positions and rebuild this tick's spacing notices — the home/away brain
    /// *notifying* that one of a camped pair should move off. Runs every match
    /// step (the nudge it drives is gameplay, not reward logging).
    ///
    /// "Cover territory" is a fundamental of soccer: two teammates in the same
    /// small patch add no value. So same-team field players are expected to keep
    /// at least [`TEAMMATE_MIN_SPACING_YARDS`] apart ([`TEAMMATE_MIN_SPACING_BOX_YARDS`]
    /// inside either 18-yard box). A *brief* overlap — a handoff, a block, a double
    /// team — is fine: it is tolerated for a grace window (shorter the tighter the
    /// overlap). Past that, the pair is flagged and the weaker-claim player gets a
    /// nudge target back toward open space / its own slot. Every distance and time
    /// here is an advisory **seed**: the LP/MDP/POMDP/neural learners may settle on
    /// other spacings (see the overlap-pressure observation feature + reward term).
    pub(crate) fn update_teammate_spacing_proximity(&mut self) {
        let dt = sane_dt_seconds(self.config.dt_seconds, DEFAULT_DT_SECONDS).max(1e-3);
        let cooldown = dt * TEAMMATE_SPACING_COOLDOWN_RATE;

        // Dead-ball / set-play shapes are scripted (walls, lined-up restarts), so do
        // not police spacing then: cool every clock and emit no notices.
        if self.active_set_play.is_some() {
            self.teammate_proximity_seconds.retain(|_, seconds| {
                *seconds -= cooldown;
                *seconds > 1e-3
            });
            self.teammate_spacing_notices.clear();
            return;
        }

        let width = self.config.field_width_yards;
        let length = self.config.field_length_yards;

        // Phase 1 — read-only scoring of every same-team field pair (keepers
        // excluded; goalmouth keeper congestion is its own concern). Collect owned
        // data so the `self.players` borrow is released before we mutate the map.
        struct PairScore {
            key: (usize, usize),
            a_id: usize,
            b_id: usize,
            a_pos: Vec2,
            b_pos: Vec2,
            a_home: Vec2,
            b_home: Vec2,
            a_exempt: bool,
            b_exempt: bool,
            distance: f64,
            min_spacing: f64,
            hard_radius: f64,
        }
        // A player with a live commitment to the ball never yields (and so is also
        // never the one nudged): the carrier, the intended pass receiver, or a
        // human-controlled player. The fuller exemption set (loose-ball retriever,
        // etc.) is re-checked authoritatively where the nudge is applied.
        let ball_holder = self.ball.holder;
        let pass_target = self.pending_pass.as_ref().and_then(|pass| pass.target);
        let exempt = |p: &PlayerAgent| -> bool {
            p.controller_slot.is_some() || ball_holder == Some(p.id) || pass_target == Some(p.id)
        };
        let mut scored: Vec<PairScore> = Vec::new();
        {
            let field: Vec<&PlayerAgent> = self
                .players
                .iter()
                .filter(|p| p.role != PlayerRole::Goalkeeper)
                .collect();
            for i in 0..field.len() {
                for j in (i + 1)..field.len() {
                    let a = field[i];
                    let b = field[j];
                    if a.team != b.team {
                        continue;
                    }
                    let distance = a.position.distance(b.position);
                    let midpoint = (a.position + b.position) * 0.5;
                    let min_spacing =
                        if soccer_point_in_either_penalty_area(midpoint, width, length) {
                            TEAMMATE_MIN_SPACING_BOX_YARDS
                        } else {
                            TEAMMATE_MIN_SPACING_YARDS
                        };
                    let key = if a.id <= b.id {
                        (a.id, b.id)
                    } else {
                        (b.id, a.id)
                    };
                    scored.push(PairScore {
                        key,
                        a_id: a.id,
                        b_id: b.id,
                        a_pos: a.position,
                        b_pos: b.position,
                        a_home: a.home_position,
                        b_home: b.home_position,
                        a_exempt: exempt(a),
                        b_exempt: exempt(b),
                        distance,
                        min_spacing,
                        hard_radius: min_spacing * TEAMMATE_SPACING_HARD_FRACTION,
                    });
                }
            }
        }

        // Phase 2 — accumulate / cool each clock and emit notices for pairs past
        // their grace window. `scored` is exhaustive over current field pairs, so
        // iterating it covers every clock; we prune the cooled-to-zero entries.
        let clock_cap = TEAMMATE_SPACING_SOFT_GRACE_SECONDS
            + TEAMMATE_SPACING_PRESSURE_SATURATION_SECONDS
            + 1.0;
        let mut notices: Vec<TeammateSpacingNotice> = Vec::new();
        for pair in &scored {
            let clock = self
                .teammate_proximity_seconds
                .entry(pair.key)
                .or_insert(0.0);
            // A non-finite separation (a corrupted position) is not an overlap —
            // `NaN > min` is false, which would otherwise spuriously accumulate the
            // clock. Treat it as separated and cool down.
            if !pair.distance.is_finite() || pair.distance > pair.min_spacing {
                *clock = (*clock - cooldown).max(0.0);
                continue;
            }
            *clock = (*clock + dt).min(clock_cap);
            let elapsed = *clock;
            let within_hard = pair.distance <= pair.hard_radius;
            let grace = if within_hard {
                TEAMMATE_SPACING_HARD_GRACE_SECONDS
            } else {
                TEAMMATE_SPACING_SOFT_GRACE_SECONDS
            };
            if elapsed <= grace {
                // Still inside the tolerated window (handoff / block / double-team).
                continue;
            }
            let severity =
                ((elapsed - grace) / TEAMMATE_SPACING_PRESSURE_SATURATION_SECONDS).clamp(0.0, 1.0);
            // Pick the yielder: weaker claim moves. A committed player never yields;
            // otherwise the one further from its own slot has the weaker positional
            // claim, with a deterministic id tie-break.
            let yield_a = match (pair.a_exempt, pair.b_exempt) {
                (true, true) => continue, // both committed — nobody to nudge
                (true, false) => false,
                (false, true) => true,
                (false, false) => {
                    let a_drift = pair.a_pos.distance(pair.a_home);
                    let b_drift = pair.b_pos.distance(pair.b_home);
                    if (a_drift - b_drift).abs() > 1e-6 {
                        a_drift > b_drift
                    } else {
                        pair.a_id > pair.b_id
                    }
                }
            };
            let (yielder_id, yielder_pos, yielder_home, other_id, other_pos) = if yield_a {
                (pair.a_id, pair.a_pos, pair.a_home, pair.b_id, pair.b_pos)
            } else {
                (pair.b_id, pair.b_pos, pair.b_home, pair.a_id, pair.a_pos)
            };
            let suggested_point = teammate_spacing_suggested_point(
                yielder_id,
                yielder_pos,
                yielder_home,
                other_id,
                other_pos,
                pair.min_spacing,
                pair.distance,
            )
            .clamp_to_pitch(width, length);
            notices.push(TeammateSpacingNotice {
                player_id: yielder_id,
                other_id,
                suggested_point,
                severity,
            });
        }
        self.teammate_proximity_seconds
            .retain(|_, seconds| *seconds > 1e-3);
        self.teammate_spacing_notices = notices;
    }

    /// Law 16 (per tick): the goal kick is legally in play the instant the ball leaves the
    /// taking team's penalty area, so retire the must-clear guard then. While the ball is
    /// still inside the box the guard stays armed; the retake itself is triggered at the
    /// moment a player brings the ball under control inside the box (see
    /// [`Self::enforce_goal_kick_clearance_on_control`]).
    pub(crate) fn update_goal_kick_clearance(&mut self) {
        if let Some((team, _)) = self.goal_kick_must_clear_box {
            if !self.point_in_own_penalty_area(team, self.ball.position) {
                self.goal_kick_must_clear_box = None;
            }
        }
    }

    /// Law 16 (on a controlling touch): if a goal kick is still pending (the ball never left
    /// the penalty area) and a player has just brought it under control while it is inside
    /// the box, the ball did not leave the area on the first touch — retake the goal kick.
    /// `control_position` is where the ball was brought under control. Returns `true` if a
    /// retake was awarded (the caller must stop processing the touch).
    fn enforce_goal_kick_clearance_on_control(&mut self, control_position: Vec2) -> bool {
        let Some((team, spot)) = self.goal_kick_must_clear_box else {
            return false;
        };
        if !self.point_in_own_penalty_area(team, control_position) {
            // Brought under control outside the box — the kick is legally in play.
            self.goal_kick_must_clear_box = None;
            return false;
        }
        // Controlled while still inside the box: an illegal short/second touch before the
        // ball left the area. Retake (this re-arms the guard for the fresh attempt).
        self.pending_pass = None;
        self.apply_restart_with_label(BallRestartKind::GoalKick, team, spot, "goal-kick");
        return true;
    }

    fn update_offside_lingering_rewards(&mut self, after: &WorldSnapshot, emit_rewards: bool) {
        let attacking_team = after
            .controlled_possession_team()
            .or_else(|| after.possession_team());
        let Some(attacking_team) = attacking_team else {
            self.offside_clocks.clear();
            return;
        };
        let Some(line_y) = after.second_last_defender_line_for(attacking_team) else {
            return;
        };
        let ball_y = after.ball.position.y;
        let attack_dir = attacking_team.attack_dir();
        let half_line = after.field_length * 0.5;
        let dt = sane_dt_seconds(self.config.dt_seconds, DEFAULT_DT_SECONDS).max(1e-3);
        // An attacker is in an offside position when they are, IN THE OPPONENTS' HALF,
        // beyond both the second-last defender line and the ball in the attacking
        // direction. (You cannot be offside in your own half — Law 11.)
        let states: Vec<(usize, bool, f64)> = self
            .players
            .iter()
            .filter(|p| p.team == attacking_team && p.role != PlayerRole::Goalkeeper)
            .map(|p| {
                let pos_y = after.player_position(p.id).unwrap_or(p.position).y;
                let beyond_line = (pos_y - line_y) * attack_dir;
                let in_opp_half = (pos_y - half_line) * attack_dir > 0.0;
                let offside = after.ball.holder != Some(p.id)
                    && in_opp_half
                    && beyond_line > 0.0
                    && (pos_y - ball_y) * attack_dir > 0.0;
                // Yards past the last-defender line — the distance dimension.
                (p.id, offside, beyond_line.max(0.0))
            })
            .collect();
        let mut events: Vec<(usize, f64)> = Vec::new();
        for (id, offside, offside_yards) in states {
            let clock = self.offside_clocks.entry(id).or_insert(0.0);
            if offside {
                *clock += dt;
                if emit_rewards && *clock > OFFSIDE_GRACE_SECONDS {
                    // Independent time and distance terms, each with its own
                    // scalar, both capped. Further AND longer => more penalty.
                    let over =
                        (*clock - OFFSIDE_GRACE_SECONDS).min(OFFSIDE_LINGER_PENALTY_CAP_SECONDS);
                    let dist = offside_yards.min(OFFSIDE_DISTANCE_PENALTY_CAP_YARDS);
                    let penalty = OFFSIDE_TIME_PENALTY_PER_SECOND * over
                        + OFFSIDE_DISTANCE_PENALTY_PER_YARD * dist;
                    events.push((id, -penalty * dt));
                }
            } else {
                if emit_rewards && *clock > OFFSIDE_GRACE_SECONDS {
                    // Reward getting back onside, scaled by how long they lingered
                    // (and capped). This is deliberately smaller than the penalty
                    // already accrued over the stint, so it can never be farmed by
                    // briefly dipping offside and stepping back.
                    let lingered =
                        (*clock - OFFSIDE_GRACE_SECONDS).min(OFFSIDE_LINGER_PENALTY_CAP_SECONDS);
                    events.push((id, (0.4 * lingered * lingered).min(OFFSIDE_RECOVERY_REWARD)));
                }
                *clock = 0.0;
            }
        }
        for (id, amount) in events {
            self.record_reward_event(id, amount);
        }
    }

    /// MDP side of the aerial-OOB loop. A LONG lofted pass that was still in flight when the
    /// ball left play sailed out untouched — over the touchline (throw-in to the other team) or
    /// the opponent byline (a conceded goal-kick). Penalise the PASSER, scaled per-yard by how
    /// far the exit point landed from where the ball was aimed (the same "hit the frame" shaping
    /// the shot-off-target penalty uses), so the policy learns to weight an ambitious loft rather
    /// than blaze it out. Returns true when it applied (the caller then suppresses the generic
    /// out-of-bounds turnover penalty for this restart so the passer is not double-charged).
    /// Gate OFF, non-aerial / short passes, a shot, or a ball the passer's team kept ⇒ no event
    /// and false (baseline byte-identical).
    fn record_aerial_pass_out_of_bounds_penalty(
        &mut self,
        pass: Option<&PendingPass>,
        restart_kind: BallRestartKind,
        awarded_team: Team,
        restart_position: Vec2,
    ) -> bool {
        if !dd_soccer_enable_aerial_pass_oob_discipline() {
            return false;
        }
        let Some(pass) = pass else {
            return false;
        };
        if !pass.flight.is_aerial() {
            return false;
        }
        // Only a loft the passer's team CONCEDED out of play: a throw-in or goal-kick awarded to
        // the other team. (A corner is won off a defensive touch — not the passer's error.)
        let conceded = matches!(
            restart_kind,
            BallRestartKind::ThrowIn | BallRestartKind::GoalKick
        ) && awarded_team != pass.team;
        if !conceded || pass.distance_yards < AERIAL_PASS_OOB_MIN_DISTANCE_YARDS {
            return false;
        }
        // How far the ball exited from where it was aimed: a loft that just grazes out next to
        // its target is unlucky; one that sails out 15yd away was badly over-hit.
        let overrun = restart_position.distance(pass.intended_target);
        let over = (overrun - AERIAL_PASS_OOB_FORGIVENESS_YARDS).max(0.0);
        let penalty = (AERIAL_PASS_OOB_BASE_PENALTY_POINTS
            + over * AERIAL_PASS_OOB_PENALTY_PER_YARD)
            .min(AERIAL_PASS_OOB_MAX_PENALTY_POINTS);
        self.record_reward_event(pass.from, -penalty);
        // An aerial hoofed out is also a turnover: give the offending team's last few seconds the
        // same retroactive, all-learner penalty (per-tick de-dup guarded), mirroring the generic
        // handler this one supersedes.
        self.penalize_turnover_window(pass.team);
        true
    }

    fn record_out_of_bounds_turnover_penalty(
        &mut self,
        restart_kind: BallRestartKind,
        awarded_team: Team,
    ) {
        // The aerial-pass OOB handler already claimed this restart (and applied a
        // distance-shaped penalty + turnover window); don't double-charge the passer.
        if self.suppress_generic_oob_turnover {
            return;
        }
        // Only throw-ins unambiguously mean "the ball was dribbled/passed out
        // over the touchline." Goal kicks can be wide shots and corners can be
        // defensive deflections, so attributing those as turnovers misfires.
        if !matches!(restart_kind, BallRestartKind::ThrowIn) {
            return;
        }
        let offending_team = awarded_team.other();
        let Some(offender) = self.possession_chain.iter().rev().copied().find(|id| {
            self.players
                .get(*id)
                .is_some_and(|p| p.team == offending_team)
        }) else {
            return;
        };
        let offender_pos = self.players[offender].position;
        let nearest_opponent = self
            .players
            .iter()
            .filter(|p| p.team == offending_team.other())
            .map(|p| p.position.distance(offender_pos))
            .fold(f64::INFINITY, f64::min);
        let pressure = pressure_from_nearest_distance(nearest_opponent);
        if pressure >= OUT_OF_BOUNDS_PRESSURE_EXEMPT_THRESHOLD {
            return;
        }
        self.record_reward_event(offender, -OUT_OF_BOUNDS_TURNOVER_PENALTY_POINTS);
        // Dribbling/passing the ball out under no pressure is a turnover too:
        // give the offending team's last few seconds of play the same
        // retroactive, all-learner penalty an open-play steal would (via the
        // canonical turnover engine, sharing its per-tick de-dup guard).
        self.penalize_turnover_window(offending_team);
    }

    pub(crate) fn update_defensive_reward_trackers(
        &mut self,
        before: &WorldSnapshot,
        after: &WorldSnapshot,
    ) {
        let Some(holder_id) = before.ball.holder else {
            self.defensive_delay_clocks.clear();
            self.defensive_beat_clocks.clear();
            return;
        };
        let Some(holder_before) = before.players.iter().find(|player| player.id == holder_id)
        else {
            return;
        };
        let holder_team = holder_before.team;
        let holder_before_position = before
            .player_position(holder_id)
            .unwrap_or(holder_before.position);
        let holder_after_position = after
            .player_position(holder_id)
            .or_else(|| after.ball.holder.and_then(|id| after.player_position(id)))
            .unwrap_or(after.ball.position);
        let attacker_progress =
            (holder_after_position.y - holder_before_position.y) * holder_team.attack_dir();
        let retained_attack = after.possession_team() == Some(holder_team);
        let retained_by_dribbler = after.ball.holder == Some(holder_id);
        let dt = self.config.dt_seconds.max(0.0);
        let holder_action = self
            .players
            .get(holder_id)
            .and_then(|player| player.last_decision.as_ref())
            .map(|decision| normalize_soccer_action_label(&decision.action))
            .unwrap_or("hold");
        let holder_dribbling = is_dribble_action_label(holder_action);

        let mut delay_rewards = Vec::new();
        let mut beat_penalties = Vec::new();
        for defender in before
            .players
            .iter()
            .filter(|player| player.team != holder_team)
        {
            let current_action = self
                .players
                .get(defender.id)
                .and_then(|player| player.last_decision.as_ref())
                .map(|decision| normalize_soccer_action_label(&decision.action))
                .unwrap_or("hold");
            let defender_before_position = before
                .player_position(defender.id)
                .unwrap_or(defender.position);
            let defender_after_position = after
                .player_position(defender.id)
                .unwrap_or(defender_before_position);
            let distance_to_holder = defender_before_position.distance(holder_before_position);
            let active_defense = matches!(current_action, "defend" | "tackle");
            let delayed = active_defense
                && retained_attack
                && distance_to_holder <= 6.0
                && attacker_progress <= 0.8;
            let delay_clock = self
                .defensive_delay_clocks
                .entry(defender.id)
                .or_insert(0.0);
            if delayed {
                *delay_clock += dt;
                if *delay_clock >= 2.0 {
                    delay_rewards.push(defender.id);
                    *delay_clock -= 2.0;
                }
            } else {
                *delay_clock = 0.0;
            }

            let beaten = holder_dribbling
                && active_defense
                && retained_by_dribbler
                && dribble_beat_geometry_is_valid(
                    holder_team,
                    holder_before_position,
                    holder_after_position,
                    defender_before_position,
                    defender_after_position,
                );
            let beat_clock = self.defensive_beat_clocks.entry(defender.id).or_insert(0.0);
            if beaten {
                *beat_clock += dt;
                if *beat_clock >= 0.25 {
                    beat_penalties.push(defender.id);
                    *beat_clock = 0.0;
                }
            } else {
                *beat_clock = 0.0;
            }
        }

        for defender_id in delay_rewards {
            self.record_reward_event_at(before.tick, defender_id, 2.0);
        }
        if !beat_penalties.is_empty() {
            self.record_reward_event_at(before.tick, holder_id, SIDE_STEP_BEAT_REWARD_POINTS);
        }
        for defender_id in beat_penalties {
            self.stat_dribble_beat(holder_team);
            let attacker_name = self
                .players
                .get(holder_id)
                .map(|player| player.name.clone())
                .unwrap_or_else(|| "attacker".to_string());
            let defender_name = self
                .players
                .get(defender_id)
                .map(|player| player.name.clone())
                .unwrap_or_else(|| "defender".to_string());
            self.events.push(MatchEvent {
                tick: before.tick,
                clock_seconds: before.clock_seconds,
                kind: "dribble-beat".to_string(),
                team: Some(holder_team),
                player_id: Some(holder_id),
                description: format!("{attacker_name} beat {defender_name} by dribble"),
                ..MatchEvent::default()
            });
            self.record_reward_event_at(
                before.tick,
                defender_id,
                -BEATEN_BY_DRIBBLE_PENALTY_POINTS,
            );
        }
    }

    pub(crate) fn score_goal(&mut self, scoring_team: Team) {
        self.finish_possession_progress_chain(true);
        // Assist: the goal came directly off the scoring team's most recent completed pass
        // (within a few seconds — not a stale earlier-possession ball).
        if self.completed_pass_chain.back().is_some_and(|entry| {
            entry.team == scoring_team
                && (self.clock_seconds - entry.clock_seconds) <= ASSIST_RECENCY_SECONDS
        }) {
            match scoring_team {
                Team::Home => self.stats.assists_home += 1,
                Team::Away => self.stats.assists_away += 1,
            }
        }
        // (The pass-chain meter was already finalised by `finish_possession_progress_chain`.)
        match scoring_team {
            Team::Home => self.score_home += 1,
            Team::Away => self.score_away += 1,
        }
        self.events.push(MatchEvent {
            tick: self.tick,
            clock_seconds: self.clock_seconds,
            kind: "goal".to_string(),
            team: Some(scoring_team),
            player_id: None,
            description: format!("{} goal", scoring_team.label()),
            ..MatchEvent::default()
        });
        // Hold a brief celebration before the kickoff (the ball stays in the net)
        // so the goal sequence completes on screen instead of cutting straight to
        // centre. `run_time_step` performs the actual reset when the hold expires.
        let dt = self.config.dt_seconds.max(1.0e-3);
        self.goal_celebration_remaining_ticks = (GOAL_CELEBRATION_SECONDS / dt).ceil() as u32;
        self.goal_celebration_kickoff_team = Some(scoring_team.other());
    }

    fn kickoff_team_for_half(&self, half_index: usize) -> Team {
        if half_index % 2 == 0 {
            Team::Home
        } else {
            Team::Away
        }
    }

    fn reset_for_new_half(&mut self, next_half_index: usize) {
        let center = Vec2::new(
            self.config.field_width_yards * 0.5,
            self.config.field_length_yards * 0.5,
        );
        let recovery = self.config.halftime_fatigue_recovery.clamp(0.0, 1.0);
        self.events.push(MatchEvent {
            tick: self.tick,
            clock_seconds: self.clock_seconds,
            kind: if next_half_index == 1 {
                "halftime".to_string()
            } else {
                "period-break".to_string()
            },
            team: None,
            player_id: None,
            description: format!("Break before half {}", next_half_index + 1),
            ..MatchEvent::default()
        });
        for p in &mut self.players {
            p.position = p.home_position;
            p.velocity = Vec2::zero();
            p.acceleration = Vec2::zero();
            p.jerk = Vec2::zero();
            p.movement_gait = MovementGait::Stand;
            p.receive_facing = FacingBucket::Unknown;
            p.action_facing = default_team_facing(p.team);
            p.last_decision = None;
            p.fatigue = (p.fatigue * (1.0 - recovery)).clamp(0.0, 1.0);
            p.record_position_history();
        }
        let kickoff_team = self.kickoff_team_for_half(next_half_index);
        let kickoff = self
            .players
            .iter()
            .filter(|p| p.team == kickoff_team)
            .min_by(|a, b| {
                a.position
                    .distance(center)
                    .partial_cmp(&b.position.distance(center))
                    .unwrap_or(std::cmp::Ordering::Equal)
            })
            .map(|p| p.id);
        self.arrange_kickoff_shape(kickoff_team, kickoff, center);
        self.activate_set_play_for_restart("kickoff", None, kickoff_team, center, kickoff);
        self.ball.position = center;
        self.ball.velocity = Vec2::zero();
        self.ball.acceleration = Vec2::zero();
        self.ball.jerk = Vec2::zero();
        self.ball.curl_acceleration = Vec2::zero();
        self.ball.altitude_yards = 0.0;
        self.ball.holder = kickoff;
        self.ball.last_touch_team = Some(kickoff_team);
        self.finish_possession_progress_chain(false);
        self.possession_chain.clear();
        self.possession_chain_previous_touch_team = None;
        self.completed_pass_chain.clear();
        if let Some(holder_id) = kickoff {
            self.mark_ball_received(holder_id);
            self.record_possession_touch(holder_id);
            // The kickoff taker may not touch the ball twice in a row: they must
            // play it to a teammate (held-restart release) before touching again.
            // Set AFTER record_possession_touch, which would otherwise clear it.
            self.restart_double_touch_guard = Some(holder_id);
        }
        self.ball.record_decision(self.tick, "kickoff", None);
        self.pending_pass = None;
        self.pending_shot = None;
        self.player_tick_carryover.clear();
        self.defensive_delay_clocks.clear();
        self.defensive_beat_clocks.clear();
        self.defensive_clear_hold_trackers.clear();
        self.shared_positions.sync_from_players_and_ball(
            &self.players,
            &self.officials,
            &self.ball,
            self.tick,
            self.clock_seconds,
        );
        let taker = kickoff
            .and_then(|id| self.players.iter().find(|player| player.id == id))
            .map(|player| player.name.as_str())
            .unwrap_or("Kickoff");
        self.events.push(MatchEvent {
            tick: self.tick,
            clock_seconds: self.clock_seconds,
            kind: "kickoff".to_string(),
            team: Some(kickoff_team),
            player_id: kickoff,
            description: format!(
                "{taker} kickoff for {} to start half {}",
                kickoff_team.label(),
                next_half_index + 1
            ),
            ..MatchEvent::default()
        });
    }

    fn reset_after_goal(&mut self, kickoff_team: Team) {
        let center = Vec2::new(
            self.config.field_width_yards * 0.5,
            self.config.field_length_yards * 0.5,
        );
        for p in &mut self.players {
            p.position = p.home_position;
            p.velocity = Vec2::zero();
            p.acceleration = Vec2::zero();
            p.jerk = Vec2::zero();
            p.movement_gait = MovementGait::Stand;
            p.receive_facing = FacingBucket::Unknown;
            p.action_facing = default_team_facing(p.team);
            p.last_decision = None;
            p.record_position_history();
        }
        let kickoff = self
            .players
            .iter()
            .filter(|p| p.team == kickoff_team)
            .min_by(|a, b| {
                a.position
                    .distance(center)
                    .partial_cmp(&b.position.distance(center))
                    .unwrap_or(std::cmp::Ordering::Equal)
            })
            .map(|p| p.id);
        self.arrange_kickoff_shape(kickoff_team, kickoff, center);
        self.activate_set_play_for_restart("kickoff", None, kickoff_team, center, kickoff);
        self.ball.position = center;
        self.ball.velocity = Vec2::zero();
        self.ball.acceleration = Vec2::zero();
        self.ball.jerk = Vec2::zero();
        self.ball.curl_acceleration = Vec2::zero();
        self.ball.altitude_yards = 0.0;
        self.ball.holder = kickoff;
        self.ball.last_touch_team = Some(kickoff_team);
        self.possession_progress_tracker = None;
        self.possession_chain.clear();
        self.possession_chain_previous_touch_team = None;
        self.completed_pass_chain.clear();
        if let Some(holder_id) = kickoff {
            self.mark_ball_received(holder_id);
            self.record_possession_touch(holder_id);
            // The kickoff taker may not touch the ball twice in a row: they must
            // play it to a teammate (held-restart release) before touching again.
            // Set AFTER record_possession_touch, which would otherwise clear it.
            self.restart_double_touch_guard = Some(holder_id);
        }
        self.ball.record_decision(self.tick, "kickoff", None);
        self.pending_pass = None;
        self.pending_shot = None;
        self.player_tick_carryover.clear();
        self.defensive_clear_hold_trackers.clear();
        self.shared_positions.sync_from_players_and_ball(
            &self.players,
            &self.officials,
            &self.ball,
            self.tick,
            self.clock_seconds,
        );
        let taker = kickoff
            .and_then(|id| self.players.iter().find(|player| player.id == id))
            .map(|player| player.name.as_str())
            .unwrap_or("Kickoff");
        self.events.push(MatchEvent {
            tick: self.tick,
            clock_seconds: self.clock_seconds,
            kind: "kickoff".to_string(),
            team: Some(kickoff_team),
            player_id: kickoff,
            description: format!("{taker} kickoff for {}", kickoff_team.label()),
            ..MatchEvent::default()
        });
    }

