/// Shared field state for the learnable attacking-spacing target: the own-team centre
/// of mass, the defending team's vector (centroid / spread / mean velocity) and the
/// carrier's heading. Built once by [`WorldSnapshot::spacing_field_terms`].
#[derive(Clone, Copy, Debug)]
struct SpacingFieldTerms {
    centroid: Vec2,
    opp_centroid: Vec2,
    opp_spread: f64,
    opp_mean_vel: Vec2,
    carrier_vel: Vec2,
}

impl CandidateOccupancy {
    pub(crate) fn teammate_occupied_space_pressure(self) -> f64 {
        teammate_occupied_space_pressure_from_distance(self.nearest_teammate_distance)
            .max(self.teammate_axis_clump_pressure)
    }

    pub(crate) fn teammate_occupied_space_penalty(self, relief: f64) -> f64 {
        TEAMMATE_OCCUPIED_SPACE_MAX_PENALTY
            * self.teammate_occupied_space_pressure()
            * (1.0 - relief.clamp(0.0, 0.78))
    }

    pub(crate) fn team_spacing_score(self, mode: TeamSpacingMode) -> f64 {
        (spacing_score_from_distance(self.nearest_teammate_distance, mode)
            - self.teammate_axis_clump_pressure * 0.55)
            .clamp(-1.0, 1.0)
    }
}

const TEAMMATE_AXIS_CLUMP_HARD_RADIUS_YARDS: f64 = 1.0;
const TEAMMATE_AXIS_CLUMP_NEAR_PRESSURE: f64 = 0.50;
const TEAMMATE_AXIS_CLUMP_PRESSURE_EPSILON: f64 = 1e-6;

fn teammate_axis_clump_pressure_from_delta(delta: Vec2) -> f64 {
    teammate_axis_clump_pressure_from_delta_with_radius(delta, TEAMMATE_MIN_SPACING_YARDS)
}

fn teammate_axis_clump_pressure_from_delta_with_radius(delta: Vec2, radius: f64) -> f64 {
    fn axis_pressure_with_radius(gap: f64, radius: f64) -> f64 {
        let radius = radius.max(0.0);
        if !gap.is_finite() || gap >= radius || radius <= 1e-6 {
            0.0
        } else {
            let hard_radius = TEAMMATE_AXIS_CLUMP_HARD_RADIUS_YARDS.min(radius * 0.5);
            if gap <= hard_radius {
                return 1.0;
            }
            ((radius - gap) / (radius - hard_radius).max(1e-6)).clamp(0.0, 1.0)
        }
    }

    axis_pressure_with_radius(delta.x.abs(), radius)
        .min(axis_pressure_with_radius(delta.y.abs(), radius))
}

impl TeamSpacingMode {
    fn band(self) -> (f64, f64, f64) {
        match self {
            TeamSpacingMode::InPossession => (
                ATTACK_SPACING_MIN_YARDS,
                ATTACK_SPACING_IDEAL_YARDS,
                ATTACK_SPACING_MAX_YARDS,
            ),
            TeamSpacingMode::Defending => (
                DEFENSE_SPACING_MIN_YARDS,
                DEFENSE_SPACING_IDEAL_YARDS,
                DEFENSE_SPACING_MAX_YARDS,
            ),
        }
    }

    fn ideal(self) -> f64 {
        let (min, upper, _) = self.band();
        (min + upper) * 0.5
    }
}

pub(crate) fn spacing_score_from_distance(distance_yards: f64, mode: TeamSpacingMode) -> f64 {
    if !distance_yards.is_finite() {
        return -1.0;
    }
    let (min, upper, max) = mode.band();
    if distance_yards < min {
        -((min - distance_yards) / min.max(1.0)).clamp(0.0, 1.0)
    } else if distance_yards > max {
        -((distance_yards - max) / max.max(1.0)).clamp(0.0, 1.0)
    } else if distance_yards <= upper {
        1.0
    } else {
        let span = (max - upper).max(1e-6);
        (1.0 - ((distance_yards - upper) / span) * 0.45).clamp(0.55, 1.0)
    }
}

pub(crate) fn teammate_occupied_space_pressure_from_distance(
    nearest_teammate_distance: f64,
) -> f64 {
    if nearest_teammate_distance <= TEAMMATE_OCCUPIED_SPACE_HARD_RADIUS_YARDS {
        1.0
    } else {
        ((TEAMMATE_OCCUPIED_SPACE_RADIUS_YARDS - nearest_teammate_distance)
            / (TEAMMATE_OCCUPIED_SPACE_RADIUS_YARDS - TEAMMATE_OCCUPIED_SPACE_HARD_RADIUS_YARDS)
                .max(1e-6))
        .clamp(0.0, 1.0)
    }
}

pub(crate) fn open_space_score_from_distances(
    opponent_distance: f64,
    teammate_crowding: f64,
) -> f64 {
    open_space_score_from_distances_with_axis_pressure(opponent_distance, teammate_crowding, 0.0)
}

/// Off-ball spacing-discipline score adjustment for one `open_space_for` candidate. Pure so it
/// can be unit-tested without the (process-cached) env gate; the caller passes
/// `current_outlet_open = false` whenever the gate is OFF, making this a no-op (returns 0.0) and
/// `open_space_for` byte-identical. When the player ALREADY offers a clean, in-range outlet:
///   1. most of the show-for-ball / ball-arrival proximity pull is cancelled (closing the gap
///      to the carrier opens no new lane, so it earns ~nothing — the reward becomes marginal);
///   2. a candidate that actively collapses inside the carrier keep-out radius (closer to the
///      carrier than the player is now) is penalised in proportion to how far inside it sits.
pub(crate) fn off_ball_space_discipline_adjustment(
    current_outlet_open: bool,
    short_outlet_bonus: f64,
    ball_arrival_bonus: f64,
    candidate_to_carrier_yards: f64,
    current_to_carrier_yards: f64,
) -> f64 {
    if !current_outlet_open {
        return 0.0;
    }
    let mut adj = -(short_outlet_bonus + ball_arrival_bonus) * OFF_BALL_MARGINAL_OUTLET_CANCEL;
    if candidate_to_carrier_yards < OFF_BALL_CARRIER_KEEP_OUT_YARDS
        && candidate_to_carrier_yards < current_to_carrier_yards - 1e-6
    {
        let intrusion = (OFF_BALL_CARRIER_KEEP_OUT_YARDS - candidate_to_carrier_yards)
            / OFF_BALL_CARRIER_KEEP_OUT_YARDS.max(1.0);
        adj -= intrusion * OFF_BALL_CARRIER_COLLAPSE_PENALTY;
    }
    adj
}

fn open_space_score_from_distances_with_axis_pressure(
    opponent_distance: f64,
    teammate_crowding: f64,
    teammate_axis_clump_pressure: f64,
) -> f64 {
    let opponent_distance = opponent_distance.min(35.0);
    let teammate_crowding = teammate_crowding.min(25.0);
    let teammate_pressure = teammate_occupied_space_pressure_from_distance(teammate_crowding)
        .max(teammate_axis_clump_pressure);
    opponent_distance * 0.68 + teammate_crowding * 0.32
        - TEAMMATE_OCCUPIED_SPACE_MAX_PENALTY * teammate_pressure * 0.72
}

// Per-process cached reads of the `DD_SOCCER_DISABLE_*` toggles. These are set in the
// environment and never change during a run, but were being read via `std::env::var` —
// which takes a process-wide lock and allocates a String — on the hot per-player-per-tick
// path (anti-bunch + spacing-nudge fire 2×/player/tick, the energy + defensive-pushup ones
// once/player/tick). Caching them once removes ~tens of thousands of syscalls per match and
// the lock contention that spikes the live server's tail latency. No test toggles these.
pub(crate) fn dd_soccer_disable_anti_bunch() -> bool {
    use std::sync::OnceLock;
    static V: OnceLock<bool> = OnceLock::new();
    *V.get_or_init(|| std::env::var("DD_SOCCER_DISABLE_ANTI_BUNCH").is_ok())
}
pub(crate) fn dd_soccer_disable_spacing_nudge() -> bool {
    use std::sync::OnceLock;
    static V: OnceLock<bool> = OnceLock::new();
    *V.get_or_init(|| std::env::var("DD_SOCCER_DISABLE_SPACING_NUDGE").is_ok())
}
/// Over-the-top ball keeper-avoidance angling (default ON). Set this to restore the historical
/// behaviour byte-for-byte: an in-behind ball is projected onto the runner's raw x with no lateral
/// nudge away from the opponent keeper, and the over-the-top selector carries no keeper-avoidance
/// preference. See `over_the_top_gk_angled_point`.
pub(crate) fn dd_soccer_disable_over_top_gk_angle() -> bool {
    use std::sync::OnceLock;
    static V: OnceLock<bool> = OnceLock::new();
    *V.get_or_init(|| std::env::var("DD_SOCCER_DISABLE_OVER_TOP_GK_ANGLE").is_ok())
}
/// When an off-ball forward/midfielder is holding a support position (NOT timing a
/// sanctioned in-behind run), they should sit level with the last defender — on the
/// shoulder, onside — rather than parking `OPEN_SPACE_RUN_OFFSIDE_TOLERANCE_YARDS`
/// beyond the line in a standing offside position. Parking offside meant any pass or
/// loose ball that reached them was (correctly) flagged offside, so strikers were
/// continually caught even though the ball never left our half. Set this env var to
/// restore the old line+tolerance parking.
pub(crate) fn dd_soccer_disable_onside_support_hold() -> bool {
    use std::sync::OnceLock;
    static V: OnceLock<bool> = OnceLock::new();
    *V.get_or_init(|| std::env::var("DD_SOCCER_DISABLE_ONSIDE_SUPPORT_HOLD").is_ok())
}

/// Quick forward ground-pass priority (OFF by default = byte-identical). When set, players
/// place much more value on a short progressive GROUND pass (≈5–8 m) into an OPEN, advanced
/// teammate and release it SOONER — as a first-time ball off the carry or a one-touch off
/// the first touch — rather than settling or dwelling on the ball. The forward-open value is
/// folded into the LEARNABLE first-time-pass field feasibility (so the neural policy adapts
/// its weight), the option score is floored to beat a settling touch / a held carry, and the
/// chosen pass is delivered through the existing MPC pass-execution path (the `Pass` action
/// is rendezvous-solved + learnable-velocity shaped downstream). Addresses "players are not
/// passing fast enough / should prioritise quick forward ground passes to open teammates."
pub(crate) fn dd_soccer_enable_quick_forward_pass() -> bool {
    #[cfg(test)]
    {
        std::env::var("DD_SOCCER_ENABLE_QUICK_FORWARD_PASS").is_ok()
    }
    #[cfg(not(test))]
    {
        use std::sync::OnceLock;
        static V: OnceLock<bool> = OnceLock::new();
        *V.get_or_init(|| gate_default_on("DD_SOCCER_ENABLE_QUICK_FORWARD_PASS"))
    }
}

/// Seed each of the 11 players' `home_position` — their field-position affinity
/// anchor, which the lane-discipline band, support scorer, and shape cohesion all
/// pull toward — from the team's evolved genome anchors on the 12×24 pitch grid,
/// instead of the hard-coded default formation literals. OFF by default ⇒ the
/// genome's per-player `anchors` stay advisory and home positions are
/// byte-identical to before. When ON, per-player WIDTH (lane = x) affinity becomes
/// grid-derived AND heritable: the tournament GA already mutates / crosses the
/// anchors, so evolving a team's shape now actually moves its players. See
/// [`SoccerMatch::apply_genome_anchor_home_positions`].
pub(crate) fn dd_soccer_enable_genome_anchor_home_positions() -> bool {
    #[cfg(test)]
    {
        std::env::var("DD_SOCCER_ENABLE_GENOME_ANCHOR_HOME_POSITIONS").is_ok()
    }
    #[cfg(not(test))]
    {
        use std::sync::OnceLock;
        static V: OnceLock<bool> = OnceLock::new();
        *V.get_or_init(|| std::env::var("DD_SOCCER_ENABLE_GENOME_ANCHOR_HOME_POSITIONS").is_ok())
    }
}

