// Run-around-dribble (knock past + sprint the body the other side + re-collect behind) tunables.
const RUNAROUND_TTL_SECONDS: f64 = 2.5;
const RUNAROUND_SUCCESS_REWARD_POINTS: f64 = 8.0;
const RUNAROUND_MIN_FORWARD_SPEED_YPS: f64 = 4.0;
const RUNAROUND_DEFENDER_MIN_AHEAD_YARDS: f64 = 1.5;
const RUNAROUND_DEFENDER_MAX_AHEAD_YARDS: f64 = 5.0;
const RUNAROUND_DEFENDER_LATERAL_YARDS: f64 = 2.5;
const RUNAROUND_DEFENDER_RANGE_YARDS: f64 = 5.5;
const RUNAROUND_MIN_SPEED_ADVANTAGE: f64 = 0.4;
const RUNAROUND_PUSH_AHEAD_YARDS: f64 = 4.5;
// Push wide enough of the defender that the ball clears their reach as it goes by (a too-narrow
// knock is simply intercepted — a listed failure mode).
const RUNAROUND_PUSH_LATERAL_YARDS: f64 = 2.6;
const RUNAROUND_RECOLLECT_AHEAD_YARDS: f64 = 7.0;
const RUNAROUND_RECOLLECT_CLEAR_YARDS: f64 = 6.0;
const RUNAROUND_LANE_HALF_WIDTH_YARDS: f64 = 1.0;
const RUNAROUND_BODY_CLEARANCE_YARDS: f64 = 1.10;
const RUNAROUND_MOMENTUM_ESCAPE_REFERENCE_YPS: f64 = 4.5;
const RUNAROUND_TOUCHLINE_MARGIN_YARDS: f64 = 2.5;
const RUNAROUND_MIN_QUALITY: f64 = 0.45;
/// Beat-the-defender duel (gated): quality bonus added to the run-around side whose knock goes to
/// the OPEN side — away from an over-committed defender's lean — so the carrier exits where the
/// defender's momentum cannot recover within their reaction window. Off ⇒ never applied (parity).
const RUNAROUND_MOMENTUM_SIDE_BONUS: f64 = 0.22;
// Appetite shaping: the move is much MORE inclined the bigger the speed differential over the
// defender, and the clearer the space behind them (nobody to intercept the longer touch). These set
// where each term saturates.
const RUNAROUND_SPEED_ADVANTAGE_FULL_YPS: f64 = 3.0;
const RUNAROUND_COVER_CLEARANCE_FULL_YARDS: f64 = 10.0;
// Knock pace: sized to the push distance so the ball rolls just past the defender into the
// re-collect zone without being overhit (a listed failure mode).
// Faster knock so the ball is past the committed defender before they react (beat the reaction
// lag); too slow and the defender simply steps across and intercepts.
const RUNAROUND_KNOCK_SPEED_PER_YARD: f64 = 1.9;
const RUNAROUND_KNOCK_MIN_SPEED_YPS: f64 = 8.0;
const RUNAROUND_KNOCK_MAX_SPEED_YPS: f64 = 14.0;
/// Immediate push of the ball off the foot on the knock — far enough past the carrier's own control
/// reach (~2.3yd) that it isn't re-grabbed the same tick, so it actually travels past the defender.
const RUNAROUND_KNOCK_NUDGE_YARDS: f64 = 2.7;

// "Outside mid attack defender" take-on tunables (see `is_outside_mid_attack_strategy`). When a
// wide midfielder/winger carries at a full-back who is ISOLATED — no covering team-mate of the
// defender within `OUTSIDE_MID_DEFENDER_COVER_RADIUS_YARDS` — back them to take the man on much more
// readily: lift the run-around appetite (quality), and relax the static-start preconditions so a
// wide man who has just received can still attack the isolated defender. This is the learnable
// MDP/POMDP appetite the user asked for (reward = beating the isolated man → flank penetration /
// xT into the cross zone); the run-around itself is the existing per-player MPC trajectory, and the
// "no cover within 10yd" is the geometry budget that makes the take-on "on".
/// A defender counts as ISOLATED for the take-on when no OTHER opponent is within this radius of
/// them — i.e. there is no second defender behind/beside the immediate man to cover the beat.
const OUTSIDE_MID_DEFENDER_COVER_RADIUS_YARDS: f64 = 10.0;
/// Default learnable uplift added to the run-around quality when a wide man faces an isolated
/// defender (scaled by how isolated the man is and the carrier's pace edge). Operator/learner
/// override via `DD_SOCCER_OMAD_TAKE_ON_UPLIFT`.
const OUTSIDE_MID_TAKE_ON_UPLIFT_DEFAULT: f64 = 0.40;

/// Learnable weight on the isolated-defender take-on appetite uplift (see
/// [`OUTSIDE_MID_TAKE_ON_UPLIFT_DEFAULT`]).
pub(crate) fn outside_mid_take_on_uplift() -> f64 {
    use std::sync::OnceLock;
    static V: OnceLock<f64> = OnceLock::new();
    *V.get_or_init(|| {
        std::env::var("DD_SOCCER_OMAD_TAKE_ON_UPLIFT")
            .ok()
            .and_then(|raw| raw.trim().parse::<f64>().ok())
            .filter(|w| w.is_finite() && *w >= 0.0)
            .map(|w| w.clamp(0.0, 1.0))
            .unwrap_or(OUTSIDE_MID_TAKE_ON_UPLIFT_DEFAULT)
    })
}

/// Quality + geometry of a viable run-around dribble (see [`RunaroundDribble`]). The carrier reads
/// this as a gated pre-empt appetite, mirroring the wall-pass plan.
#[derive(Clone, Copy, Debug)]
pub(crate) struct RunaroundDribblePlan {
    pub defender: usize,
    pub push_target: Vec2,
    pub recollect_point: Vec2,
    pub quality: f64,
}
fn soccer_observation_telemetry_enabled() -> bool {
    use std::sync::OnceLock;
    static V: OnceLock<bool> = OnceLock::new();
    *V.get_or_init(|| {
        std::env::var("DD_SOCCER_OBSERVATION_TELEMETRY")
            .map(|value| {
                matches!(
                    value.trim().to_ascii_lowercase().as_str(),
                    "1" | "true" | "yes" | "on"
                )
            })
            .unwrap_or(false)
    })
}
fn soccer_observation_telemetry_min_duration() -> Duration {
    use std::sync::OnceLock;
    static V: OnceLock<Duration> = OnceLock::new();
    *V.get_or_init(|| {
        let ms = std::env::var("DD_SOCCER_OBSERVATION_TELEMETRY_MIN_MS")
            .ok()
            .and_then(|value| value.trim().parse::<f64>().ok())
            .filter(|value| value.is_finite())
            .unwrap_or(25.0)
            .clamp(1.0, 10_000.0);
        Duration::from_secs_f64(ms / 1000.0)
    })
}
/// "Hold-and-summon support" (the carrier's wait-for-support / delay-before-pass strategy and
/// the matching off-ball summon boost) is ON by default. Set `DD_SOCCER_DISABLE_HOLD_FOR_SUPPORT=1`
/// to turn the whole mechanic off — the decision path is otherwise byte-identical to baseline,
/// since the option is only ever *added* in the calm/no-outlet/improvable window.
